/* AUTO-GENERATED — New York Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["NY"] = {"code":"NY","name":"New York","agency":"New York DMV","agencyShort":"DMV","handbook":"https://dmv.ny.gov/driver-license/commercial-drivers-manual-cdl-10","links":{},"en":[{"q":"On New York highways, what is the maximum legal height of a vehicle, including any load?","options":["13 feet 0 inches","13 feet 6 inches","14 feet 0 inches","12 feet 6 inches"],"answer":1,"explanation":"New York Vehicle and Traffic Law (VTL) Section 385 and the NY CDL Manual set the maximum vehicle height at 13 feet 6 inches (13.5 ft), including load. Posted bridges and overpasses may be lower.","handbook":"","hbref":""},{"q":"What is the maximum gross weight allowed for most vehicles on New York highways without a special permit?","options":["90,000 pounds","100,000 pounds","73,280 pounds","80,000 pounds"],"answer":3,"explanation":"Under NY VTL Section 385, the total gross weight of a vehicle or combination generally may not exceed 80,000 pounds unless an oversize/overweight permit is issued.","handbook":"","hbref":""},{"q":"Under New York Vehicle and Traffic Law, what is the maximum weight allowed on any single axle (without a permit)?","options":["18,000 pounds","24,000 pounds","20,000 pounds","22,400 pounds"],"answer":3,"explanation":"NY VTL Section 385 limits the weight on any single axle to 22,400 pounds. (On the Interstate system, the lower federal single-axle limit of 20,000 pounds applies.)","handbook":"","hbref":""},{"q":"What is the general maximum vehicle width on New York highways, except where wider widths are allowed on qualifying highways?","options":["102 inches (8 feet 6 inches)","120 inches (10 feet)","96 inches (8 feet)","90 inches (7 feet 6 inches)"],"answer":2,"explanation":"NY VTL Section 385 sets the general maximum width at 96 inches (8 feet). On the qualifying/Interstate highway system and traffic lanes 10 or more feet wide outside NYC, up to 102 inches is allowed.","handbook":"","hbref":""},{"q":"On New York's qualifying (Interstate) highway system, what maximum vehicle width is permitted?","options":["108 inches (9 feet)","120 inches (10 feet)","96 inches (8 feet)","102 inches (8 feet 6 inches)"],"answer":3,"explanation":"On the qualifying/Interstate highway system (and lanes at least 10 feet wide outside NYC), NY VTL Section 385 permits a maximum width of 102 inches, exclusive of mirrors and certain safety devices.","handbook":"","hbref":""},{"q":"In New York, what is the maximum length of a single (straight) truck, inclusive of load and bumpers?","options":["48 feet","35 feet","40 feet","45 feet"],"answer":2,"explanation":"NY VTL Section 385 limits a single vehicle (other than articulated buses and semitrailers) to 40 feet in length, inclusive of load and bumpers.","handbook":"","hbref":""},{"q":"In New York, what is the maximum length allowed for a semitrailer or trailer operated in a combination?","options":["53 feet","40 feet","45 feet","48 feet"],"answer":3,"explanation":"Under NY VTL Section 385, a semitrailer or trailer may not exceed 48 feet in length, inclusive of load. Operation of 53-foot trailers in New York generally requires special access permits.","handbook":"","hbref":""},{"q":"On the federal Interstate System in New York, what is the maximum weight allowed on a tandem axle group?","options":["40,000 pounds","22,400 pounds","36,000 pounds","34,000 pounds"],"answer":3,"explanation":"On the Interstate System, the federal tandem-axle limit of 34,000 pounds applies in New York, as referenced in 23 CFR 658.17 and the NY CDL Manual.","handbook":"","hbref":""},{"q":"On New York's Interstate System, what is the maximum allowable weight on a single axle?","options":["22,400 pounds","18,000 pounds","20,000 pounds","24,000 pounds"],"answer":2,"explanation":"The federal Interstate single-axle limit of 20,000 pounds applies on New York's Interstate System. NY's general state-law single-axle limit (off the Interstate) is higher at 22,400 pounds.","handbook":"","hbref":""},{"q":"In New York, which type of permit is used to move a load that cannot be reduced to legal size or weight?","options":["A non-divisible load (special hauling) permit","A standard registration certificate","A divisible load overweight permit","A hazardous materials endorsement"],"answer":0,"explanation":"NYSDOT issues special hauling (non-divisible load) permits for loads that cannot be divided into legal units without affecting the load's physical integrity, such as a single large machine.","handbook":"","hbref":""},{"q":"Which New York agency issues oversize/overweight special hauling permits for travel on state highways outside New York City?","options":["The Federal Motor Carrier Safety Administration (FMCSA)","The New York State Department of Transportation (NYSDOT)","The New York State Thruway Authority","The New York State DMV"],"answer":1,"explanation":"NYSDOT issues oversize/overweight (special hauling) permits for state highways. Within New York City, the NYC Department of Transportation issues such permits, and certain bridge/tunnel authorities control their own crossings.","handbook":"","hbref":""},{"q":"In New York, a 'divisible load' is best defined as a load that:","options":["May only be moved at night with an escort","Can be separated into legal units without affecting the load's physical integrity","Weighs more than 80,000 pounds in a single piece","Consists of a single indivisible machine"],"answer":1,"explanation":"Under NYSDOT rules, a divisible load is cargo of legal dimensions that can be separated into units of legal weight without affecting the load's physical integrity. Overweight permits for divisible loads are limited and not valid on local roads or in NYC.","handbook":"","hbref":""},{"q":"A New York Divisible Load Overweight Permit is generally NOT valid on which of the following?","options":["Local town, village, and county roads and roadways within New York City","Designated NYSDOT touring routes upstate","State-maintained portions of the qualifying highway system","State highways covered by the permit's region"],"answer":0,"explanation":"NYSDOT divisible load overweight permits are not valid on town, village, or county roads, on roadways under MTA/bridge or tunnel authority jurisdiction, or within New York City. Those jurisdictions enforce their own limits.","handbook":"","hbref":""},{"q":"The federal Bridge Formula, as applied in New York, limits the allowable weight on a group of axles based primarily on:","options":["The number of axles and the distance (spacing) between them","The type of cargo being hauled","The age and make of the tractor","The posted speed limit on the highway"],"answer":0,"explanation":"The Federal Bridge Gross Weight Formula, applied in NY on the Interstate system, limits weight on any group of axles according to the number of axles and the distance between the outer axles, to protect bridges.","handbook":"","hbref":""},{"q":"In New York, what is the maximum overall length of a combination of vehicles (tractor plus trailer), inclusive of load and bumpers, on highways where qualifying-highway length allowances do not apply?","options":["60 feet","65 feet","75 feet","53 feet"],"answer":1,"explanation":"NY VTL Section 385 limits a combination of vehicles to 65 feet overall, inclusive of load and bumpers, except as otherwise allowed on the qualifying highway system.","handbook":"","hbref":""},{"q":"Under New York law, what is the maximum weight allowed on any one wheel of a vehicle equipped with pneumatic tires?","options":["10,000 pounds","8,000 pounds","11,200 pounds","12,500 pounds"],"answer":2,"explanation":"NY VTL Section 385 limits the weight on any one wheel of a vehicle with pneumatic tires, when loaded, to 11,200 pounds (half of the 22,400-pound single-axle limit).","handbook":"","hbref":""},{"q":"Under New York VTL Section 385, a vehicle powered primarily by an engine fueled by natural gas may have a maximum gross weight of up to:","options":["80,000 pounds","82,000 pounds","88,000 pounds","85,000 pounds"],"answer":1,"explanation":"NY VTL Section 385 allows a vehicle operated by an engine fueled primarily by natural gas to have a maximum gross weight of up to 82,000 pounds, to account for the added weight of the fuel system.","handbook":"","hbref":""},{"q":"In New York, what is the maximum length of a bus carrying more than seven passengers (other than an articulated bus)?","options":["45 feet","40 feet","62 feet","55 feet"],"answer":0,"explanation":"NY VTL Section 385 limits a bus carrying more than seven passengers to 45 feet in length, while an articulated bus may be up to 62 feet.","handbook":"","hbref":""},{"q":"A New York carrier wants to move an oversize/overweight non-divisible load on state highways. What must be obtained before the trip?","options":["A NYSDOT special hauling permit issued before the move","Only a valid Class A CDL with no permit","A divisible load overweight permit","A hazardous materials endorsement"],"answer":0,"explanation":"Moving an oversize or overweight non-divisible load on New York state highways requires a NYSDOT special hauling permit obtained in advance; the permit specifies the route, dimensions, weight, and any escort or travel-time conditions.","handbook":"","hbref":""},{"q":"Which statement best describes how weight limits can differ between New York's state highways and local roads or bridges?","options":["Posted bridge limits never apply to commercial vehicles","Local limits are identical statewide with no posted exceptions","Local roads and posted bridges may have lower limits that must be obeyed even if a state permit is held","Local roads always allow heavier loads than state highways"],"answer":2,"explanation":"Per the NY CDL Manual and NYSDOT, a state oversize/overweight permit does not override lower limits posted on local roads, bridges, or facilities run by other authorities; drivers must obey the most restrictive posted limit.","handbook":"","hbref":""},{"q":"Under New York's CDL classification, which class is required to operate a tractor-trailer combination?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"The NY DMV defines a Class A CDL as a 'tractor-trailer' (a combination vehicle). Class B covers a bus or single-unit truck, and Class C covers a truck, bus, or stretch limo requiring an endorsement. Source: NY DMV 'Get a Commercial Driver License (CDL)' / CDL-10 Commercial Driver's Manual.","handbook":"","hbref":""},{"q":"According to the NY DMV, a single-unit truck or a bus that is not a combination vehicle is operated under which CDL class?","options":["Class A","Class B","Class C","Class E"],"answer":1,"explanation":"The NY DMV describes Class B as a 'bus or single-unit truck.' Class A is a tractor-trailer combination, and Class C is a truck, bus, or stretch limo that requires an endorsement (such as HazMat or passenger). Source: NY DMV CDL pages / CDL-10 manual.","handbook":"","hbref":""},{"q":"In New York, which CDL class is described as covering a truck, bus, or stretch limo that requires a specific endorsement?","options":["Class A","Class B","Class C","Class M"],"answer":2,"explanation":"The NY DMV defines Class C as a 'truck, bus, or stretch limo' that requires an endorsement, typically because it carries 16 or more passengers (including the driver) or hazardous materials. Source: NY DMV 'Get a Commercial Driver License (CDL)'.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a New York CDL valid only for intrastate driving (within New York State)?","options":["16 years old","18 years old","21 years old","25 years old"],"answer":1,"explanation":"A driver must be at least 18 years old to hold a New York CDL for intrastate driving (within NY only). Drivers under 21 are restricted to intrastate operation. Source: NY DMV commercial driver requirements.","handbook":"","hbref":""},{"q":"In New York, what is the minimum age required to drive a commercial vehicle in interstate commerce (across state lines)?","options":["18 years old","19 years old","20 years old","21 years old"],"answer":3,"explanation":"You must be at least 21 years old to operate a commercial vehicle in interstate commerce. Drivers aged 18 to 20 with a NY CDL are limited to intrastate (within New York) driving. Source: NY DMV CDL requirements; FMCSA 49 CFR 391.11.","handbook":"","hbref":""},{"q":"How long is a New York Commercial Learner Permit (CLP) valid after issuance under the current rules?","options":["30 days","Six months (180 days)","One year (365 days)","Five years"],"answer":2,"explanation":"For CLPs issued on or after December 27, 2022, New York extended CLP validity to one year (365 days), up from the previous six months, to streamline the process. Source: NY DMV news, 'DMV Extends Validity of Commercial Learner Permit.'","handbook":"","hbref":""},{"q":"Federal rules that apply in New York require a CLP holder to wait at least how long after the CLP is issued before taking the CDL skills (road) test?","options":["There is no minimum waiting period","7 days","14 days","30 days"],"answer":2,"explanation":"Under federal law (49 CFR 383.25), which applies in New York, a CLP holder is not eligible to take the CDL skills test until at least 14 days after the CLP was initially issued. Source: 49 CFR 383.25; FMCSA CDL standards.","handbook":"","hbref":""},{"q":"Which endorsement does a New York CDL holder need to transport hazardous materials requiring placarding?","options":["H (Hazardous Materials)","N (Tank Vehicles)","T (Doubles/Triples)","S (School Bus)"],"answer":0,"explanation":"The 'H' (Hazardous Materials) endorsement is required to haul placarded quantities of hazardous materials. In NY it requires being at least 21, passing a written test, completing HazMat ELDT (first-time applicants), and passing a fingerprint-based background check. Source: NY DMV 'CDL Endorsements.'","handbook":"","hbref":""},{"q":"To obtain a Hazardous Materials (H) endorsement in New York, an applicant must complete which security-related step?","options":["A vision exam at a private optometrist only","A fingerprint-based background check (through IdentoGO)","A 10-year residency interview with local police","A polygraph examination at the DMV"],"answer":1,"explanation":"New York HazMat (H) applicants must pass a fingerprint-based federal/state background check, conducted through IdentoGO, in addition to passing the written test and being at least 21. Source: NY DMV 'CDL Endorsements'; TSA HazMat Threat Assessment Program.","handbook":"","hbref":""},{"q":"Which NY CDL endorsement is required to operate a vehicle designed to transport liquids or gases in bulk in a permanently mounted tank?","options":["P (Passenger)","T (Doubles/Triples)","N (Tank Vehicles)","M (Metal Coil)"],"answer":2,"explanation":"The 'N' (Tank Vehicles) endorsement is required to drive vehicles transporting liquids or gases in bulk in a permanently mounted tank meeting certain thresholds. Source: NY DMV 'CDL Endorsements'; CDL-10 manual Section 9 (Tank Vehicles).","handbook":"","hbref":""},{"q":"In New York, which endorsement is required to pull double or triple trailers?","options":["T (Doubles/Triples)","N (Tank Vehicles)","H (Hazardous Materials)","P (Passenger)"],"answer":0,"explanation":"The 'T' (Doubles/Triples) endorsement is required to tow more than one trailer. It is obtained by passing a knowledge test; note that triple trailers are not legal on all New York roadways. Source: NY DMV 'CDL Endorsements'; CDL-10 manual Section 8 (Doubles and Triples).","handbook":"","hbref":""},{"q":"Which endorsement must a New York CDL holder have to drive a bus or van that carries 16 or more passengers (including the driver)?","options":["S (School Bus)","P (Passenger)","N (Tank Vehicles)","T (Doubles/Triples)"],"answer":1,"explanation":"The 'P' (Passenger) endorsement is required to operate vehicles designed to carry 16 or more people including the driver. The School Bus (S) endorsement is built on top of the P endorsement. Source: NY DMV 'CDL Endorsements'; CDL-10 manual Section 4 (Passenger Transport).","handbook":"","hbref":""},{"q":"In New York, what is a prerequisite for obtaining the School Bus (S) endorsement?","options":["Holding a HazMat (H) endorsement","Already holding, or applying at the same time for, the Passenger (P) endorsement","Holding a Tank Vehicles (N) endorsement","Holding a Doubles/Triples (T) endorsement"],"answer":1,"explanation":"Per the NY DMV, a driver must already hold the Passenger (P) endorsement or apply for the P and S endorsements at the same time to obtain the School Bus (S) endorsement. Source: NY DMV 'CDL Endorsements.'","handbook":"","hbref":""},{"q":"Which statement about New York's School Bus (S) endorsement knowledge test is correct?","options":["It has 20 multiple-choice questions and requires 16 correct answers to pass","It has 50 questions and requires 45 correct answers to pass","It requires only a road test and no written test","It is waived for anyone who already holds a Class A CDL"],"answer":0,"explanation":"The NY School Bus (S) endorsement written test is based on Section 10 of the CDL Manual and has 20 multiple-choice questions; a driver must answer 16 correctly to pass. No separate road test is required for the S endorsement itself. Source: NY DMV 'CDL Endorsements.'","handbook":"","hbref":""},{"q":"New York requires a special endorsement, not found in many other states, for commercial drivers transporting which cargo weighing 5,000 lbs or more?","options":["Compressed gas cylinders","Live animals","Metal coil","Hazardous waste"],"answer":2,"explanation":"New York Vehicle and Traffic Law requires a Metal Coil ('M') endorsement for commercial drivers who transport metal coils weighing 5,000 lbs or more. It is a NY-specific endorsement obtained by passing a 20-question written test (16 correct to pass). Source: NY DMV 'CDL Endorsements.'","handbook":"","hbref":""},{"q":"Drivers who operate buses for a motor carrier in New York (such as school or DOT-regulated carriers) are subject to which additional state program?","options":["Article 19-A (Special Requirements for Bus Drivers)","Article 31 (DWI program)","The Graduated License Law","The Move Over Law"],"answer":0,"explanation":"New York's Article 19-A of the Vehicle and Traffic Law imposes additional requirements on bus drivers for covered motor carriers, including being at least 21, having a valid license for several years, periodic physical performance tests, and an annual defensive-driving/behind-the-wheel review. Source: NY DMV Article 19-A Information; VTL Article 19-A.","handbook":"","hbref":""},{"q":"Under the federal Entry-Level Driver Training (ELDT) rule that applies in New York, who must complete training before testing?","options":["Only drivers seeking a HazMat endorsement","First-time Class A or B applicants, B-to-A upgrades, and first-time H, P, or S endorsement applicants","Only drivers over the age of 65","Every CDL holder at each license renewal"],"answer":1,"explanation":"ELDT applies to first-time Class A or Class B CDL applicants, Class B holders upgrading to Class A, and first-time applicants for the Hazardous Materials (H), Passenger (P), or School Bus (S) endorsements, for anyone who obtained a CLP on or after February 7, 2022. Source: FMCSA Training Provider Registry; NY DMV.","handbook":"","hbref":""},{"q":"Where must a New York CDL applicant's Entry-Level Driver Training (ELDT) be recorded to count toward CDL eligibility?","options":["On a paper certificate kept only by the driver","In the FMCSA Training Provider Registry (TPR)","In the local county clerk's office","Only in the driver's employer personnel file"],"answer":1,"explanation":"ELDT must be completed with a provider listed on the FMCSA Training Provider Registry (TPR), and the provider submits the completion certification electronically to the TPR before the applicant can take the CDL test. Source: FMCSA Entry-Level Driver Training (ELDT) / Training Provider Registry.","handbook":"","hbref":""},{"q":"When applying for a New York CDL, how does the DMV verify an applicant's identity?","options":["A single photo ID is always sufficient","Documents totaling at least 6 points of proof of identity, plus the Social Security Number","A verbal statement of identity only","A credit report and a utility bill"],"answer":1,"explanation":"The NY DMV uses a points-based system requiring documents totaling at least 6 points of proof of identity (with at least one bearing a signature), and applicants must provide their Social Security Number (or sign an affidavit if never issued one). Source: NY DMV proof of identity requirements (Form ID-44).","handbook":"","hbref":""},{"q":"As part of medical self-certification, a New York CDL holder who drives in interstate commerce and is not exempt from the medical card requirement must keep what on file with the DMV?","options":["A notarized letter from an employer","A current USDOT Medical Examiner's Certificate (medical card)","A copy of their high school diploma","A vehicle registration for each truck driven"],"answer":1,"explanation":"CDL holders must self-certify their driving category (e.g., Non-Excepted Interstate) and, if non-excepted, keep a current USDOT Medical Examiner's Certificate on file with the NY DMV; failure to do so can lead to downgrade of the CDL. Source: NY DMV CDL Medical Certification ('Self-Certify Your Driving Type').","handbook":"","hbref":""},{"q":"What is the maximum blood alcohol concentration (BAC) at which a person may legally operate a commercial motor vehicle (CMV) in New York?","options":["0.02%","0.04%","0.08%","0.10%"],"answer":1,"explanation":"New York follows the federal rule: it is illegal to operate a CMV with a BAC of .04% or more. This is half the 0.08% limit for non-commercial drivers. Source: NY CDL-10 Manual sec. 1.6.2; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"Under New York's implied consent rule for commercial drivers, operating a CMV means that you have automatically given your consent to what?","options":["A search of your cargo and logbook","Alcohol and drug testing","A vision and medical re-examination","An audit of your driving record"],"answer":1,"explanation":"The NY CDL manual states that if you operate a CMV, you shall be deemed to have given your consent to alcohol testing. Source: NY CDL-10 Manual sec. 1.6.2; NY VTL 1194 (implied consent).","handbook":"","hbref":""},{"q":"If a CMV driver in New York is found with a detectable amount of alcohol below the .04% limit, what happens?","options":["Nothing, because the driver is under the legal limit","The driver is placed out-of-service for 24 hours","The driver is disqualified for 60 days","The driver receives a written warning only"],"answer":1,"explanation":"A CMV driver with any detectable amount of alcohol under .04% is placed out-of-service for 24 hours, even though it is below the disqualifying limit. Source: NY CDL-10 Manual sec. 1.6.2.","handbook":"","hbref":""},{"q":"For a first major offense (such as driving a CMV with a BAC of .04% or higher), how long will a New York CDL holder be disqualified?","options":["60 days","120 days","At least one year","Three years"],"answer":2,"explanation":"A first major offense results in a disqualification of at least one year. Source: NY CDL-10 Manual sec. 1.6.2; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"A New York CDL holder commits a first major offense while operating a CMV that is placarded for hazardous materials. How long is the disqualification?","options":["One year","Three years","Five years","Lifetime"],"answer":1,"explanation":"A first major offense committed while operating a CMV placarded for hazardous materials results in a three-year disqualification, instead of the standard one year. Source: NY CDL-10 Manual sec. 1.6.2; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"What is the disqualification period for a New York CDL holder convicted of a SECOND major offense?","options":["One year","Three years","Ten years","Lifetime"],"answer":3,"explanation":"A second conviction for any of the listed major offenses results in a lifetime disqualification of the CLP and/or CDL. Source: NY CDL-10 Manual sec. 1.6.2; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"In New York, refusing to submit to blood alcohol testing while operating a CMV is treated how for CDL disqualification purposes?","options":["As a minor paperwork violation with no disqualification","As a serious traffic violation only","As a major offense, the same as a DUI conviction","As an out-of-service order violation"],"answer":2,"explanation":"Refusing to undergo blood alcohol testing is a major offense and carries the same minimum one-year first-offense disqualification as a DUI conviction. Source: NY CDL-10 Manual sec. 1.6.2; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"Which of the following is a major offense that can disqualify a New York CDL holder, even if it is committed in the driver's own personal car rather than a CMV?","options":["Following another vehicle too closely","Driving under the influence of alcohol","Making an improper lane change","Speeding 15 mph over the limit"],"answer":1,"explanation":"Driving any vehicle under the influence of alcohol or a controlled substance is a major offense that disqualifies a CDL holder; it need not occur in a CMV. The other choices are serious traffic violations. Source: NY CDL-10 Manual sec. 1.6.2 and 1.6.3.","handbook":"","hbref":""},{"q":"A New York CDL holder uses a commercial motor vehicle to commit a felony involving controlled substances. What is the result?","options":["A 120-day disqualification","A three-year disqualification","A lifetime disqualification with no 10-year reinstatement","A one-year disqualification"],"answer":2,"explanation":"Using a CMV to commit a felony involving controlled substances results in a lifetime disqualification, and the driver is not eligible for the 10-year reinstatement available for certain other lifetime cases. Source: NY CDL-10 Manual sec. 1.6.2; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"Which of the following is a major offense that causes CDL disqualification in New York?","options":["Leaving the scene of an accident without reporting","Driving 12 mph over the speed limit","Failing to use a turn signal","Parking in a no-standing zone"],"answer":0,"explanation":"Leaving the scene of an accident without reporting is a listed major offense carrying at least a one-year disqualification for a first offense. Source: NY CDL-10 Manual sec. 1.6.2; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"Which of the following is classified as a SERIOUS traffic violation under New York CDL rules?","options":["Driving with a BAC of .04% or higher","Excessive speeding of 15 mph or more above the posted limit","Refusing a chemical test","Leaving the scene of an accident"],"answer":1,"explanation":"Excessive speeding (15 mph or more above the posted limit) is a serious traffic violation. The other choices are major offenses, which carry far harsher penalties. Source: NY CDL-10 Manual sec. 1.6.3; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"How long is a New York CDL holder disqualified for committing TWO serious traffic violations in a CMV within a three-year period?","options":["At least 30 days","At least 60 days","At least 120 days","At least one year"],"answer":1,"explanation":"Two serious traffic violations within a three-year period (in a CMV) result in a disqualification of at least 60 days. Source: NY CDL-10 Manual sec. 1.6.3; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"How long is a New York CDL holder disqualified for committing THREE serious traffic violations in a CMV within a three-year period?","options":["At least 60 days","At least 90 days","At least 120 days","At least one year"],"answer":2,"explanation":"Three serious traffic violations within a three-year period (in a CMV) result in a disqualification of at least 120 days. Source: NY CDL-10 Manual sec. 1.6.3; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"Operating a CMV in New York while using a handheld cell phone or texting device is classified as what?","options":["A major offense","A serious traffic violation","An out-of-service order violation","A railroad-crossing violation"],"answer":1,"explanation":"Using a handheld cell phone and/or texting device while operating a CMV is listed as a serious traffic violation. New York also bans handheld device use for all drivers under VTL 1225-c and 1225-d. Source: NY CDL-10 Manual sec. 1.6.3.","handbook":"","hbref":""},{"q":"Which of the following is a serious traffic violation rather than a major offense for a New York CDL holder?","options":["Following a vehicle too closely","Driving a CMV while your CDL is revoked","Using a CMV to commit a felony","Causing a fatality through negligent CMV operation"],"answer":0,"explanation":"Following too closely is a serious traffic violation. The other three are major offenses carrying at least a one-year (or lifetime) disqualification. Source: NY CDL-10 Manual sec. 1.6.2 and 1.6.3; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"According to the New York CDL manual, how long is a CDL holder disqualified for a FIRST conviction of violating an out-of-service order?","options":["At least 90 days","At least 30 days","At least one year","At least three years"],"answer":0,"explanation":"The NY CDL-10 manual lists a minimum 90-day disqualification for a first out-of-service order violation. Source: NY CDL-10 Manual sec. 1.6.4. (Note: the federal table in 49 CFR 383.51 sets a 180-day minimum for non-HazMat first offenses.)","handbook":"","hbref":""},{"q":"Per the New York CDL manual, what is the disqualification for committing TWO out-of-service order violations within a ten-year period?","options":["At least 60 days","At least 120 days","At least one year","At least three years"],"answer":2,"explanation":"Two out-of-service order violations within a ten-year period result in a disqualification of at least one year. Source: NY CDL-10 Manual sec. 1.6.4.","handbook":"","hbref":""},{"q":"Per the New York CDL manual, what is the disqualification for committing THREE or more out-of-service order violations within a ten-year period?","options":["At least one year","At least two years","At least three years","At least five years"],"answer":2,"explanation":"Three or more out-of-service order violations within a ten-year period result in a disqualification of at least three years. Source: NY CDL-10 Manual sec. 1.6.4.","handbook":"","hbref":""},{"q":"What is the disqualification period for a New York CDL holder's FIRST railroad-highway grade crossing violation committed while operating a CMV?","options":["At least 30 days","At least 60 days","At least 120 days","At least one year"],"answer":1,"explanation":"A first railroad-highway grade crossing violation results in a disqualification of at least 60 days. Source: NY CDL-10 Manual sec. 1.6.5; 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"A New York CDL holder commits a THIRD railroad-highway grade crossing violation within a three-year period. What is the disqualification?","options":["At least 120 days","At least 180 days","At least one year","At least three years"],"answer":2,"explanation":"Railroad-highway grade crossing violations carry at least 60 days for the first, 120 days for the second within three years, and at least one year for the third within a three-year period. Source: NY CDL-10 Manual sec. 1.6.5; 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"You are driving a tractor-trailer in New York City and see a sign reading 'NO COMMERCIAL VEHICLES.' What does this sign indicate about the roadway ahead?","options":["It is a New York State parkway designed for automobiles only, where commercial vehicles are prohibited","It is a designated through truck route open only at night","It is a toll-free express lane reserved for buses","It is a local delivery street where trucks may travel only while loading"],"answer":0,"explanation":"New York's parkway system was built early in the 20th century for automobiles only, and no commercial vehicles, including tractor-trailers and buses, are permitted on these parkways. The 'NO COMMERCIAL VEHICLES' sign designates an automobile-only roadway. Source: NYS DOT Parkway Truck Brochure; NY VTL.","handbook":"","hbref":""},{"q":"A new commercial driver asks why low stone bridges over New York's downstate parkways are so dangerous for trucks. What is the BEST answer based on NY rules?","options":["The bridges have weight limits but no height limits posted","Some posted vertical clearances are as low as 6 feet 11 inches, and over-height trucks strike and get stuck under them","The bridges are reserved exclusively for buses during rush hour","Trucks are allowed but must sound their horn before each bridge"],"answer":1,"explanation":"The NYS DOT warns that low stone bridges on the parkway system have posted vertical clearances as low as 6 feet 11 inches. Commercial vehicles, which are banned from parkways, often hit and get stuck under these low bridges, causing serious accidents and long delays. Source: NYS DOT Parkway Truck Brochure.","handbook":"","hbref":""},{"q":"Which of the following is a downstate New York roadway where no commercial vehicles, including tractor-trailers, are permitted?","options":["The Long Island Expressway (I-495)","The New York State Thruway (I-87)","The Brooklyn-Queens Expressway (I-278)","The Belt Parkway in Brooklyn and Queens"],"answer":3,"explanation":"The Belt Parkway is one of the downstate parkways (along with the Henry Hudson, Cross Island, Hutchinson River, Grand Central, Northern State and others) where commercial vehicles are banned. Expressways and the Thruway are interstate routes open to trucks. Source: NYS DOT Parkway Truck Brochure; NYC DOT Parkway Restrictions.","handbook":"","hbref":""},{"q":"A commercial driver illegally enters a New York parkway and a tractor-trailer becomes stuck under a low bridge. Besides fines and points, what additional consequence does NY specifically warn about?","options":["A mandatory 30-day vehicle impound regardless of damage","Automatic loss of the CDL for one year on a first offense","Towing fees that can exceed $10,000 for tractor-trailers plus reimbursement to the state for bridge repair","A federal ban from operating in all 50 states"],"answer":2,"explanation":"The NYS DOT lists consequences of driving a commercial vehicle on a parkway: fines and/or points, possible injury, vehicle and bridge/guiderail damage, towing fees in excess of $10,000 for tractor-trailers, and reimbursement to the state for bridge repair. Source: NYS DOT Parkway Truck Brochure.","handbook":"","hbref":""},{"q":"In New York City, the truck route network is divided into two classes. What are they?","options":["Daytime truck routes and nighttime truck routes","Local truck routes and through truck routes","Express truck routes and toll truck routes","Borough truck routes and bridge truck routes"],"answer":1,"explanation":"NYC's truck route network (about 1,000 miles, defined in Section 4-13 of the NYC Traffic Rules) consists of Local Truck Routes, for trucks making a local pickup or delivery within a borough, and Through Truck Routes, for trucks passing through without an origin or destination in the area. Source: NYC DOT Truck Routing; NYC Traffic Rules 4-13.","handbook":"","hbref":""},{"q":"A truck must leave a designated NYC truck route to reach a delivery address. Under NYC truck route rules, how must the driver proceed?","options":["Use any street, in any direction, until the delivery is completed","Leave the truck route at the intersection nearest the destination, take the most direct route, and return to the nearest truck route the same way","Travel only on residential streets to avoid traffic congestion","Obtain a separate written off-route permit for each delivery"],"answer":1,"explanation":"NYC rules allow a truck to leave a designated route only to reach an origin or destination. The driver must leave at the intersection nearest the destination, proceed by the most direct route, then return to the nearest designated truck route by the most direct route. Source: NYC DOT Truck Routing; NYC Traffic Rules 4-13.","handbook":"","hbref":""},{"q":"Which vehicles are required to STOP at every railroad-highway grade crossing under New York and federal rules adopted by NY?","options":["All commercial vehicles over 26,000 pounds","Only vehicles towing trailers","Buses carrying passengers and vehicles carrying placarded hazardous materials","Only empty tank vehicles previously used for flammables"],"answer":2,"explanation":"In New York, buses carrying passengers and commercial vehicles displaying hazardous-materials placards must stop at all railroad crossings. They stop within 50 feet but not closer than 15 feet, look and listen, and must not shift gears while crossing. Source: NY CDL Manual CDL-10; 49 CFR 392.10.","handbook":"","hbref":""},{"q":"A New York driver of a placarded hazardous-materials truck must stop at a railroad crossing. Within what distance from the nearest rail must the vehicle stop?","options":["Within 50 feet but not closer than 15 feet","Within 100 feet but not closer than 25 feet","Exactly 5 feet from the nearest rail","Within 30 feet but not closer than 10 feet"],"answer":0,"explanation":"Vehicles required to stop at railroad crossings (placarded hazmat and buses with passengers) must stop within 50 feet but not closer than 15 feet from the nearest rail, then look and listen for trains before proceeding without shifting gears. Source: NY CDL Manual CDL-10; 49 CFR 392.10.","handbook":"","hbref":""},{"q":"Under New York's Move Over Law (VTL 1144-a), what must a commercial driver do when approaching an emergency or hazard vehicle stopped on the roadside with its warning lights flashing?","options":["Stop completely until the emergency vehicle leaves","Slow down and, when possible, move over one full lane away from the stopped vehicle","Sound the horn and maintain the posted speed","Move onto the shoulder and pass on the right"],"answer":1,"explanation":"New York's Move Over Law requires drivers to exercise due care, slow down, and move over one full lane away from a stopped emergency or hazard vehicle displaying flashing lights when it is safe to do so. As of 2023 the law was expanded to cover all stopped vehicles. Source: NY VTL 1144-a; NYS Governor's Traffic Safety Committee.","handbook":"","hbref":""},{"q":"New York's Move Over Law applies to hazard vehicles as well as emergency vehicles. Which of these is a 'hazard vehicle' covered by the law?","options":["A passenger car parked legally at a curb","A tow truck or maintenance vehicle displaying flashing amber lights","A taxi stopped to pick up a fare","A delivery van with its four-way flashers on in a driveway"],"answer":1,"explanation":"New York's Move Over Law covers hazard vehicles such as tow trucks, construction and maintenance vehicles, and sanitation vehicles that display flashing amber lights, in addition to police, fire, and ambulance vehicles. Source: NY VTL 1144-a; NYS Thruway Move Over materials.","handbook":"","hbref":""},{"q":"Under New York law, when may a commercial driver use a hand-held cell phone or texting device while operating a CMV?","options":["Only while stopped at a red light or stop sign","Only for calls under 30 seconds","Only when using the device for navigation","Never while operating the CMV; hand-held use and texting are prohibited"],"answer":3,"explanation":"New York prohibits commercial drivers from using a hand-held mobile phone or texting device while operating a CMV. Unlike some non-commercial situations, a commercial driver may not use a hand-held device even when stopped at a light. A conviction adds points and is a serious CDL offense. Source: NY VTL 1225-c and 1225-d; NY CDL Manual CDL-10.","handbook":"","hbref":""},{"q":"A commercial driver in New York is convicted a second time within three years of operating a CMV while using a hand-held phone or texting. What federal consequence applies on top of NY penalties?","options":["A permanent lifetime CDL revocation","A 60-day CDL disqualification for a second conviction within three years","Only a written warning from FMCSA","A $50 administrative fee with no disqualification"],"answer":1,"explanation":"Federal FMCSA rules, enforced in New York, disqualify a CDL holder for 60 days for a second hand-held phone/texting conviction within three years, and 120 days for a third or subsequent conviction within three years, in addition to state fines and points. Source: FMCSA 49 CFR 383.51; NY DMV.","handbook":"","hbref":""},{"q":"After stopping for a school bus with flashing red lights in New York, when may a driver proceed?","options":["Immediately after counting to five","As soon as no children are visible, even if lights still flash","When the bus resumes motion, or the bus driver or a traffic officer signals that it is safe to proceed","After the bus closes its door, regardless of the lights"],"answer":2,"explanation":"In New York a driver who has stopped for a school bus may not move again until the bus begins to move, or the bus driver or a police/traffic officer signals to proceed. The red flashers control the stop. Source: NY VTL 1174; NY DMV Driver's Manual Chapter 6.","handbook":"","hbref":""},{"q":"If a commercial vehicle must stop on the shoulder of a one-way or divided highway in New York, where should the three warning triangles (reflective devices) be placed?","options":["All three within 10 feet behind the vehicle","At about 10 feet, 100 feet, and 200 feet toward the approaching traffic","One in front and two directly under the trailer","At 25 feet, 50 feet, and 75 feet on the driver's side only"],"answer":1,"explanation":"On a one-way or divided highway, place warning devices about 10 feet, 100 feet, and 200 feet from the vehicle toward approaching traffic, in the center of the lane or shoulder the CMV occupies. Devices must be set out within 10 minutes. Source: NY CDL Manual CDL-10; 49 CFR 392.22.","handbook":"","hbref":""},{"q":"A commercial vehicle is stopped on a two-lane, two-way road in New York. How should the driver place the three emergency warning triangles?","options":["One 10 feet to the side, one 100 feet behind, and one 100 feet in front of the vehicle","All three 200 feet behind the vehicle","One on the roof and two on the front bumper","One 10 feet behind, one 50 feet behind, and one 50 feet in front"],"answer":0,"explanation":"On a two-way road, place one triangle within 10 feet of the rear on the traffic side, one about 100 feet behind, and one about 100 feet ahead of the vehicle, so traffic is warned from both directions. Source: NY CDL Manual CDL-10; 49 CFR 392.22.","handbook":"","hbref":""},{"q":"In New York, what is the maximum height a truck and its load may be WITHOUT a special oversize permit?","options":["11 feet","15 feet","16 feet 6 inches","13 feet 6 inches"],"answer":3,"explanation":"Under NY Vehicle and Traffic Law Section 385, the maximum legal height of a vehicle and load is 13 feet 6 inches; a height of 14 feet or more requires an oversize permit. Drivers must also obey posted clearance signs, which are common on NY's older bridges. Source: NY VTL 385; NY DMV.","handbook":"","hbref":""},{"q":"A New York bridge displays a posted overhead clearance lower than the truck's height. What must the commercial driver do?","options":["Proceed slowly and sound the horn while passing under","Let air out of the tires to lower the vehicle and continue","Not pass under the bridge and instead find an alternate legal route","Proceed if the load is the only part exceeding the clearance"],"answer":2,"explanation":"NY law prohibits moving a vehicle through any bridge or structure if the vehicle's height exceeds the posted clearance. The driver must take an alternate route. Over-height strikes on low-clearance bridges and parkways are a major NY safety problem. Source: NY VTL 385; NYS DOT bridge-strike guidance.","handbook":"","hbref":""},{"q":"How is a toll typically collected from a commercial vehicle on the modern New York State Thruway?","options":["Drivers must stop and pay cash at every interchange booth","Through cashless tolling using E-ZPass tags or tolls-by-mail invoices read by overhead gantries","Tolls are waived for all vehicles with a CDL","Drivers prepay a single flat annual fee at the DMV"],"answer":1,"explanation":"The New York State Thruway uses cashless tolling: overhead gantries read E-ZPass tags or photograph plates for a Tolls by Mail invoice, so vehicles no longer stop at booths. Commercial vehicles are charged by vehicle class and can earn discounts with NY E-ZPass. Source: NYS Thruway Authority - Cashless Tolling.","handbook":"","hbref":""},{"q":"What is the BEST practice for a commercial driver operating in New York during winter conditions such as snow and ice?","options":["Maintain normal highway speed and following distance to keep traffic moving","Reduce speed, increase following distance, and use tire chains where conditions or posted requirements demand them","Apply the brakes firmly and frequently to keep them warm","Drive in the far-left lane only and disengage all traction systems"],"answer":1,"explanation":"New York winters bring snow and ice, especially in upstate and lake-effect regions. The NY CDL Manual instructs drivers to slow down, increase following distance, brake gently, and use tire chains when conditions or posted signs require traction devices. Source: NY CDL Manual CDL-10, Driving in Adverse Conditions.","handbook":"","hbref":""},{"q":"Which government agency issues Commercial Driver Licenses (CDLs) in New York State?","options":["The Federal Motor Carrier Safety Administration (FMCSA)","The New York State Department of Motor Vehicles (NY DMV)","The New York State Department of Transportation (NYSDOT)","The U.S. Department of Motor Vehicles"],"answer":1,"explanation":"In New York, CDLs are administered and issued by the New York State Department of Motor Vehicles (NY DMV). The FMCSA sets federal CDL standards but does not issue the license. Source: NY DMV, Commercial Driver License (CDL).","handbook":"","hbref":""},{"q":"Before you can apply for a CDL or Commercial Learner Permit in New York, what must you generally already hold?","options":["A federal interstate operating authority number","A completed Article 19-A bus driver certification","A U.S. DOT Medical Examiner's Certificate dated within 24 hours","A valid New York State driver license (Class D, Class E, or Non-CDL C) or a valid CDL from another state"],"answer":3,"explanation":"NY DMV requires a first-time CDL applicant to already hold a New York driver license (Class D, E, or Non-CDL C) or a valid out-of-state CDL before applying. Source: NY DMV, Get a Commercial Driver License (CDL).","handbook":"","hbref":""},{"q":"New York verifies an applicant's identity for a CDL or permit using which system?","options":["A federal fingerprint-only background check","A 10-point credit-history verification system","A notarized single-document affidavit only","The NY DMV 6-point proof-of-identity system"],"answer":3,"explanation":"New York uses a 6-point proof-of-identity system: applicants must present documents totaling at least 6 points to prove their identity, plus proof of date of birth and residency. Source: NY DMV, Proof of Identity (6-point system).","handbook":"","hbref":""},{"q":"Under New York's 6-point ID system, what is the rule about the documents you present?","options":["Only photocopies are accepted so the DMV can keep them on file","Any document is accepted as long as it shows your photo","They must be originals or certified copies; photocopies and laminated documents are not accepted","Laminated documents are preferred because they last longer"],"answer":2,"explanation":"NY DMV requires that 6-point documents be original or certified copies. The DMV will not accept plain photocopies or laminated documents. Source: NY DMV, Proof of Identity.","handbook":"","hbref":""},{"q":"In addition to 6 points of identity documents, what else must a New York CDL applicant provide regarding their Social Security number?","options":["Nothing; New York does not collect Social Security numbers for CDLs","A federal tax return from each of the last three years","A Social Security number issued only after the CDL is granted","Proof of their Social Security number, or a signed affidavit if one was never issued"],"answer":3,"explanation":"NY DMV requires proof of your Social Security number; if you were never issued one, you must sign an affidavit stating that. Source: NY DMV, Proof of Identity / How to Apply.","handbook":"","hbref":""},{"q":"How does a New York applicant typically begin the CDL process at a DMV office?","options":["By scheduling and passing the road test before any written test","By submitting an Article 19-A affidavit to the carrier","By applying for a Commercial Learner Permit (CLP) and passing the required written knowledge test(s)","By mailing a renewal application and waiting for a new license"],"answer":2,"explanation":"The process starts at a DMV office: the applicant applies for a Commercial Learner Permit (CLP) and passes the written knowledge test(s) for the desired class and endorsements. Source: NY DMV, Get a Commercial Driver License (CDL).","handbook":"","hbref":""},{"q":"Which set of written knowledge tests does a New York applicant commonly take to obtain a Class A CLP?","options":["Only a single combined commercial driving exam","Only the Hazardous Materials and Passenger endorsement tests","An Article 19-A oral exam and a defensive driving test","General Knowledge, Air Brakes, and Combination Vehicles"],"answer":3,"explanation":"For a Class A CLP, New York applicants typically pass the General Knowledge, Air Brakes, and Combination Vehicles knowledge tests. Endorsement tests (Hazmat, Passenger, School Bus, etc.) are taken separately. Source: NY DMV, CDL knowledge tests.","handbook":"","hbref":""},{"q":"How long is a New York Commercial Learner Permit (CLP) valid after New York extended its validity period?","options":["30 days","Six months","Eight years","One year (365 days)"],"answer":3,"explanation":"New York extended CLP validity from six months to one year (365 days). Knowledge test scores are valid for the same period. Source: NY DMV, DMV Extends Validity of Commercial Learner Permit.","handbook":"","hbref":""},{"q":"What is the minimum amount of time a New York applicant must hold a CLP before taking the CDL road (skills) test?","options":["At least 90 days","There is no required waiting period","At least 14 days","At least 6 months"],"answer":2,"explanation":"Following the federal rule, you cannot schedule a New York CDL road test for a date within 14 days of when your CLP was issued. Source: NY DMV, Get a Commercial Driver License (CDL) / FMCSA.","handbook":"","hbref":""},{"q":"Before taking the CDL road test in New York for a first CDL (or to add a Hazmat, Passenger, or School Bus endorsement), what training must be completed first?","options":["Entry-Level Driver Training (ELDT) from a provider listed on the FMCSA Training Provider Registry","A New York-only defensive driving point-reduction course","An Article 19-A biennial behind-the-wheel evaluation","A 19A motor carrier affidavit course"],"answer":0,"explanation":"Federal ELDT rules (in effect since Feb. 7, 2022) require new CDL applicants and certain endorsement applicants to complete training from a provider on the FMCSA Training Provider Registry before the skills test. Source: NY DMV / FMCSA ELDT.","handbook":"","hbref":""},{"q":"In New York, how does completed ELDT need to relate to a scheduled CDL road test?","options":["ELDT can be completed at the test site on the day of the road test","Your completed ELDT must be on file with the DMV at least 7 days before the road test, or the test is canceled","ELDT only needs to be on file within 30 days after passing the road test","ELDT is never required to be on file with the New York DMV"],"answer":1,"explanation":"New York lets you schedule the road test before finishing ELDT, but the completed ELDT must be on file with DMV at least 7 days before the test or the road test is canceled (the $40 fee is not lost; you reschedule). Source: NY DMV, Get a CDL.","handbook":"","hbref":""},{"q":"How is the CDL road test scheduled in New York?","options":["By walking into any DMV office and testing immediately without an appointment","Through the NY DMV Road Test Scheduling System (online portal/phone)","Only by mailing a paper request to the FMCSA","Automatically, by the ELDT training provider on the applicant's behalf"],"answer":1,"explanation":"New York CDL road tests are scheduled through the DMV's Road Test Scheduling System (online portal, also available by phone). Source: NY DMV, Schedule and Take a Road Test.","handbook":"","hbref":""},{"q":"The New York CDL skills/road test is made up of which three components?","options":["Pre-trip vehicle inspection, basic control skills, and an on-road driving test","A written exam, a vision screening, and a fingerprint check","A Hazmat test, a passenger test, and a school bus test","An Article 19-A oral exam, a medical exam, and a defensive driving test"],"answer":0,"explanation":"The CDL skills test in New York has three parts: a pre-trip vehicle inspection, a basic control skills test, and an on-road driving test. Source: NY DMV / CDL Manual (CDL-10).","handbook":"","hbref":""},{"q":"If you take the New York CDL road test in a vehicle without air brakes, what happens to your CDL?","options":["An L restriction is added, prohibiting you from operating vehicles equipped with air brakes","Your CDL is upgraded to allow all brake types automatically","You receive a Hazmat endorsement by default","Nothing changes; brake equipment does not affect restrictions"],"answer":0,"explanation":"Testing in a vehicle without full air brakes results in an 'L' restriction (no air brakes). Related restrictions include 'E' (automatic transmission) and 'Z' (air-over-hydraulic brakes). Source: NY DMV, Get a CDL / CDL Manual.","handbook":"","hbref":""},{"q":"New York CDL self-certification requires a driver to choose how many federal driving categories?","options":["All four federal driving categories at once","One of four federal driving categories","Two of three federal driving categories","None; self-certification is optional in New York"],"answer":1,"explanation":"CDL holders must self-certify by choosing exactly ONE of four federal driving types. Source: NY DMV, Self-Certify Your Driving Type.","handbook":"","hbref":""},{"q":"Which are the four federal self-certification driving categories a New York CDL holder chooses from?","options":["Local, Regional, National, and International","Class A, Class B, Class C, and Class D","Interstate Non-Excepted, Intrastate Non-Excepted, Interstate Excepted, and Intrastate Excepted","Hazmat, Passenger, School Bus, and Tank"],"answer":2,"explanation":"The four self-certification categories are Interstate Non-Excepted (NI), Intrastate Non-Excepted (NA), Interstate Excepted (EI), and Intrastate Excepted (EA). Source: NY DMV, Self-Certify Your Driving Type.","handbook":"","hbref":""},{"q":"Which self-certification categories require a New York CDL holder to keep a current U.S. DOT Medical Examiner's Certificate on file?","options":["The Excepted categories only","The Non-Excepted categories (Interstate Non-Excepted and Intrastate Non-Excepted)","All four categories equally","None of the categories require a medical certificate"],"answer":1,"explanation":"Drivers who self-certify to a Non-Excepted type (NI or NA) must keep a current USDOT Medical Examiner's Certificate on file; Excepted drivers (EI/EA) do not. Source: NY DMV, CDL Medical Certification.","handbook":"","hbref":""},{"q":"Under current federal and New York procedures, how is a CDL holder's Medical Examiner's Certificate generally transmitted to the NY DMV?","options":["The certified medical examiner submits it electronically to the FMCSA National Registry, which forwards the result to DMV","The driver must always hand-deliver the original paper certificate to a DMV office","The certificate is never reported to DMV and is kept only by the driver","The employer mails the certificate to the FMCSA once per year"],"answer":0,"explanation":"Under federal rules, certified medical examiners upload exam results to the FMCSA National Registry, which then transmits the medical certification status to NY DMV electronically, rather than the driver mailing in a copy. Source: NY DMV / FMCSA Medical Certification.","handbook":"","hbref":""},{"q":"How long is a New York CDL valid, and how is it typically renewed?","options":["Valid for eight years; CDLs generally cannot be renewed online and are renewed by mail or in person","Valid for one year; renewed only online","Valid for two years; renewed automatically with no action","Valid for ten years; renewed only at the FMCSA"],"answer":0,"explanation":"A New York CDL is valid for eight years. Unlike standard licenses, CDLs generally cannot be renewed online and must be renewed by mail or at a DMV office. Source: NY DMV, Renew a Commercial Driver License (CDL).","handbook":"","hbref":""},{"q":"New York's Article 19-A sets special requirements for which group of drivers?","options":["All passenger-car drivers in New York City","Only hazardous materials tank-truck drivers","Bus drivers operating for covered motor carriers (such as school bus and certain NYSDOT-authorized carriers)","Out-of-state CDL holders passing through New York"],"answer":2,"explanation":"Article 19-A establishes special qualification requirements for bus drivers of covered motor carriers (e.g., school bus carriers and certain NYSDOT-authorized carriers), including biennial medical exams, behind-the-wheel and written/oral testing. Source: NY DMV, Article 19-A Information.","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная разрешённая высота транспортного средства, включая любой груз, на автомагистралях Нью-Йорка?","options":["13 футов 0 дюймов","13 футов 6 дюймов","14 футов 0 дюймов","12 футов 6 дюймов"],"explanation":"Закон Нью-Йорка о транспортных средствах и дорожном движении (VTL) §385 и Руководство NY CDL устанавливают максимальную высоту транспортного средства 13 футов 6 дюймов (13,5 фута), включая груз. Обозначенные знаками мосты и путепроводы могут иметь меньшую высоту."},"1":{"q":"Какова максимальная полная масса, разрешённая для большинства транспортных средств на автомагистралях Нью-Йорка без специального разрешения?","options":["90 000 фунтов","100 000 фунтов","73 280 фунтов","80 000 фунтов"],"explanation":"Согласно VTL §385 Нью-Йорка, полная масса транспортного средства или автопоезда, как правило, не может превышать 80 000 фунтов, если не выдано разрешение на сверхгабаритный/сверхтяжёлый груз."},"2":{"q":"Согласно Закону Нью-Йорка о транспортных средствах и дорожном движении, какова максимальная масса, разрешённая на любую одиночную ось (без разрешения)?","options":["18 000 фунтов","24 000 фунтов","20 000 фунтов","22 400 фунтов"],"explanation":"VTL §385 Нью-Йорка ограничивает массу на любую одиночную ось до 22 400 фунтов. (В системе межштатных автомагистралей действует более низкий федеральный предел для одиночной оси — 20 000 фунтов.)"},"3":{"q":"Какова общая максимальная ширина транспортного средства на автомагистралях Нью-Йорка, за исключением случаев, когда большая ширина разрешена на соответствующих автомагистралях?","options":["102 дюйма (8 футов 6 дюймов)","120 дюймов (10 футов)","96 дюймов (8 футов)","90 дюймов (7 футов 6 дюймов)"],"explanation":"VTL §385 Нью-Йорка устанавливает общую максимальную ширину 96 дюймов (8 футов). На соответствующей системе межштатных автомагистралей и на полосах движения шириной 10 футов и более за пределами Нью-Йорка допускается ширина до 102 дюймов."},"4":{"q":"Какая максимальная ширина транспортного средства разрешена на соответствующей (межштатной) системе автомагистралей Нью-Йорка?","options":["108 дюймов (9 футов)","120 дюймов (10 футов)","96 дюймов (8 футов)","102 дюйма (8 футов 6 дюймов)"],"explanation":"На соответствующей системе межштатных автомагистралей (и на полосах шириной не менее 10 футов за пределами Нью-Йорка) VTL §385 Нью-Йорка разрешает максимальную ширину 102 дюйма, без учёта зеркал и некоторых устройств безопасности."},"5":{"q":"Какова в Нью-Йорке максимальная длина одиночного (прямого) грузовика, включая груз и бамперы?","options":["48 футов","35 футов","40 футов","45 футов"],"explanation":"VTL §385 Нью-Йорка ограничивает длину одиночного транспортного средства (кроме сочленённых автобусов и полуприцепов) до 40 футов, включая груз и бамперы."},"6":{"q":"Какова в Нью-Йорке максимальная разрешённая длина полуприцепа или прицепа, эксплуатируемого в составе автопоезда?","options":["53 фута","40 футов","45 футов","48 футов"],"explanation":"Согласно VTL §385 Нью-Йорка, полуприцеп или прицеп не может превышать 48 футов в длину, включая груз. Эксплуатация 53-футовых прицепов в Нью-Йорке, как правило, требует специальных разрешений на доступ."},"7":{"q":"Какова на федеральной системе межштатных автомагистралей в Нью-Йорке максимальная масса, разрешённая на группу сдвоенных осей (тандем)?","options":["40 000 фунтов","22 400 фунтов","36 000 фунтов","34 000 фунтов"],"explanation":"На системе межштатных автомагистралей в Нью-Йорке действует федеральный предел для тандемной оси — 34 000 фунтов, как указано в 23 CFR 658.17 и Руководстве NY CDL."},"8":{"q":"Какова на системе межштатных автомагистралей Нью-Йорка максимально допустимая масса на одиночную ось?","options":["22 400 фунтов","18 000 фунтов","20 000 фунтов","24 000 фунтов"],"explanation":"На системе межштатных автомагистралей Нью-Йорка действует федеральный предел для одиночной оси — 20 000 фунтов. Общий предел Нью-Йорка по законодательству штата для одиночной оси (вне межштатных автомагистралей) выше — 22 400 фунтов."},"9":{"q":"Какой тип разрешения используется в Нью-Йорке для перевозки груза, который нельзя уменьшить до законных размеров или массы?","options":["Разрешение на неделимый груз (специальную перевозку)","Стандартное свидетельство о регистрации","Разрешение на перегруз для делимого груза","Допуск на перевозку опасных материалов"],"explanation":"NYSDOT выдаёт разрешения на специальную перевозку (неделимого груза) для грузов, которые нельзя разделить на законные единицы без нарушения физической целостности груза, например, для одной крупной машины."},"10":{"q":"Какое ведомство Нью-Йорка выдаёт специальные разрешения на сверхгабаритные/сверхтяжёлые перевозки для движения по автомагистралям штата за пределами города Нью-Йорк?","options":["Федеральное управление безопасности автоперевозчиков (FMCSA)","Департамент транспорта штата Нью-Йорк (NYSDOT)","Управление платных автомагистралей штата Нью-Йорк","NY DMV"],"explanation":"NYSDOT выдаёт разрешения на сверхгабаритные/сверхтяжёлые (специальные) перевозки для автомагистралей штата. В пределах города Нью-Йорк такие разрешения выдаёт NYC DOT, а некоторые мостовые/тоннельные управления контролируют собственные переправы."},"11":{"q":"В Нью-Йорке «делимый груз» лучше всего определяется как груз, который:","options":["Можно перевозить только ночью с сопровождением","Можно разделить на законные единицы без нарушения физической целостности груза","Весит более 80 000 фунтов в одном куске","Состоит из одной неделимой машины"],"explanation":"Согласно правилам NYSDOT, делимый груз — это груз законных размеров, который можно разделить на единицы законной массы без нарушения физической целостности груза. Разрешения на перегруз для делимых грузов ограничены и недействительны на местных дорогах или в Нью-Йорке."},"12":{"q":"Разрешение Нью-Йорка на перегруз делимого груза, как правило, НЕдействительно на каком из перечисленного?","options":["Местные дороги городов, посёлков и округов, а также дороги в пределах города Нью-Йорк","Обозначенные туристические маршруты NYSDOT в северной части штата","Обслуживаемые штатом участки соответствующей системы автомагистралей","Автомагистрали штата, охваченные регионом действия разрешения"],"explanation":"Разрешения NYSDOT на перегруз делимого груза недействительны на дорогах городов, посёлков или округов, на дорогах под юрисдикцией MTA/мостовых или тоннельных управлений, а также в пределах города Нью-Йорк. Эти юрисдикции применяют собственные ограничения."},"13":{"q":"Федеральная мостовая формула в применении в Нью-Йорке ограничивает допустимую массу на группу осей в первую очередь на основе:","options":["Количества осей и расстояния (интервала) между ними","Типа перевозимого груза","Возраста и марки тягача","Установленного ограничения скорости на автомагистрали"],"explanation":"Федеральная мостовая формула полной массы, применяемая в Нью-Йорке на системе межштатных автомагистралей, ограничивает массу на любую группу осей в зависимости от количества осей и расстояния между крайними осями для защиты мостов."},"14":{"q":"Какова в Нью-Йорке максимальная общая длина автопоезда (тягач плюс прицеп), включая груз и бамперы, на автомагистралях, где не применяются допуски по длине для соответствующих автомагистралей?","options":["60 футов","65 футов","75 футов","53 фута"],"explanation":"VTL §385 Нью-Йорка ограничивает автопоезд до 65 футов общей длины, включая груз и бамперы, за исключением случаев, иначе разрешённых на соответствующей системе автомагистралей."},"15":{"q":"Согласно закону Нью-Йорка, какова максимальная масса, разрешённая на любое одно колесо транспортного средства, оснащённого пневматическими шинами?","options":["10 000 фунтов","8 000 фунтов","11 200 фунтов","12 500 фунтов"],"explanation":"VTL §385 Нью-Йорка ограничивает массу на любое одно колесо транспортного средства с пневматическими шинами в гружёном состоянии до 11 200 фунтов (половина предела одиночной оси в 22 400 фунтов)."},"16":{"q":"Согласно VTL §385 Нью-Йорка, транспортное средство, приводимое в движение преимущественно двигателем на природном газе, может иметь максимальную полную массу до:","options":["80 000 фунтов","82 000 фунтов","88 000 фунтов","85 000 фунтов"],"explanation":"VTL §385 Нью-Йорка разрешает транспортному средству, приводимому в движение двигателем, работающим преимущественно на природном газе, иметь максимальную полную массу до 82 000 фунтов с учётом дополнительной массы топливной системы."},"17":{"q":"Какова в Нью-Йорке максимальная длина автобуса, перевозящего более семи пассажиров (кроме сочленённого автобуса)?","options":["45 футов","40 футов","62 фута","55 футов"],"explanation":"VTL §385 Нью-Йорка ограничивает длину автобуса, перевозящего более семи пассажиров, до 45 футов, тогда как сочленённый автобус может достигать 62 футов."},"18":{"q":"Перевозчик в Нью-Йорке хочет перевезти сверхгабаритный/сверхтяжёлый неделимый груз по автомагистралям штата. Что необходимо получить до поездки?","options":["Разрешение NYSDOT на специальную перевозку, выданное до перевозки","Только действующую CDL класса A без разрешения","Разрешение на перегруз для делимого груза","Допуск на перевозку опасных материалов"],"explanation":"Перевозка сверхгабаритного или сверхтяжёлого неделимого груза по автомагистралям штата Нью-Йорк требует разрешения NYSDOT на специальную перевозку, полученного заранее; в разрешении указываются маршрут, габариты, масса и любые условия по сопровождению или времени движения."},"19":{"q":"Какое утверждение лучше всего описывает, чем могут отличаться ограничения по массе между автомагистралями штата Нью-Йорк и местными дорогами или мостами?","options":["Обозначенные знаками ограничения для мостов никогда не применяются к коммерческим транспортным средствам","Местные ограничения одинаковы по всему штату без обозначенных исключений","Местные дороги и обозначенные знаками мосты могут иметь более низкие ограничения, которые необходимо соблюдать, даже при наличии разрешения штата","Местные дороги всегда допускают более тяжёлые грузы, чем автомагистрали штата"],"explanation":"Согласно Руководству NY CDL и NYSDOT, разрешение штата на сверхгабаритный/сверхтяжёлый груз не отменяет более низких ограничений, обозначенных знаками на местных дорогах, мостах или объектах, управляемых другими ведомствами; водители должны соблюдать наиболее строгое обозначенное знаками ограничение."},"20":{"q":"Согласно классификации CDL Нью-Йорка, какой класс требуется для управления автопоездом «тягач-прицеп»?","options":["Класс A","Класс B","Класс C","Класс D"],"explanation":"NY DMV определяет CDL класса A как «тягач-прицеп» (составное транспортное средство). Класс B охватывает автобус или одиночный грузовик, а класс C охватывает грузовик, автобус или лимузин-удлинитель, требующий допуска. Источник: NY DMV «Get a Commercial Driver License (CDL)» / Руководство для коммерческих водителей CDL-10."},"21":{"q":"Согласно NY DMV, одиночный грузовик или автобус, не являющийся составным транспортным средством, эксплуатируется по какому классу CDL?","options":["Класс A","Класс B","Класс C","Класс E"],"explanation":"NY DMV описывает класс B как «автобус или одиночный грузовик». Класс A — это автопоезд «тягач-прицеп», а класс C — грузовик, автобус или лимузин-удлинитель, требующий допуска (например, HazMat или пассажирского). Источник: страницы CDL NY DMV / руководство CDL-10."},"22":{"q":"В Нью-Йорке какой класс CDL описывается как охватывающий грузовик, автобус или лимузин-удлинитель, требующий определённого допуска?","options":["Класс A","Класс B","Класс C","Класс M"],"explanation":"NY DMV определяет класс C как «грузовик, автобус или лимузин-удлинитель», требующий допуска, обычно потому что он перевозит 16 или более пассажиров (включая водителя) или опасные материалы. Источник: NY DMV «Get a Commercial Driver License (CDL)»."},"23":{"q":"Каков минимальный возраст для получения CDL Нью-Йорка, действительной только для внутриштатного вождения (в пределах штата Нью-Йорк)?","options":["16 лет","18 лет","21 год","25 лет"],"explanation":"Водитель должен быть не моложе 18 лет, чтобы иметь CDL Нью-Йорка для внутриштатного вождения (только в пределах Нью-Йорка). Водители младше 21 года ограничены внутриштатной эксплуатацией. Источник: требования NY DMV к коммерческим водителям."},"24":{"q":"Каков в Нью-Йорке минимальный возраст, необходимый для управления коммерческим транспортным средством в межштатном сообщении (через границы штата)?","options":["18 лет","19 лет","20 лет","21 год"],"explanation":"Вам должно быть не менее 21 года для управления коммерческим транспортным средством в межштатном сообщении. Водители в возрасте от 18 до 20 лет с CDL Нью-Йорка ограничены внутриштатным (в пределах Нью-Йорка) вождением. Источник: требования NY DMV к CDL; FMCSA 49 CFR 391.11."},"25":{"q":"Сколько действует коммерческое ученическое разрешение Нью-Йорка (CLP) после выдачи согласно действующим правилам?","options":["30 дней","Шесть месяцев (180 дней)","Один год (365 дней)","Пять лет"],"explanation":"Для CLP, выданных 27 декабря 2022 года или позднее, Нью-Йорк продлил срок действия CLP до одного года (365 дней) по сравнению с прежними шестью месяцами для упрощения процесса. Источник: новости NY DMV «DMV Extends Validity of Commercial Learner Permit»."},"26":{"q":"Федеральные правила, действующие в Нью-Йорке, требуют, чтобы владелец CLP подождал не менее какого срока после выдачи CLP, прежде чем сдавать практический экзамен CDL (вождение)?","options":["Минимального периода ожидания нет","7 дней","14 дней","30 дней"],"explanation":"Согласно федеральному закону (49 CFR 383.25), действующему в Нью-Йорке, владелец CLP не имеет права сдавать практический экзамен CDL, пока не пройдёт не менее 14 дней с момента первоначальной выдачи CLP. Источник: 49 CFR 383.25; стандарты CDL FMCSA."},"27":{"q":"Какой допуск нужен владельцу CDL Нью-Йорка для перевозки опасных материалов, требующих размещения предупреждающих табличек?","options":["H (опасные материалы)","N (цистерны)","T (двойные/тройные прицепы)","S (школьный автобус)"],"explanation":"Допуск «H» (опасные материалы) требуется для перевозки опасных материалов в количествах, требующих размещения табличек. В Нью-Йорке для этого нужно быть не моложе 21 года, сдать письменный экзамен, пройти ELDT по HazMat (для впервые обращающихся) и пройти проверку биографических данных по отпечаткам пальцев. Источник: NY DMV «CDL Endorsements»."},"28":{"q":"Чтобы получить допуск на опасные материалы (H) в Нью-Йорке, заявитель должен выполнить какой шаг, связанный с безопасностью?","options":["Только проверку зрения у частного оптометриста","Проверку биографических данных по отпечаткам пальцев (через IdentoGO)","10-летнее собеседование по месту жительства с местной полицией","Проверку на полиграфе в DMV"],"explanation":"Заявители на HazMat (H) в Нью-Йорке должны пройти федеральную/штатную проверку биографических данных по отпечаткам пальцев, проводимую через IdentoGO, в дополнение к сдаче письменного экзамена и достижению возраста не менее 21 года. Источник: NY DMV «CDL Endorsements»; программа оценки угроз HazMat от TSA."},"29":{"q":"Какой допуск CDL Нью-Йорка требуется для управления транспортным средством, предназначенным для перевозки жидкостей или газов навалом в стационарно установленной цистерне?","options":["P (пассажирский)","T (двойные/тройные прицепы)","N (цистерны)","M (металлический рулон)"],"explanation":"Допуск «N» (цистерны) требуется для управления транспортными средствами, перевозящими жидкости или газы навалом в стационарно установленной цистерне, отвечающей определённым пороговым значениям. Источник: NY DMV «CDL Endorsements»; руководство CDL-10, раздел 9 (цистерны)."},"30":{"q":"В Нью-Йорке какой допуск требуется для буксировки двойных или тройных прицепов?","options":["T (двойные/тройные прицепы)","N (цистерны)","H (опасные материалы)","P (пассажирский)"],"explanation":"Допуск «T» (двойные/тройные прицепы) требуется для буксировки более одного прицепа. Он получается путём сдачи экзамена на знания; обратите внимание, что тройные прицепы разрешены не на всех дорогах Нью-Йорка. Источник: NY DMV «CDL Endorsements»; руководство CDL-10, раздел 8 (двойные и тройные прицепы)."},"31":{"q":"Какой допуск должен иметь владелец CDL Нью-Йорка для управления автобусом или фургоном, перевозящим 16 или более пассажиров (включая водителя)?","options":["S (школьный автобус)","P (пассажирский)","N (цистерны)","T (двойные/тройные прицепы)"],"explanation":"Допуск «P» (пассажирский) требуется для управления транспортными средствами, предназначенными для перевозки 16 или более человек, включая водителя. Допуск на школьный автобус (S) надстраивается поверх допуска P. Источник: NY DMV «CDL Endorsements»; руководство CDL-10, раздел 4 (перевозка пассажиров)."},"32":{"q":"В Нью-Йорке что является предварительным условием для получения допуска на школьный автобус (S)?","options":["Наличие допуска на опасные материалы (H)","Уже иметь, или подавать заявку одновременно на допуск пассажирский (P)","Наличие допуска на цистерны (N)","Наличие допуска на двойные/тройные прицепы (T)"],"explanation":"Согласно NY DMV, водитель должен уже иметь допуск пассажирский (P) или подавать заявку на допуски P и S одновременно, чтобы получить допуск на школьный автобус (S). Источник: NY DMV «CDL Endorsements»."},"33":{"q":"Какое утверждение об экзамене на знания для допуска на школьный автобус (S) в Нью-Йорке верно?","options":["В нём 20 вопросов с выбором ответа, и для сдачи требуется 16 правильных ответов","В нём 50 вопросов, и для сдачи требуется 45 правильных ответов","Он требует только экзамена по вождению и не требует письменного экзамена","Он не требуется для любого, кто уже имеет CDL класса A"],"explanation":"Письменный экзамен на допуск на школьный автобус (S) в Нью-Йорке основан на разделе 10 Руководства CDL и содержит 20 вопросов с выбором ответа; водитель должен ответить правильно на 16, чтобы сдать. Отдельного экзамена по вождению для самого допуска S не требуется. Источник: NY DMV «CDL Endorsements»."},"34":{"q":"Нью-Йорк требует специальный допуск, отсутствующий во многих других штатах, для коммерческих водителей, перевозящих какой груз массой 5 000 фунтов или более?","options":["Баллоны со сжатым газом","Живые животные","Металлический рулон","Опасные отходы"],"explanation":"Закон Нью-Йорка о транспортных средствах и дорожном движении требует допуск на металлический рулон («M») для коммерческих водителей, перевозящих металлические рулоны массой 5 000 фунтов или более. Это специфичный для Нью-Йорка допуск, получаемый путём сдачи письменного экзамена из 20 вопросов (16 правильных для сдачи). Источник: NY DMV «CDL Endorsements»."},"35":{"q":"Водители, управляющие автобусами для автоперевозчика в Нью-Йорке (например, школьными или регулируемыми DOT перевозчиками), подпадают под какую дополнительную программу штата?","options":["Article 19-A (особые требования к водителям автобусов)","Article 31 (программа DWI)","Закон о ступенчатой выдаче водительских прав","Закон Move Over"],"explanation":"Article 19-A Закона Нью-Йорка о транспортных средствах и дорожном движении налагает дополнительные требования на водителей автобусов охваченных автоперевозчиков, включая возраст не менее 21 года, наличие действующих прав в течение нескольких лет, периодические проверки физической подготовленности и ежегодную проверку безопасного вождения/вождения за рулём. Источник: NY DMV Article 19-A Information; VTL Article 19-A."},"36":{"q":"Согласно федеральному правилу об обучении водителей начального уровня (ELDT), действующему в Нью-Йорке, кто должен пройти обучение перед сдачей экзамена?","options":["Только водители, желающие получить допуск на HazMat","Впервые обращающиеся за CDL класса A или B, переходящие с B на A, а также впервые обращающиеся за допусками H, P или S","Только водители старше 65 лет","Каждый владелец CDL при каждом продлении прав"],"explanation":"ELDT применяется к впервые обращающимся за CDL класса A или класса B, владельцам класса B, переходящим на класс A, а также впервые обращающимся за допусками на опасные материалы (H), пассажирский (P) или школьный автобус (S), для всех, кто получил CLP 7 февраля 2022 года или позднее. Источник: FMCSA Training Provider Registry; NY DMV."},"37":{"q":"Где должно быть зарегистрировано обучение водителей начального уровня (ELDT) заявителя на CDL Нью-Йорка, чтобы оно засчитывалось для права на CDL?","options":["На бумажном сертификате, хранящемся только у водителя","В Реестре обучающих провайдеров FMCSA (TPR)","В офисе секретаря местного округа","Только в личном деле работодателя водителя"],"explanation":"ELDT должно быть пройдено у провайдера, включённого в Реестр обучающих провайдеров FMCSA (TPR), и провайдер электронно подаёт сертификацию о завершении в TPR, прежде чем заявитель сможет сдавать экзамен CDL. Источник: FMCSA Entry-Level Driver Training (ELDT) / Training Provider Registry."},"38":{"q":"При подаче заявки на CDL Нью-Йорка как DMV проверяет личность заявителя?","options":["Одного удостоверения личности с фотографией всегда достаточно","Документы на сумму не менее 6 баллов подтверждения личности, плюс номер социального страхования","Только устное заявление о личности","Кредитный отчёт и счёт за коммунальные услуги"],"explanation":"NY DMV использует балльную систему, требующую документы на сумму не менее 6 баллов подтверждения личности (как минимум один с подписью), а заявители должны предоставить свой номер социального страхования (или подписать аффидевит, если он никогда не выдавался). Источник: требования NY DMV к подтверждению личности (форма ID-44)."},"39":{"q":"В рамках медицинской самосертификации владелец CDL Нью-Йорка, который водит в межштатном сообщении и не освобождён от требования о медицинской карте, должен хранить что в DMV?","options":["Нотариально заверенное письмо от работодателя","Действующий медицинский сертификат USDOT (медицинскую карту)","Копию аттестата о среднем образовании","Регистрацию транспортного средства для каждого управляемого грузовика"],"explanation":"Владельцы CDL должны самостоятельно сертифицировать свою категорию вождения (например, Non-Excepted Interstate) и, если они не освобождены, хранить действующий медицинский сертификат USDOT в NY DMV; несоблюдение этого может привести к понижению категории CDL. Источник: NY DMV CDL Medical Certification («Self-Certify Your Driving Type»)."},"40":{"q":"Какова максимальная концентрация алкоголя в крови (BAC), при которой лицо может законно управлять коммерческим транспортным средством (CMV) в Нью-Йорке?","options":["0,02%","0,04%","0,08%","0,10%"],"explanation":"Нью-Йорк следует федеральному правилу: запрещено управлять CMV с BAC 0,04% или выше. Это половина предела 0,08% для некоммерческих водителей. Источник: NY CDL-10 Manual разд. 1.6.2; 49 CFR 383.51 Table 1."},"41":{"q":"Согласно правилу о подразумеваемом согласии Нью-Йорка для коммерческих водителей, управление CMV означает, что вы автоматически дали своё согласие на что?","options":["Обыск вашего груза и журнала учёта","Тестирование на алкоголь и наркотики","Повторное обследование зрения и медицинское обследование","Аудит вашей водительской истории"],"explanation":"Руководство NY CDL гласит, что если вы управляете CMV, считается, что вы дали своё согласие на тестирование на алкоголь. Источник: NY CDL-10 Manual разд. 1.6.2; NY VTL 1194 (подразумеваемое согласие)."},"42":{"q":"Если у водителя CMV в Нью-Йорке обнаружено определяемое количество алкоголя ниже предела 0,04%, что произойдёт?","options":["Ничего, поскольку водитель ниже законного предела","Водитель отстраняется от работы на 24 часа","Водитель дисквалифицируется на 60 дней","Водитель получает только письменное предупреждение"],"explanation":"Водитель CMV с любым определяемым количеством алкоголя ниже 0,04% отстраняется от работы на 24 часа, даже если это ниже дисквалифицирующего предела. Источник: NY CDL-10 Manual разд. 1.6.2."},"43":{"q":"За первое серьёзное нарушение (например, управление CMV с BAC 0,04% или выше) на какой срок будет дисквалифицирован владелец CDL Нью-Йорка?","options":["60 дней","120 дней","Не менее одного года","Три года"],"explanation":"Первое серьёзное нарушение влечёт дисквалификацию не менее чем на один год. Источник: NY CDL-10 Manual разд. 1.6.2; 49 CFR 383.51 Table 1."},"44":{"q":"Владелец CDL Нью-Йорка совершает первое серьёзное нарушение при управлении CMV, на котором размещены таблички для опасных материалов. Какова длительность дисквалификации?","options":["Один год","Три года","Пять лет","Пожизненно"],"explanation":"Первое серьёзное нарушение, совершённое при управлении CMV с табличками для опасных материалов, влечёт трёхлетнюю дисквалификацию вместо стандартного одного года. Источник: NY CDL-10 Manual разд. 1.6.2; 49 CFR 383.51 Table 1."},"45":{"q":"Каков срок дисквалификации для владельца CDL Нью-Йорка, осуждённого за ВТОРОЕ серьёзное нарушение?","options":["Один год","Три года","Десять лет","Пожизненно"],"explanation":"Второе осуждение за любое из перечисленных серьёзных нарушений влечёт пожизненную дисквалификацию CLP и/или CDL. Источник: NY CDL-10 Manual разд. 1.6.2; 49 CFR 383.51 Table 1."},"46":{"q":"В Нью-Йорке как для целей дисквалификации CDL рассматривается отказ пройти тестирование на содержание алкоголя в крови при управлении CMV?","options":["Как незначительное канцелярское нарушение без дисквалификации","Только как серьёзное нарушение правил дорожного движения","Как серьёзное нарушение, наравне с осуждением за DUI","Как нарушение приказа об отстранении от работы"],"explanation":"Отказ пройти тестирование на содержание алкоголя в крови является серьёзным нарушением и влечёт ту же минимальную дисквалификацию за первое нарушение в один год, что и осуждение за DUI. Источник: NY CDL-10 Manual разд. 1.6.2; 49 CFR 383.51 Table 1."},"47":{"q":"Что из перечисленного является серьёзным нарушением, которое может дисквалифицировать владельца CDL Нью-Йорка, даже если оно совершено в личном автомобиле водителя, а не в CMV?","options":["Слишком близкое следование за другим транспортным средством","Вождение в состоянии алкогольного опьянения","Неправильная смена полосы движения","Превышение скорости на 15 миль/ч"],"explanation":"Вождение любого транспортного средства в состоянии алкогольного или наркотического опьянения является серьёзным нарушением, дисквалифицирующим владельца CDL; оно не обязательно должно происходить в CMV. Остальные варианты являются серьёзными нарушениями правил дорожного движения. Источник: NY CDL-10 Manual разд. 1.6.2 и 1.6.3."},"48":{"q":"Владелец CDL Нью-Йорка использует коммерческое транспортное средство для совершения тяжкого преступления, связанного с контролируемыми веществами. Каков результат?","options":["Дисквалификация на 120 дней","Дисквалификация на три года","Пожизненная дисквалификация без 10-летнего восстановления","Дисквалификация на один год"],"explanation":"Использование CMV для совершения тяжкого преступления, связанного с контролируемыми веществами, влечёт пожизненную дисквалификацию, и водитель не имеет права на 10-летнее восстановление, доступное в некоторых других случаях пожизненной дисквалификации. Источник: NY CDL-10 Manual разд. 1.6.2; 49 CFR 383.51 Table 1."},"49":{"q":"Что из перечисленного является серьёзным нарушением, вызывающим дисквалификацию CDL в Нью-Йорке?","options":["Оставление места происшествия без уведомления","Превышение скорости на 12 миль/ч","Неиспользование сигнала поворота","Парковка в зоне запрета остановки"],"explanation":"Оставление места происшествия без уведомления является перечисленным серьёзным нарушением, влекущим дисквалификацию не менее чем на один год за первое нарушение. Источник: NY CDL-10 Manual разд. 1.6.2; 49 CFR 383.51 Table 1."},"50":{"q":"Что из перечисленного классифицируется как СЕРЬЕЗНОЕ нарушение правил дорожного движения согласно правилам CDL штата Нью-Йорк?","options":["Управление транспортным средством с уровнем BAC .04% или выше","Превышение скорости на 15 миль/ч или более сверх установленного ограничения","Отказ от прохождения химического теста","Оставление места происшествия"],"explanation":"Чрезмерное превышение скорости (на 15 миль/ч или более сверх установленного ограничения) является серьезным нарушением правил дорожного движения. Остальные варианты являются тяжкими нарушениями, которые влекут за собой гораздо более суровые наказания. Источник: Руководство NY CDL-10, разд. 1.6.3; 49 CFR 383.51, Таблица 2."},"51":{"q":"На какой срок дисквалифицируется владелец CDL штата Нью-Йорк за совершение ДВУХ серьезных нарушений правил дорожного движения на CMV в течение трехлетнего периода?","options":["Не менее 30 дней","Не менее 60 дней","Не менее 120 дней","Не менее одного года"],"explanation":"Два серьезных нарушения правил дорожного движения в течение трехлетнего периода (на CMV) влекут дисквалификацию на срок не менее 60 дней. Источник: Руководство NY CDL-10, разд. 1.6.3; 49 CFR 383.51, Таблица 2."},"52":{"q":"На какой срок дисквалифицируется владелец CDL штата Нью-Йорк за совершение ТРЕХ серьезных нарушений правил дорожного движения на CMV в течение трехлетнего периода?","options":["Не менее 60 дней","Не менее 90 дней","Не менее 120 дней","Не менее одного года"],"explanation":"Три серьезных нарушения правил дорожного движения в течение трехлетнего периода (на CMV) влекут дисквалификацию на срок не менее 120 дней. Источник: Руководство NY CDL-10, разд. 1.6.3; 49 CFR 383.51, Таблица 2."},"53":{"q":"Управление CMV в штате Нью-Йорк при использовании ручного мобильного телефона или устройства для обмена текстовыми сообщениями классифицируется как что?","options":["Тяжкое нарушение","Серьезное нарушение правил дорожного движения","Нарушение предписания об отстранении от эксплуатации (out-of-service)","Нарушение на железнодорожном переезде"],"explanation":"Использование ручного мобильного телефона и/или устройства для обмена текстовыми сообщениями во время управления CMV числится серьезным нарушением правил дорожного движения. В штате Нью-Йорк также запрещено использование ручных устройств для всех водителей согласно VTL 1225-c и 1225-d. Источник: Руководство NY CDL-10, разд. 1.6.3."},"54":{"q":"Что из перечисленного является серьезным нарушением правил дорожного движения, а не тяжким нарушением для владельца CDL штата Нью-Йорк?","options":["Движение на слишком близком расстоянии за транспортным средством","Управление CMV при аннулированном CDL","Использование CMV для совершения тяжкого преступления (felony)","Причинение смерти в результате небрежного управления CMV"],"explanation":"Движение на слишком близком расстоянии является серьезным нарушением правил дорожного движения. Остальные три варианта являются тяжкими нарушениями, влекущими дисквалификацию не менее чем на один год (или пожизненную). Источник: Руководство NY CDL-10, разд. 1.6.2 и 1.6.3; 49 CFR 383.51."},"55":{"q":"Согласно руководству CDL штата Нью-Йорк, на какой срок дисквалифицируется владелец CDL за ПЕРВОЕ нарушение предписания об отстранении от эксплуатации (out-of-service)?","options":["Не менее 90 дней","Не менее 30 дней","Не менее одного года","Не менее трех лет"],"explanation":"Руководство NY CDL-10 указывает минимальную дисквалификацию на 90 дней за первое нарушение предписания об отстранении от эксплуатации. Источник: Руководство NY CDL-10, разд. 1.6.4. (Примечание: федеральная таблица в 49 CFR 383.51 устанавливает минимум 180 дней за первое нарушение для не-HazMat.)"},"56":{"q":"Согласно руководству CDL штата Нью-Йорк, какова дисквалификация за совершение ДВУХ нарушений предписания об отстранении от эксплуатации в течение десятилетнего периода?","options":["Не менее 60 дней","Не менее 120 дней","Не менее одного года","Не менее трех лет"],"explanation":"Два нарушения предписания об отстранении от эксплуатации в течение десятилетнего периода влекут дисквалификацию на срок не менее одного года. Источник: Руководство NY CDL-10, разд. 1.6.4."},"57":{"q":"Согласно руководству CDL штата Нью-Йорк, какова дисквалификация за совершение ТРЕХ или более нарушений предписания об отстранении от эксплуатации в течение десятилетнего периода?","options":["Не менее одного года","Не менее двух лет","Не менее трех лет","Не менее пяти лет"],"explanation":"Три или более нарушений предписания об отстранении от эксплуатации в течение десятилетнего периода влекут дисквалификацию на срок не менее трех лет. Источник: Руководство NY CDL-10, разд. 1.6.4."},"58":{"q":"Каков срок дисквалификации владельца CDL штата Нью-Йорк за ПЕРВОЕ нарушение на железнодорожном переезде (railroad-highway grade crossing), совершенное во время управления CMV?","options":["Не менее 30 дней","Не менее 60 дней","Не менее 120 дней","Не менее одного года"],"explanation":"Первое нарушение на железнодорожном переезде влечет дисквалификацию на срок не менее 60 дней. Источник: Руководство NY CDL-10, разд. 1.6.5; 49 CFR 383.51, Таблица 3."},"59":{"q":"Владелец CDL штата Нью-Йорк совершает ТРЕТЬЕ нарушение на железнодорожном переезде в течение трехлетнего периода. Какова дисквалификация?","options":["Не менее 120 дней","Не менее 180 дней","Не менее одного года","Не менее трех лет"],"explanation":"Нарушения на железнодорожном переезде влекут дисквалификацию не менее чем на 60 дней за первое, 120 дней за второе в течение трех лет и не менее одного года за третье в течение трехлетнего периода. Источник: Руководство NY CDL-10, разд. 1.6.5; 49 CFR 383.51, Таблица 3."},"60":{"q":"Вы управляете тягачом с прицепом в Нью-Йорке и видите знак с надписью 'NO COMMERCIAL VEHICLES' (коммерческим транспортным средствам проезд запрещен). Что этот знак указывает о дороге впереди?","options":["Это парквей (parkway) штата Нью-Йорк, предназначенный только для легковых автомобилей, где коммерческие транспортные средства запрещены","Это назначенный транзитный грузовой маршрут, открытый только ночью","Это бесплатная скоростная полоса, зарезервированная для автобусов","Это местная улица доставки, где грузовики могут двигаться только во время погрузки"],"explanation":"Система парквеев Нью-Йорка была построена в начале XX века только для легковых автомобилей, и никакие коммерческие транспортные средства, включая тягачи с прицепами и автобусы, не допускаются на эти парквеи. Знак 'NO COMMERCIAL VEHICLES' обозначает дорогу только для легковых автомобилей. Источник: Брошюра NYS DOT Parkway Truck; NY VTL."},"61":{"q":"Новый коммерческий водитель спрашивает, почему низкие каменные мосты над парквеями в южной части штата Нью-Йорк (downstate) так опасны для грузовиков. Каков ЛУЧШИЙ ответ согласно правилам штата Нью-Йорк?","options":["У мостов есть ограничения по весу, но не указаны ограничения по высоте","Некоторые указанные значения вертикального зазора составляют всего 6 футов 11 дюймов, и слишком высокие грузовики ударяются и застревают под ними","Мосты зарезервированы исключительно для автобусов в часы пик","Грузовикам разрешено, но они должны подавать звуковой сигнал перед каждым мостом"],"explanation":"NYS DOT предупреждает, что низкие каменные мосты в системе парквеев имеют указанный вертикальный зазор всего 6 футов 11 дюймов. Коммерческие транспортные средства, которым запрещен проезд по парквеям, часто ударяются и застревают под этими низкими мостами, вызывая серьезные аварии и длительные задержки. Источник: Брошюра NYS DOT Parkway Truck."},"62":{"q":"Какая из следующих дорог в южной части штата Нью-Йорк (downstate) является дорогой, где не допускаются никакие коммерческие транспортные средства, включая тягачи с прицепами?","options":["Лонг-Айлендский экспрессвей (I-495)","Тру́эй штата Нью-Йорк (New York State Thruway, I-87)","Бруклин-Куинский экспрессвей (I-278)","Белт-парквей (Belt Parkway) в Бруклине и Куинсе"],"explanation":"Белт-парквей — это один из парквеев южной части штата (наряду с Генри-Гудзон, Кросс-Айленд, Хатчинсон-Ривер, Гранд-Сентрал, Нортерн-Стейт и другими), где коммерческие транспортные средства запрещены. Экспрессвеи и Тру́эй являются маршрутами межштатного значения, открытыми для грузовиков. Источник: Брошюра NYS DOT Parkway Truck; ограничения парквеев NYC DOT."},"63":{"q":"Коммерческий водитель незаконно выезжает на парквей штата Нью-Йорк, и тягач с прицепом застревает под низким мостом. Помимо штрафов и баллов, о каком дополнительном последствии конкретно предупреждает штат Нью-Йорк?","options":["Обязательное изъятие транспортного средства на 30 дней независимо от ущерба","Автоматическая потеря CDL на один год при первом нарушении","Расходы на эвакуацию, которые могут превышать $10,000 для тягачей с прицепами, плюс возмещение штату за ремонт моста","Федеральный запрет на работу во всех 50 штатах"],"explanation":"NYS DOT перечисляет последствия управления коммерческим транспортным средством по парквею: штрафы и/или баллы, возможные травмы, повреждение транспортного средства и моста/отбойника, расходы на эвакуацию свыше $10,000 для тягачей с прицепами и возмещение штату за ремонт моста. Источник: Брошюра NYS DOT Parkway Truck."},"64":{"q":"В Нью-Йорке сеть грузовых маршрутов разделена на два класса. Какие они?","options":["Дневные грузовые маршруты и ночные грузовые маршруты","Местные грузовые маршруты и транзитные грузовые маршруты","Скоростные грузовые маршруты и платные грузовые маршруты","Окружные (borough) грузовые маршруты и мостовые грузовые маршруты"],"explanation":"Сеть грузовых маршрутов Нью-Йорка (около 1,000 миль, определенная в разделе 4-13 Правил дорожного движения NYC) состоит из местных грузовых маршрутов — для грузовиков, осуществляющих местный забор или доставку в пределах округа, — и транзитных грузовых маршрутов — для грузовиков, проезжающих транзитом без пункта отправления или назначения в данном районе. Источник: NYC DOT Truck Routing; Правила дорожного движения NYC 4-13."},"65":{"q":"Грузовик должен покинуть назначенный грузовой маршрут NYC, чтобы доехать до адреса доставки. Согласно правилам грузовых маршрутов NYC, как должен действовать водитель?","options":["Использовать любую улицу, в любом направлении, пока доставка не будет завершена","Покинуть грузовой маршрут на ближайшем к пункту назначения перекрестке, проехать самым прямым путем и вернуться на ближайший грузовой маршрут таким же образом","Двигаться только по жилым улицам, чтобы избежать дорожных заторов","Получать отдельное письменное разрешение на отклонение от маршрута для каждой доставки"],"explanation":"Правила NYC разрешают грузовику покидать назначенный маршрут только для того, чтобы доехать до пункта отправления или назначения. Водитель должен покинуть маршрут на ближайшем к пункту назначения перекрестке, проехать самым прямым путем, а затем вернуться на ближайший назначенный грузовой маршрут самым прямым путем. Источник: NYC DOT Truck Routing; Правила дорожного движения NYC 4-13."},"66":{"q":"Какие транспортные средства обязаны ОСТАНАВЛИВАТЬСЯ на каждом железнодорожном переезде согласно правилам штата Нью-Йорк и федеральным правилам, принятым штатом Нью-Йорк?","options":["Все коммерческие транспортные средства массой свыше 26,000 фунтов","Только транспортные средства, буксирующие прицепы","Автобусы с пассажирами и транспортные средства, перевозящие опасные материалы с табличками-плакатами (placards)","Только пустые автоцистерны, ранее использовавшиеся для легковоспламеняющихся веществ"],"explanation":"В штате Нью-Йорк автобусы, перевозящие пассажиров, и коммерческие транспортные средства с табличками-плакатами опасных материалов должны останавливаться на всех железнодорожных переездах. Они останавливаются в пределах 50 футов, но не ближе 15 футов, смотрят и слушают, и не должны переключать передачи во время переезда. Источник: Руководство NY CDL CDL-10; 49 CFR 392.10."},"67":{"q":"Водитель грузовика с опасными материалами, имеющего таблички-плакаты, в штате Нью-Йорк должен остановиться на железнодорожном переезде. В пределах какого расстояния от ближайшего рельса должно остановиться транспортное средство?","options":["В пределах 50 футов, но не ближе 15 футов","В пределах 100 футов, но не ближе 25 футов","Ровно в 5 футах от ближайшего рельса","В пределах 30 футов, но не ближе 10 футов"],"explanation":"Транспортные средства, обязанные останавливаться на железнодорожных переездах (с табличками-плакатами опасных материалов и автобусы с пассажирами), должны останавливаться в пределах 50 футов, но не ближе 15 футов от ближайшего рельса, затем смотреть и слушать поезда, прежде чем продолжить движение без переключения передач. Источник: Руководство NY CDL CDL-10; 49 CFR 392.10."},"68":{"q":"Согласно закону штата Нью-Йорк «Уступи дорогу» (Move Over Law, VTL 1144-a), что должен делать коммерческий водитель при приближении к аварийному транспортному средству или транспортному средству-помехе, остановившемуся на обочине с включенными мигающими предупредительными огнями?","options":["Полностью остановиться, пока аварийное транспортное средство не уедет","Снизить скорость и, когда это возможно, перестроиться на одну полную полосу в сторону от остановившегося транспортного средства","Подать звуковой сигнал и сохранять установленную скорость","Выехать на обочину и обогнать справа"],"explanation":"Закон штата Нью-Йорк «Уступи дорогу» требует от водителей проявлять должную осторожность, снижать скорость и перестраиваться на одну полную полосу в сторону от остановившегося аварийного транспортного средства или транспортного средства-помехи с включенными мигающими огнями, когда это безопасно. С 2023 года закон был расширен и охватывает все остановившиеся транспортные средства. Источник: NY VTL 1144-a; Комитет губернатора штата Нью-Йорк по безопасности дорожного движения."},"69":{"q":"Закон штата Нью-Йорк «Уступи дорогу» применяется к транспортным средствам-помехам, а также к аварийным транспортным средствам. Что из перечисленного является «транспортным средством-помехой», на которое распространяется этот закон?","options":["Легковой автомобиль, законно припаркованный у бордюра","Эвакуатор или ремонтное транспортное средство с включенными мигающими желтыми (амбер) огнями","Такси, остановившееся, чтобы подобрать пассажира","Грузовой фургон доставки с включенной аварийной сигнализацией на подъездной дорожке"],"explanation":"Закон штата Нью-Йорк «Уступи дорогу» охватывает транспортные средства-помехи, такие как эвакуаторы, строительные и ремонтные транспортные средства, а также мусоровозы с включенными мигающими желтыми (амбер) огнями, в дополнение к полицейским, пожарным машинам и машинам скорой помощи. Источник: NY VTL 1144-a; материалы Move Over Тру́эя штата Нью-Йорк."},"70":{"q":"Согласно закону штата Нью-Йорк, когда коммерческий водитель может использовать ручной мобильный телефон или устройство для обмена текстовыми сообщениями во время управления CMV?","options":["Только во время остановки на красный свет или у знака «Стоп»","Только для звонков короче 30 секунд","Только при использовании устройства для навигации","Никогда во время управления CMV; использование ручных устройств и обмен текстовыми сообщениями запрещены"],"explanation":"Штат Нью-Йорк запрещает коммерческим водителям использовать ручной мобильный телефон или устройство для обмена текстовыми сообщениями во время управления CMV. В отличие от некоторых некоммерческих ситуаций, коммерческий водитель не может использовать ручное устройство даже во время остановки на светофоре. Осуждение добавляет баллы и является серьезным нарушением для CDL. Источник: NY VTL 1225-c и 1225-d; Руководство NY CDL CDL-10."},"71":{"q":"Коммерческий водитель в штате Нью-Йорк осужден второй раз в течение трех лет за управление CMV с использованием ручного телефона или обмен текстовыми сообщениями. Какое федеральное последствие применяется в дополнение к наказаниям штата Нью-Йорк?","options":["Постоянное пожизненное аннулирование CDL","60-дневная дисквалификация CDL за второе осуждение в течение трех лет","Только письменное предупреждение от FMCSA","Административный сбор в $50 без дисквалификации"],"explanation":"Федеральные правила FMCSA, применяемые в штате Нью-Йорк, дисквалифицируют владельца CDL на 60 дней за второе осуждение за использование ручного телефона/обмен текстовыми сообщениями в течение трех лет и на 120 дней за третье или последующее осуждение в течение трех лет, в дополнение к штрафам и баллам штата. Источник: FMCSA 49 CFR 383.51; NY DMV."},"72":{"q":"После остановки перед школьным автобусом с мигающими красными огнями в штате Нью-Йорк, когда водитель может продолжить движение?","options":["Сразу после счета до пяти","Как только дети больше не видны, даже если огни все еще мигают","Когда автобус возобновляет движение, или водитель автобуса либо инспектор дорожного движения подает сигнал, что можно безопасно продолжить движение","После того как автобус закрыл двери, независимо от огней"],"explanation":"В штате Нью-Йорк водитель, остановившийся перед школьным автобусом, не может снова начать движение, пока автобус не начнет движение, или водитель автобуса либо сотрудник полиции/инспектор дорожного движения не подаст сигнал продолжать движение. Красные мигающие огни управляют остановкой. Источник: NY VTL 1174; Руководство водителя NY DMV, глава 6."},"73":{"q":"Если коммерческое транспортное средство должно остановиться на обочине дороги с односторонним движением или разделенной дороги в штате Нью-Йорк, где следует разместить три предупредительных треугольника (светоотражающих устройства)?","options":["Все три в пределах 10 футов позади транспортного средства","Примерно на 10 футах, 100 футах и 200 футах в сторону приближающегося транспортного потока","Один спереди и два прямо под прицепом","На 25 футах, 50 футах и 75 футах только со стороны водителя"],"explanation":"На дороге с односторонним движением или разделенной дороге разместите предупредительные устройства примерно на 10 футах, 100 футах и 200 футах от транспортного средства в сторону приближающегося потока, по центру полосы или обочины, которую занимает CMV. Устройства должны быть выставлены в течение 10 минут. Источник: Руководство NY CDL CDL-10; 49 CFR 392.22."},"74":{"q":"Коммерческое транспортное средство остановилось на двухполосной дороге с двусторонним движением в штате Нью-Йорк. Как водитель должен разместить три аварийных предупредительных треугольника?","options":["Один в 10 футах сбоку, один в 100 футах позади и один в 100 футах впереди транспортного средства","Все три в 200 футах позади транспортного средства","Один на крыше и два на переднем бампере","Один в 10 футах позади, один в 50 футах позади и один в 50 футах впереди"],"explanation":"На дороге с двусторонним движением разместите один треугольник в пределах 10 футов от задней части со стороны движения, один примерно в 100 футах позади и один примерно в 100 футах впереди транспортного средства, чтобы предупредить транспортный поток с обоих направлений. Источник: Руководство NY CDL CDL-10; 49 CFR 392.22."},"75":{"q":"Какова в штате Нью-Йорк максимальная высота грузовика и его груза БЕЗ специального разрешения на негабаритный груз?","options":["11 футов","15 футов","16 футов 6 дюймов","13 футов 6 дюймов"],"explanation":"Согласно разделу 385 Закона о транспортных средствах и дорожном движении штата Нью-Йорк (Vehicle and Traffic Law), максимальная допустимая высота транспортного средства с грузом составляет 13 футов 6 дюймов; высота 14 футов или более требует разрешения на негабаритный груз. Водители также должны соблюдать установленные знаки зазора, которые часто встречаются на старых мостах штата Нью-Йорк. Источник: NY VTL 385; NY DMV."},"76":{"q":"На мосту в штате Нью-Йорк указан надземный зазор ниже высоты грузовика. Что должен сделать коммерческий водитель?","options":["Проехать медленно и подавать звуковой сигнал во время проезда под мостом","Спустить воздух из шин, чтобы опустить транспортное средство, и продолжить движение","Не проезжать под мостом, а найти альтернативный законный маршрут","Проехать, если только груз превышает зазор"],"explanation":"Закон штата Нью-Йорк запрещает проезд транспортного средства через любой мост или сооружение, если высота транспортного средства превышает указанный зазор. Водитель должен выбрать альтернативный маршрут. Удары транспортных средств чрезмерной высоты по мостам и парквеям с низким зазором являются серьезной проблемой безопасности в штате Нью-Йорк. Источник: NY VTL 385; рекомендации NYS DOT по столкновениям с мостами."},"77":{"q":"Как обычно взимается плата за проезд с коммерческого транспортного средства на современном Тру́эе штата Нью-Йорк (New York State Thruway)?","options":["Водители должны останавливаться и платить наличными в каждой будке развязки","Посредством бескассового взимания платы (cashless tolling) с использованием меток E-ZPass или счетов «оплата по почте» (tolls-by-mail), считываемых надземными порталами","Плата за проезд отменена для всех транспортных средств с CDL","Водители заранее оплачивают единый фиксированный годовой сбор в DMV"],"explanation":"Тру́эй штата Нью-Йорк использует бескассовое взимание платы: надземные порталы считывают метки E-ZPass или фотографируют номерные знаки для счета Tolls by Mail, поэтому транспортные средства больше не останавливаются у будок. Плата с коммерческих транспортных средств взимается по классу транспортного средства, и они могут получать скидки с NY E-ZPass. Источник: Управление Тру́эя штата Нью-Йорк — Cashless Tolling."},"78":{"q":"Какова НАИЛУЧШАЯ практика для коммерческого водителя, работающего в штате Нью-Йорк в зимних условиях, таких как снег и лед?","options":["Сохранять нормальную скорость на трассе и дистанцию, чтобы поддерживать движение потока","Снизить скорость, увеличить дистанцию и использовать цепи противоскольжения там, где этого требуют условия или установленные знаки","Тормозить сильно и часто, чтобы тормоза оставались теплыми","Двигаться только по крайней левой полосе и отключить все системы сцепления"],"explanation":"Зимы в штате Нью-Йорк приносят снег и лед, особенно в северных (upstate) и подверженных эффекту озер регионах. Руководство NY CDL предписывает водителям снижать скорость, увеличивать дистанцию, тормозить плавно и использовать цепи противоскольжения, когда условия или установленные знаки требуют устройств сцепления. Источник: Руководство NY CDL CDL-10, раздел о вождении в неблагоприятных условиях."},"79":{"q":"Какое государственное ведомство выдает коммерческие водительские удостоверения (CDL) в штате Нью-Йорк?","options":["Федеральное управление безопасности грузовых перевозчиков (FMCSA)","Департамент транспортных средств штата Нью-Йорк (NY DMV)","Департамент транспорта штата Нью-Йорк (NYSDOT)","Департамент транспортных средств США"],"explanation":"В штате Нью-Йорк CDL администрируются и выдаются Департаментом транспортных средств штата Нью-Йорк (NY DMV). FMCSA устанавливает федеральные стандарты CDL, но не выдает удостоверение. Источник: NY DMV, Commercial Driver License (CDL)."},"80":{"q":"Прежде чем вы сможете подать заявление на CDL или коммерческое ученическое разрешение (Commercial Learner Permit) в штате Нью-Йорк, что вы, как правило, уже должны иметь?","options":["Федеральный номер разрешения на межштатную перевозку","Завершенную сертификацию водителя автобуса по Article 19-A","Медицинский сертификат врача-эксперта Министерства транспорта США (U.S. DOT), датированный в пределах 24 часов","Действующее водительское удостоверение штата Нью-Йорк (Class D, Class E или Non-CDL C) или действующее CDL другого штата"],"explanation":"NY DMV требует, чтобы заявитель, впервые получающий CDL, уже имел водительское удостоверение штата Нью-Йорк (Class D, E или Non-CDL C) или действующее CDL другого штата перед подачей заявления. Источник: NY DMV, Get a Commercial Driver License (CDL)."},"81":{"q":"С помощью какой системы штат Нью-Йорк проверяет личность заявителя на CDL или разрешение?","options":["Федеральная проверка биографии только по отпечаткам пальцев","10-балльная система проверки кредитной истории","Только нотариально заверенный аффидевит на основании одного документа","6-балльная система подтверждения личности NY DMV"],"explanation":"Штат Нью-Йорк использует 6-балльную систему подтверждения личности: заявители должны предъявить документы, в сумме дающие не менее 6 баллов, чтобы подтвердить свою личность, плюс подтверждение даты рождения и места жительства. Источник: NY DMV, Proof of Identity (6-балльная система)."},"82":{"q":"Согласно 6-балльной системе подтверждения личности штата Нью-Йорк, каково правило относительно предъявляемых документов?","options":["Принимаются только фотокопии, чтобы DMV мог хранить их в деле","Принимается любой документ, если на нем есть ваша фотография","Они должны быть оригиналами или заверенными копиями; фотокопии и ламинированные документы не принимаются","Ламинированные документы предпочтительнее, потому что служат дольше"],"explanation":"NY DMV требует, чтобы 6-балльные документы были оригиналами или заверенными копиями. DMV не примет простые фотокопии или ламинированные документы. Источник: NY DMV, Proof of Identity."},"83":{"q":"В дополнение к 6 баллам документов, удостоверяющих личность, что еще должен предоставить заявитель на CDL в штате Нью-Йорк в отношении своего номера социального страхования (Social Security number)?","options":["Ничего; штат Нью-Йорк не собирает номера социального страхования для CDL","Федеральную налоговую декларацию за каждый из последних трех лет","Номер социального страхования, выданный только после получения CDL","Подтверждение своего номера социального страхования или подписанный аффидевит, если он никогда не выдавался"],"explanation":"NY DMV требует подтверждения вашего номера социального страхования; если он вам никогда не выдавался, вы должны подписать аффидевит, заявляющий об этом. Источник: NY DMV, Proof of Identity / How to Apply."},"84":{"q":"Как заявитель в штате Нью-Йорк обычно начинает процесс получения CDL в офисе DMV?","options":["Записавшись и сдав дорожный тест до любого письменного теста","Подав аффидевит по Article 19-A перевозчику","Подав заявление на коммерческое ученическое разрешение (CLP) и сдав необходимый письменный тест(ы) на знание","Отправив заявление на продление по почте и ожидая нового удостоверения"],"explanation":"Процесс начинается в офисе DMV: заявитель подает заявление на коммерческое ученическое разрешение (CLP) и сдает письменный тест(ы) на знание для желаемого класса и подтверждений (endorsements). Источник: NY DMV, Get a Commercial Driver License (CDL)."},"85":{"q":"Какой набор письменных тестов на знание обычно сдает заявитель в штате Нью-Йорк для получения CLP класса A?","options":["Только один объединенный экзамен по коммерческому вождению","Только тесты на подтверждения для опасных материалов и пассажиров","Устный экзамен по Article 19-A и тест на безопасное вождение","Общие знания (General Knowledge), воздушные тормоза (Air Brakes) и составные транспортные средства (Combination Vehicles)"],"explanation":"Для CLP класса A заявители в штате Нью-Йорк обычно сдают тесты на знание по общим знаниям (General Knowledge), воздушным тормозам (Air Brakes) и составным транспортным средствам (Combination Vehicles). Тесты на подтверждения (Hazmat, Passenger, School Bus и т. д.) сдаются отдельно. Источник: NY DMV, CDL knowledge tests."},"86":{"q":"Сколько времени действует коммерческое ученическое разрешение (CLP) штата Нью-Йорк после того, как штат Нью-Йорк продлил срок его действия?","options":["30 дней","Шесть месяцев","Восемь лет","Один год (365 дней)"],"explanation":"Штат Нью-Йорк продлил срок действия CLP с шести месяцев до одного года (365 дней). Результаты теста на знание действительны в течение того же периода. Источник: NY DMV, DMV Extends Validity of Commercial Learner Permit."},"87":{"q":"Какой минимальный срок заявитель в штате Нью-Йорк должен владеть CLP, прежде чем сдавать дорожный тест (тест навыков) на CDL?","options":["Не менее 90 дней","Обязательного периода ожидания нет","Не менее 14 дней","Не менее 6 месяцев"],"explanation":"Согласно федеральному правилу, вы не можете назначить дорожный тест на CDL в штате Нью-Йорк на дату в пределах 14 дней с момента выдачи вашего CLP. Источник: NY DMV, Get a Commercial Driver License (CDL) / FMCSA."},"88":{"q":"Прежде чем сдавать дорожный тест на CDL в штате Нью-Йорк для первого CDL (или для добавления подтверждения Hazmat, Passenger или School Bus), какое обучение должно быть пройдено в первую очередь?","options":["Обучение водителей начального уровня (Entry-Level Driver Training, ELDT) от провайдера, указанного в Реестре провайдеров обучения FMCSA (Training Provider Registry)","Курс по снижению баллов за безопасное вождение, действующий только в штате Нью-Йорк","Двухгодичная оценка вождения за рулем по Article 19-A","Курс аффидевита автоперевозчика по 19A"],"explanation":"Федеральные правила ELDT (действуют с 7 февраля 2022 года) требуют, чтобы новые заявители на CDL и определенные заявители на подтверждения прошли обучение у провайдера из Реестра провайдеров обучения FMCSA перед тестом навыков. Источник: NY DMV / FMCSA ELDT."},"89":{"q":"В штате Нью-Йорк, как пройденное ELDT должно соотноситься с назначенным дорожным тестом на CDL?","options":["ELDT может быть пройдено на месте теста в день дорожного теста","Ваше пройденное ELDT должно быть в деле DMV не менее чем за 7 дней до дорожного теста, иначе тест отменяется","ELDT должно быть в деле только в течение 30 дней после сдачи дорожного теста","ELDT никогда не требуется иметь в деле в DMV штата Нью-Йорк"],"explanation":"Штат Нью-Йорк позволяет назначить дорожный тест до завершения ELDT, но пройденное ELDT должно быть в деле DMV не менее чем за 7 дней до теста, иначе дорожный тест отменяется (сбор $40 не теряется; вы переназначаете тест). Источник: NY DMV, Get a CDL."},"90":{"q":"Как назначается дорожный тест на CDL в штате Нью-Йорк?","options":["Зайдя в любой офис DMV и сдав тест немедленно без записи","Через систему записи на дорожный тест NY DMV (онлайн-портал/телефон)","Только отправив бумажный запрос в FMCSA по почте","Автоматически, провайдером обучения ELDT от имени заявителя"],"explanation":"Дорожные тесты на CDL в штате Нью-Йорк назначаются через систему записи на дорожный тест DMV (онлайн-портал, также доступна по телефону). Источник: NY DMV, Schedule and Take a Road Test."},"91":{"q":"Из каких трех компонентов состоит тест навыков/дорожный тест на CDL в штате Нью-Йорк?","options":["Предрейсовый осмотр транспортного средства, базовые навыки управления и дорожный тест вождения","Письменный экзамен, проверка зрения и проверка отпечатков пальцев","Тест Hazmat, тест на пассажиров и тест на школьный автобус","Устный экзамен по Article 19-A, медицинский осмотр и тест на безопасное вождение"],"explanation":"Тест навыков на CDL в штате Нью-Йорк состоит из трех частей: предрейсовый осмотр транспортного средства, тест базовых навыков управления и дорожный тест вождения. Источник: NY DMV / Руководство CDL (CDL-10)."},"92":{"q":"Если вы сдаете дорожный тест на CDL в штате Нью-Йорк на транспортном средстве без воздушных тормозов, что произойдет с вашим CDL?","options":["Добавляется ограничение L, запрещающее вам управлять транспортными средствами, оснащенными воздушными тормозами","Ваше CDL автоматически повышается, чтобы разрешить все типы тормозов","Вы получаете подтверждение Hazmat по умолчанию","Ничего не меняется; тормозное оборудование не влияет на ограничения"],"explanation":"Сдача теста на транспортном средстве без полноценных воздушных тормозов приводит к ограничению 'L' (без воздушных тормозов). Связанные ограничения включают 'E' (автоматическая трансмиссия) и 'Z' (пневмогидравлические тормоза). Источник: NY DMV, Get a CDL / Руководство CDL."},"93":{"q":"Самостоятельная сертификация (self-certification) для CDL штата Нью-Йорк требует, чтобы водитель выбрал, сколько федеральных категорий вождения?","options":["Все четыре федеральные категории вождения одновременно","Одну из четырех федеральных категорий вождения","Две из трех федеральных категорий вождения","Ни одной; самостоятельная сертификация необязательна в штате Нью-Йорк"],"explanation":"Владельцы CDL должны пройти самостоятельную сертификацию, выбрав ровно ОДНУ из четырех федеральных категорий вождения. Источник: NY DMV, Self-Certify Your Driving Type."},"94":{"q":"Какие четыре федеральные категории вождения для самостоятельной сертификации может выбрать владелец CDL штата Нью-Йорк?","options":["Местная, региональная, национальная и международная","Class A, Class B, Class C и Class D","Межштатная неисключенная (Interstate Non-Excepted), внутриштатная неисключенная (Intrastate Non-Excepted), межштатная исключенная (Interstate Excepted) и внутриштатная исключенная (Intrastate Excepted)","Hazmat, Passenger, School Bus и Tank"],"explanation":"Четыре категории самостоятельной сертификации — это межштатная неисключенная (NI), внутриштатная неисключенная (NA), межштатная исключенная (EI) и внутриштатная исключенная (EA). Источник: NY DMV, Self-Certify Your Driving Type."},"95":{"q":"Какие категории самостоятельной сертификации требуют, чтобы владелец CDL штата Нью-Йорк имел в деле действующий медицинский сертификат врача-эксперта Министерства транспорта США (U.S. DOT)?","options":["Только исключенные (Excepted) категории","Неисключенные (Non-Excepted) категории (межштатная неисключенная и внутриштатная неисключенная)","Все четыре категории одинаково","Ни одна из категорий не требует медицинского сертификата"],"explanation":"Водители, которые проходят самостоятельную сертификацию по неисключенному типу (NI или NA), должны иметь в деле действующий медицинский сертификат врача-эксперта USDOT; исключенные водители (EI/EA) — нет. Источник: NY DMV, CDL Medical Certification."},"96":{"q":"Согласно действующим федеральным процедурам и процедурам штата Нью-Йорк, как обычно передается медицинский сертификат врача-эксперта владельца CDL в NY DMV?","options":["Сертифицированный врач-эксперт подает его в электронном виде в Национальный реестр FMCSA (National Registry), который пересылает результат в DMV","Водитель всегда должен лично доставить оригинал бумажного сертификата в офис DMV","Сертификат никогда не сообщается в DMV и хранится только у водителя","Работодатель отправляет сертификат в FMCSA по почте раз в год"],"explanation":"Согласно федеральным правилам, сертифицированные врачи-эксперты загружают результаты осмотра в Национальный реестр FMCSA, который затем в электронном виде передает статус медицинской сертификации в NY DMV, вместо того чтобы водитель отправлял копию по почте. Источник: NY DMV / FMCSA Medical Certification."},"97":{"q":"Сколько времени действует CDL штата Нью-Йорк и как оно обычно продлевается?","options":["Действует восемь лет; CDL, как правило, нельзя продлить онлайн, и они продлеваются по почте или лично","Действует один год; продлевается только онлайн","Действует два года; продлевается автоматически без каких-либо действий","Действует десять лет; продлевается только в FMCSA"],"explanation":"CDL штата Нью-Йорк действует восемь лет. В отличие от стандартных удостоверений, CDL, как правило, нельзя продлить онлайн, и они должны продлеваться по почте или в офисе DMV. Источник: NY DMV, Renew a Commercial Driver License (CDL)."},"98":{"q":"Article 19-A штата Нью-Йорк устанавливает особые требования для какой группы водителей?","options":["Все водители легковых автомобилей в Нью-Йорке","Только водители автоцистерн с опасными материалами","Водители автобусов, работающие для охваченных автоперевозчиков (таких как школьные автобусы и определенные перевозчики, авторизованные NYSDOT)","Владельцы CDL других штатов, проезжающие транзитом через штат Нью-Йорк"],"explanation":"Article 19-A устанавливает особые квалификационные требования для водителей автобусов охваченных автоперевозчиков (например, перевозчиков школьных автобусов и определенных перевозчиков, авторизованных NYSDOT), включая двухгодичные медицинские осмотры, тестирование за рулем и письменное/устное тестирование. Источник: NY DMV, Article 19-A Information."}},"tr":{"0":{"q":"New York karayollarında, yükü dahil bir aracın yasal olarak izin verilen maksimum yüksekliği nedir?","options":["13 fit 0 inç","13 fit 6 inç","14 fit 0 inç","12 fit 6 inç"],"explanation":"New York Araç ve Trafik Kanunu (VTL) Bölüm 385 ve NY CDL Kılavuzu, yük dahil maksimum araç yüksekliğini 13 fit 6 inç (13,5 fit) olarak belirler. İşaretlenmiş köprüler ve üst geçitler daha düşük olabilir."},"1":{"q":"Özel bir izin olmaksızın New York karayollarında çoğu araç için izin verilen maksimum brüt ağırlık nedir?","options":["90.000 pound","100.000 pound","73.280 pound","80.000 pound"],"explanation":"NY VTL Bölüm 385 uyarınca, bir aracın veya kombinasyonun toplam brüt ağırlığı, bir gabari dışı/aşırı yük izni verilmediği sürece genel olarak 80.000 pound'u aşamaz."},"2":{"q":"New York Araç ve Trafik Kanunu uyarınca, herhangi bir tek aks üzerinde (izin olmaksızın) izin verilen maksimum ağırlık nedir?","options":["18.000 pound","24.000 pound","20.000 pound","22.400 pound"],"explanation":"NY VTL Bölüm 385, herhangi bir tek aks üzerindeki ağırlığı 22.400 pound ile sınırlar. (Interstate sisteminde, daha düşük olan federal tek aks sınırı 20.000 pound geçerlidir.)"},"3":{"q":"Uygun karayollarında daha geniş genişliklere izin verilen yerler hariç, New York karayollarında genel maksimum araç genişliği nedir?","options":["102 inç (8 fit 6 inç)","120 inç (10 fit)","96 inç (8 fit)","90 inç (7 fit 6 inç)"],"explanation":"NY VTL Bölüm 385, genel maksimum genişliği 96 inç (8 fit) olarak belirler. Uygun/Interstate karayolu sisteminde ve NYC dışında 10 fit veya daha geniş trafik şeritlerinde 102 inçe kadar izin verilir."},"4":{"q":"New York'un uygun (Interstate) karayolu sisteminde, izin verilen maksimum araç genişliği nedir?","options":["108 inç (9 fit)","120 inç (10 fit)","96 inç (8 fit)","102 inç (8 fit 6 inç)"],"explanation":"Uygun/Interstate karayolu sisteminde (ve NYC dışında en az 10 fit genişliğindeki şeritlerde), NY VTL Bölüm 385, aynalar ve belirli güvenlik cihazları hariç olmak üzere maksimum 102 inç genişliğe izin verir."},"5":{"q":"New York'ta, yük ve tamponlar dahil tek (düz) bir kamyonun maksimum uzunluğu nedir?","options":["48 fit","35 fit","40 fit","45 fit"],"explanation":"NY VTL Bölüm 385, tek bir aracı (mafsallı otobüsler ve yarı römorklar hariç) yük ve tamponlar dahil 40 fit uzunlukla sınırlar."},"6":{"q":"New York'ta, bir kombinasyonda çalıştırılan bir yarı römork veya römork için izin verilen maksimum uzunluk nedir?","options":["53 fit","40 fit","45 fit","48 fit"],"explanation":"NY VTL Bölüm 385 uyarınca, bir yarı römork veya römork, yük dahil 48 fit uzunluğu aşamaz. New York'ta 53 fitlik römorkların işletilmesi genellikle özel erişim izinleri gerektirir."},"7":{"q":"New York'taki federal Interstate Sisteminde, bir tandem aks grubu üzerinde izin verilen maksimum ağırlık nedir?","options":["40.000 pound","22.400 pound","36.000 pound","34.000 pound"],"explanation":"Interstate Sisteminde, federal tandem aks sınırı olan 34.000 pound, 23 CFR 658.17 ve NY CDL Kılavuzu'nda belirtildiği gibi New York'ta geçerlidir."},"8":{"q":"New York'un Interstate Sisteminde, tek bir aks üzerinde izin verilen maksimum ağırlık nedir?","options":["22.400 pound","18.000 pound","20.000 pound","24.000 pound"],"explanation":"Federal Interstate tek aks sınırı olan 20.000 pound, New York'un Interstate Sisteminde geçerlidir. NY'nin genel eyalet kanununa göre tek aks sınırı (Interstate dışında) 22.400 pound ile daha yüksektir."},"9":{"q":"New York'ta, yasal boyut veya ağırlığa indirgenemeyen bir yükü taşımak için hangi tür izin kullanılır?","options":["Bölünemez yük (özel taşıma) izni","Standart bir tescil belgesi","Bölünebilir yük aşırı ağırlık izni","Tehlikeli madde onayı"],"explanation":"NYSDOT, tek bir büyük makine gibi, yükün fiziksel bütünlüğünü etkilemeden yasal birimlere bölünemeyen yükler için özel taşıma (bölünemez yük) izinleri verir."},"10":{"q":"New York City dışındaki eyalet karayollarında seyahat için gabari dışı/aşırı yük özel taşıma izinlerini hangi New York kurumu verir?","options":["Federal Motorlu Taşıyıcı Güvenliği İdaresi (FMCSA)","New York Eyalet Ulaştırma Bakanlığı (NYSDOT)","New York Eyalet Thruway İdaresi","New York Eyalet DMV"],"explanation":"NYSDOT, eyalet karayolları için gabari dışı/aşırı yük (özel taşıma) izinlerini verir. New York City içinde, bu tür izinleri NYC DOT verir ve belirli köprü/tünel idareleri kendi geçişlerini kontrol eder."},"11":{"q":"New York'ta, 'bölünebilir yük' en iyi şekilde nasıl tanımlanan bir yüktür:","options":["Yalnızca geceleri bir refakatçi eşliğinde taşınabilen","Yükün fiziksel bütünlüğünü etkilemeden yasal birimlere ayrılabilen","Tek bir parça halinde 80.000 pound'dan fazla ağırlığa sahip olan","Tek bir bölünemez makineden oluşan"],"explanation":"NYSDOT kurallarına göre, bölünebilir bir yük, yükün fiziksel bütünlüğünü etkilemeden yasal ağırlıktaki birimlere ayrılabilen yasal boyutlardaki yüktür. Bölünebilir yükler için aşırı ağırlık izinleri sınırlıdır ve yerel yollarda veya NYC'de geçerli değildir."},"12":{"q":"New York Bölünebilir Yük Aşırı Ağırlık İzni genellikle aşağıdakilerden hangisinde geçerli DEĞİLDİR?","options":["New York City içindeki yerel kasaba, köy ve ilçe yolları ve karayolları","Eyaletin kuzeyinde belirlenmiş NYSDOT tur güzergahları","Uygun karayolu sisteminin eyalet tarafından bakımı yapılan bölümleri","İznin bölgesi kapsamındaki eyalet karayolları"],"explanation":"NYSDOT bölünebilir yük aşırı ağırlık izinleri, kasaba, köy veya ilçe yollarında, MTA/köprü veya tünel idaresi yetki alanındaki karayollarında veya New York City içinde geçerli değildir. Bu yetki alanları kendi sınırlarını uygular."},"13":{"q":"New York'ta uygulanan federal Köprü Formülü, bir aks grubu üzerindeki izin verilen ağırlığı esas olarak neye göre sınırlar:","options":["Aks sayısı ve aralarındaki mesafe (aralık)","Taşınan yükün türü","Çekicinin yaşı ve markası","Karayolundaki işaretlenmiş hız sınırı"],"explanation":"NY'de Interstate sisteminde uygulanan Federal Köprü Brüt Ağırlık Formülü, köprüleri korumak amacıyla herhangi bir aks grubu üzerindeki ağırlığı aks sayısına ve dış akslar arasındaki mesafeye göre sınırlar."},"14":{"q":"New York'ta, uygun karayolu uzunluk izinlerinin geçerli olmadığı karayollarında, bir araç kombinasyonunun (çekici artı römork) yük ve tamponlar dahil maksimum toplam uzunluğu nedir?","options":["60 fit","65 fit","75 fit","53 fit"],"explanation":"NY VTL Bölüm 385, uygun karayolu sisteminde aksi izin verilmedikçe, bir araç kombinasyonunu yük ve tamponlar dahil toplam 65 fit ile sınırlar."},"15":{"q":"New York kanunu uyarınca, pnömatik lastiklerle donatılmış bir aracın herhangi bir tekerleği üzerinde izin verilen maksimum ağırlık nedir?","options":["10.000 pound","8.000 pound","11.200 pound","12.500 pound"],"explanation":"NY VTL Bölüm 385, yüklendiğinde pnömatik lastikli bir aracın herhangi bir tekerleği üzerindeki ağırlığı 11.200 pound (22.400 poundluk tek aks sınırının yarısı) ile sınırlar."},"16":{"q":"NY VTL Bölüm 385 uyarınca, esas olarak doğal gazla çalışan bir motorla çalıştırılan bir araç, maksimum şu kadar brüt ağırlığa sahip olabilir:","options":["80.000 pound","82.000 pound","88.000 pound","85.000 pound"],"explanation":"NY VTL Bölüm 385, esas olarak doğal gazla çalışan bir motorla işletilen bir aracın, yakıt sisteminin ek ağırlığını hesaba katmak için maksimum 82.000 pound'a kadar brüt ağırlığa sahip olmasına izin verir."},"17":{"q":"New York'ta, yediden fazla yolcu taşıyan bir otobüsün (mafsallı otobüs hariç) maksimum uzunluğu nedir?","options":["45 fit","40 fit","62 fit","55 fit"],"explanation":"NY VTL Bölüm 385, yediden fazla yolcu taşıyan bir otobüsü 45 fit uzunlukla sınırlarken, mafsallı bir otobüs 62 fite kadar olabilir."},"18":{"q":"Bir New York taşıyıcısı, eyalet karayollarında gabari dışı/aşırı yük bölünemez bir yük taşımak istiyor. Seferden önce ne elde edilmelidir?","options":["Taşımadan önce verilen bir NYSDOT özel taşıma izni","İzin olmaksızın yalnızca geçerli bir Sınıf A CDL","Bölünebilir yük aşırı ağırlık izni","Tehlikeli madde onayı"],"explanation":"New York eyalet karayollarında gabari dışı veya aşırı yük bölünemez bir yükü taşımak, önceden alınmış bir NYSDOT özel taşıma izni gerektirir; izin, güzergahı, boyutları, ağırlığı ve herhangi bir refakat veya seyahat zamanı koşullarını belirtir."},"19":{"q":"New York'un eyalet karayolları ile yerel yollar veya köprüler arasında ağırlık sınırlarının nasıl farklılaşabileceğini en iyi hangi ifade tanımlar?","options":["İşaretlenmiş köprü sınırları ticari araçlar için asla geçerli değildir","Yerel sınırlar, işaretlenmiş istisnalar olmaksızın eyalet genelinde aynıdır","Yerel yollar ve işaretlenmiş köprüler, bir eyalet izni tutulsa bile uyulması gereken daha düşük sınırlara sahip olabilir","Yerel yollar her zaman eyalet karayollarından daha ağır yüklere izin verir"],"explanation":"NY CDL Kılavuzu ve NYSDOT'a göre, bir eyalet gabari dışı/aşırı yük izni, yerel yollarda, köprülerde veya diğer idarelerce işletilen tesislerde işaretlenmiş daha düşük sınırları geçersiz kılmaz; sürücüler en kısıtlayıcı işaretlenmiş sınıra uymalıdır."},"20":{"q":"New York'un CDL sınıflandırmasına göre, bir çekici-römork kombinasyonunu çalıştırmak için hangi sınıf gereklidir?","options":["Sınıf A","Sınıf B","Sınıf C","Sınıf D"],"explanation":"NY DMV, Sınıf A CDL'yi bir 'çekici-römork' (bir kombinasyon aracı) olarak tanımlar. Sınıf B bir otobüsü veya tek üniteli kamyonu kapsar ve Sınıf C bir onay gerektiren kamyon, otobüs veya uzatılmış limuzini kapsar. Kaynak: NY DMV 'Ticari Sürücü Belgesi (CDL) Edinin' / CDL-10 Ticari Sürücü Kılavuzu."},"21":{"q":"NY DMV'ye göre, kombinasyon aracı olmayan tek üniteli bir kamyon veya otobüs hangi CDL sınıfı altında çalıştırılır?","options":["Sınıf A","Sınıf B","Sınıf C","Sınıf E"],"explanation":"NY DMV, Sınıf B'yi bir 'otobüs veya tek üniteli kamyon' olarak tanımlar. Sınıf A bir çekici-römork kombinasyonudur ve Sınıf C, bir onay (HazMat veya yolcu gibi) gerektiren bir kamyon, otobüs veya uzatılmış limuzindir. Kaynak: NY DMV CDL sayfaları / CDL-10 kılavuzu."},"22":{"q":"New York'ta, belirli bir onay gerektiren bir kamyon, otobüs veya uzatılmış limuzini kapsayan olarak tanımlanan CDL sınıfı hangisidir?","options":["Sınıf A","Sınıf B","Sınıf C","Sınıf M"],"explanation":"NY DMV, Sınıf C'yi, genellikle 16 veya daha fazla yolcu (sürücü dahil) veya tehlikeli madde taşıdığı için bir onay gerektiren bir 'kamyon, otobüs veya uzatılmış limuzin' olarak tanımlar. Kaynak: NY DMV 'Ticari Sürücü Belgesi (CDL) Edinin'."},"23":{"q":"Yalnızca eyalet içi sürüş (New York Eyaleti içinde) için geçerli bir New York CDL'si almak için minimum yaş nedir?","options":["16 yaş","18 yaş","21 yaş","25 yaş"],"explanation":"Eyalet içi sürüş (yalnızca NY içinde) için bir New York CDL'sine sahip olmak için bir sürücünün en az 18 yaşında olması gerekir. 21 yaşından küçük sürücüler eyalet içi işletimle sınırlıdır. Kaynak: NY DMV ticari sürücü gereksinimleri."},"24":{"q":"New York'ta, eyaletler arası ticarette (eyalet sınırları boyunca) ticari bir aracı sürmek için gereken minimum yaş nedir?","options":["18 yaş","19 yaş","20 yaş","21 yaş"],"explanation":"Eyaletler arası ticarette ticari bir aracı çalıştırmak için en az 21 yaşında olmanız gerekir. NY CDL'sine sahip 18 ila 20 yaşındaki sürücüler eyalet içi (New York içinde) sürüşle sınırlıdır. Kaynak: NY DMV CDL gereksinimleri; FMCSA 49 CFR 391.11."},"25":{"q":"Mevcut kurallar kapsamında, bir New York Ticari Öğrenci İzni (CLP), verildikten sonra ne kadar süre geçerlidir?","options":["30 gün","Altı ay (180 gün)","Bir yıl (365 gün)","Beş yıl"],"explanation":"27 Aralık 2022 tarihinde veya sonrasında verilen CLP'ler için New York, süreci kolaylaştırmak amacıyla CLP geçerliliğini önceki altı aydan bir yıla (365 gün) uzattı. Kaynak: NY DMV haberleri, 'DMV Ticari Öğrenci İzninin Geçerliliğini Uzatıyor.'"},"26":{"q":"New York'ta geçerli olan federal kurallar, bir CLP sahibinin CDL beceri (yol) sınavına girmeden önce CLP verildikten sonra en az ne kadar beklemesini gerektirir?","options":["Minimum bekleme süresi yoktur","7 gün","14 gün","30 gün"],"explanation":"New York'ta geçerli olan federal kanun (49 CFR 383.25) uyarınca, bir CLP sahibi, CLP ilk verildikten sonra en az 14 gün geçene kadar CDL beceri sınavına girmeye uygun değildir. Kaynak: 49 CFR 383.25; FMCSA CDL standartları."},"27":{"q":"Bir New York CDL sahibinin, plakalama gerektiren tehlikeli maddeleri taşımak için hangi onaya ihtiyacı vardır?","options":["H (Tehlikeli Madde)","N (Tank Araçları)","T (İkili/Üçlü Römork)","S (Okul Otobüsü)"],"explanation":"Plakalanmış miktarlarda tehlikeli madde taşımak için 'H' (Tehlikeli Madde) onayı gereklidir. NY'de en az 21 yaşında olmayı, yazılı bir sınavı geçmeyi, HazMat ELDT'yi tamamlamayı (ilk kez başvuranlar için) ve parmak izine dayalı bir geçmiş kontrolünü geçmeyi gerektirir. Kaynak: NY DMV 'CDL Onayları.'"},"28":{"q":"New York'ta Tehlikeli Madde (H) onayı almak için bir başvuru sahibinin hangi güvenlikle ilgili adımı tamamlaması gerekir?","options":["Yalnızca özel bir göz doktorunda bir görme muayenesi","Parmak izine dayalı bir geçmiş kontrolü (IdentoGO aracılığıyla)","Yerel polisle 10 yıllık bir ikamet görüşmesi","DMV'de bir poligraf muayenesi"],"explanation":"New York HazMat (H) başvuru sahipleri, yazılı sınavı geçmenin ve en az 21 yaşında olmanın yanı sıra, IdentoGO aracılığıyla yürütülen parmak izine dayalı bir federal/eyalet geçmiş kontrolünü geçmelidir. Kaynak: NY DMV 'CDL Onayları'; TSA HazMat Tehdit Değerlendirme Programı."},"29":{"q":"Kalıcı olarak monte edilmiş bir tankta dökme halinde sıvı veya gaz taşımak üzere tasarlanmış bir aracı çalıştırmak için hangi NY CDL onayı gereklidir?","options":["P (Yolcu)","T (İkili/Üçlü Römork)","N (Tank Araçları)","M (Metal Coil)"],"explanation":"Belirli eşikleri karşılayan kalıcı olarak monte edilmiş bir tankta dökme halinde sıvı veya gaz taşıyan araçları sürmek için 'N' (Tank Araçları) onayı gereklidir. Kaynak: NY DMV 'CDL Onayları'; CDL-10 kılavuzu Bölüm 9 (Tank Araçları)."},"30":{"q":"New York'ta, ikili veya üçlü römork çekmek için hangi onay gereklidir?","options":["T (İkili/Üçlü Römork)","N (Tank Araçları)","H (Tehlikeli Madde)","P (Yolcu)"],"explanation":"Birden fazla römork çekmek için 'T' (İkili/Üçlü Römork) onayı gereklidir. Bir bilgi sınavı geçilerek elde edilir; üçlü römorkların tüm New York karayollarında yasal olmadığını unutmayın. Kaynak: NY DMV 'CDL Onayları'; CDL-10 kılavuzu Bölüm 8 (İkili ve Üçlü Römorklar)."},"31":{"q":"Bir New York CDL sahibinin 16 veya daha fazla yolcu (sürücü dahil) taşıyan bir otobüs veya minibüs sürmek için hangi onaya sahip olması gerekir?","options":["S (Okul Otobüsü)","P (Yolcu)","N (Tank Araçları)","T (İkili/Üçlü Römork)"],"explanation":"Sürücü dahil 16 veya daha fazla kişi taşımak üzere tasarlanmış araçları çalıştırmak için 'P' (Yolcu) onayı gereklidir. Okul Otobüsü (S) onayı, P onayının üzerine inşa edilir. Kaynak: NY DMV 'CDL Onayları'; CDL-10 kılavuzu Bölüm 4 (Yolcu Taşımacılığı)."},"32":{"q":"New York'ta, Okul Otobüsü (S) onayını almak için bir ön koşul nedir?","options":["Bir HazMat (H) onayına sahip olmak","Yolcu (P) onayına zaten sahip olmak veya aynı anda başvurmak","Bir Tank Araçları (N) onayına sahip olmak","Bir İkili/Üçlü Römork (T) onayına sahip olmak"],"explanation":"NY DMV'ye göre, bir sürücünün Okul Otobüsü (S) onayını alabilmesi için Yolcu (P) onayına zaten sahip olması veya P ve S onayları için aynı anda başvurması gerekir. Kaynak: NY DMV 'CDL Onayları.'"},"33":{"q":"New York'un Okul Otobüsü (S) onay bilgi sınavı hakkında hangi ifade doğrudur?","options":["20 çoktan seçmeli soru içerir ve geçmek için 16 doğru cevap gerektirir","50 soru içerir ve geçmek için 45 doğru cevap gerektirir","Yalnızca bir yol sınavı gerektirir ve yazılı sınav gerektirmez","Zaten bir Sınıf A CDL'sine sahip olan herkes için muaftır"],"explanation":"NY Okul Otobüsü (S) onay yazılı sınavı, CDL Kılavuzu'nun 10. Bölümüne dayanır ve 20 çoktan seçmeli soru içerir; bir sürücünün geçmek için 16'sını doğru cevaplaması gerekir. S onayının kendisi için ayrı bir yol sınavı gerekmez. Kaynak: NY DMV 'CDL Onayları.'"},"34":{"q":"New York, 5.000 lb veya daha ağır hangi yükü taşıyan ticari sürücüler için, diğer birçok eyalette bulunmayan özel bir onay gerektirir?","options":["Sıkıştırılmış gaz tüpleri","Canlı hayvanlar","Metal coil","Tehlikeli atık"],"explanation":"New York Araç ve Trafik Kanunu, 5.000 lb veya daha ağır metal coil taşıyan ticari sürücüler için bir Metal Coil ('M') onayı gerektirir. Bu, 20 soruluk bir yazılı sınavı (geçmek için 16 doğru) geçerek elde edilen NY'ye özgü bir onaydır. Kaynak: NY DMV 'CDL Onayları.'"},"35":{"q":"New York'ta bir motorlu taşıyıcı için (okul veya DOT tarafından düzenlenen taşıyıcılar gibi) otobüs çalıştıran sürücüler hangi ek eyalet programına tabidir?","options":["Article 19-A (Otobüs Sürücüleri için Özel Gereksinimler)","Article 31 (DWI programı)","Kademeli Lisans Kanunu","Move Over Kanunu"],"explanation":"New York'un Araç ve Trafik Kanunu Article 19-A, kapsanan motorlu taşıyıcılar için otobüs sürücülerine, en az 21 yaşında olmak, birkaç yıl boyunca geçerli bir lisansa sahip olmak, periyodik fiziksel performans testleri ve yıllık bir savunma sürüş/direksiyon başında incelemesi dahil olmak üzere ek gereksinimler getirir. Kaynak: NY DMV Article 19-A Bilgileri; VTL Article 19-A."},"36":{"q":"New York'ta geçerli olan federal Giriş Düzeyi Sürücü Eğitimi (ELDT) kuralı uyarınca, sınavdan önce kimin eğitimi tamamlaması gerekir?","options":["Yalnızca HazMat onayı arayan sürücüler","İlk kez başvuran Sınıf A veya B başvuru sahipleri, B'den A'ya yükseltmeler ve ilk kez başvuran H, P veya S onayı başvuru sahipleri","Yalnızca 65 yaşın üzerindeki sürücüler","Her lisans yenilemesinde her CDL sahibi"],"explanation":"ELDT, 7 Şubat 2022 tarihinde veya sonrasında bir CLP edinen herkes için, ilk kez başvuran Sınıf A veya Sınıf B CDL başvuru sahipleri, Sınıf A'ya yükselten Sınıf B sahipleri ve Tehlikeli Madde (H), Yolcu (P) veya Okul Otobüsü (S) onayı için ilk kez başvuran kişiler için geçerlidir. Kaynak: FMCSA Eğitim Sağlayıcı Kaydı; NY DMV."},"37":{"q":"Bir New York CDL başvuru sahibinin Giriş Düzeyi Sürücü Eğitimi (ELDT), CDL uygunluğuna sayılması için nereye kaydedilmelidir?","options":["Yalnızca sürücü tarafından tutulan bir kağıt sertifikada","FMCSA Eğitim Sağlayıcı Kaydında (TPR)","Yerel ilçe katibi ofisinde","Yalnızca sürücünün işveren personel dosyasında"],"explanation":"ELDT, FMCSA Eğitim Sağlayıcı Kaydında (TPR) listelenen bir sağlayıcıyla tamamlanmalıdır ve sağlayıcı, başvuru sahibi CDL sınavına girmeden önce tamamlama sertifikasını elektronik olarak TPR'ye gönderir. Kaynak: FMCSA Giriş Düzeyi Sürücü Eğitimi (ELDT) / Eğitim Sağlayıcı Kaydı."},"38":{"q":"Bir New York CDL'si için başvururken, DMV bir başvuru sahibinin kimliğini nasıl doğrular?","options":["Tek bir fotoğraflı kimlik her zaman yeterlidir","Toplamda en az 6 puanlık kimlik kanıtı belgeleri, artı Sosyal Güvenlik Numarası","Yalnızca sözlü bir kimlik beyanı","Bir kredi raporu ve bir fatura"],"explanation":"NY DMV, toplamda en az 6 puanlık kimlik kanıtı belgesi gerektiren puana dayalı bir sistem kullanır (en az biri imza taşımalıdır) ve başvuru sahiplerinin Sosyal Güvenlik Numaralarını sağlamaları gerekir (veya hiç verilmemişse bir yeminli beyan imzalamaları gerekir). Kaynak: NY DMV kimlik kanıtı gereksinimleri (Form ID-44)."},"39":{"q":"Tıbbi öz-sertifikasyonun bir parçası olarak, eyaletler arası ticarette araç süren ve tıbbi kart gereksiniminden muaf olmayan bir New York CDL sahibinin DMV'de neyi dosyada tutması gerekir?","options":["Bir işverenden noter onaylı bir mektup","Güncel bir USDOT Tıbbi Muayene Sertifikası (tıbbi kart)","Lise diplomalarının bir kopyası","Sürülen her kamyon için bir araç tescili"],"explanation":"CDL sahipleri sürüş kategorilerini (örneğin, Muaf Olmayan Eyaletler Arası) öz-sertifika etmeli ve muaf değillerse, NY DMV'de güncel bir USDOT Tıbbi Muayene Sertifikasını dosyada tutmalıdır; bunu yapmamak CDL'nin düşürülmesine yol açabilir. Kaynak: NY DMV CDL Tıbbi Sertifikasyon ('Sürüş Türünüzü Öz-Sertifika Edin')."},"40":{"q":"New York'ta bir kişinin ticari bir motorlu aracı (CMV) yasal olarak çalıştırabileceği maksimum kan alkol konsantrasyonu (BAC) nedir?","options":["0,02%","0,04%","0,08%","0,10%"],"explanation":"New York federal kuralı izler: 0,04% veya daha yüksek bir BAC ile bir CMV çalıştırmak yasa dışıdır. Bu, ticari olmayan sürücüler için 0,08% sınırının yarısıdır. Kaynak: NY CDL-10 Kılavuzu böl. 1.6.2; 49 CFR 383.51 Tablo 1."},"41":{"q":"New York'un ticari sürücüler için zımni rıza kuralı uyarınca, bir CMV çalıştırmak, otomatik olarak neye rıza gösterdiğiniz anlamına gelir?","options":["Yükünüzün ve seyir defterinizin aranmasına","Alkol ve uyuşturucu testine","Bir görme ve tıbbi yeniden muayeneye","Sürüş kaydınızın denetlenmesine"],"explanation":"NY CDL kılavuzu, bir CMV çalıştırırsanız, alkol testine rıza göstermiş sayılacağınızı belirtir. Kaynak: NY CDL-10 Kılavuzu böl. 1.6.2; NY VTL 1194 (zımni rıza)."},"42":{"q":"New York'ta bir CMV sürücüsünde, 0,04% sınırının altında tespit edilebilir miktarda alkol bulunursa ne olur?","options":["Hiçbir şey, çünkü sürücü yasal sınırın altındadır","Sürücü 24 saat boyunca hizmet dışı bırakılır","Sürücü 60 gün boyunca diskalifiye edilir","Sürücü yalnızca yazılı bir uyarı alır"],"explanation":"0,04%'ün altında tespit edilebilir herhangi bir miktarda alkol bulunan bir CMV sürücüsü, diskalifiye edici sınırın altında olsa bile, 24 saat boyunca hizmet dışı bırakılır. Kaynak: NY CDL-10 Kılavuzu böl. 1.6.2."},"43":{"q":"İlk büyük suç için (0,04% veya daha yüksek bir BAC ile bir CMV sürmek gibi), bir New York CDL sahibi ne kadar süre diskalifiye edilir?","options":["60 gün","120 gün","En az bir yıl","Üç yıl"],"explanation":"İlk büyük suç, en az bir yıllık bir diskalifiye ile sonuçlanır. Kaynak: NY CDL-10 Kılavuzu böl. 1.6.2; 49 CFR 383.51 Tablo 1."},"44":{"q":"Bir New York CDL sahibi, tehlikeli maddeler için plakalanmış bir CMV çalıştırırken ilk büyük suçu işliyor. Diskalifiye ne kadar sürer?","options":["Bir yıl","Üç yıl","Beş yıl","Ömür boyu"],"explanation":"Tehlikeli maddeler için plakalanmış bir CMV çalıştırılırken işlenen ilk büyük suç, standart bir yıl yerine üç yıllık bir diskalifiye ile sonuçlanır. Kaynak: NY CDL-10 Kılavuzu böl. 1.6.2; 49 CFR 383.51 Tablo 1."},"45":{"q":"İKİNCİ bir büyük suçtan hüküm giyen bir New York CDL sahibi için diskalifiye süresi nedir?","options":["Bir yıl","Üç yıl","On yıl","Ömür boyu"],"explanation":"Listelenen büyük suçlardan herhangi biri için ikinci bir mahkumiyet, CLP ve/veya CDL'nin ömür boyu diskalifiye edilmesiyle sonuçlanır. Kaynak: NY CDL-10 Kılavuzu böl. 1.6.2; 49 CFR 383.51 Tablo 1."},"46":{"q":"New York'ta, bir CMV çalıştırırken kan alkol testine girmeyi reddetmek, CDL diskalifiyesi amaçları için nasıl değerlendirilir?","options":["Diskalifiye olmayan küçük bir evrak ihlali olarak","Yalnızca ciddi bir trafik ihlali olarak","Bir DUI mahkumiyetiyle aynı şekilde, büyük bir suç olarak","Bir hizmet dışı emir ihlali olarak"],"explanation":"Kan alkol testine girmeyi reddetmek büyük bir suçtur ve bir DUI mahkumiyeti ile aynı minimum bir yıllık ilk suç diskalifiyesini taşır. Kaynak: NY CDL-10 Kılavuzu böl. 1.6.2; 49 CFR 383.51 Tablo 1."},"47":{"q":"Aşağıdakilerden hangisi, bir CMV yerine sürücünün kendi özel arabasında işlense bile bir New York CDL sahibini diskalifiye edebilecek büyük bir suçtur?","options":["Başka bir aracı çok yakından takip etmek","Alkolün etkisi altında araç kullanmak","Uygunsuz bir şerit değişikliği yapmak","Sınırın 15 mil/saat üzerinde hız yapmak"],"explanation":"Herhangi bir aracı alkolün veya kontrollü bir maddenin etkisi altında sürmek, bir CDL sahibini diskalifiye eden büyük bir suçtur; bir CMV'de gerçekleşmesi gerekmez. Diğer seçenekler ciddi trafik ihlalleridir. Kaynak: NY CDL-10 Kılavuzu böl. 1.6.2 ve 1.6.3."},"48":{"q":"Bir New York CDL sahibi, kontrollü maddeler içeren bir suç işlemek için ticari bir motorlu araç kullanıyor. Sonuç nedir?","options":["120 günlük bir diskalifiye","Üç yıllık bir diskalifiye","10 yıllık yeniden yetkilendirme olmaksızın ömür boyu bir diskalifiye","Bir yıllık bir diskalifiye"],"explanation":"Kontrollü maddeler içeren bir suç işlemek için bir CMV kullanmak, ömür boyu bir diskalifiye ile sonuçlanır ve sürücü, belirli diğer ömür boyu durumları için mevcut olan 10 yıllık yeniden yetkilendirmeye uygun değildir. Kaynak: NY CDL-10 Kılavuzu böl. 1.6.2; 49 CFR 383.51 Tablo 1."},"49":{"q":"Aşağıdakilerden hangisi New York'ta CDL diskalifiyesine neden olan büyük bir suçtur?","options":["Bir kazanın olay yerini rapor etmeden terk etmek","Hız sınırının 12 mil/saat üzerinde araç kullanmak","Dönüş sinyali kullanmamak","Durmanın yasak olduğu bir bölgeye park etmek"],"explanation":"Bir kazanın olay yerini rapor etmeden terk etmek, ilk suç için en az bir yıllık diskalifiye taşıyan listelenmiş büyük bir suçtur. Kaynak: NY CDL-10 Kılavuzu böl. 1.6.2; 49 CFR 383.51 Tablo 1."},"50":{"q":"New York CDL kurallarına göre aşağıdakilerden hangisi CİDDİ bir trafik ihlali olarak sınıflandırılır?","options":["BAC değeri %.04 veya daha yüksekken araç kullanmak","Belirtilen limitin 15 mph veya daha fazla üzerinde aşırı hız yapmak","Kimyasal testi reddetmek","Kaza yerini terk etmek"],"explanation":"Aşırı hız (belirtilen limitin 15 mph veya daha fazla üzerinde) ciddi bir trafik ihlalidir. Diğer seçenekler çok daha ağır cezalar taşıyan büyük suçlardır. Kaynak: NY CDL-10 Manual böl. 1.6.3; 49 CFR 383.51 Table 2."},"51":{"q":"Bir New York CDL sahibi, üç yıllık süre içinde bir CMV'de İKİ ciddi trafik ihlali işlediğinde ne kadar süre diskalifiye edilir?","options":["En az 30 gün","En az 60 gün","En az 120 gün","En az bir yıl"],"explanation":"Üç yıllık süre içinde (bir CMV'de) iki ciddi trafik ihlali, en az 60 gün diskalifiyeyle sonuçlanır. Kaynak: NY CDL-10 Manual böl. 1.6.3; 49 CFR 383.51 Table 2."},"52":{"q":"Bir New York CDL sahibi, üç yıllık süre içinde bir CMV'de ÜÇ ciddi trafik ihlali işlediğinde ne kadar süre diskalifiye edilir?","options":["En az 60 gün","En az 90 gün","En az 120 gün","En az bir yıl"],"explanation":"Üç yıllık süre içinde (bir CMV'de) üç ciddi trafik ihlali, en az 120 gün diskalifiyeyle sonuçlanır. Kaynak: NY CDL-10 Manual böl. 1.6.3; 49 CFR 383.51 Table 2."},"53":{"q":"New York'ta bir CMV kullanırken elde tutulan cep telefonu veya mesajlaşma cihazı kullanmak ne olarak sınıflandırılır?","options":["Büyük bir suç","Ciddi bir trafik ihlali","Bir hizmet dışı (out-of-service) emrinin ihlali","Bir demiryolu geçidi ihlali"],"explanation":"Bir CMV kullanırken elde tutulan cep telefonu ve/veya mesajlaşma cihazı kullanmak ciddi bir trafik ihlali olarak listelenmiştir. New York ayrıca VTL 1225-c ve 1225-d uyarınca tüm sürücüler için elde tutulan cihaz kullanımını yasaklar. Kaynak: NY CDL-10 Manual böl. 1.6.3."},"54":{"q":"Bir New York CDL sahibi için aşağıdakilerden hangisi büyük bir suç değil, ciddi bir trafik ihlalidir?","options":["Bir aracı çok yakından takip etmek","CDL'iniz iptal edilmişken bir CMV kullanmak","Bir ağır suç işlemek için bir CMV kullanmak","İhmalkar CMV kullanımı yoluyla bir ölüme neden olmak"],"explanation":"Çok yakından takip etmek ciddi bir trafik ihlalidir. Diğer üçü, en az bir yıllık (veya ömür boyu) diskalifiye taşıyan büyük suçlardır. Kaynak: NY CDL-10 Manual böl. 1.6.2 ve 1.6.3; 49 CFR 383.51."},"55":{"q":"New York CDL kılavuzuna göre, bir CDL sahibi bir hizmet dışı (out-of-service) emrini ihlal etmekten İLK kez mahkum edildiğinde ne kadar süre diskalifiye edilir?","options":["En az 90 gün","En az 30 gün","En az bir yıl","En az üç yıl"],"explanation":"NY CDL-10 kılavuzu, ilk hizmet dışı emri ihlali için en az 90 günlük bir diskalifiye listeler. Kaynak: NY CDL-10 Manual böl. 1.6.4. (Not: 49 CFR 383.51'deki federal tablo, HazMat içermeyen ilk suçlar için 180 günlük bir minimum belirler.)"},"56":{"q":"New York CDL kılavuzuna göre, on yıllık süre içinde İKİ hizmet dışı (out-of-service) emri ihlali işlemenin diskalifiyesi nedir?","options":["En az 60 gün","En az 120 gün","En az bir yıl","En az üç yıl"],"explanation":"On yıllık süre içinde iki hizmet dışı emri ihlali, en az bir yıllık diskalifiyeyle sonuçlanır. Kaynak: NY CDL-10 Manual böl. 1.6.4."},"57":{"q":"New York CDL kılavuzuna göre, on yıllık süre içinde ÜÇ veya daha fazla hizmet dışı (out-of-service) emri ihlali işlemenin diskalifiyesi nedir?","options":["En az bir yıl","En az iki yıl","En az üç yıl","En az beş yıl"],"explanation":"On yıllık süre içinde üç veya daha fazla hizmet dışı emri ihlali, en az üç yıllık diskalifiyeyle sonuçlanır. Kaynak: NY CDL-10 Manual böl. 1.6.4."},"58":{"q":"Bir New York CDL sahibinin bir CMV kullanırken işlediği İLK demiryolu-karayolu hemzemin geçit ihlali için diskalifiye süresi nedir?","options":["En az 30 gün","En az 60 gün","En az 120 gün","En az bir yıl"],"explanation":"İlk demiryolu-karayolu hemzemin geçit ihlali, en az 60 günlük bir diskalifiyeyle sonuçlanır. Kaynak: NY CDL-10 Manual böl. 1.6.5; 49 CFR 383.51 Table 3."},"59":{"q":"Bir New York CDL sahibi, üç yıllık süre içinde ÜÇÜNCÜ bir demiryolu-karayolu hemzemin geçit ihlali işler. Diskalifiye nedir?","options":["En az 120 gün","En az 180 gün","En az bir yıl","En az üç yıl"],"explanation":"Demiryolu-karayolu hemzemin geçit ihlalleri, birincisi için en az 60 gün, üç yıl içindeki ikincisi için 120 gün ve üç yıllık süre içindeki üçüncüsü için en az bir yıl taşır. Kaynak: NY CDL-10 Manual böl. 1.6.5; 49 CFR 383.51 Table 3."},"60":{"q":"New York City'de bir çekici-römork kullanıyorsunuz ve 'NO COMMERCIAL VEHICLES' (TİCARİ ARAÇ GİREMEZ) yazan bir tabela görüyorsunuz. Bu tabela ilerideki yol hakkında ne ifade eder?","options":["Yalnızca otomobiller için tasarlanmış, ticari araçların yasaklandığı bir New York State parkway'idir","Yalnızca geceleri açık olan belirlenmiş bir geçiş kamyon güzergahıdır","Otobüsler için ayrılmış ücretsiz bir ekspres şerittir","Kamyonların yalnızca yükleme yaparken seyahat edebileceği yerel bir teslimat sokağıdır"],"explanation":"New York'un parkway sistemi 20. yüzyılın başlarında yalnızca otomobiller için inşa edildi ve çekici-römorklar ile otobüsler dahil hiçbir ticari aracın bu parkway'lerde dolaşmasına izin verilmez. 'NO COMMERCIAL VEHICLES' tabelası yalnızca otomobillere açık bir yolu belirtir. Kaynak: NYSDOT Parkway Truck Brochure; NY VTL."},"61":{"q":"Yeni bir ticari sürücü, New York'un eyaletin güney kesimindeki parkway'lerinin üzerindeki alçak taş köprülerin kamyonlar için neden bu kadar tehlikeli olduğunu soruyor. NY kurallarına göre EN İYİ cevap nedir?","options":["Köprülerde ağırlık limitleri vardır ama belirtilmiş bir yükseklik limiti yoktur","Bazı belirtilen dikey açıklıklar 6 fit 11 inç kadar düşüktür ve aşırı yüksek kamyonlar bunlara çarpıp altlarında sıkışır","Köprüler yoğun saatlerde yalnızca otobüsler için ayrılmıştır","Kamyonlara izin verilir ama her köprüden önce kornaya basmaları gerekir"],"explanation":"NYSDOT, parkway sistemindeki alçak taş köprülerin 6 fit 11 inç kadar düşük belirtilen dikey açıklıklara sahip olduğu konusunda uyarır. Parkway'lerden men edilen ticari araçlar, genellikle bu alçak köprülere çarpıp altlarında sıkışarak ciddi kazalara ve uzun gecikmelere neden olur. Kaynak: NYSDOT Parkway Truck Brochure."},"62":{"q":"Aşağıdakilerden hangisi, çekici-römorklar dahil hiçbir ticari aracın izin verilmediği, New York'un güney kesimindeki bir yoldur?","options":["The Long Island Expressway (I-495)","The New York State Thruway (I-87)","The Brooklyn-Queens Expressway (I-278)","Brooklyn ve Queens'teki Belt Parkway"],"explanation":"Belt Parkway, ticari araçların yasaklandığı eyaletin güney kesimindeki parkway'lerden biridir (Henry Hudson, Cross Island, Hutchinson River, Grand Central, Northern State ve diğerleriyle birlikte). Expressway'ler ve Thruway kamyonlara açık interstate güzergahlarıdır. Kaynak: NYSDOT Parkway Truck Brochure; NYC DOT Parkway Restrictions."},"63":{"q":"Bir ticari sürücü yasa dışı olarak bir New York parkway'ine girer ve bir çekici-römork alçak bir köprünün altında sıkışır. Para cezaları ve ceza puanlarının yanı sıra, NY'in özellikle uyardığı ek sonuç nedir?","options":["Hasara bakılmaksızın zorunlu 30 günlük araç haczi","İlk suçta otomatik olarak CDL'in bir yıl kaybı","Çekici-römorklar için $10,000'ı aşabilen çekme ücretleri artı köprü onarımı için eyalete geri ödeme","Tüm 50 eyalette araç kullanmaktan federal men"],"explanation":"NYSDOT, bir parkway'de ticari araç kullanmanın sonuçlarını listeler: para cezaları ve/veya ceza puanları, olası yaralanma, araç ve köprü/koruma bariyeri hasarı, çekici-römorklar için $10,000'ın üzerinde çekme ücretleri ve köprü onarımı için eyalete geri ödeme. Kaynak: NYSDOT Parkway Truck Brochure."},"64":{"q":"New York City'de kamyon güzergahı ağı iki sınıfa ayrılır. Bunlar nelerdir?","options":["Gündüz kamyon güzergahları ve gece kamyon güzergahları","Yerel kamyon güzergahları ve geçiş kamyon güzergahları","Ekspres kamyon güzergahları ve ücretli kamyon güzergahları","Borough kamyon güzergahları ve köprü kamyon güzergahları"],"explanation":"NYC'nin kamyon güzergahı ağı (yaklaşık 1,000 mil, NYC Traffic Rules'un Section 4-13'ünde tanımlanmıştır) bir borough içinde yerel bir alım veya teslimat yapan kamyonlar için Yerel Kamyon Güzergahları (Local Truck Routes) ve bölgede bir başlangıç veya varış noktası olmadan geçen kamyonlar için Geçiş Kamyon Güzergahları (Through Truck Routes) içerir. Kaynak: NYC DOT Truck Routing; NYC Traffic Rules 4-13."},"65":{"q":"Bir kamyonun bir teslimat adresine ulaşmak için belirlenmiş bir NYC kamyon güzergahından ayrılması gerekir. NYC kamyon güzergahı kurallarına göre, sürücü nasıl ilerlemelidir?","options":["Teslimat tamamlanana kadar herhangi bir yönde herhangi bir sokağı kullanmak","Kamyon güzergahından varış noktasına en yakın kavşakta ayrılmak, en doğrudan güzergahı kullanmak ve aynı şekilde en yakın kamyon güzergahına geri dönmek","Trafik sıkışıklığından kaçınmak için yalnızca yerleşim sokaklarında seyahat etmek","Her teslimat için ayrı bir yazılı güzergah dışı izin almak"],"explanation":"NYC kuralları, bir kamyonun belirlenmiş bir güzergahtan yalnızca bir başlangıç veya varış noktasına ulaşmak için ayrılmasına izin verir. Sürücü, varış noktasına en yakın kavşakta ayrılmalı, en doğrudan güzergahla ilerlemeli, sonra en doğrudan güzergahla en yakın belirlenmiş kamyon güzergahına geri dönmelidir. Kaynak: NYC DOT Truck Routing; NYC Traffic Rules 4-13."},"66":{"q":"NY tarafından benimsenen New York ve federal kurallar uyarınca hangi araçların her demiryolu-karayolu hemzemin geçidinde DURMASI gerekir?","options":["26,000 lb üzerindeki tüm ticari araçlar","Yalnızca römork çeken araçlar","Yolcu taşıyan otobüsler ve plakart taşıyan tehlikeli madde taşıyan araçlar","Yalnızca daha önce yanıcı maddeler için kullanılmış boş tank araçları"],"explanation":"New York'ta, yolcu taşıyan otobüsler ve tehlikeli madde plakartı sergileyen ticari araçların tüm demiryolu geçitlerinde durması gerekir. 50 fit içinde ama 15 fitten daha yakın olmamak üzere dururlar, bakar ve dinlerler ve geçerken vites değiştirmemelidirler. Kaynak: NY CDL Manual CDL-10; 49 CFR 392.10."},"67":{"q":"Plakart taşıyan tehlikeli madde kamyonu kullanan bir New York sürücüsünün bir demiryolu geçidinde durması gerekir. Araç en yakın raydan ne kadar mesafe içinde durmalıdır?","options":["50 fit içinde ama 15 fitten daha yakın olmamak üzere","100 fit içinde ama 25 fitten daha yakın olmamak üzere","En yakın raydan tam olarak 5 fit","30 fit içinde ama 10 fitten daha yakın olmamak üzere"],"explanation":"Demiryolu geçitlerinde durması gereken araçlar (plakart taşıyan tehlikeli madde ve yolcu taşıyan otobüsler) en yakın raydan 50 fit içinde ama 15 fitten daha yakın olmamak üzere durmalı, sonra vites değiştirmeden ilerlemeden önce trenleri görmek ve duymak için bakıp dinlemelidir. Kaynak: NY CDL Manual CDL-10; 49 CFR 392.10."},"68":{"q":"New York'un Move Over Law'u (VTL 1144-a) uyarınca, bir ticari sürücü uyarı ışıkları yanıp sönerek yol kenarında durmuş bir acil durum veya tehlike aracına yaklaşırken ne yapmalıdır?","options":["Acil durum aracı ayrılana kadar tamamen durmak","Yavaşlamak ve mümkün olduğunda durmuş araçtan tam bir şerit uzağa geçmek","Kornaya basmak ve belirtilen hızı korumak","Banket üzerine geçip sağdan geçmek"],"explanation":"New York'un Move Over Law'u, sürücülerin gereken özeni göstermesini, yavaşlamasını ve güvenli olduğunda yanıp sönen ışıklar sergileyen durmuş bir acil durum veya tehlike aracından tam bir şerit uzağa geçmesini gerektirir. 2023 itibarıyla yasa tüm durmuş araçları kapsayacak şekilde genişletildi. Kaynak: NY VTL 1144-a; NYS Governor's Traffic Safety Committee."},"69":{"q":"New York'un Move Over Law'u, acil durum araçları kadar tehlike araçları için de geçerlidir. Bunlardan hangisi yasanın kapsadığı bir 'tehlike aracı'dır?","options":["Bordür kenarına yasal olarak park etmiş bir binek otomobil","Yanıp sönen amber ışıklar sergileyen bir çekici veya bakım aracı","Bir yolcu almak için durmuş bir taksi","Bir garaj yolunda dörtlü flaşörleri açık bir teslimat minibüsü"],"explanation":"New York'un Move Over Law'u, polis, itfaiye ve ambulans araçlarına ek olarak, yanıp sönen amber ışıklar sergileyen çekiciler, inşaat ve bakım araçları ve temizlik araçları gibi tehlike araçlarını kapsar. Kaynak: NY VTL 1144-a; NYS Thruway Move Over materials."},"70":{"q":"New York yasalarına göre, bir ticari sürücü bir CMV kullanırken elde tutulan bir cep telefonu veya mesajlaşma cihazını ne zaman kullanabilir?","options":["Yalnızca kırmızı ışıkta veya dur işaretinde durmuşken","Yalnızca 30 saniyenin altındaki aramalar için","Yalnızca cihazı navigasyon için kullanırken","CMV'yi kullanırken asla; elde tutulan cihaz kullanımı ve mesajlaşma yasaktır"],"explanation":"New York, ticari sürücülerin bir CMV kullanırken elde tutulan bir cep telefonu veya mesajlaşma cihazı kullanmasını yasaklar. Bazı ticari olmayan durumların aksine, bir ticari sürücü bir ışıkta durmuşken bile elde tutulan bir cihaz kullanamaz. Bir mahkumiyet ceza puanı ekler ve ciddi bir CDL suçudur. Kaynak: NY VTL 1225-c ve 1225-d; NY CDL Manual CDL-10."},"71":{"q":"New York'ta bir ticari sürücü, üç yıl içinde ikinci kez bir CMV'yi elde tutulan telefon veya mesajlaşma kullanarak kullanmaktan mahkum edilir. NY cezalarının üzerine hangi federal sonuç uygulanır?","options":["Kalıcı ömür boyu CDL iptali","Üç yıl içinde ikinci mahkumiyet için 60 günlük CDL diskalifiyesi","Yalnızca FMCSA'dan yazılı bir uyarı","Diskalifiye olmadan $50 idari ücret"],"explanation":"New York'ta uygulanan federal FMCSA kuralları, eyalet para cezaları ve ceza puanlarına ek olarak, üç yıl içinde ikinci elde tutulan telefon/mesajlaşma mahkumiyeti için bir CDL sahibini 60 gün ve üç yıl içinde üçüncü veya sonraki mahkumiyet için 120 gün diskalifiye eder. Kaynak: FMCSA 49 CFR 383.51; NY DMV."},"72":{"q":"New York'ta yanıp sönen kırmızı ışıkları olan bir okul otobüsü için durduktan sonra, bir sürücü ne zaman ilerleyebilir?","options":["Beşe kadar saydıktan hemen sonra","Işıklar hala yanıp sönse bile, hiçbir çocuk görünmez olur olmaz","Otobüs hareket etmeye devam ettiğinde veya otobüs sürücüsü ya da bir trafik görevlisi ilerlemenin güvenli olduğunu işaret ettiğinde","Işıklara bakılmaksızın, otobüs kapısını kapattıktan sonra"],"explanation":"New York'ta bir okul otobüsü için durmuş bir sürücü, otobüs hareket etmeye başlayana veya otobüs sürücüsü ya da bir polis/trafik görevlisi ilerlemeyi işaret edene kadar tekrar hareket edemez. Kırmızı flaşörler durmayı kontrol eder. Kaynak: NY VTL 1174; NY DMV Driver's Manual Chapter 6."},"73":{"q":"New York'ta bir ticari araç tek yönlü veya bölünmüş bir karayolunun bankette durmak zorunda kalırsa, üç uyarı üçgeni (yansıtıcı cihazlar) nereye yerleştirilmelidir?","options":["Üçünün hepsi aracın arkasında 10 fit içinde","Yaklaşan trafiğe doğru yaklaşık 10 fit, 100 fit ve 200 fit'te","Biri önde ve ikisi doğrudan römorkun altında","Yalnızca sürücü tarafında 25 fit, 50 fit ve 75 fit'te"],"explanation":"Tek yönlü veya bölünmüş bir karayolunda, uyarı cihazlarını CMV'nin işgal ettiği şeridin veya banketin merkezinde, yaklaşan trafiğe doğru araçtan yaklaşık 10 fit, 100 fit ve 200 fit'te yerleştirin. Cihazlar 10 dakika içinde yerleştirilmelidir. Kaynak: NY CDL Manual CDL-10; 49 CFR 392.22."},"74":{"q":"New York'ta iki şeritli, iki yönlü bir yolda bir ticari araç durmuştur. Sürücü üç acil durum uyarı üçgenini nasıl yerleştirmelidir?","options":["Biri yan tarafta 10 fit, biri arkada 100 fit ve biri aracın önünde 100 fit","Üçünün hepsi aracın arkasında 200 fit","Biri tavanda ve ikisi ön tamponda","Biri arkada 10 fit, biri arkada 50 fit ve biri önde 50 fit"],"explanation":"İki yönlü bir yolda, bir üçgeni trafik tarafında arkanın 10 fit içine, bir tanesini yaklaşık 100 fit arkaya ve bir tanesini aracın yaklaşık 100 fit önüne yerleştirin, böylece trafik her iki yönden uyarılır. Kaynak: NY CDL Manual CDL-10; 49 CFR 392.22."},"75":{"q":"New York'ta, özel bir oversize izni OLMADAN bir kamyon ve yükünün maksimum yüksekliği ne kadardır?","options":["11 fit","15 fit","16 fit 6 inç","13 fit 6 inç"],"explanation":"NY Vehicle and Traffic Law Section 385 uyarınca, bir araç ve yükün maksimum yasal yüksekliği 13 fit 6 inç'tir; 14 fit veya daha fazla bir yükseklik bir oversize izni gerektirir. Sürücüler ayrıca, NY'in eski köprülerinde yaygın olan belirtilen açıklık tabelalarına uymalıdır. Kaynak: NY VTL 385; NY DMV."},"76":{"q":"Bir New York köprüsü, kamyonun yüksekliğinden daha düşük bir belirtilen üst açıklık sergiliyor. Ticari sürücü ne yapmalıdır?","options":["Yavaşça ilerlemek ve altından geçerken kornaya basmak","Aracı alçaltmak için lastiklerden hava boşaltıp devam etmek","Köprünün altından geçmemek ve bunun yerine alternatif bir yasal güzergah bulmak","Açıklığı aşan tek kısım yükse ilerlemek"],"explanation":"NY yasaları, aracın yüksekliği belirtilen açıklığı aşıyorsa, bir aracı herhangi bir köprü veya yapıdan geçirmeyi yasaklar. Sürücü alternatif bir güzergah almalıdır. Düşük açıklıklı köprülere ve parkway'lere aşırı yükseklikte çarpmalar, büyük bir NY güvenlik sorunudur. Kaynak: NY VTL 385; NYSDOT bridge-strike guidance."},"77":{"q":"Modern New York State Thruway'de bir ticari araçtan bir ücret tipik olarak nasıl tahsil edilir?","options":["Sürücüler her kavşak gişesinde durup nakit ödemelidir","Üst geçit gantrylerinin okuduğu E-ZPass etiketleri veya posta yoluyla ücret (tolls-by-mail) faturaları kullanılarak nakitsiz ücretlendirme yoluyla","CDL'i olan tüm araçlar için ücretler kaldırılır","Sürücüler DMV'de tek bir sabit yıllık ücreti önceden öder"],"explanation":"New York State Thruway nakitsiz ücretlendirme kullanır: üst geçit gantryleri E-ZPass etiketlerini okur veya Tolls by Mail faturası için plakaların fotoğrafını çeker, böylece araçlar artık gişelerde durmaz. Ticari araçlar araç sınıfına göre ücretlendirilir ve NY E-ZPass ile indirim kazanabilir. Kaynak: NYS Thruway Authority - Cashless Tolling."},"78":{"q":"New York'ta kar ve buz gibi kış koşullarında araç kullanan bir ticari sürücü için EN İYİ uygulama nedir?","options":["Trafiği hareket halinde tutmak için normal karayolu hızını ve takip mesafesini korumak","Hızı azaltmak, takip mesafesini artırmak ve koşulların veya belirtilen gereksinimlerin talep ettiği yerlerde lastik zinciri kullanmak","Frenleri sıcak tutmak için sıkıca ve sık sık frenlere basmak","Yalnızca en sol şeritte sürmek ve tüm çekiş sistemlerini devre dışı bırakmak"],"explanation":"New York kışları, özellikle eyaletin kuzey kesiminde ve göl etkisi (lake-effect) bölgelerinde kar ve buz getirir. NY CDL Manual, sürücülere yavaşlamalarını, takip mesafesini artırmalarını, nazikçe fren yapmalarını ve koşullar veya belirtilen tabelalar çekiş cihazları gerektirdiğinde lastik zinciri kullanmalarını talimat verir. Kaynak: NY CDL Manual CDL-10, Driving in Adverse Conditions."},"79":{"q":"New York State'te Ticari Sürücü Belgelerini (CDL'ler) hangi devlet kurumu verir?","options":["Federal Motor Carrier Safety Administration (FMCSA)","New York State Department of Motor Vehicles (NY DMV)","New York State Department of Transportation (NYSDOT)","U.S. Department of Motor Vehicles"],"explanation":"New York'ta CDL'ler, New York State Department of Motor Vehicles (NY DMV) tarafından yönetilir ve verilir. FMCSA federal CDL standartlarını belirler ancak belgeyi vermez. Kaynak: NY DMV, Commercial Driver License (CDL)."},"80":{"q":"New York'ta bir CDL veya Commercial Learner Permit için başvurabilmeniz için, genel olarak halihazırda neye sahip olmanız gerekir?","options":["Bir federal interstate işletme yetki numarası","Tamamlanmış bir Article 19-A otobüs sürücüsü sertifikası","24 saat içinde tarihlenmiş bir U.S. DOT Medical Examiner's Certificate","Geçerli bir New York State sürücü belgesi (Class D, Class E veya Non-CDL C) veya başka bir eyaletten geçerli bir CDL"],"explanation":"NY DMV, ilk kez CDL başvurusunda bulunan bir kişinin başvurmadan önce halihazırda bir New York sürücü belgesine (Class D, E veya Non-CDL C) veya geçerli bir eyalet dışı CDL'e sahip olmasını gerektirir. Kaynak: NY DMV, Get a Commercial Driver License (CDL)."},"81":{"q":"New York, bir CDL veya permit için bir başvuru sahibinin kimliğini hangi sistemi kullanarak doğrular?","options":["Yalnızca federal parmak izi geçmiş kontrolü","10 puanlık bir kredi geçmişi doğrulama sistemi","Yalnızca noter onaylı tek belgeli bir beyanname","NY DMV 6-point proof-of-identity sistemi"],"explanation":"New York bir 6-point proof-of-identity sistemi kullanır: başvuru sahipleri kimliklerini kanıtlamak için toplamda en az 6 puana ulaşan belgeler ve ayrıca doğum tarihi ve ikamet kanıtı sunmalıdır. Kaynak: NY DMV, Proof of Identity (6-point system)."},"82":{"q":"New York'un 6-point ID sistemi uyarınca, sunduğunuz belgelerle ilgili kural nedir?","options":["DMV dosyada tutabilsin diye yalnızca fotokopiler kabul edilir","Fotoğrafınızı gösterdiği sürece herhangi bir belge kabul edilir","Orijinal veya onaylı kopyalar olmalıdır; fotokopiler ve laminasyonlu belgeler kabul edilmez","Laminasyonlu belgeler daha uzun dayandığı için tercih edilir"],"explanation":"NY DMV, 6-point belgelerinin orijinal veya onaylı kopyalar olmasını gerektirir. DMV düz fotokopileri veya laminasyonlu belgeleri kabul etmez. Kaynak: NY DMV, Proof of Identity."},"83":{"q":"6 puanlık kimlik belgelerine ek olarak, bir New York CDL başvuru sahibinin Sosyal Güvenlik numarasıyla ilgili başka neyi sağlaması gerekir?","options":["Hiçbir şey; New York CDL'ler için Sosyal Güvenlik numaraları toplamaz","Son üç yılın her birinden bir federal vergi beyannamesi","Yalnızca CDL verildikten sonra çıkarılmış bir Sosyal Güvenlik numarası","Sosyal Güvenlik numaralarının kanıtı veya hiç verilmemişse imzalı bir beyanname"],"explanation":"NY DMV, Sosyal Güvenlik numaranızın kanıtını gerektirir; hiç verilmemişse, bunu belirten bir beyanname imzalamanız gerekir. Kaynak: NY DMV, Proof of Identity / How to Apply."},"84":{"q":"Bir New York başvuru sahibi tipik olarak bir DMV ofisinde CDL sürecine nasıl başlar?","options":["Herhangi bir yazılı testten önce yol testini planlayıp geçerek","Taşıyıcıya bir Article 19-A beyannamesi sunarak","Bir Commercial Learner Permit (CLP) için başvurarak ve gerekli yazılı bilgi testini/testlerini geçerek","Bir yenileme başvurusu postalayıp yeni bir belge bekleyerek"],"explanation":"Süreç bir DMV ofisinde başlar: başvuru sahibi bir Commercial Learner Permit (CLP) için başvurur ve istenen sınıf ile onaylar (endorsements) için yazılı bilgi testini/testlerini geçer. Kaynak: NY DMV, Get a Commercial Driver License (CDL)."},"85":{"q":"Bir New York başvuru sahibi bir Class A CLP almak için yaygın olarak hangi yazılı bilgi testleri setini alır?","options":["Yalnızca tek bir birleşik ticari sürüş sınavı","Yalnızca Hazardous Materials ve Passenger onay (endorsement) testleri","Bir Article 19-A sözlü sınavı ve bir defansif sürüş testi","General Knowledge, Air Brakes ve Combination Vehicles"],"explanation":"Bir Class A CLP için, New York başvuru sahipleri tipik olarak General Knowledge, Air Brakes ve Combination Vehicles bilgi testlerini geçer. Onay (endorsement) testleri (Hazmat, Passenger, School Bus vb.) ayrı olarak alınır. Kaynak: NY DMV, CDL knowledge tests."},"86":{"q":"New York geçerlilik süresini uzattıktan sonra, bir New York Commercial Learner Permit (CLP) ne kadar süre geçerlidir?","options":["30 gün","Altı ay","Sekiz yıl","Bir yıl (365 gün)"],"explanation":"New York, CLP geçerliliğini altı aydan bir yıla (365 gün) uzattı. Bilgi testi puanları aynı süre boyunca geçerlidir. Kaynak: NY DMV, DMV Extends Validity of Commercial Learner Permit."},"87":{"q":"Bir New York başvuru sahibinin CDL yol (beceri) testini almadan önce bir CLP'yi tutması gereken minimum süre nedir?","options":["En az 90 gün","Gerekli bir bekleme süresi yoktur","En az 14 gün","En az 6 ay"],"explanation":"Federal kurala uyarak, CLP'niz verildikten sonraki 14 gün içindeki bir tarih için bir New York CDL yol testi planlayamazsınız. Kaynak: NY DMV, Get a Commercial Driver License (CDL) / FMCSA."},"88":{"q":"New York'ta ilk bir CDL için (veya bir Hazmat, Passenger ya da School Bus onayı eklemek için) CDL yol testini almadan önce, ilk olarak hangi eğitimin tamamlanması gerekir?","options":["FMCSA Training Provider Registry'de listelenen bir sağlayıcıdan Entry-Level Driver Training (ELDT)","Yalnızca New York'a özel bir defansif sürüş ceza puanı azaltma kursu","Bir Article 19-A iki yılda bir direksiyon başı değerlendirmesi","Bir 19A motor taşıyıcısı beyanname kursu"],"explanation":"Federal ELDT kuralları (7 Şubat 2022'den beri yürürlükte), yeni CDL başvuru sahiplerinin ve belirli onay (endorsement) başvuru sahiplerinin beceri testinden önce FMCSA Training Provider Registry'de bulunan bir sağlayıcıdan eğitim tamamlamasını gerektirir. Kaynak: NY DMV / FMCSA ELDT."},"89":{"q":"New York'ta, tamamlanmış ELDT'nin planlanmış bir CDL yol testiyle nasıl ilişkili olması gerekir?","options":["ELDT, yol testi gününde test alanında tamamlanabilir","Tamamlanmış ELDT'niz yol testinden en az 7 gün önce DMV'de dosyada olmalıdır, aksi takdirde test iptal edilir","ELDT'nin yol testini geçtikten sonra yalnızca 30 gün içinde dosyada olması gerekir","ELDT'nin New York DMV'de dosyada olması asla gerekmez"],"explanation":"New York, yol testini ELDT'yi bitirmeden önce planlamanıza izin verir, ancak tamamlanmış ELDT testten en az 7 gün önce DMV'de dosyada olmalıdır, aksi takdirde yol testi iptal edilir ($40 ücret kaybedilmez; yeniden planlarsınız). Kaynak: NY DMV, Get a CDL."},"90":{"q":"New York'ta CDL yol testi nasıl planlanır?","options":["Herhangi bir DMV ofisine girerek ve randevu olmadan hemen test alarak","NY DMV Road Test Scheduling System aracılığıyla (çevrimiçi portal/telefon)","Yalnızca FMCSA'ya kağıt bir talep postalayarak","Otomatik olarak, başvuru sahibi adına ELDT eğitim sağlayıcısı tarafından"],"explanation":"New York CDL yol testleri, DMV'nin Road Test Scheduling System'i aracılığıyla planlanır (çevrimiçi portal, ayrıca telefonla da mevcuttur). Kaynak: NY DMV, Schedule and Take a Road Test."},"91":{"q":"New York CDL beceri/yol testi hangi üç bileşenden oluşur?","options":["Sürüş öncesi araç muayenesi, temel kontrol becerileri ve bir yolda sürüş testi","Bir yazılı sınav, bir görüş taraması ve bir parmak izi kontrolü","Bir Hazmat testi, bir passenger testi ve bir school bus testi","Bir Article 19-A sözlü sınavı, bir tıbbi muayene ve bir defansif sürüş testi"],"explanation":"New York'ta CDL beceri testi üç bölümden oluşur: bir sürüş öncesi araç muayenesi, bir temel kontrol becerileri testi ve bir yolda sürüş testi. Kaynak: NY DMV / CDL Manual (CDL-10)."},"92":{"q":"New York CDL yol testini hava frenleri olmayan bir araçta alırsanız, CDL'inize ne olur?","options":["Hava frenleriyle donatılmış araçları kullanmanızı yasaklayan bir L kısıtlaması eklenir","CDL'iniz otomatik olarak tüm fren tiplerine izin verecek şekilde yükseltilir","Varsayılan olarak bir Hazmat onayı alırsınız","Hiçbir şey değişmez; fren ekipmanı kısıtlamaları etkilemez"],"explanation":"Tam hava frenleri olmayan bir araçta test almak, bir 'L' kısıtlamasıyla (hava freni yok) sonuçlanır. İlgili kısıtlamalar 'E' (otomatik şanzıman) ve 'Z' (hava destekli hidrolik frenler) içerir. Kaynak: NY DMV, Get a CDL / CDL Manual."},"93":{"q":"New York CDL öz sertifikasyonu, bir sürücünün kaç federal sürüş kategorisi seçmesini gerektirir?","options":["Dört federal sürüş kategorisinin hepsini birden","Dört federal sürüş kategorisinden birini","Üç federal sürüş kategorisinden ikisini","Hiçbiri; öz sertifikasyon New York'ta isteğe bağlıdır"],"explanation":"CDL sahipleri, dört federal sürüş tipinden tam olarak BİRİNİ seçerek öz sertifikasyon yapmalıdır. Kaynak: NY DMV, Self-Certify Your Driving Type."},"94":{"q":"Bir New York CDL sahibinin arasından seçim yaptığı dört federal öz sertifikasyon sürüş kategorisi hangileridir?","options":["Local, Regional, National ve International","Class A, Class B, Class C ve Class D","Interstate Non-Excepted, Intrastate Non-Excepted, Interstate Excepted ve Intrastate Excepted","Hazmat, Passenger, School Bus ve Tank"],"explanation":"Dört öz sertifikasyon kategorisi Interstate Non-Excepted (NI), Intrastate Non-Excepted (NA), Interstate Excepted (EI) ve Intrastate Excepted (EA)'dır. Kaynak: NY DMV, Self-Certify Your Driving Type."},"95":{"q":"Hangi öz sertifikasyon kategorileri, bir New York CDL sahibinin dosyada güncel bir U.S. DOT Medical Examiner's Certificate tutmasını gerektirir?","options":["Yalnızca Excepted kategorileri","Non-Excepted kategorileri (Interstate Non-Excepted ve Intrastate Non-Excepted)","Dört kategorinin hepsi eşit olarak","Kategorilerin hiçbiri bir tıbbi sertifika gerektirmez"],"explanation":"Bir Non-Excepted tipe (NI veya NA) öz sertifikasyon yapan sürücüler, dosyada güncel bir USDOT Medical Examiner's Certificate tutmalıdır; Excepted sürücüler (EI/EA) tutmaz. Kaynak: NY DMV, CDL Medical Certification."},"96":{"q":"Mevcut federal ve New York prosedürleri uyarınca, bir CDL sahibinin Medical Examiner's Certificate'ı genel olarak NY DMV'ye nasıl iletilir?","options":["Sertifikalı tıbbi muayene uzmanı bunu FMCSA National Registry'ye elektronik olarak sunar ve bu da sonucu DMV'ye iletir","Sürücü her zaman orijinal kağıt sertifikayı bir DMV ofisine elden teslim etmelidir","Sertifika asla DMV'ye bildirilmez ve yalnızca sürücü tarafından saklanır","İşveren sertifikayı yılda bir kez FMCSA'ya postalar"],"explanation":"Federal kurallar uyarınca, sertifikalı tıbbi muayene uzmanları muayene sonuçlarını FMCSA National Registry'ye yükler ve bu da tıbbi sertifikasyon durumunu, sürücünün bir kopya postalaması yerine, NY DMV'ye elektronik olarak iletir. Kaynak: NY DMV / FMCSA Medical Certification."},"97":{"q":"Bir New York CDL ne kadar süre geçerlidir ve tipik olarak nasıl yenilenir?","options":["Sekiz yıl geçerli; CDL'ler genel olarak çevrimiçi yenilenemez ve posta yoluyla veya şahsen yenilenir","Bir yıl geçerli; yalnızca çevrimiçi yenilenir","İki yıl geçerli; herhangi bir işlem olmadan otomatik olarak yenilenir","On yıl geçerli; yalnızca FMCSA'da yenilenir"],"explanation":"Bir New York CDL sekiz yıl geçerlidir. Standart belgelerin aksine, CDL'ler genel olarak çevrimiçi yenilenemez ve posta yoluyla veya bir DMV ofisinde yenilenmelidir. Kaynak: NY DMV, Renew a Commercial Driver License (CDL)."},"98":{"q":"New York'un Article 19-A'sı hangi sürücü grubu için özel gereksinimler belirler?","options":["New York City'deki tüm binek otomobil sürücüleri","Yalnızca tehlikeli madde tank kamyonu sürücüleri","Kapsanan motor taşıyıcıları için çalışan otobüs sürücüleri (school bus ve belirli NYSDOT yetkili taşıyıcılar gibi)","New York'tan geçen eyalet dışı CDL sahipleri"],"explanation":"Article 19-A, kapsanan motor taşıyıcılarının otobüs sürücüleri (örneğin school bus taşıyıcıları ve belirli NYSDOT yetkili taşıyıcılar) için, iki yılda bir tıbbi muayeneler, direksiyon başı ve yazılı/sözlü test dahil özel yeterlilik gereksinimleri belirler. Kaynak: NY DMV, Article 19-A Information."}},"es":{"0":{"q":"En las carreteras de Nueva York, ¿cuál es la altura máxima legal de un vehículo, incluyendo cualquier carga?","options":["13 pies 0 pulgadas","13 pies 6 pulgadas","14 pies 0 pulgadas","12 pies 6 pulgadas"],"explanation":"La Ley de Vehículos y Tránsito de Nueva York (VTL) Sección 385 y el Manual de CDL de Nueva York establecen la altura máxima del vehículo en 13 pies 6 pulgadas (13.5 pies), incluyendo la carga. Los puentes y pasos elevados señalizados pueden tener una altura menor."},"1":{"q":"¿Cuál es el peso bruto máximo permitido para la mayoría de los vehículos en las carreteras de Nueva York sin un permiso especial?","options":["90,000 libras","100,000 libras","73,280 libras","80,000 libras"],"explanation":"Según la VTL Sección 385 de Nueva York, el peso bruto total de un vehículo o combinación generalmente no puede exceder las 80,000 libras, a menos que se emita un permiso de sobredimensión/sobrepeso."},"2":{"q":"Según la Ley de Vehículos y Tránsito de Nueva York, ¿cuál es el peso máximo permitido en cualquier eje sencillo (sin permiso)?","options":["18,000 libras","24,000 libras","20,000 libras","22,400 libras"],"explanation":"La VTL Sección 385 de Nueva York limita el peso en cualquier eje sencillo a 22,400 libras. (En el sistema interestatal, se aplica el límite federal más bajo de 20,000 libras por eje sencillo)."},"3":{"q":"¿Cuál es el ancho máximo general de un vehículo en las carreteras de Nueva York, excepto donde se permiten anchos mayores en carreteras que califican?","options":["102 pulgadas (8 pies 6 pulgadas)","120 pulgadas (10 pies)","96 pulgadas (8 pies)","90 pulgadas (7 pies 6 pulgadas)"],"explanation":"La VTL Sección 385 de Nueva York establece el ancho máximo general en 96 pulgadas (8 pies). En el sistema de carreteras que califican/interestatales y en los carriles de tránsito de 10 o más pies de ancho fuera de la Ciudad de Nueva York, se permiten hasta 102 pulgadas."},"4":{"q":"En el sistema de carreteras que califican (interestatales) de Nueva York, ¿qué ancho máximo de vehículo se permite?","options":["108 pulgadas (9 pies)","120 pulgadas (10 pies)","96 pulgadas (8 pies)","102 pulgadas (8 pies 6 pulgadas)"],"explanation":"En el sistema de carreteras que califican/interestatales (y en carriles de al menos 10 pies de ancho fuera de la Ciudad de Nueva York), la VTL Sección 385 de Nueva York permite un ancho máximo de 102 pulgadas, sin incluir los espejos ni ciertos dispositivos de seguridad."},"5":{"q":"En Nueva York, ¿cuál es la longitud máxima de un camión sencillo (de chasis recto), incluyendo la carga y los parachoques?","options":["48 pies","35 pies","40 pies","45 pies"],"explanation":"La VTL Sección 385 de Nueva York limita un vehículo sencillo (que no sea un autobús articulado ni un semirremolque) a 40 pies de longitud, incluyendo la carga y los parachoques."},"6":{"q":"En Nueva York, ¿cuál es la longitud máxima permitida para un semirremolque o remolque operado en una combinación?","options":["53 pies","40 pies","45 pies","48 pies"],"explanation":"Según la VTL Sección 385 de Nueva York, un semirremolque o remolque no puede exceder los 48 pies de longitud, incluyendo la carga. La operación de remolques de 53 pies en Nueva York generalmente requiere permisos de acceso especiales."},"7":{"q":"En el Sistema Interestatal federal en Nueva York, ¿cuál es el peso máximo permitido en un grupo de ejes en tándem?","options":["40,000 libras","22,400 libras","36,000 libras","34,000 libras"],"explanation":"En el Sistema Interestatal, se aplica en Nueva York el límite federal de 34,000 libras para ejes en tándem, según lo referenciado en 23 CFR 658.17 y el Manual de CDL de Nueva York."},"8":{"q":"En el Sistema Interestatal de Nueva York, ¿cuál es el peso máximo permitido en un eje sencillo?","options":["22,400 libras","18,000 libras","20,000 libras","24,000 libras"],"explanation":"El límite federal de 20,000 libras por eje sencillo se aplica en el Sistema Interestatal de Nueva York. El límite general de la ley estatal de Nueva York para ejes sencillos (fuera del interestatal) es mayor, de 22,400 libras."},"9":{"q":"En Nueva York, ¿qué tipo de permiso se utiliza para transportar una carga que no puede reducirse a un tamaño o peso legal?","options":["Un permiso de carga no divisible (transporte especial)","Un certificado de registro estándar","Un permiso de sobrepeso para carga divisible","Un endoso de materiales peligrosos"],"explanation":"El NYSDOT emite permisos de transporte especial (carga no divisible) para cargas que no pueden dividirse en unidades legales sin afectar la integridad física de la carga, como una sola máquina grande."},"10":{"q":"¿Qué agencia de Nueva York emite los permisos de transporte especial de sobredimensión/sobrepeso para circular por las carreteras estatales fuera de la Ciudad de Nueva York?","options":["La Administración Federal de Seguridad de Autotransportes (FMCSA)","El Departamento de Transporte del Estado de Nueva York (NYSDOT)","La Autoridad de la Thruway del Estado de Nueva York","El DMV del Estado de Nueva York"],"explanation":"El NYSDOT emite los permisos de sobredimensión/sobrepeso (transporte especial) para las carreteras estatales. Dentro de la Ciudad de Nueva York, el NYC Department of Transportation emite dichos permisos, y ciertas autoridades de puentes/túneles controlan sus propios cruces."},"11":{"q":"En Nueva York, una 'carga divisible' se define mejor como una carga que:","options":["Solo puede transportarse de noche con escolta","Puede separarse en unidades legales sin afectar la integridad física de la carga","Pesa más de 80,000 libras en una sola pieza","Consiste en una sola máquina indivisible"],"explanation":"Según las normas del NYSDOT, una carga divisible es carga de dimensiones legales que puede separarse en unidades de peso legal sin afectar la integridad física de la carga. Los permisos de sobrepeso para cargas divisibles son limitados y no son válidos en caminos locales ni en la Ciudad de Nueva York."},"12":{"q":"Un Permiso de Sobrepeso para Carga Divisible de Nueva York generalmente NO es válido en cuál de las siguientes opciones?","options":["Caminos y vías de pueblos, aldeas y condados locales, y dentro de la Ciudad de Nueva York","Rutas turísticas designadas del NYSDOT en el norte del estado","Tramos del sistema de carreteras que califican mantenidos por el estado","Carreteras estatales cubiertas por la región del permiso"],"explanation":"Los permisos de sobrepeso para carga divisible del NYSDOT no son válidos en caminos de pueblos, aldeas o condados, en vías bajo la jurisdicción de la MTA o de autoridades de puentes o túneles, ni dentro de la Ciudad de Nueva York. Esas jurisdicciones hacen cumplir sus propios límites."},"13":{"q":"La Fórmula Federal de Puentes, tal como se aplica en Nueva York, limita el peso permitido en un grupo de ejes basándose principalmente en:","options":["El número de ejes y la distancia (separación) entre ellos","El tipo de carga que se transporta","La antigüedad y la marca del tractocamión","El límite de velocidad señalizado en la carretera"],"explanation":"La Fórmula Federal de Peso Bruto sobre Puentes, aplicada en Nueva York en el sistema interestatal, limita el peso en cualquier grupo de ejes según el número de ejes y la distancia entre los ejes exteriores, para proteger los puentes."},"14":{"q":"En Nueva York, ¿cuál es la longitud máxima total de una combinación de vehículos (tractocamión más remolque), incluyendo la carga y los parachoques, en carreteras donde no se aplican las concesiones de longitud para carreteras que califican?","options":["60 pies","65 pies","75 pies","53 pies"],"explanation":"La VTL Sección 385 de Nueva York limita una combinación de vehículos a 65 pies en total, incluyendo la carga y los parachoques, excepto cuando se permita otra cosa en el sistema de carreteras que califican."},"15":{"q":"Según la ley de Nueva York, ¿cuál es el peso máximo permitido en cualquier rueda de un vehículo equipado con neumáticos?","options":["10,000 libras","8,000 libras","11,200 libras","12,500 libras"],"explanation":"La VTL Sección 385 de Nueva York limita el peso en cualquier rueda de un vehículo con neumáticos, cuando está cargado, a 11,200 libras (la mitad del límite de 22,400 libras por eje sencillo)."},"16":{"q":"Según la VTL Sección 385 de Nueva York, un vehículo impulsado principalmente por un motor que funciona con gas natural puede tener un peso bruto máximo de hasta:","options":["80,000 libras","82,000 libras","88,000 libras","85,000 libras"],"explanation":"La VTL Sección 385 de Nueva York permite que un vehículo operado por un motor que funciona principalmente con gas natural tenga un peso bruto máximo de hasta 82,000 libras, para tener en cuenta el peso adicional del sistema de combustible."},"17":{"q":"En Nueva York, ¿cuál es la longitud máxima de un autobús que transporta más de siete pasajeros (que no sea un autobús articulado)?","options":["45 pies","40 pies","62 pies","55 pies"],"explanation":"La VTL Sección 385 de Nueva York limita un autobús que transporta más de siete pasajeros a 45 pies de longitud, mientras que un autobús articulado puede tener hasta 62 pies."},"18":{"q":"Un transportista de Nueva York desea trasladar una carga no divisible de sobredimensión/sobrepeso por carreteras estatales. ¿Qué debe obtener antes del viaje?","options":["Un permiso de transporte especial del NYSDOT emitido antes del traslado","Solo una CDL Clase A válida sin permiso","Un permiso de sobrepeso para carga divisible","Un endoso de materiales peligrosos"],"explanation":"Trasladar una carga no divisible de sobredimensión o sobrepeso por las carreteras estatales de Nueva York requiere un permiso de transporte especial del NYSDOT obtenido con anticipación; el permiso especifica la ruta, las dimensiones, el peso y cualquier condición de escolta u horario de viaje."},"19":{"q":"¿Qué afirmación describe mejor cómo pueden diferir los límites de peso entre las carreteras estatales de Nueva York y los caminos o puentes locales?","options":["Los límites señalizados de los puentes nunca se aplican a los vehículos comerciales","Los límites locales son idénticos en todo el estado, sin excepciones señalizadas","Los caminos locales y los puentes señalizados pueden tener límites más bajos que deben respetarse incluso si se cuenta con un permiso estatal","Los caminos locales siempre permiten cargas más pesadas que las carreteras estatales"],"explanation":"Según el Manual de CDL de Nueva York y el NYSDOT, un permiso estatal de sobredimensión/sobrepeso no anula los límites más bajos señalizados en caminos locales, puentes o instalaciones administradas por otras autoridades; los conductores deben respetar el límite señalizado más restrictivo."},"20":{"q":"Según la clasificación de CDL de Nueva York, ¿qué clase se requiere para operar una combinación de tractocamión con remolque?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"El NY DMV define la CDL Clase A como un 'tractocamión con remolque' (un vehículo de combinación). La Clase B cubre un autobús o camión de unidad sencilla, y la Clase C cubre un camión, autobús o limusina estirada que requiere un endoso. Fuente: NY DMV 'Get a Commercial Driver License (CDL)' / Manual del Conductor Comercial CDL-10."},"21":{"q":"Según el NY DMV, ¿bajo qué clase de CDL se opera un camión de unidad sencilla o un autobús que no es un vehículo de combinación?","options":["Clase A","Clase B","Clase C","Clase E"],"explanation":"El NY DMV describe la Clase B como un 'autobús o camión de unidad sencilla.' La Clase A es una combinación de tractocamión con remolque, y la Clase C es un camión, autobús o limusina estirada que requiere un endoso (como HazMat o de pasajeros). Fuente: páginas de CDL del NY DMV / manual CDL-10."},"22":{"q":"En Nueva York, ¿qué clase de CDL se describe como aquella que cubre un camión, autobús o limusina estirada que requiere un endoso específico?","options":["Clase A","Clase B","Clase C","Clase M"],"explanation":"El NY DMV define la Clase C como un 'camión, autobús o limusina estirada' que requiere un endoso, generalmente porque transporta 16 o más pasajeros (incluyendo al conductor) o materiales peligrosos. Fuente: NY DMV 'Get a Commercial Driver License (CDL)'."},"23":{"q":"¿Cuál es la edad mínima para obtener una CDL de Nueva York válida solo para conducir dentro del estado (conducción intraestatal en el Estado de Nueva York)?","options":["16 años","18 años","21 años","25 años"],"explanation":"Un conductor debe tener al menos 18 años para tener una CDL de Nueva York para conducción intraestatal (solo dentro de Nueva York). Los conductores menores de 21 años están restringidos a la operación intraestatal. Fuente: requisitos para conductores comerciales del NY DMV."},"24":{"q":"En Nueva York, ¿cuál es la edad mínima requerida para conducir un vehículo comercial en el comercio interestatal (cruzando las fronteras estatales)?","options":["18 años","19 años","20 años","21 años"],"explanation":"Debe tener al menos 21 años para operar un vehículo comercial en el comercio interestatal. Los conductores de 18 a 20 años con una CDL de Nueva York están limitados a la conducción intraestatal (dentro de Nueva York). Fuente: requisitos de CDL del NY DMV; FMCSA 49 CFR 391.11."},"25":{"q":"¿Cuánto tiempo es válido un Permiso de Aprendizaje Comercial (CLP) de Nueva York después de su emisión según las reglas actuales?","options":["30 días","Seis meses (180 días)","Un año (365 días)","Cinco años"],"explanation":"Para los CLP emitidos a partir del 27 de diciembre de 2022, Nueva York extendió la validez del CLP a un año (365 días), en lugar de los seis meses anteriores, para agilizar el proceso. Fuente: noticias del NY DMV, 'DMV Extends Validity of Commercial Learner Permit.'"},"26":{"q":"Las reglas federales que se aplican en Nueva York exigen que el titular de un CLP espere al menos cuánto tiempo después de que se emite el CLP antes de presentar el examen de habilidades (de manejo) de la CDL?","options":["No hay período de espera mínimo","7 días","14 días","30 días"],"explanation":"Según la ley federal (49 CFR 383.25), que se aplica en Nueva York, el titular de un CLP no es elegible para presentar el examen de habilidades de la CDL hasta al menos 14 días después de que se emitió inicialmente el CLP. Fuente: 49 CFR 383.25; estándares de CDL de la FMCSA."},"27":{"q":"¿Qué endoso necesita el titular de una CDL de Nueva York para transportar materiales peligrosos que requieren señalización con carteles (placarding)?","options":["H (Materiales Peligrosos)","N (Vehículos Cisterna)","T (Dobles/Triples)","S (Autobús Escolar)"],"explanation":"El endoso 'H' (Materiales Peligrosos) se requiere para transportar cantidades señalizadas con carteles de materiales peligrosos. En Nueva York requiere tener al menos 21 años, aprobar un examen escrito, completar el ELDT de HazMat (solicitantes por primera vez) y aprobar una verificación de antecedentes basada en huellas dactilares. Fuente: NY DMV 'CDL Endorsements.'"},"28":{"q":"Para obtener un endoso de Materiales Peligrosos (H) en Nueva York, el solicitante debe completar cuál paso relacionado con la seguridad?","options":["Un examen de la vista únicamente con un optometrista privado","Una verificación de antecedentes basada en huellas dactilares (a través de IdentoGO)","Una entrevista de residencia de 10 años con la policía local","Un examen de polígrafo en el DMV"],"explanation":"Los solicitantes de HazMat (H) de Nueva York deben aprobar una verificación de antecedentes federal/estatal basada en huellas dactilares, realizada a través de IdentoGO, además de aprobar el examen escrito y tener al menos 21 años. Fuente: NY DMV 'CDL Endorsements'; Programa de Evaluación de Amenazas de HazMat de la TSA."},"29":{"q":"¿Qué endoso de CDL de Nueva York se requiere para operar un vehículo diseñado para transportar líquidos o gases a granel en un tanque montado de forma permanente?","options":["P (Pasajeros)","T (Dobles/Triples)","N (Vehículos Cisterna)","M (Bobinas de Metal)"],"explanation":"El endoso 'N' (Vehículos Cisterna) se requiere para conducir vehículos que transportan líquidos o gases a granel en un tanque montado de forma permanente que cumpla con ciertos umbrales. Fuente: NY DMV 'CDL Endorsements'; manual CDL-10 Sección 9 (Vehículos Cisterna)."},"30":{"q":"En Nueva York, ¿qué endoso se requiere para arrastrar remolques dobles o triples?","options":["T (Dobles/Triples)","N (Vehículos Cisterna)","H (Materiales Peligrosos)","P (Pasajeros)"],"explanation":"El endoso 'T' (Dobles/Triples) se requiere para remolcar más de un remolque. Se obtiene aprobando un examen de conocimientos; tenga en cuenta que los remolques triples no son legales en todas las vías de Nueva York. Fuente: NY DMV 'CDL Endorsements'; manual CDL-10 Sección 8 (Dobles y Triples)."},"31":{"q":"¿Qué endoso debe tener el titular de una CDL de Nueva York para conducir un autobús o una van que transporta 16 o más pasajeros (incluyendo al conductor)?","options":["S (Autobús Escolar)","P (Pasajeros)","N (Vehículos Cisterna)","T (Dobles/Triples)"],"explanation":"El endoso 'P' (Pasajeros) se requiere para operar vehículos diseñados para transportar 16 o más personas, incluyendo al conductor. El endoso de Autobús Escolar (S) se basa en el endoso P. Fuente: NY DMV 'CDL Endorsements'; manual CDL-10 Sección 4 (Transporte de Pasajeros)."},"32":{"q":"En Nueva York, ¿cuál es un requisito previo para obtener el endoso de Autobús Escolar (S)?","options":["Tener un endoso de HazMat (H)","Tener ya, o solicitar al mismo tiempo, el endoso de Pasajeros (P)","Tener un endoso de Vehículos Cisterna (N)","Tener un endoso de Dobles/Triples (T)"],"explanation":"Según el NY DMV, un conductor debe tener ya el endoso de Pasajeros (P) o solicitar los endosos P y S al mismo tiempo para obtener el endoso de Autobús Escolar (S). Fuente: NY DMV 'CDL Endorsements.'"},"33":{"q":"¿Qué afirmación sobre el examen de conocimientos del endoso de Autobús Escolar (S) de Nueva York es correcta?","options":["Tiene 20 preguntas de opción múltiple y requiere 16 respuestas correctas para aprobar","Tiene 50 preguntas y requiere 45 respuestas correctas para aprobar","Solo requiere un examen de manejo y ningún examen escrito","Se exime a cualquier persona que ya tenga una CDL Clase A"],"explanation":"El examen escrito del endoso de Autobús Escolar (S) de Nueva York se basa en la Sección 10 del Manual de CDL y tiene 20 preguntas de opción múltiple; un conductor debe responder 16 correctamente para aprobar. No se requiere un examen de manejo aparte para el endoso S en sí. Fuente: NY DMV 'CDL Endorsements.'"},"34":{"q":"Nueva York exige un endoso especial, que no existe en muchos otros estados, para los conductores comerciales que transportan cuál carga que pesa 5,000 libras o más?","options":["Cilindros de gas comprimido","Animales vivos","Bobinas de metal","Residuos peligrosos"],"explanation":"La Ley de Vehículos y Tránsito de Nueva York exige un endoso de Bobinas de Metal ('M') para los conductores comerciales que transportan bobinas de metal que pesan 5,000 libras o más. Es un endoso específico de Nueva York que se obtiene aprobando un examen escrito de 20 preguntas (16 correctas para aprobar). Fuente: NY DMV 'CDL Endorsements.'"},"35":{"q":"Los conductores que operan autobuses para un transportista en Nueva York (como transportistas escolares o regulados por el DOT) están sujetos a cuál programa estatal adicional?","options":["Article 19-A (Requisitos Especiales para Conductores de Autobús)","Artículo 31 (programa de DWI)","La Ley de Licencia Graduada","La Ley de Cambio de Carril (Move Over Law)"],"explanation":"El Article 19-A de la Ley de Vehículos y Tránsito de Nueva York impone requisitos adicionales a los conductores de autobús de transportistas cubiertos, incluyendo tener al menos 21 años, tener una licencia válida por varios años, pruebas periódicas de desempeño físico y una revisión anual de manejo defensivo/detrás del volante. Fuente: NY DMV Article 19-A Information; VTL Article 19-A."},"36":{"q":"Según la regla federal de Capacitación para Conductores Principiantes (ELDT) que se aplica en Nueva York, ¿quién debe completar la capacitación antes de presentar el examen?","options":["Solo los conductores que buscan un endoso de HazMat","Los solicitantes de Clase A o B por primera vez, las actualizaciones de B a A, y los solicitantes por primera vez de los endosos H, P o S","Solo los conductores mayores de 65 años","Todos los titulares de CDL en cada renovación de licencia"],"explanation":"El ELDT se aplica a los solicitantes de CDL de Clase A o Clase B por primera vez, a los titulares de Clase B que actualizan a Clase A, y a los solicitantes por primera vez de los endosos de Materiales Peligrosos (H), Pasajeros (P) o Autobús Escolar (S), para cualquier persona que haya obtenido un CLP a partir del 7 de febrero de 2022. Fuente: FMCSA Training Provider Registry; NY DMV."},"37":{"q":"¿Dónde debe registrarse la Capacitación para Conductores Principiantes (ELDT) de un solicitante de CDL de Nueva York para que cuente hacia la elegibilidad de la CDL?","options":["En un certificado en papel que solo conserva el conductor","En el Registro de Proveedores de Capacitación (TPR) de la FMCSA","En la oficina del secretario del condado local","Solo en el archivo de personal del empleador del conductor"],"explanation":"El ELDT debe completarse con un proveedor que figure en el Registro de Proveedores de Capacitación (TPR) de la FMCSA, y el proveedor envía la certificación de finalización electrónicamente al TPR antes de que el solicitante pueda presentar el examen de la CDL. Fuente: FMCSA Entry-Level Driver Training (ELDT) / Training Provider Registry."},"38":{"q":"Al solicitar una CDL de Nueva York, ¿cómo verifica el DMV la identidad de un solicitante?","options":["Una sola identificación con foto siempre es suficiente","Documentos que sumen al menos 6 puntos de prueba de identidad, más el Número de Seguro Social","Solo una declaración verbal de identidad","Un informe de crédito y una factura de servicios públicos"],"explanation":"El NY DMV utiliza un sistema basado en puntos que requiere documentos que sumen al menos 6 puntos de prueba de identidad (con al menos uno que lleve una firma), y los solicitantes deben proporcionar su Número de Seguro Social (o firmar una declaración jurada si nunca se les emitió uno). Fuente: requisitos de prueba de identidad del NY DMV (Formulario ID-44)."},"39":{"q":"Como parte de la autocertificación médica, un titular de CDL de Nueva York que conduce en el comercio interestatal y no está exento del requisito de la tarjeta médica, ¿qué debe mantener archivado en el DMV?","options":["Una carta notariada de un empleador","Un Certificado de Examinador Médico (tarjeta médica) USDOT vigente","Una copia de su diploma de escuela secundaria","Un registro de vehículo por cada camión conducido"],"explanation":"Los titulares de CDL deben autocertificar su categoría de conducción (por ejemplo, Interestatal No Exento) y, si no están exentos, mantener un Certificado de Examinador Médico USDOT vigente archivado en el NY DMV; no hacerlo puede llevar a la degradación de la CDL. Fuente: NY DMV CDL Medical Certification ('Self-Certify Your Driving Type')."},"40":{"q":"¿Cuál es la concentración máxima de alcohol en sangre (BAC) con la que una persona puede operar legalmente un vehículo motor comercial (CMV) en Nueva York?","options":["0.02%","0.04%","0.08%","0.10%"],"explanation":"Nueva York sigue la regla federal: es ilegal operar un CMV con un BAC de .04% o más. Esto es la mitad del límite de 0.08% para conductores no comerciales. Fuente: NY CDL-10 Manual sec. 1.6.2; 49 CFR 383.51 Tabla 1."},"41":{"q":"Según la regla de consentimiento implícito de Nueva York para conductores comerciales, operar un CMV significa que usted ha dado automáticamente su consentimiento para qué?","options":["Una inspección de su carga y bitácora","Pruebas de alcohol y drogas","Una reexaminación de la vista y médica","Una auditoría de su historial de manejo"],"explanation":"El manual de CDL de Nueva York establece que si usted opera un CMV, se considerará que ha dado su consentimiento para las pruebas de alcohol. Fuente: NY CDL-10 Manual sec. 1.6.2; NY VTL 1194 (consentimiento implícito)."},"42":{"q":"Si se descubre que un conductor de CMV en Nueva York tiene una cantidad detectable de alcohol por debajo del límite de .04%, ¿qué sucede?","options":["Nada, porque el conductor está por debajo del límite legal","El conductor es puesto fuera de servicio durante 24 horas","El conductor es descalificado por 60 días","El conductor recibe únicamente una advertencia por escrito"],"explanation":"Un conductor de CMV con cualquier cantidad detectable de alcohol por debajo de .04% es puesto fuera de servicio durante 24 horas, aunque esté por debajo del límite que conlleva descalificación. Fuente: NY CDL-10 Manual sec. 1.6.2."},"43":{"q":"Por una primera infracción grave (como conducir un CMV con un BAC de .04% o más), ¿por cuánto tiempo será descalificado el titular de una CDL de Nueva York?","options":["60 días","120 días","Al menos un año","Tres años"],"explanation":"Una primera infracción grave resulta en una descalificación de al menos un año. Fuente: NY CDL-10 Manual sec. 1.6.2; 49 CFR 383.51 Tabla 1."},"44":{"q":"Un titular de CDL de Nueva York comete una primera infracción grave mientras opera un CMV que está señalizado con carteles de materiales peligrosos. ¿Cuánto dura la descalificación?","options":["Un año","Tres años","Cinco años","De por vida"],"explanation":"Una primera infracción grave cometida mientras se opera un CMV señalizado con carteles de materiales peligrosos resulta en una descalificación de tres años, en lugar del año estándar. Fuente: NY CDL-10 Manual sec. 1.6.2; 49 CFR 383.51 Tabla 1."},"45":{"q":"¿Cuál es el período de descalificación para un titular de CDL de Nueva York condenado por una SEGUNDA infracción grave?","options":["Un año","Tres años","Diez años","De por vida"],"explanation":"Una segunda condena por cualquiera de las infracciones graves enumeradas resulta en una descalificación de por vida del CLP y/o la CDL. Fuente: NY CDL-10 Manual sec. 1.6.2; 49 CFR 383.51 Tabla 1."},"46":{"q":"En Nueva York, ¿cómo se trata, a efectos de descalificación de la CDL, negarse a someterse a una prueba de alcohol en sangre mientras se opera un CMV?","options":["Como una infracción menor de papeleo sin descalificación","Solo como una infracción de tránsito grave","Como una infracción grave, igual que una condena por DUI","Como una violación de una orden de fuera de servicio"],"explanation":"Negarse a someterse a una prueba de alcohol en sangre es una infracción grave y conlleva la misma descalificación mínima de un año por primera infracción que una condena por DUI. Fuente: NY CDL-10 Manual sec. 1.6.2; 49 CFR 383.51 Tabla 1."},"47":{"q":"¿Cuál de las siguientes es una infracción grave que puede descalificar al titular de una CDL de Nueva York, incluso si se comete en el automóvil personal del conductor en lugar de en un CMV?","options":["Seguir a otro vehículo demasiado de cerca","Conducir bajo la influencia del alcohol","Hacer un cambio de carril indebido","Exceder el límite de velocidad por 15 mph"],"explanation":"Conducir cualquier vehículo bajo la influencia del alcohol o de una sustancia controlada es una infracción grave que descalifica al titular de una CDL; no necesita ocurrir en un CMV. Las otras opciones son infracciones de tránsito graves. Fuente: NY CDL-10 Manual sec. 1.6.2 y 1.6.3."},"48":{"q":"Un titular de CDL de Nueva York usa un vehículo motor comercial para cometer un delito grave relacionado con sustancias controladas. ¿Cuál es el resultado?","options":["Una descalificación de 120 días","Una descalificación de tres años","Una descalificación de por vida sin posibilidad de reinstalación a los 10 años","Una descalificación de un año"],"explanation":"Usar un CMV para cometer un delito grave relacionado con sustancias controladas resulta en una descalificación de por vida, y el conductor no es elegible para la reinstalación a los 10 años disponible para ciertos otros casos de por vida. Fuente: NY CDL-10 Manual sec. 1.6.2; 49 CFR 383.51 Tabla 1."},"49":{"q":"¿Cuál de las siguientes es una infracción grave que causa la descalificación de la CDL en Nueva York?","options":["Abandonar la escena de un accidente sin reportarlo","Conducir 12 mph por encima del límite de velocidad","No usar una señal de giro","Estacionarse en una zona de no detención (no-standing)"],"explanation":"Abandonar la escena de un accidente sin reportarlo es una infracción grave enumerada que conlleva al menos una descalificación de un año por una primera infracción. Fuente: NY CDL-10 Manual sec. 1.6.2; 49 CFR 383.51 Tabla 1."},"50":{"q":"¿Cuál de las siguientes se clasifica como una infracción de tránsito GRAVE según las reglas de CDL de Nueva York?","options":["Conducir con un BAC de .04% o superior","Exceso de velocidad de 15 mph o más por encima del límite indicado","Negarse a hacer una prueba química","Abandonar el lugar de un accidente"],"explanation":"El exceso de velocidad (15 mph o más por encima del límite indicado) es una infracción de tránsito grave. Las demás opciones son delitos mayores, que conllevan sanciones mucho más severas. Fuente: Manual NY CDL-10 sec. 1.6.3; 49 CFR 383.51 Tabla 2."},"51":{"q":"¿Por cuánto tiempo se descalifica a un titular de CDL de Nueva York por cometer DOS infracciones de tránsito graves en un CMV dentro de un período de tres años?","options":["Al menos 30 días","Al menos 60 días","Al menos 120 días","Al menos un año"],"explanation":"Dos infracciones de tránsito graves dentro de un período de tres años (en un CMV) resultan en una descalificación de al menos 60 días. Fuente: Manual NY CDL-10 sec. 1.6.3; 49 CFR 383.51 Tabla 2."},"52":{"q":"¿Por cuánto tiempo se descalifica a un titular de CDL de Nueva York por cometer TRES infracciones de tránsito graves en un CMV dentro de un período de tres años?","options":["Al menos 60 días","Al menos 90 días","Al menos 120 días","Al menos un año"],"explanation":"Tres infracciones de tránsito graves dentro de un período de tres años (en un CMV) resultan en una descalificación de al menos 120 días. Fuente: Manual NY CDL-10 sec. 1.6.3; 49 CFR 383.51 Tabla 2."},"53":{"q":"Operar un CMV en Nueva York mientras se usa un teléfono celular de mano o un dispositivo para enviar mensajes de texto se clasifica como ¿qué?","options":["Un delito mayor","Una infracción de tránsito grave","Una violación de una orden de fuera de servicio","Una violación de cruce de ferrocarril"],"explanation":"Usar un teléfono celular de mano o un dispositivo para enviar mensajes de texto mientras se opera un CMV está catalogado como una infracción de tránsito grave. Nueva York también prohíbe el uso de dispositivos de mano para todos los conductores según VTL 1225-c y 1225-d. Fuente: Manual NY CDL-10 sec. 1.6.3."},"54":{"q":"¿Cuál de las siguientes es una infracción de tránsito grave en lugar de un delito mayor para un titular de CDL de Nueva York?","options":["Seguir a un vehículo demasiado de cerca","Conducir un CMV mientras su CDL está revocada","Usar un CMV para cometer un delito grave","Causar una muerte por operación negligente de un CMV"],"explanation":"Seguir demasiado de cerca es una infracción de tránsito grave. Las otras tres son delitos mayores que conllevan al menos una descalificación de un año (o de por vida). Fuente: Manual NY CDL-10 sec. 1.6.2 y 1.6.3; 49 CFR 383.51."},"55":{"q":"Según el manual de CDL de Nueva York, ¿por cuánto tiempo se descalifica a un titular de CDL por una PRIMERA condena por violar una orden de fuera de servicio?","options":["Al menos 90 días","Al menos 30 días","Al menos un año","Al menos tres años"],"explanation":"El manual NY CDL-10 indica una descalificación mínima de 90 días por una primera violación de una orden de fuera de servicio. Fuente: Manual NY CDL-10 sec. 1.6.4. (Nota: la tabla federal en 49 CFR 383.51 establece un mínimo de 180 días para primeras infracciones que no sean de HazMat.)"},"56":{"q":"Según el manual de CDL de Nueva York, ¿cuál es la descalificación por cometer DOS violaciones de órdenes de fuera de servicio dentro de un período de diez años?","options":["Al menos 60 días","Al menos 120 días","Al menos un año","Al menos tres años"],"explanation":"Dos violaciones de órdenes de fuera de servicio dentro de un período de diez años resultan en una descalificación de al menos un año. Fuente: Manual NY CDL-10 sec. 1.6.4."},"57":{"q":"Según el manual de CDL de Nueva York, ¿cuál es la descalificación por cometer TRES o más violaciones de órdenes de fuera de servicio dentro de un período de diez años?","options":["Al menos un año","Al menos dos años","Al menos tres años","Al menos cinco años"],"explanation":"Tres o más violaciones de órdenes de fuera de servicio dentro de un período de diez años resultan en una descalificación de al menos tres años. Fuente: Manual NY CDL-10 sec. 1.6.4."},"58":{"q":"¿Cuál es el período de descalificación para la PRIMERA violación de un cruce a nivel de ferrocarril y carretera de un titular de CDL de Nueva York cometida mientras operaba un CMV?","options":["Al menos 30 días","Al menos 60 días","Al menos 120 días","Al menos un año"],"explanation":"Una primera violación de un cruce a nivel de ferrocarril y carretera resulta en una descalificación de al menos 60 días. Fuente: Manual NY CDL-10 sec. 1.6.5; 49 CFR 383.51 Tabla 3."},"59":{"q":"Un titular de CDL de Nueva York comete una TERCERA violación de un cruce a nivel de ferrocarril y carretera dentro de un período de tres años. ¿Cuál es la descalificación?","options":["Al menos 120 días","Al menos 180 días","Al menos un año","Al menos tres años"],"explanation":"Las violaciones de cruces a nivel de ferrocarril y carretera conllevan al menos 60 días por la primera, 120 días por la segunda dentro de tres años y al menos un año por la tercera dentro de un período de tres años. Fuente: Manual NY CDL-10 sec. 1.6.5; 49 CFR 383.51 Tabla 3."},"60":{"q":"Está conduciendo un tractocamión con remolque en la ciudad de Nueva York y ve un letrero que dice 'NO COMMERCIAL VEHICLES' (NO SE PERMITEN VEHÍCULOS COMERCIALES). ¿Qué indica este letrero sobre la vía que tiene adelante?","options":["Es una parkway del estado de Nueva York diseñada solo para automóviles, donde los vehículos comerciales están prohibidos","Es una ruta de paso para camiones designada que solo está abierta de noche","Es un carril expreso sin peaje reservado para autobuses","Es una calle de entrega local donde los camiones pueden circular solo mientras cargan"],"explanation":"El sistema de parkways de Nueva York se construyó a principios del siglo XX solo para automóviles, y no se permiten vehículos comerciales, incluyendo tractocamiones con remolque y autobuses, en estas parkways. El letrero 'NO COMMERCIAL VEHICLES' designa una vía exclusiva para automóviles. Fuente: NYS DOT Parkway Truck Brochure; NY VTL."},"61":{"q":"Un nuevo conductor comercial pregunta por qué los puentes bajos de piedra sobre las parkways del sur del estado de Nueva York son tan peligrosos para los camiones. ¿Cuál es la MEJOR respuesta según las reglas de Nueva York?","options":["Los puentes tienen límites de peso pero no tienen límites de altura indicados","Algunas alturas libres verticales indicadas son tan bajas como 6 pies 11 pulgadas, y los camiones que exceden la altura las golpean y quedan atascados debajo de ellos","Los puentes están reservados exclusivamente para autobuses durante la hora pico","Se permiten los camiones, pero deben tocar la bocina antes de cada puente"],"explanation":"El NYS DOT advierte que los puentes bajos de piedra en el sistema de parkways tienen alturas libres verticales indicadas tan bajas como 6 pies 11 pulgadas. Los vehículos comerciales, que tienen prohibido el acceso a las parkways, a menudo golpean y quedan atascados debajo de estos puentes bajos, causando accidentes graves y largas demoras. Fuente: NYS DOT Parkway Truck Brochure."},"62":{"q":"¿Cuál de las siguientes es una vía del sur del estado de Nueva York donde no se permiten vehículos comerciales, incluyendo tractocamiones con remolque?","options":["La Long Island Expressway (I-495)","La New York State Thruway (I-87)","La Brooklyn-Queens Expressway (I-278)","La Belt Parkway en Brooklyn y Queens"],"explanation":"La Belt Parkway es una de las parkways del sur del estado (junto con la Henry Hudson, Cross Island, Hutchinson River, Grand Central, Northern State y otras) donde están prohibidos los vehículos comerciales. Las expressways y la Thruway son rutas interestatales abiertas a los camiones. Fuente: NYS DOT Parkway Truck Brochure; NYC DOT Parkway Restrictions."},"63":{"q":"Un conductor comercial ingresa ilegalmente a una parkway de Nueva York y un tractocamión con remolque queda atascado debajo de un puente bajo. Además de multas y puntos, ¿sobre qué consecuencia adicional advierte específicamente Nueva York?","options":["Una confiscación obligatoria del vehículo por 30 días sin importar el daño","Pérdida automática de la CDL por un año en una primera infracción","Tarifas de remolque que pueden superar los $10,000 para tractocamiones con remolque más el reembolso al estado por la reparación del puente","Una prohibición federal de operar en los 50 estados"],"explanation":"El NYS DOT enumera las consecuencias de conducir un vehículo comercial en una parkway: multas y/o puntos, posibles lesiones, daños al vehículo y al puente/guardarriel, tarifas de remolque superiores a $10,000 para tractocamiones con remolque y reembolso al estado por la reparación del puente. Fuente: NYS DOT Parkway Truck Brochure."},"64":{"q":"En la ciudad de Nueva York, la red de rutas para camiones se divide en dos clases. ¿Cuáles son?","options":["Rutas para camiones diurnas y rutas para camiones nocturnas","Rutas locales para camiones y rutas de paso para camiones","Rutas expresas para camiones y rutas de peaje para camiones","Rutas para camiones por distrito y rutas para camiones por puente"],"explanation":"La red de rutas para camiones de NYC (aproximadamente 1,000 millas, definida en la Sección 4-13 de las Reglas de Tránsito de NYC) consiste en Rutas Locales para Camiones, para camiones que hacen una recogida o entrega local dentro de un distrito, y Rutas de Paso para Camiones, para camiones que pasan por la zona sin un origen o destino en el área. Fuente: NYC DOT Truck Routing; NYC Traffic Rules 4-13."},"65":{"q":"Un camión debe salir de una ruta para camiones designada de NYC para llegar a una dirección de entrega. Según las reglas de rutas para camiones de NYC, ¿cómo debe proceder el conductor?","options":["Usar cualquier calle, en cualquier dirección, hasta que se complete la entrega","Salir de la ruta para camiones en la intersección más cercana al destino, tomar la ruta más directa y regresar a la ruta para camiones más cercana de la misma manera","Circular solo por calles residenciales para evitar la congestión del tránsito","Obtener un permiso escrito por separado para salir de la ruta en cada entrega"],"explanation":"Las reglas de NYC permiten que un camión salga de una ruta designada solo para llegar a un origen o destino. El conductor debe salir en la intersección más cercana al destino, proceder por la ruta más directa y luego regresar a la ruta para camiones designada más cercana por la ruta más directa. Fuente: NYC DOT Truck Routing; NYC Traffic Rules 4-13."},"66":{"q":"¿Qué vehículos están obligados a DETENERSE en cada cruce a nivel de ferrocarril y carretera según las reglas de Nueva York y las reglas federales adoptadas por Nueva York?","options":["Todos los vehículos comerciales de más de 26,000 libras","Solo los vehículos que remolcan remolques","Los autobuses que transportan pasajeros y los vehículos que transportan materiales peligrosos con carteles","Solo los vehículos cisterna vacíos usados anteriormente para inflamables"],"explanation":"En Nueva York, los autobuses que transportan pasajeros y los vehículos comerciales que muestran carteles de materiales peligrosos deben detenerse en todos los cruces de ferrocarril. Se detienen dentro de los 50 pies pero no más cerca de 15 pies, miran y escuchan, y no deben cambiar de marcha mientras cruzan. Fuente: Manual NY CDL CDL-10; 49 CFR 392.10."},"67":{"q":"Un conductor de Nueva York de un camión de materiales peligrosos con carteles debe detenerse en un cruce de ferrocarril. ¿Dentro de qué distancia del riel más cercano debe detenerse el vehículo?","options":["Dentro de 50 pies pero no más cerca de 15 pies","Dentro de 100 pies pero no más cerca de 25 pies","Exactamente 5 pies del riel más cercano","Dentro de 30 pies pero no más cerca de 10 pies"],"explanation":"Los vehículos obligados a detenerse en los cruces de ferrocarril (HazMat con carteles y autobuses con pasajeros) deben detenerse dentro de los 50 pies pero no más cerca de 15 pies del riel más cercano, luego mirar y escuchar si vienen trenes antes de proceder sin cambiar de marcha. Fuente: Manual NY CDL CDL-10; 49 CFR 392.10."},"68":{"q":"Según la Ley Move Over de Nueva York (VTL 1144-a), ¿qué debe hacer un conductor comercial al acercarse a un vehículo de emergencia o de peligro detenido al costado de la carretera con sus luces de advertencia destellando?","options":["Detenerse por completo hasta que el vehículo de emergencia se vaya","Reducir la velocidad y, cuando sea posible, cambiarse un carril completo para alejarse del vehículo detenido","Tocar la bocina y mantener la velocidad indicada","Pasarse al acotamiento y rebasar por la derecha"],"explanation":"La Ley Move Over de Nueva York exige que los conductores tengan el debido cuidado, reduzcan la velocidad y se cambien un carril completo para alejarse de un vehículo de emergencia o de peligro detenido que muestre luces destellantes cuando sea seguro hacerlo. A partir de 2023 la ley se amplió para cubrir todos los vehículos detenidos. Fuente: NY VTL 1144-a; NYS Governor's Traffic Safety Committee."},"69":{"q":"La Ley Move Over de Nueva York se aplica tanto a los vehículos de peligro como a los vehículos de emergencia. ¿Cuál de estos es un 'vehículo de peligro' cubierto por la ley?","options":["Un automóvil de pasajeros estacionado legalmente junto a la acera","Una grúa o vehículo de mantenimiento que muestra luces ámbar destellantes","Un taxi detenido para recoger a un pasajero","Una camioneta de reparto con sus intermitentes de cuatro luces encendidos en una entrada de vehículos"],"explanation":"La Ley Move Over de Nueva York cubre vehículos de peligro como grúas, vehículos de construcción y mantenimiento y vehículos de saneamiento que muestren luces ámbar destellantes, además de los vehículos de policía, bomberos y ambulancias. Fuente: NY VTL 1144-a; NYS Thruway Move Over materials."},"70":{"q":"Según la ley de Nueva York, ¿cuándo puede un conductor comercial usar un teléfono celular de mano o un dispositivo para enviar mensajes de texto mientras opera un CMV?","options":["Solo mientras está detenido en un semáforo en rojo o en una señal de alto","Solo para llamadas de menos de 30 segundos","Solo cuando usa el dispositivo para navegación","Nunca mientras opera el CMV; el uso de dispositivos de mano y el envío de mensajes de texto están prohibidos"],"explanation":"Nueva York prohíbe a los conductores comerciales usar un teléfono móvil de mano o un dispositivo para enviar mensajes de texto mientras operan un CMV. A diferencia de algunas situaciones no comerciales, un conductor comercial no puede usar un dispositivo de mano ni siquiera detenido en un semáforo. Una condena agrega puntos y es un delito grave de CDL. Fuente: NY VTL 1225-c y 1225-d; Manual NY CDL CDL-10."},"71":{"q":"Un conductor comercial en Nueva York es condenado por segunda vez dentro de tres años por operar un CMV mientras usaba un teléfono de mano o enviaba mensajes de texto. ¿Qué consecuencia federal se aplica además de las sanciones de Nueva York?","options":["Una revocación permanente de la CDL de por vida","Una descalificación de la CDL de 60 días por una segunda condena dentro de tres años","Solo una advertencia escrita de la FMCSA","Una tarifa administrativa de $50 sin descalificación"],"explanation":"Las reglas federales de la FMCSA, aplicadas en Nueva York, descalifican a un titular de CDL por 60 días por una segunda condena por teléfono de mano/mensajes de texto dentro de tres años, y por 120 días por una tercera condena o posterior dentro de tres años, además de las multas y puntos estatales. Fuente: FMCSA 49 CFR 383.51; NY DMV."},"72":{"q":"Después de detenerse por un autobús escolar con luces rojas destellantes en Nueva York, ¿cuándo puede un conductor proceder?","options":["Inmediatamente después de contar hasta cinco","Tan pronto como no haya niños a la vista, incluso si las luces siguen destellando","Cuando el autobús reanude la marcha, o cuando el conductor del autobús o un agente de tránsito indique que es seguro proceder","Después de que el autobús cierre su puerta, sin importar las luces"],"explanation":"En Nueva York, un conductor que se ha detenido por un autobús escolar no puede moverse de nuevo hasta que el autobús comience a moverse, o hasta que el conductor del autobús o un agente de policía o de tránsito indique proceder. Las luces rojas destellantes controlan la detención. Fuente: NY VTL 1174; NY DMV Driver's Manual Capítulo 6."},"73":{"q":"Si un vehículo comercial debe detenerse en el acotamiento de una autopista de un solo sentido o dividida en Nueva York, ¿dónde se deben colocar los tres triángulos de advertencia (dispositivos reflectantes)?","options":["Los tres dentro de los 10 pies detrás del vehículo","A aproximadamente 10 pies, 100 pies y 200 pies hacia el tránsito que se aproxima","Uno adelante y dos directamente debajo del remolque","A 25 pies, 50 pies y 75 pies solo del lado del conductor"],"explanation":"En una autopista de un solo sentido o dividida, coloque los dispositivos de advertencia a aproximadamente 10 pies, 100 pies y 200 pies del vehículo hacia el tránsito que se aproxima, en el centro del carril o acotamiento que ocupa el CMV. Los dispositivos deben colocarse dentro de los 10 minutos. Fuente: Manual NY CDL CDL-10; 49 CFR 392.22."},"74":{"q":"Un vehículo comercial está detenido en un camino de dos carriles y doble sentido en Nueva York. ¿Cómo debe colocar el conductor los tres triángulos de advertencia de emergencia?","options":["Uno a 10 pies hacia el costado, uno a 100 pies detrás y uno a 100 pies delante del vehículo","Los tres a 200 pies detrás del vehículo","Uno en el techo y dos en el parachoques delantero","Uno a 10 pies detrás, uno a 50 pies detrás y uno a 50 pies delante"],"explanation":"En un camino de doble sentido, coloque un triángulo dentro de los 10 pies de la parte trasera del lado del tránsito, uno a aproximadamente 100 pies detrás y uno a aproximadamente 100 pies delante del vehículo, para que el tránsito sea advertido desde ambas direcciones. Fuente: Manual NY CDL CDL-10; 49 CFR 392.22."},"75":{"q":"En Nueva York, ¿cuál es la altura máxima que un camión y su carga pueden tener SIN un permiso especial de sobredimensión?","options":["11 pies","15 pies","16 pies 6 pulgadas","13 pies 6 pulgadas"],"explanation":"Según la Sección 385 de la Ley de Vehículos y Tránsito de Nueva York, la altura máxima legal de un vehículo y su carga es de 13 pies 6 pulgadas; una altura de 14 pies o más requiere un permiso de sobredimensión. Los conductores también deben obedecer los letreros de altura libre indicados, que son comunes en los puentes más antiguos de Nueva York. Fuente: NY VTL 385; NY DMV."},"76":{"q":"Un puente de Nueva York muestra una altura libre superior indicada más baja que la altura del camión. ¿Qué debe hacer el conductor comercial?","options":["Proceder lentamente y tocar la bocina mientras pasa por debajo","Dejar salir aire de los neumáticos para bajar el vehículo y continuar","No pasar por debajo del puente y, en su lugar, buscar una ruta alternativa legal","Proceder si la carga es la única parte que excede la altura libre"],"explanation":"La ley de Nueva York prohíbe pasar un vehículo a través de cualquier puente o estructura si la altura del vehículo excede la altura libre indicada. El conductor debe tomar una ruta alternativa. Los impactos por exceso de altura en puentes y parkways de baja altura libre son un grave problema de seguridad en Nueva York. Fuente: NY VTL 385; NYS DOT bridge-strike guidance."},"77":{"q":"¿Cómo se cobra típicamente un peaje a un vehículo comercial en la moderna New York State Thruway?","options":["Los conductores deben detenerse y pagar en efectivo en cada cabina de intercambio","Mediante peaje sin efectivo usando etiquetas E-ZPass o facturas de peaje por correo leídas por pórticos elevados","Se exime de peajes a todos los vehículos con una CDL","Los conductores prepagan una única tarifa anual fija en el DMV"],"explanation":"La New York State Thruway usa peaje sin efectivo: los pórticos elevados leen las etiquetas E-ZPass o fotografían las placas para una factura de Peaje por Correo (Tolls by Mail), de modo que los vehículos ya no se detienen en las cabinas. A los vehículos comerciales se les cobra por clase de vehículo y pueden obtener descuentos con NY E-ZPass. Fuente: NYS Thruway Authority - Cashless Tolling."},"78":{"q":"¿Cuál es la MEJOR práctica para un conductor comercial que opera en Nueva York durante condiciones invernales como nieve y hielo?","options":["Mantener la velocidad y la distancia de seguimiento normales de la autopista para mantener el tránsito en movimiento","Reducir la velocidad, aumentar la distancia de seguimiento y usar cadenas para neumáticos donde las condiciones o los requisitos indicados lo exijan","Aplicar los frenos con fuerza y frecuencia para mantenerlos calientes","Conducir solo en el carril del extremo izquierdo y desactivar todos los sistemas de tracción"],"explanation":"Los inviernos de Nueva York traen nieve y hielo, especialmente en las regiones del norte del estado y de efecto lago. El Manual NY CDL indica a los conductores que reduzcan la velocidad, aumenten la distancia de seguimiento, frenen suavemente y usen cadenas para neumáticos cuando las condiciones o los letreros indicados requieran dispositivos de tracción. Fuente: Manual NY CDL CDL-10, Driving in Adverse Conditions."},"79":{"q":"¿Qué agencia gubernamental emite las Licencias de Conducir Comerciales (CDL) en el estado de Nueva York?","options":["La Administración Federal de Seguridad de Autotransportes (FMCSA)","El Departamento de Vehículos Motorizados del Estado de Nueva York (NY DMV)","El Departamento de Transporte del Estado de Nueva York (NYSDOT)","El Departamento de Vehículos Motorizados de los EE. UU."],"explanation":"En Nueva York, las CDL son administradas y emitidas por el Departamento de Vehículos Motorizados del Estado de Nueva York (NY DMV). La FMCSA establece los estándares federales de CDL pero no emite la licencia. Fuente: NY DMV, Commercial Driver License (CDL)."},"80":{"q":"Antes de poder solicitar una CDL o un Permiso de Aprendizaje Comercial en Nueva York, ¿qué debe tener ya generalmente?","options":["Un número federal de autoridad de operación interestatal","Una certificación de conductor de autobús del Artículo 19-A completada","Un Certificado de Examinador Médico del DOT de los EE. UU. con fecha de las últimas 24 horas","Una licencia de conducir válida del estado de Nueva York (Clase D, Clase E o Non-CDL C) o una CDL válida de otro estado"],"explanation":"El NY DMV requiere que un solicitante de CDL por primera vez ya tenga una licencia de conducir de Nueva York (Clase D, E o Non-CDL C) o una CDL válida de otro estado antes de solicitar. Fuente: NY DMV, Get a Commercial Driver License (CDL)."},"81":{"q":"Nueva York verifica la identidad de un solicitante para una CDL o permiso usando ¿qué sistema?","options":["Una verificación de antecedentes federal solo con huellas dactilares","Un sistema de verificación de historial crediticio de 10 puntos","Solo una declaración jurada notariada de un solo documento","El sistema de prueba de identidad de 6 puntos del NY DMV"],"explanation":"Nueva York usa un sistema de prueba de identidad de 6 puntos: los solicitantes deben presentar documentos que totalicen al menos 6 puntos para probar su identidad, además de la prueba de fecha de nacimiento y de residencia. Fuente: NY DMV, Proof of Identity (6-point system)."},"82":{"q":"Según el sistema de identidad de 6 puntos de Nueva York, ¿cuál es la regla sobre los documentos que presenta?","options":["Solo se aceptan fotocopias para que el DMV pueda conservarlas en el archivo","Se acepta cualquier documento siempre que muestre su foto","Deben ser originales o copias certificadas; no se aceptan fotocopias ni documentos plastificados","Se prefieren los documentos plastificados porque duran más"],"explanation":"El NY DMV requiere que los documentos de 6 puntos sean originales o copias certificadas. El DMV no aceptará fotocopias simples ni documentos plastificados. Fuente: NY DMV, Proof of Identity."},"83":{"q":"Además de 6 puntos de documentos de identidad, ¿qué más debe proporcionar un solicitante de CDL de Nueva York con respecto a su número de Seguro Social?","options":["Nada; Nueva York no recopila números de Seguro Social para las CDL","Una declaración de impuestos federal de cada uno de los últimos tres años","Un número de Seguro Social emitido solo después de que se otorgue la CDL","Prueba de su número de Seguro Social, o una declaración jurada firmada si nunca se le emitió uno"],"explanation":"El NY DMV requiere prueba de su número de Seguro Social; si nunca se le emitió uno, debe firmar una declaración jurada que lo indique. Fuente: NY DMV, Proof of Identity / How to Apply."},"84":{"q":"¿Cómo comienza típicamente un solicitante de Nueva York el proceso de CDL en una oficina del DMV?","options":["Programando y aprobando el examen de manejo antes de cualquier examen escrito","Presentando una declaración jurada del Artículo 19-A al transportista","Solicitando un Permiso de Aprendizaje Comercial (CLP) y aprobando los exámenes escritos de conocimientos requeridos","Enviando por correo una solicitud de renovación y esperando una nueva licencia"],"explanation":"El proceso comienza en una oficina del DMV: el solicitante solicita un Permiso de Aprendizaje Comercial (CLP) y aprueba los exámenes escritos de conocimientos para la clase y los endosos deseados. Fuente: NY DMV, Get a Commercial Driver License (CDL)."},"85":{"q":"¿Qué conjunto de exámenes escritos de conocimientos toma comúnmente un solicitante de Nueva York para obtener un CLP de Clase A?","options":["Solo un único examen combinado de conducción comercial","Solo los exámenes de endoso de Materiales Peligrosos y de Pasajeros","Un examen oral del Artículo 19-A y un examen de manejo defensivo","Conocimientos Generales, Frenos de Aire y Vehículos Combinados"],"explanation":"Para un CLP de Clase A, los solicitantes de Nueva York típicamente aprueban los exámenes de conocimientos de Conocimientos Generales, Frenos de Aire y Vehículos Combinados. Los exámenes de endoso (HazMat, Pasajeros, Autobús Escolar, etc.) se toman por separado. Fuente: NY DMV, CDL knowledge tests."},"86":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendizaje Comercial (CLP) de Nueva York después de que Nueva York extendió su período de validez?","options":["30 días","Seis meses","Ocho años","Un año (365 días)"],"explanation":"Nueva York extendió la validez del CLP de seis meses a un año (365 días). Los puntajes de los exámenes de conocimientos son válidos por el mismo período. Fuente: NY DMV, DMV Extends Validity of Commercial Learner Permit."},"87":{"q":"¿Cuál es la cantidad mínima de tiempo que un solicitante de Nueva York debe tener un CLP antes de tomar el examen de manejo (de habilidades) de la CDL?","options":["Al menos 90 días","No hay un período de espera requerido","Al menos 14 días","Al menos 6 meses"],"explanation":"Siguiendo la regla federal, no puede programar un examen de manejo de CDL de Nueva York para una fecha dentro de los 14 días de cuando se emitió su CLP. Fuente: NY DMV, Get a Commercial Driver License (CDL) / FMCSA."},"88":{"q":"Antes de tomar el examen de manejo de la CDL en Nueva York para una primera CDL (o para agregar un endoso de HazMat, Pasajeros o Autobús Escolar), ¿qué capacitación debe completarse primero?","options":["Capacitación para Conductores de Nivel Inicial (ELDT) de un proveedor incluido en el Registro de Proveedores de Capacitación de la FMCSA","Un curso de reducción de puntos por manejo defensivo exclusivo de Nueva York","Una evaluación bienal de manejo detrás del volante del Artículo 19-A","Un curso de declaración jurada de autotransportista 19A"],"explanation":"Las reglas federales de ELDT (en vigor desde el 7 de febrero de 2022) requieren que los nuevos solicitantes de CDL y ciertos solicitantes de endosos completen la capacitación de un proveedor en el Registro de Proveedores de Capacitación de la FMCSA antes del examen de habilidades. Fuente: NY DMV / FMCSA ELDT."},"89":{"q":"En Nueva York, ¿cómo debe relacionarse la ELDT completada con un examen de manejo de CDL programado?","options":["La ELDT puede completarse en el sitio de examen el día del examen de manejo","Su ELDT completada debe estar registrada con el DMV al menos 7 días antes del examen de manejo, o el examen se cancela","La ELDT solo necesita estar registrada dentro de los 30 días después de aprobar el examen de manejo","La ELDT nunca es requerida estar registrada con el DMV de Nueva York"],"explanation":"Nueva York le permite programar el examen de manejo antes de terminar la ELDT, pero la ELDT completada debe estar registrada con el DMV al menos 7 días antes del examen o el examen de manejo se cancela (no se pierde la tarifa de $40; usted reprograma). Fuente: NY DMV, Get a CDL."},"90":{"q":"¿Cómo se programa el examen de manejo de la CDL en Nueva York?","options":["Entrando a cualquier oficina del DMV y haciendo el examen de inmediato sin cita","A través del Sistema de Programación de Exámenes de Manejo del NY DMV (portal en línea/teléfono)","Solo enviando por correo una solicitud en papel a la FMCSA","Automáticamente, por el proveedor de capacitación de ELDT en nombre del solicitante"],"explanation":"Los exámenes de manejo de CDL de Nueva York se programan a través del Sistema de Programación de Exámenes de Manejo del DMV (portal en línea, también disponible por teléfono). Fuente: NY DMV, Schedule and Take a Road Test."},"91":{"q":"El examen de habilidades/manejo de la CDL de Nueva York se compone de ¿cuáles tres componentes?","options":["Inspección del vehículo antes del viaje, habilidades básicas de control y un examen de conducción en carretera","Un examen escrito, un examen de la vista y una verificación de huellas dactilares","Un examen de HazMat, un examen de pasajeros y un examen de autobús escolar","Un examen oral del Artículo 19-A, un examen médico y un examen de manejo defensivo"],"explanation":"El examen de habilidades de la CDL en Nueva York tiene tres partes: una inspección del vehículo antes del viaje, un examen de habilidades básicas de control y un examen de conducción en carretera. Fuente: NY DMV / CDL Manual (CDL-10)."},"92":{"q":"Si toma el examen de manejo de la CDL de Nueva York en un vehículo sin frenos de aire, ¿qué le sucede a su CDL?","options":["Se agrega una restricción L, que le prohíbe operar vehículos equipados con frenos de aire","Su CDL se actualiza para permitir todos los tipos de frenos automáticamente","Recibe un endoso de HazMat por defecto","Nada cambia; el equipo de frenos no afecta las restricciones"],"explanation":"Hacer el examen en un vehículo sin frenos de aire completos resulta en una restricción 'L' (sin frenos de aire). Las restricciones relacionadas incluyen 'E' (transmisión automática) y 'Z' (frenos de aire sobre hidráulico). Fuente: NY DMV, Get a CDL / CDL Manual."},"93":{"q":"La autocertificación de CDL de Nueva York requiere que un conductor elija cuántas categorías federales de conducción?","options":["Las cuatro categorías federales de conducción a la vez","Una de cuatro categorías federales de conducción","Dos de tres categorías federales de conducción","Ninguna; la autocertificación es opcional en Nueva York"],"explanation":"Los titulares de CDL deben autocertificarse eligiendo exactamente UNA de cuatro categorías federales de conducción. Fuente: NY DMV, Self-Certify Your Driving Type."},"94":{"q":"¿Cuáles son las cuatro categorías federales de conducción de autocertificación entre las que elige un titular de CDL de Nueva York?","options":["Local, Regional, Nacional e Internacional","Clase A, Clase B, Clase C y Clase D","Interestatal No Exento, Intraestatal No Exento, Interestatal Exento e Intraestatal Exento","HazMat, Pasajeros, Autobús Escolar y Cisterna"],"explanation":"Las cuatro categorías de autocertificación son Interestatal No Exento (NI), Intraestatal No Exento (NA), Interestatal Exento (EI) e Intraestatal Exento (EA). Fuente: NY DMV, Self-Certify Your Driving Type."},"95":{"q":"¿Cuáles categorías de autocertificación requieren que un titular de CDL de Nueva York mantenga un Certificado de Examinador Médico del DOT de los EE. UU. vigente en el archivo?","options":["Solo las categorías Exentas","Las categorías No Exentas (Interestatal No Exento e Intraestatal No Exento)","Las cuatro categorías por igual","Ninguna de las categorías requiere un certificado médico"],"explanation":"Los conductores que se autocertifican en un tipo No Exento (NI o NA) deben mantener un Certificado de Examinador Médico del USDOT vigente en el archivo; los conductores Exentos (EI/EA) no. Fuente: NY DMV, CDL Medical Certification."},"96":{"q":"Según los procedimientos federales y de Nueva York actuales, ¿cómo se transmite generalmente el Certificado de Examinador Médico de un titular de CDL al NY DMV?","options":["El examinador médico certificado lo envía electrónicamente al Registro Nacional de la FMCSA, que reenvía el resultado al DMV","El conductor siempre debe entregar en persona el certificado original en papel a una oficina del DMV","El certificado nunca se reporta al DMV y lo conserva solo el conductor","El empleador envía el certificado por correo a la FMCSA una vez al año"],"explanation":"Según las reglas federales, los examinadores médicos certificados cargan los resultados de los exámenes al Registro Nacional de la FMCSA, que luego transmite el estado de la certificación médica al NY DMV electrónicamente, en lugar de que el conductor envíe una copia por correo. Fuente: NY DMV / FMCSA Medical Certification."},"97":{"q":"¿Por cuánto tiempo es válida una CDL de Nueva York y cómo se renueva típicamente?","options":["Válida por ocho años; las CDL generalmente no se pueden renovar en línea y se renuevan por correo o en persona","Válida por un año; se renueva solo en línea","Válida por dos años; se renueva automáticamente sin ninguna acción","Válida por diez años; se renueva solo en la FMCSA"],"explanation":"Una CDL de Nueva York es válida por ocho años. A diferencia de las licencias estándar, las CDL generalmente no se pueden renovar en línea y deben renovarse por correo o en una oficina del DMV. Fuente: NY DMV, Renew a Commercial Driver License (CDL)."},"98":{"q":"El Artículo 19-A de Nueva York establece requisitos especiales para ¿qué grupo de conductores?","options":["Todos los conductores de automóviles de pasajeros en la ciudad de Nueva York","Solo los conductores de camiones cisterna de materiales peligrosos","Conductores de autobús que operan para autotransportistas cubiertos (como autobuses escolares y ciertos transportistas autorizados por el NYSDOT)","Titulares de CDL de otros estados que pasan por Nueva York"],"explanation":"El Artículo 19-A establece requisitos especiales de calificación para los conductores de autobús de autotransportistas cubiertos (por ejemplo, transportistas de autobuses escolares y ciertos transportistas autorizados por el NYSDOT), incluyendo exámenes médicos bienales, exámenes detrás del volante y exámenes escritos/orales. Fuente: NY DMV, Article 19-A Information."}},"hi":{"0":{"q":"न्यूयॉर्क के राजमार्गों पर, किसी लोड सहित वाहन की अधिकतम कानूनी ऊँचाई कितनी है?","options":["13 फ़ुट 0 इंच","13 फ़ुट 6 इंच","14 फ़ुट 0 इंच","12 फ़ुट 6 इंच"],"explanation":"न्यूयॉर्क Vehicle and Traffic Law (VTL) Section 385 और NY CDL Manual वाहन की अधिकतम ऊँचाई लोड सहित 13 फ़ुट 6 इंच (13.5 फ़ुट) निर्धारित करते हैं। चिह्नित पुल और ओवरपास इससे कम हो सकते हैं।"},"1":{"q":"बिना किसी विशेष परमिट के न्यूयॉर्क के राजमार्गों पर अधिकांश वाहनों के लिए अनुमत अधिकतम सकल वज़न कितना है?","options":["90,000 पाउंड","100,000 पाउंड","73,280 पाउंड","80,000 पाउंड"],"explanation":"NY VTL Section 385 के अंतर्गत, किसी वाहन या संयोजन का कुल सकल वज़न आम तौर पर 80,000 पाउंड से अधिक नहीं हो सकता, जब तक कि कोई ओवरसाइज़/ओवरवेट परमिट जारी न किया गया हो।"},"2":{"q":"न्यूयॉर्क Vehicle and Traffic Law के अंतर्गत, किसी एकल एक्सल पर (बिना परमिट के) अनुमत अधिकतम वज़न कितना है?","options":["18,000 पाउंड","24,000 पाउंड","20,000 पाउंड","22,400 पाउंड"],"explanation":"NY VTL Section 385 किसी एकल एक्सल पर वज़न को 22,400 पाउंड तक सीमित करता है। (Interstate प्रणाली पर, 20,000 पाउंड की कम संघीय एकल-एक्सल सीमा लागू होती है।)"},"3":{"q":"न्यूयॉर्क के राजमार्गों पर सामान्य अधिकतम वाहन चौड़ाई कितनी है, सिवाय उन योग्य राजमार्गों के जहाँ अधिक चौड़ाई की अनुमति है?","options":["102 इंच (8 फ़ुट 6 इंच)","120 इंच (10 फ़ुट)","96 इंच (8 फ़ुट)","90 इंच (7 फ़ुट 6 इंच)"],"explanation":"NY VTL Section 385 सामान्य अधिकतम चौड़ाई 96 इंच (8 फ़ुट) निर्धारित करता है। योग्य/Interstate राजमार्ग प्रणाली पर और NYC के बाहर 10 या अधिक फ़ुट चौड़ी ट्रैफ़िक लेन में, 102 इंच तक की अनुमति है।"},"4":{"q":"न्यूयॉर्क की योग्य (Interstate) राजमार्ग प्रणाली पर, अधिकतम कितनी वाहन चौड़ाई की अनुमति है?","options":["108 इंच (9 फ़ुट)","120 इंच (10 फ़ुट)","96 इंच (8 फ़ुट)","102 इंच (8 फ़ुट 6 इंच)"],"explanation":"योग्य/Interstate राजमार्ग प्रणाली पर (और NYC के बाहर कम से कम 10 फ़ुट चौड़ी लेन में), NY VTL Section 385 दर्पणों और कुछ सुरक्षा उपकरणों को छोड़कर अधिकतम 102 इंच चौड़ाई की अनुमति देता है।"},"5":{"q":"न्यूयॉर्क में, लोड और बंपर सहित किसी एकल (सीधे) ट्रक की अधिकतम लंबाई कितनी है?","options":["48 फ़ुट","35 फ़ुट","40 फ़ुट","45 फ़ुट"],"explanation":"NY VTL Section 385 किसी एकल वाहन (आर्टिकुलेटेड बसों और सेमीट्रेलरों को छोड़कर) को लोड और बंपर सहित 40 फ़ुट लंबाई तक सीमित करता है।"},"6":{"q":"न्यूयॉर्क में, किसी संयोजन में संचालित सेमीट्रेलर या ट्रेलर के लिए अनुमत अधिकतम लंबाई कितनी है?","options":["53 फ़ुट","40 फ़ुट","45 फ़ुट","48 फ़ुट"],"explanation":"NY VTL Section 385 के अंतर्गत, कोई सेमीट्रेलर या ट्रेलर लोड सहित 48 फ़ुट लंबाई से अधिक नहीं हो सकता। न्यूयॉर्क में 53-फ़ुट ट्रेलरों का संचालन आम तौर पर विशेष एक्सेस परमिट की आवश्यकता रखता है।"},"7":{"q":"न्यूयॉर्क में संघीय Interstate System पर, किसी टैंडम एक्सल समूह पर अनुमत अधिकतम वज़न कितना है?","options":["40,000 पाउंड","22,400 पाउंड","36,000 पाउंड","34,000 पाउंड"],"explanation":"Interstate System पर, 34,000 पाउंड की संघीय टैंडम-एक्सल सीमा न्यूयॉर्क में लागू होती है, जैसा कि 23 CFR 658.17 और NY CDL Manual में उल्लिखित है।"},"8":{"q":"न्यूयॉर्क की Interstate System पर, किसी एकल एक्सल पर अनुमत अधिकतम वज़न कितना है?","options":["22,400 पाउंड","18,000 पाउंड","20,000 पाउंड","24,000 पाउंड"],"explanation":"20,000 पाउंड की संघीय Interstate एकल-एक्सल सीमा न्यूयॉर्क की Interstate System पर लागू होती है। NY की सामान्य राज्य-कानून एकल-एक्सल सीमा (Interstate से बाहर) 22,400 पाउंड पर अधिक है।"},"9":{"q":"न्यूयॉर्क में, ऐसे लोड को ले जाने के लिए किस प्रकार के परमिट का उपयोग किया जाता है जिसे कानूनी आकार या वज़न तक कम नहीं किया जा सकता?","options":["एक अविभाज्य लोड (विशेष हॉलिंग) परमिट","एक मानक पंजीकरण प्रमाणपत्र","एक विभाज्य लोड ओवरवेट परमिट","एक खतरनाक सामग्री समर्थन (एंडोर्समेंट)"],"explanation":"NYSDOT उन लोडों के लिए विशेष हॉलिंग (अविभाज्य लोड) परमिट जारी करता है जिन्हें लोड की भौतिक अखंडता को प्रभावित किए बिना कानूनी इकाइयों में विभाजित नहीं किया जा सकता, जैसे कि एक एकल बड़ी मशीन।"},"10":{"q":"न्यूयॉर्क शहर के बाहर राज्य के राजमार्गों पर यात्रा के लिए कौन-सी न्यूयॉर्क एजेंसी ओवरसाइज़/ओवरवेट विशेष हॉलिंग परमिट जारी करती है?","options":["Federal Motor Carrier Safety Administration (FMCSA)","New York State Department of Transportation (NYSDOT)","New York State Thruway Authority","New York State DMV"],"explanation":"NYSDOT राज्य के राजमार्गों के लिए ओवरसाइज़/ओवरवेट (विशेष हॉलिंग) परमिट जारी करता है। न्यूयॉर्क शहर के भीतर, NYC Department of Transportation ऐसे परमिट जारी करता है, और कुछ पुल/सुरंग प्राधिकरण अपने स्वयं के क्रॉसिंग को नियंत्रित करते हैं।"},"11":{"q":"न्यूयॉर्क में, 'विभाज्य लोड' को सबसे अच्छी तरह से ऐसे लोड के रूप में परिभाषित किया जाता है जो:","options":["केवल रात में एस्कॉर्ट के साथ ले जाया जा सकता है","लोड की भौतिक अखंडता को प्रभावित किए बिना कानूनी इकाइयों में अलग किया जा सकता है","एक ही टुकड़े में 80,000 पाउंड से अधिक वज़न का है","एक एकल अविभाज्य मशीन से बना है"],"explanation":"NYSDOT नियमों के अंतर्गत, विभाज्य लोड कानूनी आयामों वाला कार्गो है जिसे लोड की भौतिक अखंडता को प्रभावित किए बिना कानूनी वज़न की इकाइयों में अलग किया जा सकता है। विभाज्य लोडों के लिए ओवरवेट परमिट सीमित हैं और स्थानीय सड़कों पर या NYC में मान्य नहीं हैं।"},"12":{"q":"न्यूयॉर्क Divisible Load Overweight Permit आम तौर पर निम्नलिखित में से किस पर मान्य नहीं है?","options":["स्थानीय टाउन, गाँव और काउंटी सड़कें तथा न्यूयॉर्क शहर के भीतर की सड़कें","अपस्टेट निर्दिष्ट NYSDOT टूरिंग मार्ग","योग्य राजमार्ग प्रणाली के राज्य-अनुरक्षित हिस्से","परमिट के क्षेत्र द्वारा कवर किए गए राज्य राजमार्ग"],"explanation":"NYSDOT विभाज्य लोड ओवरवेट परमिट टाउन, गाँव या काउंटी सड़कों पर, MTA/पुल या सुरंग प्राधिकरण के अधिकार क्षेत्र की सड़कों पर, या न्यूयॉर्क शहर के भीतर मान्य नहीं हैं। वे अधिकार क्षेत्र अपनी स्वयं की सीमाएँ लागू करते हैं।"},"13":{"q":"न्यूयॉर्क में लागू होने वाला संघीय Bridge Formula, एक्सलों के समूह पर अनुमत वज़न को मुख्य रूप से किस आधार पर सीमित करता है?","options":["एक्सलों की संख्या और उनके बीच की दूरी (अंतराल)","ले जाए जा रहे कार्गो का प्रकार","ट्रैक्टर की आयु और मेक","राजमार्ग पर चिह्नित गति सीमा"],"explanation":"Federal Bridge Gross Weight Formula, जो NY में Interstate प्रणाली पर लागू होता है, पुलों की रक्षा के लिए एक्सलों की संख्या और बाहरी एक्सलों के बीच की दूरी के अनुसार किसी एक्सल समूह पर वज़न को सीमित करता है।"},"14":{"q":"न्यूयॉर्क में, उन राजमार्गों पर जहाँ योग्य-राजमार्ग लंबाई भत्ते लागू नहीं होते, लोड और बंपर सहित वाहनों के संयोजन (ट्रैक्टर प्लस ट्रेलर) की अधिकतम समग्र लंबाई कितनी है?","options":["60 फ़ुट","65 फ़ुट","75 फ़ुट","53 फ़ुट"],"explanation":"NY VTL Section 385 वाहनों के संयोजन को लोड और बंपर सहित कुल 65 फ़ुट तक सीमित करता है, सिवाय उन मामलों के जैसा योग्य राजमार्ग प्रणाली पर अन्यथा अनुमत है।"},"15":{"q":"न्यूयॉर्क कानून के अंतर्गत, न्यूमैटिक टायरों से सुसज्जित वाहन के किसी एक पहिये पर अनुमत अधिकतम वज़न कितना है?","options":["10,000 पाउंड","8,000 पाउंड","11,200 पाउंड","12,500 पाउंड"],"explanation":"NY VTL Section 385 न्यूमैटिक टायरों वाले वाहन के किसी एक पहिये पर, लोड किए जाने पर, वज़न को 11,200 पाउंड तक सीमित करता है (22,400-पाउंड की एकल-एक्सल सीमा का आधा)।"},"16":{"q":"न्यूयॉर्क VTL Section 385 के अंतर्गत, मुख्य रूप से प्राकृतिक गैस से चलने वाले इंजन द्वारा संचालित वाहन का अधिकतम सकल वज़न कितना हो सकता है?","options":["80,000 पाउंड","82,000 पाउंड","88,000 पाउंड","85,000 पाउंड"],"explanation":"NY VTL Section 385 मुख्य रूप से प्राकृतिक गैस से चलने वाले इंजन द्वारा संचालित वाहन को अधिकतम 82,000 पाउंड तक सकल वज़न की अनुमति देता है, ताकि ईंधन प्रणाली के अतिरिक्त वज़न की भरपाई हो सके।"},"17":{"q":"न्यूयॉर्क में, सात से अधिक यात्रियों को ले जाने वाली बस (आर्टिकुलेटेड बस को छोड़कर) की अधिकतम लंबाई कितनी है?","options":["45 फ़ुट","40 फ़ुट","62 फ़ुट","55 फ़ुट"],"explanation":"NY VTL Section 385 सात से अधिक यात्रियों को ले जाने वाली बस को 45 फ़ुट लंबाई तक सीमित करता है, जबकि एक आर्टिकुलेटेड बस 62 फ़ुट तक हो सकती है।"},"18":{"q":"एक न्यूयॉर्क कैरियर राज्य के राजमार्गों पर ओवरसाइज़/ओवरवेट अविभाज्य लोड ले जाना चाहता है। यात्रा से पहले क्या प्राप्त किया जाना चाहिए?","options":["गति से पहले जारी किया गया NYSDOT विशेष हॉलिंग परमिट","केवल बिना परमिट के एक वैध Class A CDL","एक विभाज्य लोड ओवरवेट परमिट","एक खतरनाक सामग्री समर्थन (एंडोर्समेंट)"],"explanation":"न्यूयॉर्क राज्य के राजमार्गों पर ओवरसाइज़ या ओवरवेट अविभाज्य लोड ले जाने के लिए पहले से प्राप्त NYSDOT विशेष हॉलिंग परमिट की आवश्यकता होती है; परमिट मार्ग, आयाम, वज़न और किसी भी एस्कॉर्ट या यात्रा-समय की शर्तों को निर्दिष्ट करता है।"},"19":{"q":"कौन-सा कथन सबसे अच्छी तरह से वर्णन करता है कि न्यूयॉर्क के राज्य राजमार्गों और स्थानीय सड़कों या पुलों के बीच वज़न सीमाएँ कैसे भिन्न हो सकती हैं?","options":["चिह्नित पुल सीमाएँ कभी भी वाणिज्यिक वाहनों पर लागू नहीं होतीं","स्थानीय सीमाएँ बिना किसी चिह्नित अपवाद के राज्यभर में समान हैं","स्थानीय सड़कों और चिह्नित पुलों की कम सीमाएँ हो सकती हैं जिनका पालन राज्य परमिट होने पर भी किया जाना चाहिए","स्थानीय सड़कें हमेशा राज्य राजमार्गों की तुलना में भारी लोड की अनुमति देती हैं"],"explanation":"NY CDL Manual और NYSDOT के अनुसार, कोई राज्य ओवरसाइज़/ओवरवेट परमिट स्थानीय सड़कों, पुलों, या अन्य प्राधिकरणों द्वारा संचालित सुविधाओं पर चिह्नित कम सीमाओं को रद्द नहीं करता; चालकों को सबसे प्रतिबंधात्मक चिह्नित सीमा का पालन करना चाहिए।"},"20":{"q":"न्यूयॉर्क के CDL वर्गीकरण के अंतर्गत, ट्रैक्टर-ट्रेलर संयोजन का संचालन करने के लिए कौन-सा वर्ग आवश्यक है?","options":["Class A","Class B","Class C","Class D"],"explanation":"NY DMV एक Class A CDL को 'ट्रैक्टर-ट्रेलर' (एक संयोजन वाहन) के रूप में परिभाषित करता है। Class B एक बस या एकल-इकाई ट्रक को कवर करता है, और Class C एक ट्रक, बस, या स्ट्रेच लिमो को कवर करता है जिसके लिए समर्थन (एंडोर्समेंट) की आवश्यकता होती है। स्रोत: NY DMV 'Get a Commercial Driver License (CDL)' / CDL-10 Commercial Driver's Manual।"},"21":{"q":"NY DMV के अनुसार, एक एकल-इकाई ट्रक या एक बस जो संयोजन वाहन नहीं है, किस CDL वर्ग के अंतर्गत संचालित की जाती है?","options":["Class A","Class B","Class C","Class E"],"explanation":"NY DMV Class B को 'बस या एकल-इकाई ट्रक' के रूप में वर्णित करता है। Class A एक ट्रैक्टर-ट्रेलर संयोजन है, और Class C एक ट्रक, बस, या स्ट्रेच लिमो है जिसके लिए समर्थन (एंडोर्समेंट) की आवश्यकता होती है (जैसे HazMat या यात्री)। स्रोत: NY DMV CDL पेज / CDL-10 manual।"},"22":{"q":"न्यूयॉर्क में, किस CDL वर्ग को ऐसे ट्रक, बस, या स्ट्रेच लिमो को कवर करने के रूप में वर्णित किया गया है जिसके लिए एक विशिष्ट समर्थन (एंडोर्समेंट) की आवश्यकता होती है?","options":["Class A","Class B","Class C","Class M"],"explanation":"NY DMV Class C को एक 'ट्रक, बस, या स्ट्रेच लिमो' के रूप में परिभाषित करता है जिसके लिए समर्थन (एंडोर्समेंट) की आवश्यकता होती है, आम तौर पर क्योंकि यह 16 या अधिक यात्रियों (चालक सहित) या खतरनाक सामग्री ले जाता है। स्रोत: NY DMV 'Get a Commercial Driver License (CDL)'।"},"23":{"q":"केवल इंट्रास्टेट ड्राइविंग (न्यूयॉर्क राज्य के भीतर) के लिए मान्य न्यूयॉर्क CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["16 वर्ष","18 वर्ष","21 वर्ष","25 वर्ष"],"explanation":"इंट्रास्टेट ड्राइविंग (केवल NY के भीतर) के लिए न्यूयॉर्क CDL रखने के लिए चालक की आयु कम से कम 18 वर्ष होनी चाहिए। 21 वर्ष से कम आयु के चालक इंट्रास्टेट संचालन तक सीमित हैं। स्रोत: NY DMV वाणिज्यिक चालक आवश्यकताएँ।"},"24":{"q":"न्यूयॉर्क में, इंटरस्टेट वाणिज्य में (राज्य की सीमाओं के पार) वाणिज्यिक वाहन चलाने के लिए आवश्यक न्यूनतम आयु क्या है?","options":["18 वर्ष","19 वर्ष","20 वर्ष","21 वर्ष"],"explanation":"इंटरस्टेट वाणिज्य में वाणिज्यिक वाहन का संचालन करने के लिए आपकी आयु कम से कम 21 वर्ष होनी चाहिए। NY CDL वाले 18 से 20 वर्ष की आयु के चालक इंट्रास्टेट (न्यूयॉर्क के भीतर) ड्राइविंग तक सीमित हैं। स्रोत: NY DMV CDL आवश्यकताएँ; FMCSA 49 CFR 391.11।"},"25":{"q":"वर्तमान नियमों के अंतर्गत, जारी किए जाने के बाद एक न्यूयॉर्क Commercial Learner Permit (CLP) कितने समय तक मान्य रहता है?","options":["30 दिन","छह महीने (180 दिन)","एक वर्ष (365 दिन)","पाँच वर्ष"],"explanation":"27 दिसंबर 2022 को या उसके बाद जारी किए गए CLP के लिए, न्यूयॉर्क ने प्रक्रिया को सरल बनाने के लिए CLP वैधता को पिछले छह महीने से बढ़ाकर एक वर्ष (365 दिन) कर दिया। स्रोत: NY DMV समाचार, 'DMV Extends Validity of Commercial Learner Permit'।"},"26":{"q":"न्यूयॉर्क में लागू होने वाले संघीय नियमों के अनुसार, CDL स्किल्स (रोड) टेस्ट देने से पहले एक CLP धारक को CLP जारी होने के बाद कम से कम कितने समय प्रतीक्षा करनी होती है?","options":["कोई न्यूनतम प्रतीक्षा अवधि नहीं है","7 दिन","14 दिन","30 दिन"],"explanation":"संघीय कानून (49 CFR 383.25) के अंतर्गत, जो न्यूयॉर्क में लागू होता है, एक CLP धारक CLP के प्रारंभिक रूप से जारी होने के कम से कम 14 दिन बाद तक CDL स्किल्स टेस्ट देने के योग्य नहीं होता। स्रोत: 49 CFR 383.25; FMCSA CDL मानक।"},"27":{"q":"प्लेकार्डिंग की आवश्यकता वाली खतरनाक सामग्री ले जाने के लिए एक न्यूयॉर्क CDL धारक को किस समर्थन (एंडोर्समेंट) की आवश्यकता होती है?","options":["H (खतरनाक सामग्री)","N (टैंक वाहन)","T (डबल्स/ट्रिपल्स)","S (स्कूल बस)"],"explanation":"प्लेकार्डेड मात्रा में खतरनाक सामग्री ले जाने के लिए 'H' (खतरनाक सामग्री) समर्थन (एंडोर्समेंट) आवश्यक है। NY में इसके लिए कम से कम 21 वर्ष का होना, एक लिखित परीक्षा पास करना, HazMat ELDT पूरा करना (पहली बार के आवेदकों के लिए), और एक फ़िंगरप्रिंट-आधारित पृष्ठभूमि जाँच पास करना आवश्यक है। स्रोत: NY DMV 'CDL Endorsements'।"},"28":{"q":"न्यूयॉर्क में खतरनाक सामग्री (H) समर्थन (एंडोर्समेंट) प्राप्त करने के लिए, एक आवेदक को कौन-सा सुरक्षा-संबंधी कदम पूरा करना होता है?","options":["केवल एक निजी ऑप्टोमेट्रिस्ट से एक दृष्टि परीक्षा","एक फ़िंगरप्रिंट-आधारित पृष्ठभूमि जाँच (IdentoGO के माध्यम से)","स्थानीय पुलिस के साथ 10-वर्षीय निवास साक्षात्कार","DMV में एक पॉलीग्राफ परीक्षा"],"explanation":"न्यूयॉर्क HazMat (H) आवेदकों को लिखित परीक्षा पास करने और कम से कम 21 वर्ष का होने के अतिरिक्त, IdentoGO के माध्यम से आयोजित एक फ़िंगरप्रिंट-आधारित संघीय/राज्य पृष्ठभूमि जाँच पास करनी होती है। स्रोत: NY DMV 'CDL Endorsements'; TSA HazMat Threat Assessment Program।"},"29":{"q":"स्थायी रूप से लगे टैंक में थोक में तरल पदार्थ या गैसों के परिवहन के लिए डिज़ाइन किए गए वाहन का संचालन करने के लिए किस NY CDL समर्थन (एंडोर्समेंट) की आवश्यकता होती है?","options":["P (यात्री)","T (डबल्स/ट्रिपल्स)","N (टैंक वाहन)","M (Metal Coil)"],"explanation":"कुछ सीमाओं को पूरा करने वाले स्थायी रूप से लगे टैंक में थोक में तरल पदार्थ या गैसों का परिवहन करने वाले वाहनों को चलाने के लिए 'N' (टैंक वाहन) समर्थन (एंडोर्समेंट) आवश्यक है। स्रोत: NY DMV 'CDL Endorsements'; CDL-10 manual Section 9 (Tank Vehicles)।"},"30":{"q":"न्यूयॉर्क में, डबल या ट्रिपल ट्रेलर खींचने के लिए किस समर्थन (एंडोर्समेंट) की आवश्यकता होती है?","options":["T (डबल्स/ट्रिपल्स)","N (टैंक वाहन)","H (खतरनाक सामग्री)","P (यात्री)"],"explanation":"एक से अधिक ट्रेलर को खींचने के लिए 'T' (डबल्स/ट्रिपल्स) समर्थन (एंडोर्समेंट) आवश्यक है। यह एक ज्ञान परीक्षा पास करके प्राप्त किया जाता है; ध्यान दें कि ट्रिपल ट्रेलर सभी न्यूयॉर्क सड़कों पर कानूनी नहीं हैं। स्रोत: NY DMV 'CDL Endorsements'; CDL-10 manual Section 8 (Doubles and Triples)।"},"31":{"q":"16 या अधिक यात्रियों (चालक सहित) ले जाने वाली बस या वैन को चलाने के लिए एक न्यूयॉर्क CDL धारक के पास कौन-सा समर्थन (एंडोर्समेंट) होना चाहिए?","options":["S (स्कूल बस)","P (यात्री)","N (टैंक वाहन)","T (डबल्स/ट्रिपल्स)"],"explanation":"चालक सहित 16 या अधिक लोगों को ले जाने के लिए डिज़ाइन किए गए वाहनों का संचालन करने के लिए 'P' (यात्री) समर्थन (एंडोर्समेंट) आवश्यक है। School Bus (S) समर्थन (एंडोर्समेंट) P समर्थन के ऊपर बनाया गया है। स्रोत: NY DMV 'CDL Endorsements'; CDL-10 manual Section 4 (Passenger Transport)।"},"32":{"q":"न्यूयॉर्क में, School Bus (S) समर्थन (एंडोर्समेंट) प्राप्त करने के लिए पूर्वापेक्षा क्या है?","options":["एक HazMat (H) समर्थन (एंडोर्समेंट) रखना","पहले से Passenger (P) समर्थन (एंडोर्समेंट) रखना, या उसी समय उसके लिए आवेदन करना","एक Tank Vehicles (N) समर्थन (एंडोर्समेंट) रखना","एक Doubles/Triples (T) समर्थन (एंडोर्समेंट) रखना"],"explanation":"NY DMV के अनुसार, School Bus (S) समर्थन (एंडोर्समेंट) प्राप्त करने के लिए चालक के पास पहले से Passenger (P) समर्थन (एंडोर्समेंट) होना चाहिए या P और S समर्थनों के लिए एक ही समय में आवेदन करना चाहिए। स्रोत: NY DMV 'CDL Endorsements'।"},"33":{"q":"न्यूयॉर्क की School Bus (S) समर्थन (एंडोर्समेंट) ज्ञान परीक्षा के बारे में कौन-सा कथन सही है?","options":["इसमें 20 बहुविकल्पीय प्रश्न होते हैं और पास होने के लिए 16 सही उत्तरों की आवश्यकता होती है","इसमें 50 प्रश्न होते हैं और पास होने के लिए 45 सही उत्तरों की आवश्यकता होती है","इसके लिए केवल एक रोड टेस्ट की आवश्यकता होती है और कोई लिखित परीक्षा नहीं","यह किसी भी ऐसे व्यक्ति के लिए माफ़ कर दी जाती है जिसके पास पहले से Class A CDL है"],"explanation":"NY School Bus (S) समर्थन (एंडोर्समेंट) लिखित परीक्षा CDL Manual के Section 10 पर आधारित है और इसमें 20 बहुविकल्पीय प्रश्न होते हैं; पास होने के लिए चालक को 16 सही उत्तर देने होते हैं। S समर्थन के लिए स्वयं किसी अलग रोड टेस्ट की आवश्यकता नहीं होती। स्रोत: NY DMV 'CDL Endorsements'।"},"34":{"q":"न्यूयॉर्क को कई अन्य राज्यों में नहीं पाया जाने वाला एक विशेष समर्थन (एंडोर्समेंट) आवश्यक है, उन वाणिज्यिक चालकों के लिए जो 5,000 पाउंड या अधिक वज़न का कौन-सा कार्गो परिवहन करते हैं?","options":["संपीड़ित गैस सिलेंडर","जीवित पशु","Metal coil","खतरनाक अपशिष्ट"],"explanation":"न्यूयॉर्क Vehicle and Traffic Law उन वाणिज्यिक चालकों के लिए Metal Coil ('M') समर्थन (एंडोर्समेंट) आवश्यक करता है जो 5,000 पाउंड या अधिक वज़न के मेटल कॉइल परिवहन करते हैं। यह एक NY-विशिष्ट समर्थन (एंडोर्समेंट) है जो 20-प्रश्नों की लिखित परीक्षा पास करके प्राप्त किया जाता है (पास होने के लिए 16 सही)। स्रोत: NY DMV 'CDL Endorsements'।"},"35":{"q":"न्यूयॉर्क में किसी मोटर कैरियर (जैसे स्कूल या DOT-विनियमित कैरियर) के लिए बसें चलाने वाले चालक किस अतिरिक्त राज्य कार्यक्रम के अधीन होते हैं?","options":["Article 19-A (बस चालकों के लिए विशेष आवश्यकताएँ)","Article 31 (DWI कार्यक्रम)","Graduated License Law","Move Over Law"],"explanation":"न्यूयॉर्क के Vehicle and Traffic Law का Article 19-A कवर किए गए मोटर कैरियरों के बस चालकों पर अतिरिक्त आवश्यकताएँ लगाता है, जिसमें कम से कम 21 वर्ष का होना, कई वर्षों तक एक वैध लाइसेंस होना, आवधिक शारीरिक प्रदर्शन परीक्षण, और एक वार्षिक रक्षात्मक-ड्राइविंग/बिहाइंड-द-व्हील समीक्षा शामिल है। स्रोत: NY DMV Article 19-A Information; VTL Article 19-A।"},"36":{"q":"न्यूयॉर्क में लागू होने वाले संघीय Entry-Level Driver Training (ELDT) नियम के अंतर्गत, परीक्षण से पहले किसे प्रशिक्षण पूरा करना होगा?","options":["केवल HazMat समर्थन (एंडोर्समेंट) चाहने वाले चालक","पहली बार के Class A या B आवेदक, B-से-A अपग्रेड, और पहली बार के H, P, या S समर्थन (एंडोर्समेंट) आवेदक","केवल 65 वर्ष से अधिक आयु के चालक","प्रत्येक लाइसेंस नवीनीकरण पर हर CDL धारक"],"explanation":"ELDT पहली बार के Class A या Class B CDL आवेदकों, Class A में अपग्रेड करने वाले Class B धारकों, और खतरनाक सामग्री (H), यात्री (P), या स्कूल बस (S) समर्थन (एंडोर्समेंट) के पहली बार के आवेदकों पर लागू होता है, उन सभी के लिए जिन्होंने 7 फ़रवरी 2022 को या उसके बाद CLP प्राप्त किया। स्रोत: FMCSA Training Provider Registry; NY DMV।"},"37":{"q":"CDL पात्रता की ओर गिनती करने के लिए एक न्यूयॉर्क CDL आवेदक का Entry-Level Driver Training (ELDT) कहाँ दर्ज किया जाना चाहिए?","options":["केवल चालक द्वारा रखा गया एक कागज़ी प्रमाणपत्र","FMCSA Training Provider Registry (TPR) में","स्थानीय काउंटी क्लर्क के कार्यालय में","केवल चालक की नियोक्ता कार्मिक फ़ाइल में"],"explanation":"ELDT FMCSA Training Provider Registry (TPR) पर सूचीबद्ध एक प्रदाता के साथ पूरा किया जाना चाहिए, और आवेदक के CDL टेस्ट देने से पहले प्रदाता पूर्णता प्रमाणन को इलेक्ट्रॉनिक रूप से TPR में जमा करता है। स्रोत: FMCSA Entry-Level Driver Training (ELDT) / Training Provider Registry।"},"38":{"q":"न्यूयॉर्क CDL के लिए आवेदन करते समय, DMV किसी आवेदक की पहचान की पुष्टि कैसे करता है?","options":["एक एकल फ़ोटो ID हमेशा पर्याप्त होती है","पहचान के प्रमाण के कम से कम 6 अंकों के कुल दस्तावेज़, साथ ही Social Security Number","केवल पहचान का एक मौखिक कथन","एक क्रेडिट रिपोर्ट और एक उपयोगिता बिल"],"explanation":"NY DMV एक अंक-आधारित प्रणाली का उपयोग करता है जिसमें पहचान के प्रमाण के कम से कम 6 अंकों के कुल दस्तावेज़ आवश्यक होते हैं (कम से कम एक पर हस्ताक्षर होना चाहिए), और आवेदकों को अपना Social Security Number प्रदान करना होगा (या यदि कभी जारी नहीं हुआ तो एक शपथपत्र पर हस्ताक्षर करना होगा)। स्रोत: NY DMV पहचान प्रमाण आवश्यकताएँ (Form ID-44)।"},"39":{"q":"चिकित्सा स्व-प्रमाणन के भाग के रूप में, इंटरस्टेट वाणिज्य में गाड़ी चलाने वाले और मेडिकल कार्ड आवश्यकता से छूट प्राप्त नहीं किए गए एक न्यूयॉर्क CDL धारक को DMV के पास क्या फ़ाइल पर रखना होगा?","options":["एक नियोक्ता का नोटरीकृत पत्र","एक वर्तमान USDOT Medical Examiner's Certificate (मेडिकल कार्ड)","अपने हाई स्कूल डिप्लोमा की एक प्रति","चलाए गए प्रत्येक ट्रक के लिए एक वाहन पंजीकरण"],"explanation":"CDL धारकों को अपनी ड्राइविंग श्रेणी (जैसे, Non-Excepted Interstate) का स्व-प्रमाणन करना होगा और, यदि गैर-छूट प्राप्त है, तो NY DMV के पास एक वर्तमान USDOT Medical Examiner's Certificate फ़ाइल पर रखना होगा; ऐसा न करने पर CDL का डाउनग्रेड हो सकता है। स्रोत: NY DMV CDL Medical Certification ('Self-Certify Your Driving Type')।"},"40":{"q":"न्यूयॉर्क में अधिकतम कितने रक्त अल्कोहल सांद्रता (BAC) पर कोई व्यक्ति कानूनी रूप से एक वाणिज्यिक मोटर वाहन (CMV) का संचालन कर सकता है?","options":["0.02%","0.04%","0.08%","0.10%"],"explanation":"न्यूयॉर्क संघीय नियम का पालन करता है: 0.04% या अधिक के BAC के साथ CMV का संचालन करना अवैध है। यह गैर-वाणिज्यिक चालकों के लिए 0.08% सीमा का आधा है। स्रोत: NY CDL-10 Manual sec. 1.6.2; 49 CFR 383.51 Table 1।"},"41":{"q":"न्यूयॉर्क के वाणिज्यिक चालकों के लिए निहित सहमति नियम के अंतर्गत, CMV का संचालन करने का अर्थ है कि आपने स्वतः किसके लिए अपनी सहमति दे दी है?","options":["आपके कार्गो और लॉगबुक की तलाशी","अल्कोहल और ड्रग परीक्षण","एक दृष्टि और चिकित्सा पुनः-परीक्षा","आपके ड्राइविंग रिकॉर्ड का ऑडिट"],"explanation":"NY CDL manual कहता है कि यदि आप एक CMV का संचालन करते हैं, तो माना जाएगा कि आपने अल्कोहल परीक्षण के लिए अपनी सहमति दे दी है। स्रोत: NY CDL-10 Manual sec. 1.6.2; NY VTL 1194 (निहित सहमति)।"},"42":{"q":"यदि न्यूयॉर्क में एक CMV चालक .04% सीमा से कम अल्कोहल की पता लगाने योग्य मात्रा के साथ पाया जाता है, तो क्या होता है?","options":["कुछ नहीं, क्योंकि चालक कानूनी सीमा से नीचे है","चालक को 24 घंटे के लिए आउट-ऑफ़-सर्विस कर दिया जाता है","चालक को 60 दिन के लिए अयोग्य घोषित कर दिया जाता है","चालक को केवल एक लिखित चेतावनी मिलती है"],"explanation":".04% से कम किसी भी पता लगाने योग्य मात्रा में अल्कोहल वाले CMV चालक को 24 घंटे के लिए आउट-ऑफ़-सर्विस कर दिया जाता है, भले ही यह अयोग्यता सीमा से नीचे हो। स्रोत: NY CDL-10 Manual sec. 1.6.2।"},"43":{"q":"पहले बड़े अपराध (जैसे .04% या अधिक के BAC के साथ CMV चलाना) के लिए, एक न्यूयॉर्क CDL धारक कितने समय के लिए अयोग्य होगा?","options":["60 दिन","120 दिन","कम से कम एक वर्ष","तीन वर्ष"],"explanation":"पहले बड़े अपराध के परिणामस्वरूप कम से कम एक वर्ष की अयोग्यता होती है। स्रोत: NY CDL-10 Manual sec. 1.6.2; 49 CFR 383.51 Table 1।"},"44":{"q":"एक न्यूयॉर्क CDL धारक खतरनाक सामग्री के लिए प्लेकार्डेड CMV का संचालन करते हुए पहला बड़ा अपराध करता है। अयोग्यता कितने समय की होती है?","options":["एक वर्ष","तीन वर्ष","पाँच वर्ष","आजीवन"],"explanation":"खतरनाक सामग्री के लिए प्लेकार्डेड CMV का संचालन करते हुए किया गया पहला बड़ा अपराध मानक एक वर्ष के बजाय तीन-वर्ष की अयोग्यता का परिणाम होता है। स्रोत: NY CDL-10 Manual sec. 1.6.2; 49 CFR 383.51 Table 1।"},"45":{"q":"दूसरे बड़े अपराध के लिए दोषी पाए गए एक न्यूयॉर्क CDL धारक के लिए अयोग्यता अवधि क्या है?","options":["एक वर्ष","तीन वर्ष","दस वर्ष","आजीवन"],"explanation":"सूचीबद्ध बड़े अपराधों में से किसी के लिए दूसरी दोषसिद्धि के परिणामस्वरूप CLP और/या CDL की आजीवन अयोग्यता होती है। स्रोत: NY CDL-10 Manual sec. 1.6.2; 49 CFR 383.51 Table 1।"},"46":{"q":"न्यूयॉर्क में, CMV का संचालन करते समय रक्त अल्कोहल परीक्षण से इनकार करना CDL अयोग्यता उद्देश्यों के लिए कैसे माना जाता है?","options":["बिना किसी अयोग्यता के एक मामूली कागज़ी उल्लंघन के रूप में","केवल एक गंभीर यातायात उल्लंघन के रूप में","एक बड़े अपराध के रूप में, DUI दोषसिद्धि के समान","एक आउट-ऑफ़-सर्विस आदेश उल्लंघन के रूप में"],"explanation":"रक्त अल्कोहल परीक्षण से इनकार करना एक बड़ा अपराध है और इसमें DUI दोषसिद्धि के समान न्यूनतम एक-वर्ष की पहली-अपराध अयोग्यता होती है। स्रोत: NY CDL-10 Manual sec. 1.6.2; 49 CFR 383.51 Table 1।"},"47":{"q":"निम्नलिखित में से कौन-सा एक बड़ा अपराध है जो एक न्यूयॉर्क CDL धारक को अयोग्य घोषित कर सकता है, भले ही यह CMV के बजाय चालक की अपनी निजी कार में किया गया हो?","options":["किसी अन्य वाहन का बहुत निकट से अनुसरण करना","अल्कोहल के प्रभाव में गाड़ी चलाना","अनुचित लेन परिवर्तन करना","सीमा से 15 mph अधिक गति से चलना"],"explanation":"किसी भी वाहन को अल्कोहल या नियंत्रित पदार्थ के प्रभाव में चलाना एक बड़ा अपराध है जो एक CDL धारक को अयोग्य घोषित करता है; यह CMV में होना आवश्यक नहीं है। अन्य विकल्प गंभीर यातायात उल्लंघन हैं। स्रोत: NY CDL-10 Manual sec. 1.6.2 और 1.6.3।"},"48":{"q":"एक न्यूयॉर्क CDL धारक नियंत्रित पदार्थों से जुड़े एक अपराध (फ़ेलनी) को करने के लिए एक वाणिज्यिक मोटर वाहन का उपयोग करता है। इसका परिणाम क्या होता है?","options":["एक 120-दिन की अयोग्यता","एक तीन-वर्ष की अयोग्यता","बिना 10-वर्षीय पुनर्बहाली के एक आजीवन अयोग्यता","एक एक-वर्ष की अयोग्यता"],"explanation":"नियंत्रित पदार्थों से जुड़े एक अपराध (फ़ेलनी) को करने के लिए CMV का उपयोग करने के परिणामस्वरूप एक आजीवन अयोग्यता होती है, और चालक कुछ अन्य आजीवन मामलों के लिए उपलब्ध 10-वर्षीय पुनर्बहाली के लिए पात्र नहीं होता। स्रोत: NY CDL-10 Manual sec. 1.6.2; 49 CFR 383.51 Table 1।"},"49":{"q":"निम्नलिखित में से कौन-सा एक बड़ा अपराध है जो न्यूयॉर्क में CDL अयोग्यता का कारण बनता है?","options":["रिपोर्ट किए बिना दुर्घटना स्थल से चले जाना","गति सीमा से 12 mph अधिक गाड़ी चलाना","टर्न सिग्नल का उपयोग करने में विफल रहना","नो-स्टैंडिंग ज़ोन में पार्क करना"],"explanation":"रिपोर्ट किए बिना दुर्घटना स्थल से चले जाना एक सूचीबद्ध बड़ा अपराध है जिसमें पहले अपराध के लिए कम से कम एक-वर्ष की अयोग्यता होती है। स्रोत: NY CDL-10 Manual sec. 1.6.2; 49 CFR 383.51 Table 1।"},"50":{"q":"न्यूयॉर्क CDL नियमों के तहत निम्नलिखित में से किसे SERIOUS (गंभीर) यातायात उल्लंघन के रूप में वर्गीकृत किया गया है?","options":["0.04% या उससे अधिक BAC के साथ गाड़ी चलाना","निर्धारित सीमा से 15 mph या उससे अधिक की अत्यधिक तेज़ रफ़्तार","रासायनिक परीक्षण (chemical test) से इनकार करना","दुर्घटना स्थल से चले जाना"],"explanation":"अत्यधिक तेज़ रफ़्तार (निर्धारित सीमा से 15 mph या उससे अधिक) एक गंभीर यातायात उल्लंघन है। अन्य विकल्प प्रमुख अपराध (major offenses) हैं, जिन पर कहीं अधिक कठोर दंड लगते हैं। स्रोत: NY CDL-10 Manual sec. 1.6.3; 49 CFR 383.51 Table 2।"},"51":{"q":"तीन-वर्ष की अवधि के भीतर किसी CMV में दो गंभीर यातायात उल्लंघन करने पर न्यूयॉर्क CDL धारक को कितने समय के लिए अयोग्य (disqualified) किया जाता है?","options":["कम से कम 30 दिन","कम से कम 60 दिन","कम से कम 120 दिन","कम से कम एक वर्ष"],"explanation":"तीन-वर्ष की अवधि के भीतर (किसी CMV में) दो गंभीर यातायात उल्लंघनों के परिणामस्वरूप कम से कम 60 दिन की अयोग्यता होती है। स्रोत: NY CDL-10 Manual sec. 1.6.3; 49 CFR 383.51 Table 2।"},"52":{"q":"तीन-वर्ष की अवधि के भीतर किसी CMV में तीन गंभीर यातायात उल्लंघन करने पर न्यूयॉर्क CDL धारक को कितने समय के लिए अयोग्य किया जाता है?","options":["कम से कम 60 दिन","कम से कम 90 दिन","कम से कम 120 दिन","कम से कम एक वर्ष"],"explanation":"तीन-वर्ष की अवधि के भीतर (किसी CMV में) तीन गंभीर यातायात उल्लंघनों के परिणामस्वरूप कम से कम 120 दिन की अयोग्यता होती है। स्रोत: NY CDL-10 Manual sec. 1.6.3; 49 CFR 383.51 Table 2।"},"53":{"q":"न्यूयॉर्क में किसी CMV का संचालन करते समय हैंडहेल्ड सेल फ़ोन या टेक्स्टिंग उपकरण का उपयोग करना किस रूप में वर्गीकृत है?","options":["एक प्रमुख अपराध (major offense)","एक गंभीर यातायात उल्लंघन","एक आउट-ऑफ़-सर्विस ऑर्डर उल्लंघन","एक रेलरोड-क्रॉसिंग उल्लंघन"],"explanation":"किसी CMV का संचालन करते समय हैंडहेल्ड सेल फ़ोन और/या टेक्स्टिंग उपकरण का उपयोग करना एक गंभीर यातायात उल्लंघन के रूप में सूचीबद्ध है। न्यूयॉर्क VTL 1225-c और 1225-d के तहत सभी ड्राइवरों के लिए हैंडहेल्ड उपकरण के उपयोग पर भी प्रतिबंध लगाता है। स्रोत: NY CDL-10 Manual sec. 1.6.3।"},"54":{"q":"न्यूयॉर्क CDL धारक के लिए निम्नलिखित में से कौन सा प्रमुख अपराध के बजाय एक गंभीर यातायात उल्लंघन है?","options":["किसी वाहन के बहुत करीब (पीछे) चलना","अपना CDL रद्द (revoked) होने के बावजूद CMV चलाना","किसी अपराध (felony) को अंजाम देने के लिए CMV का उपयोग करना","लापरवाही से CMV संचालन के कारण किसी की मृत्यु होना"],"explanation":"बहुत करीब (पीछे) चलना एक गंभीर यातायात उल्लंघन है। अन्य तीन प्रमुख अपराध हैं जिन पर कम से कम एक वर्ष (या आजीवन) की अयोग्यता लगती है। स्रोत: NY CDL-10 Manual sec. 1.6.2 and 1.6.3; 49 CFR 383.51।"},"55":{"q":"न्यूयॉर्क CDL मैनुअल के अनुसार, आउट-ऑफ़-सर्विस ऑर्डर के उल्लंघन की पहली दोषसिद्धि (first conviction) पर CDL धारक को कितने समय के लिए अयोग्य किया जाता है?","options":["कम से कम 90 दिन","कम से कम 30 दिन","कम से कम एक वर्ष","कम से कम तीन वर्ष"],"explanation":"NY CDL-10 मैनुअल पहले आउट-ऑफ़-सर्विस ऑर्डर उल्लंघन के लिए न्यूनतम 90-दिन की अयोग्यता सूचीबद्ध करता है। स्रोत: NY CDL-10 Manual sec. 1.6.4। (नोट: 49 CFR 383.51 की संघीय तालिका गैर-HazMat पहले अपराधों के लिए 180-दिन का न्यूनतम निर्धारित करती है।)"},"56":{"q":"न्यूयॉर्क CDL मैनुअल के अनुसार, दस-वर्ष की अवधि के भीतर दो आउट-ऑफ़-सर्विस ऑर्डर उल्लंघन करने पर अयोग्यता क्या है?","options":["कम से कम 60 दिन","कम से कम 120 दिन","कम से कम एक वर्ष","कम से कम तीन वर्ष"],"explanation":"दस-वर्ष की अवधि के भीतर दो आउट-ऑफ़-सर्विस ऑर्डर उल्लंघनों के परिणामस्वरूप कम से कम एक वर्ष की अयोग्यता होती है। स्रोत: NY CDL-10 Manual sec. 1.6.4।"},"57":{"q":"न्यूयॉर्क CDL मैनुअल के अनुसार, दस-वर्ष की अवधि के भीतर तीन या अधिक आउट-ऑफ़-सर्विस ऑर्डर उल्लंघन करने पर अयोग्यता क्या है?","options":["कम से कम एक वर्ष","कम से कम दो वर्ष","कम से कम तीन वर्ष","कम से कम पाँच वर्ष"],"explanation":"दस-वर्ष की अवधि के भीतर तीन या अधिक आउट-ऑफ़-सर्विस ऑर्डर उल्लंघनों के परिणामस्वरूप कम से कम तीन वर्ष की अयोग्यता होती है। स्रोत: NY CDL-10 Manual sec. 1.6.4।"},"58":{"q":"किसी CMV का संचालन करते समय किए गए न्यूयॉर्क CDL धारक के पहले रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन के लिए अयोग्यता अवधि क्या है?","options":["कम से कम 30 दिन","कम से कम 60 दिन","कम से कम 120 दिन","कम से कम एक वर्ष"],"explanation":"पहले रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन के परिणामस्वरूप कम से कम 60 दिन की अयोग्यता होती है। स्रोत: NY CDL-10 Manual sec. 1.6.5; 49 CFR 383.51 Table 3।"},"59":{"q":"एक न्यूयॉर्क CDL धारक तीन-वर्ष की अवधि के भीतर तीसरा रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन करता है। अयोग्यता क्या है?","options":["कम से कम 120 दिन","कम से कम 180 दिन","कम से कम एक वर्ष","कम से कम तीन वर्ष"],"explanation":"रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघनों पर पहले के लिए कम से कम 60 दिन, तीन वर्ष के भीतर दूसरे के लिए 120 दिन, और तीन-वर्ष की अवधि के भीतर तीसरे के लिए कम से कम एक वर्ष लगता है। स्रोत: NY CDL-10 Manual sec. 1.6.5; 49 CFR 383.51 Table 3।"},"60":{"q":"आप न्यूयॉर्क सिटी में एक ट्रैक्टर-ट्रेलर चला रहे हैं और 'NO COMMERCIAL VEHICLES' लिखा एक चिह्न देखते हैं। यह चिह्न आगे की सड़क के बारे में क्या इंगित करता है?","options":["यह केवल ऑटोमोबाइल के लिए डिज़ाइन किया गया एक न्यूयॉर्क स्टेट पार्कवे है, जहाँ वाणिज्यिक वाहन निषिद्ध हैं","यह एक निर्दिष्ट थ्रू ट्रक रूट है जो केवल रात में खुला रहता है","यह बसों के लिए आरक्षित एक टोल-मुक्त एक्सप्रेस लेन है","यह एक स्थानीय डिलीवरी सड़क है जहाँ ट्रक केवल लोडिंग के दौरान चल सकते हैं"],"explanation":"न्यूयॉर्क की पार्कवे प्रणाली 20वीं सदी की शुरुआत में केवल ऑटोमोबाइल के लिए बनाई गई थी, और इन पार्कवे पर ट्रैक्टर-ट्रेलर और बसों सहित किसी भी वाणिज्यिक वाहन की अनुमति नहीं है। 'NO COMMERCIAL VEHICLES' चिह्न केवल-ऑटोमोबाइल वाली सड़क को नामित करता है। स्रोत: NYS DOT Parkway Truck Brochure; NY VTL।"},"61":{"q":"एक नया वाणिज्यिक ड्राइवर पूछता है कि न्यूयॉर्क के डाउनस्टेट पार्कवे पर बने नीचे पत्थर के पुल ट्रकों के लिए इतने खतरनाक क्यों हैं। NY नियमों के आधार पर सबसे अच्छा उत्तर क्या है?","options":["पुलों पर वज़न सीमाएँ हैं लेकिन कोई ऊँचाई सीमा नहीं लगाई गई है","कुछ निर्धारित ऊर्ध्वाधर क्लीयरेंस 6 फ़ुट 11 इंच जितनी कम हैं, और अधिक-ऊँचाई वाले ट्रक उनसे टकराते हैं और नीचे फँस जाते हैं","ये पुल भीड़भाड़ के समय केवल बसों के लिए विशेष रूप से आरक्षित हैं","ट्रकों की अनुमति है लेकिन उन्हें प्रत्येक पुल से पहले हॉर्न बजाना होगा"],"explanation":"NYS DOT चेतावनी देता है कि पार्कवे प्रणाली पर नीचे पत्थर के पुलों की निर्धारित ऊर्ध्वाधर क्लीयरेंस 6 फ़ुट 11 इंच जितनी कम है। वाणिज्यिक वाहन, जो पार्कवे से प्रतिबंधित हैं, अक्सर इन नीचे पुलों से टकराते हैं और नीचे फँस जाते हैं, जिससे गंभीर दुर्घटनाएँ और लंबी देरी होती है। स्रोत: NYS DOT Parkway Truck Brochure।"},"62":{"q":"निम्नलिखित में से कौन सी डाउनस्टेट न्यूयॉर्क सड़क है जहाँ ट्रैक्टर-ट्रेलर सहित किसी भी वाणिज्यिक वाहन की अनुमति नहीं है?","options":["द लॉन्ग आइलैंड एक्सप्रेसवे (I-495)","द न्यूयॉर्क स्टेट थ्रूवे (I-87)","द ब्रुकलिन-क्वींस एक्सप्रेसवे (I-278)","ब्रुकलिन और क्वींस में बेल्ट पार्कवे"],"explanation":"बेल्ट पार्कवे उन डाउनस्टेट पार्कवे में से एक है (हेनरी हडसन, क्रॉस आइलैंड, हचिंसन रिवर, ग्रैंड सेंट्रल, नॉर्दर्न स्टेट और अन्य के साथ) जहाँ वाणिज्यिक वाहन प्रतिबंधित हैं। एक्सप्रेसवे और थ्रूवे इंटरस्टेट मार्ग हैं जो ट्रकों के लिए खुले हैं। स्रोत: NYS DOT Parkway Truck Brochure; NYC DOT Parkway Restrictions।"},"63":{"q":"एक वाणिज्यिक ड्राइवर अवैध रूप से न्यूयॉर्क पार्कवे में प्रवेश करता है और एक ट्रैक्टर-ट्रेलर नीचे पुल के नीचे फँस जाता है। जुर्माने और अंकों के अलावा, NY विशेष रूप से किस अतिरिक्त परिणाम के बारे में चेतावनी देता है?","options":["क्षति की परवाह किए बिना अनिवार्य 30-दिन का वाहन जब्ती","पहले अपराध पर एक वर्ष के लिए CDL का स्वचालित नुकसान","ट्रैक्टर-ट्रेलर के लिए टोइंग शुल्क जो $10,000 से अधिक हो सकता है, साथ ही पुल मरम्मत के लिए राज्य को प्रतिपूर्ति","सभी 50 राज्यों में संचालन से एक संघीय प्रतिबंध"],"explanation":"NYS DOT पार्कवे पर वाणिज्यिक वाहन चलाने के परिणामों को सूचीबद्ध करता है: जुर्माना और/या अंक, संभावित चोट, वाहन और पुल/गाइडरेल क्षति, ट्रैक्टर-ट्रेलर के लिए $10,000 से अधिक टोइंग शुल्क, और पुल मरम्मत के लिए राज्य को प्रतिपूर्ति। स्रोत: NYS DOT Parkway Truck Brochure।"},"64":{"q":"न्यूयॉर्क सिटी में, ट्रक रूट नेटवर्क को दो वर्गों में विभाजित किया गया है। वे क्या हैं?","options":["दिन के समय के ट्रक रूट और रात के समय के ट्रक रूट","लोकल ट्रक रूट और थ्रू ट्रक रूट","एक्सप्रेस ट्रक रूट और टोल ट्रक रूट","बरो ट्रक रूट और ब्रिज ट्रक रूट"],"explanation":"NYC का ट्रक रूट नेटवर्क (लगभग 1,000 मील, NYC Traffic Rules के Section 4-13 में परिभाषित) में लोकल ट्रक रूट शामिल हैं, जो किसी बरो के भीतर स्थानीय पिकअप या डिलीवरी करने वाले ट्रकों के लिए हैं, और थ्रू ट्रक रूट, जो उन ट्रकों के लिए हैं जो क्षेत्र में किसी मूल या गंतव्य के बिना गुज़रते हैं। स्रोत: NYC DOT Truck Routing; NYC Traffic Rules 4-13।"},"65":{"q":"एक ट्रक को किसी डिलीवरी पते तक पहुँचने के लिए एक निर्दिष्ट NYC ट्रक रूट छोड़ना होगा। NYC ट्रक रूट नियमों के तहत, ड्राइवर को कैसे आगे बढ़ना चाहिए?","options":["डिलीवरी पूरी होने तक किसी भी सड़क का, किसी भी दिशा में उपयोग करें","गंतव्य के निकटतम चौराहे पर ट्रक रूट छोड़ें, सबसे सीधा मार्ग लें, और उसी तरह निकटतम ट्रक रूट पर लौटें","भीड़भाड़ से बचने के लिए केवल आवासीय सड़कों पर यात्रा करें","प्रत्येक डिलीवरी के लिए एक अलग लिखित ऑफ़-रूट परमिट प्राप्त करें"],"explanation":"NYC नियम किसी ट्रक को किसी मूल या गंतव्य तक पहुँचने के लिए ही निर्दिष्ट रूट छोड़ने की अनुमति देते हैं। ड्राइवर को गंतव्य के निकटतम चौराहे पर छोड़ना होगा, सबसे सीधे मार्ग से आगे बढ़ना होगा, फिर सबसे सीधे मार्ग से निकटतम निर्दिष्ट ट्रक रूट पर लौटना होगा। स्रोत: NYC DOT Truck Routing; NYC Traffic Rules 4-13।"},"66":{"q":"न्यूयॉर्क और NY द्वारा अपनाए गए संघीय नियमों के तहत किन वाहनों को प्रत्येक रेलरोड-हाईवे ग्रेड क्रॉसिंग पर रुकना आवश्यक है?","options":["26,000 पाउंड से अधिक के सभी वाणिज्यिक वाहन","केवल ट्रेलर खींचने वाले वाहन","यात्रियों को ले जाने वाली बसें और प्लेकार्ड वाली खतरनाक सामग्री ले जाने वाले वाहन","केवल पहले ज्वलनशील पदार्थों के लिए उपयोग किए गए खाली टैंक वाहन"],"explanation":"न्यूयॉर्क में, यात्रियों को ले जाने वाली बसों और खतरनाक-सामग्री प्लेकार्ड प्रदर्शित करने वाले वाणिज्यिक वाहनों को सभी रेलरोड क्रॉसिंग पर रुकना होगा। वे 50 फ़ुट के भीतर लेकिन 15 फ़ुट से अधिक करीब नहीं रुकते हैं, देखते और सुनते हैं, और क्रॉसिंग के दौरान गियर नहीं बदलना चाहिए। स्रोत: NY CDL Manual CDL-10; 49 CFR 392.10।"},"67":{"q":"प्लेकार्ड वाली खतरनाक-सामग्री ट्रक के एक न्यूयॉर्क ड्राइवर को रेलरोड क्रॉसिंग पर रुकना होगा। निकटतम रेल से कितनी दूरी के भीतर वाहन को रुकना होगा?","options":["50 फ़ुट के भीतर लेकिन 15 फ़ुट से अधिक करीब नहीं","100 फ़ुट के भीतर लेकिन 25 फ़ुट से अधिक करीब नहीं","निकटतम रेल से ठीक 5 फ़ुट","30 फ़ुट के भीतर लेकिन 10 फ़ुट से अधिक करीब नहीं"],"explanation":"रेलरोड क्रॉसिंग पर रुकने के लिए आवश्यक वाहनों (प्लेकार्ड वाले hazmat और यात्रियों वाली बसें) को निकटतम रेल से 50 फ़ुट के भीतर लेकिन 15 फ़ुट से अधिक करीब नहीं रुकना होगा, फिर गियर बदले बिना आगे बढ़ने से पहले ट्रेनों के लिए देखना और सुनना होगा। स्रोत: NY CDL Manual CDL-10; 49 CFR 392.10।"},"68":{"q":"न्यूयॉर्क के मूव ओवर लॉ (VTL 1144-a) के तहत, जब कोई वाणिज्यिक ड्राइवर सड़क के किनारे अपनी चेतावनी लाइटों के साथ रुकी हुई किसी आपातकालीन या हज़ार्ड वाहन के पास पहुँचता है तो उसे क्या करना चाहिए?","options":["आपातकालीन वाहन के जाने तक पूरी तरह रुकें","गति धीमी करें और, जब संभव हो, रुके हुए वाहन से एक पूरी लेन दूर हट जाएँ","हॉर्न बजाएँ और निर्धारित गति बनाए रखें","कंधे (shoulder) पर जाएँ और दाईं ओर से गुज़रें"],"explanation":"न्यूयॉर्क का मूव ओवर लॉ ड्राइवरों से अपेक्षा करता है कि वे उचित सावधानी बरतें, गति धीमी करें, और जब ऐसा करना सुरक्षित हो तब चमकती लाइटें प्रदर्शित करने वाले रुके हुए आपातकालीन या हज़ार्ड वाहन से एक पूरी लेन दूर हट जाएँ। 2023 तक इस कानून को सभी रुके हुए वाहनों को कवर करने के लिए विस्तारित किया गया। स्रोत: NY VTL 1144-a; NYS Governor's Traffic Safety Committee।"},"69":{"q":"न्यूयॉर्क का मूव ओवर लॉ आपातकालीन वाहनों के साथ-साथ हज़ार्ड वाहनों पर भी लागू होता है। इनमें से कौन सा कानून द्वारा कवर किया गया 'हज़ार्ड वाहन' है?","options":["कर्ब पर कानूनी रूप से पार्क की गई एक यात्री कार","चमकती एम्बर लाइटें प्रदर्शित करने वाला एक टो ट्रक या रखरखाव वाहन","सवारी लेने के लिए रुकी हुई एक टैक्सी","ड्राइववे में अपने चार-तरफ़ा फ़्लैशर के साथ एक डिलीवरी वैन"],"explanation":"न्यूयॉर्क का मूव ओवर लॉ पुलिस, फ़ायर और एम्बुलेंस वाहनों के अलावा टो ट्रक, निर्माण और रखरखाव वाहन, और स्वच्छता वाहन जैसे हज़ार्ड वाहनों को कवर करता है जो चमकती एम्बर लाइटें प्रदर्शित करते हैं। स्रोत: NY VTL 1144-a; NYS Thruway Move Over materials।"},"70":{"q":"न्यूयॉर्क कानून के तहत, एक वाणिज्यिक ड्राइवर किसी CMV का संचालन करते समय हैंड-हेल्ड सेल फ़ोन या टेक्स्टिंग उपकरण का उपयोग कब कर सकता है?","options":["केवल लाल बत्ती या स्टॉप साइन पर रुके होने पर","केवल 30 सेकंड से कम की कॉल के लिए","केवल नेविगेशन के लिए उपकरण का उपयोग करते समय","CMV का संचालन करते समय कभी नहीं; हैंड-हेल्ड उपयोग और टेक्स्टिंग निषिद्ध हैं"],"explanation":"न्यूयॉर्क वाणिज्यिक ड्राइवरों को किसी CMV का संचालन करते समय हैंड-हेल्ड मोबाइल फ़ोन या टेक्स्टिंग उपकरण का उपयोग करने से प्रतिबंधित करता है। कुछ गैर-वाणिज्यिक स्थितियों के विपरीत, एक वाणिज्यिक ड्राइवर बत्ती पर रुके होने पर भी हैंड-हेल्ड उपकरण का उपयोग नहीं कर सकता। दोषसिद्धि अंक जोड़ती है और यह एक गंभीर CDL अपराध है। स्रोत: NY VTL 1225-c and 1225-d; NY CDL Manual CDL-10।"},"71":{"q":"न्यूयॉर्क में एक वाणिज्यिक ड्राइवर को तीन वर्षों के भीतर दूसरी बार हैंड-हेल्ड फ़ोन का उपयोग करते हुए या टेक्स्टिंग करते हुए CMV का संचालन करने के लिए दोषी ठहराया जाता है। NY दंडों के ऊपर कौन सा संघीय परिणाम लागू होता है?","options":["एक स्थायी आजीवन CDL रद्दीकरण","तीन वर्षों के भीतर दूसरी दोषसिद्धि के लिए 60-दिन की CDL अयोग्यता","केवल FMCSA से एक लिखित चेतावनी","बिना किसी अयोग्यता के $50 का प्रशासनिक शुल्क"],"explanation":"न्यूयॉर्क में लागू संघीय FMCSA नियम, राज्य के जुर्माने और अंकों के अलावा, तीन वर्षों के भीतर दूसरी हैंड-हेल्ड फ़ोन/टेक्स्टिंग दोषसिद्धि के लिए CDL धारक को 60 दिनों के लिए अयोग्य करते हैं, और तीन वर्षों के भीतर तीसरी या बाद की दोषसिद्धि के लिए 120 दिनों के लिए। स्रोत: FMCSA 49 CFR 383.51; NY DMV।"},"72":{"q":"न्यूयॉर्क में चमकती लाल लाइटों वाली स्कूल बस के लिए रुकने के बाद, एक ड्राइवर कब आगे बढ़ सकता है?","options":["पाँच तक गिनती करने के तुरंत बाद","जैसे ही कोई बच्चा दिखाई न दे, भले ही लाइटें अभी भी चमक रही हों","जब बस फिर से चलना शुरू कर दे, या बस ड्राइवर या कोई ट्रैफ़िक अधिकारी संकेत दे कि आगे बढ़ना सुरक्षित है","बस अपना दरवाज़ा बंद करने के बाद, लाइटों की परवाह किए बिना"],"explanation":"न्यूयॉर्क में जो ड्राइवर किसी स्कूल बस के लिए रुका है, वह तब तक फिर से नहीं चल सकता जब तक बस चलना शुरू न करे, या बस ड्राइवर या कोई पुलिस/ट्रैफ़िक अधिकारी आगे बढ़ने का संकेत न दे। लाल फ़्लैशर रुकाव को नियंत्रित करते हैं। स्रोत: NY VTL 1174; NY DMV Driver's Manual Chapter 6।"},"73":{"q":"यदि किसी वाणिज्यिक वाहन को न्यूयॉर्क में किसी एक-तरफ़ा या विभाजित राजमार्ग के कंधे पर रुकना पड़े, तो तीन चेतावनी त्रिकोण (परावर्तक उपकरण) कहाँ रखे जाने चाहिए?","options":["सभी तीन वाहन के पीछे 10 फ़ुट के भीतर","आने वाले यातायात की ओर लगभग 10 फ़ुट, 100 फ़ुट और 200 फ़ुट पर","एक सामने और दो सीधे ट्रेलर के नीचे","केवल ड्राइवर की ओर 25 फ़ुट, 50 फ़ुट और 75 फ़ुट पर"],"explanation":"किसी एक-तरफ़ा या विभाजित राजमार्ग पर, चेतावनी उपकरणों को वाहन से आने वाले यातायात की ओर लगभग 10 फ़ुट, 100 फ़ुट और 200 फ़ुट पर रखें, उस लेन या कंधे के केंद्र में जिसे CMV घेरता है। उपकरणों को 10 मिनट के भीतर रखा जाना चाहिए। स्रोत: NY CDL Manual CDL-10; 49 CFR 392.22।"},"74":{"q":"एक वाणिज्यिक वाहन न्यूयॉर्क में किसी दो-लेन, दो-तरफ़ा सड़क पर रुका है। ड्राइवर को तीन आपातकालीन चेतावनी त्रिकोण कैसे रखने चाहिए?","options":["एक 10 फ़ुट बगल में, एक 100 फ़ुट पीछे, और एक वाहन के 100 फ़ुट सामने","सभी तीन वाहन के 200 फ़ुट पीछे","एक छत पर और दो आगे के बंपर पर","एक 10 फ़ुट पीछे, एक 50 फ़ुट पीछे, और एक 50 फ़ुट सामने"],"explanation":"दो-तरफ़ा सड़क पर, एक त्रिकोण को यातायात की ओर पिछले हिस्से के 10 फ़ुट के भीतर, एक लगभग 100 फ़ुट पीछे, और एक वाहन के लगभग 100 फ़ुट आगे रखें, ताकि दोनों दिशाओं से यातायात को चेतावनी मिले। स्रोत: NY CDL Manual CDL-10; 49 CFR 392.22।"},"75":{"q":"न्यूयॉर्क में, किसी विशेष ओवरसाइज़ परमिट के बिना एक ट्रक और उसके भार की अधिकतम ऊँचाई क्या हो सकती है?","options":["11 फ़ुट","15 फ़ुट","16 फ़ुट 6 इंच","13 फ़ुट 6 इंच"],"explanation":"NY Vehicle and Traffic Law Section 385 के तहत, किसी वाहन और भार की अधिकतम कानूनी ऊँचाई 13 फ़ुट 6 इंच है; 14 फ़ुट या उससे अधिक की ऊँचाई के लिए ओवरसाइज़ परमिट की आवश्यकता होती है। ड्राइवरों को निर्धारित क्लीयरेंस चिह्नों का भी पालन करना चाहिए, जो NY के पुराने पुलों पर आम हैं। स्रोत: NY VTL 385; NY DMV।"},"76":{"q":"एक न्यूयॉर्क पुल पर ट्रक की ऊँचाई से कम एक निर्धारित ओवरहेड क्लीयरेंस प्रदर्शित होती है। वाणिज्यिक ड्राइवर को क्या करना चाहिए?","options":["धीरे-धीरे आगे बढ़ें और नीचे से गुज़रते समय हॉर्न बजाएँ","वाहन को नीचा करने के लिए टायरों से हवा निकालें और जारी रखें","पुल के नीचे से न गुज़रें और इसके बजाय कोई वैकल्पिक कानूनी मार्ग खोजें","यदि केवल भार ही क्लीयरेंस से अधिक है तो आगे बढ़ें"],"explanation":"NY कानून किसी वाहन को किसी भी पुल या संरचना से गुज़ारने पर रोक लगाता है यदि वाहन की ऊँचाई निर्धारित क्लीयरेंस से अधिक है। ड्राइवर को एक वैकल्पिक मार्ग लेना होगा। नीचे-क्लीयरेंस वाले पुलों और पार्कवे पर अधिक-ऊँचाई की टक्करें NY की एक प्रमुख सुरक्षा समस्या हैं। स्रोत: NY VTL 385; NYS DOT bridge-strike guidance।"},"77":{"q":"आधुनिक न्यूयॉर्क स्टेट थ्रूवे पर किसी वाणिज्यिक वाहन से टोल आमतौर पर कैसे एकत्र किया जाता है?","options":["ड्राइवरों को हर इंटरचेंज बूथ पर रुककर नकद भुगतान करना होगा","ओवरहेड गैंट्री द्वारा पढ़े गए E-ZPass टैग या टोल्स-बाय-मेल इनवॉइस का उपयोग करते हुए कैशलेस टोलिंग के माध्यम से","CDL वाले सभी वाहनों के लिए टोल माफ़ किया जाता है","ड्राइवर DMV में एक एकल फ़्लैट वार्षिक शुल्क का अग्रिम भुगतान करते हैं"],"explanation":"न्यूयॉर्क स्टेट थ्रूवे कैशलेस टोलिंग का उपयोग करता है: ओवरहेड गैंट्री E-ZPass टैग पढ़ते हैं या Tolls by Mail इनवॉइस के लिए प्लेट की तस्वीर लेते हैं, इसलिए वाहन अब बूथ पर नहीं रुकते। वाणिज्यिक वाहनों से वाहन वर्ग के अनुसार शुल्क लिया जाता है और NY E-ZPass के साथ छूट अर्जित कर सकते हैं। स्रोत: NYS Thruway Authority - Cashless Tolling।"},"78":{"q":"बर्फ़ और बर्फ़ीली परिस्थितियों जैसी सर्दियों की स्थितियों के दौरान न्यूयॉर्क में संचालन करने वाले वाणिज्यिक ड्राइवर के लिए सबसे अच्छा अभ्यास क्या है?","options":["यातायात को चालू रखने के लिए सामान्य राजमार्ग गति और अनुसरण दूरी बनाए रखें","गति कम करें, अनुसरण दूरी बढ़ाएँ, और जहाँ परिस्थितियाँ या निर्धारित आवश्यकताएँ माँगें वहाँ टायर चेन का उपयोग करें","ब्रेक को गर्म रखने के लिए दृढ़ता और बार-बार लगाएँ","केवल सबसे बाईं लेन में चलें और सभी ट्रैक्शन सिस्टम को बंद कर दें"],"explanation":"न्यूयॉर्क की सर्दियाँ बर्फ़ और बर्फ़ीली स्थितियाँ लाती हैं, विशेष रूप से अपस्टेट और लेक-इफ़ेक्ट क्षेत्रों में। NY CDL Manual ड्राइवरों को निर्देश देता है कि गति कम करें, अनुसरण दूरी बढ़ाएँ, धीरे से ब्रेक लगाएँ, और जब परिस्थितियाँ या निर्धारित चिह्न ट्रैक्शन उपकरणों की आवश्यकता हो तब टायर चेन का उपयोग करें। स्रोत: NY CDL Manual CDL-10, Driving in Adverse Conditions।"},"79":{"q":"न्यूयॉर्क स्टेट में कमर्शियल ड्राइवर लाइसेंस (CDL) कौन सी सरकारी एजेंसी जारी करती है?","options":["द फ़ेडरल मोटर कैरियर सेफ़्टी एडमिनिस्ट्रेशन (FMCSA)","द न्यूयॉर्क स्टेट डिपार्टमेंट ऑफ़ मोटर व्हीकल्स (NY DMV)","द न्यूयॉर्क स्टेट डिपार्टमेंट ऑफ़ ट्रांसपोर्टेशन (NYSDOT)","द यू.एस. डिपार्टमेंट ऑफ़ मोटर व्हीकल्स"],"explanation":"न्यूयॉर्क में, CDL का प्रशासन और जारी करना न्यूयॉर्क स्टेट डिपार्टमेंट ऑफ़ मोटर व्हीकल्स (NY DMV) द्वारा किया जाता है। FMCSA संघीय CDL मानक निर्धारित करता है लेकिन लाइसेंस जारी नहीं करता। स्रोत: NY DMV, Commercial Driver License (CDL)।"},"80":{"q":"न्यूयॉर्क में किसी CDL या कमर्शियल लर्नर परमिट के लिए आवेदन करने से पहले, आपके पास आम तौर पर पहले से क्या होना चाहिए?","options":["एक संघीय इंटरस्टेट ऑपरेटिंग अथॉरिटी नंबर","एक पूर्ण Article 19-A बस ड्राइवर प्रमाणन","24 घंटों के भीतर का एक यू.एस. DOT मेडिकल एग्ज़ामिनर्स सर्टिफ़िकेट","एक वैध न्यूयॉर्क स्टेट ड्राइवर लाइसेंस (Class D, Class E, या Non-CDL C) या किसी अन्य राज्य का एक वैध CDL"],"explanation":"NY DMV को एक पहली बार के CDL आवेदक के पास आवेदन करने से पहले पहले से ही एक न्यूयॉर्क ड्राइवर लाइसेंस (Class D, E, या Non-CDL C) या एक वैध आउट-ऑफ़-स्टेट CDL होना आवश्यक है। स्रोत: NY DMV, Get a Commercial Driver License (CDL)।"},"81":{"q":"न्यूयॉर्क किसी CDL या परमिट के लिए आवेदक की पहचान किस प्रणाली का उपयोग करके सत्यापित करता है?","options":["एक केवल-फ़िंगरप्रिंट संघीय पृष्ठभूमि जाँच","एक 10-अंकीय क्रेडिट-इतिहास सत्यापन प्रणाली","केवल एक नोटरीकृत एकल-दस्तावेज़ शपथपत्र","NY DMV 6-अंकीय पहचान-प्रमाण प्रणाली"],"explanation":"न्यूयॉर्क एक 6-अंकीय पहचान-प्रमाण प्रणाली का उपयोग करता है: आवेदकों को अपनी पहचान साबित करने के लिए कुल कम से कम 6 अंक वाले दस्तावेज़ प्रस्तुत करने होंगे, साथ ही जन्म तिथि और निवास का प्रमाण। स्रोत: NY DMV, Proof of Identity (6-point system)।"},"82":{"q":"न्यूयॉर्क की 6-अंकीय ID प्रणाली के तहत, आपके द्वारा प्रस्तुत दस्तावेज़ों के बारे में नियम क्या है?","options":["केवल फ़ोटोकॉपी स्वीकार की जाती हैं ताकि DMV उन्हें फ़ाइल में रख सके","कोई भी दस्तावेज़ स्वीकार किया जाता है जब तक वह आपकी फ़ोटो दिखाता है","वे मूल या प्रमाणित प्रतियाँ होनी चाहिए; फ़ोटोकॉपी और लैमिनेटेड दस्तावेज़ स्वीकार नहीं किए जाते","लैमिनेटेड दस्तावेज़ पसंद किए जाते हैं क्योंकि वे लंबे समय तक चलते हैं"],"explanation":"NY DMV को आवश्यक है कि 6-अंकीय दस्तावेज़ मूल या प्रमाणित प्रतियाँ हों। DMV सादी फ़ोटोकॉपी या लैमिनेटेड दस्तावेज़ स्वीकार नहीं करेगा। स्रोत: NY DMV, Proof of Identity।"},"83":{"q":"6 अंक के पहचान दस्तावेज़ों के अलावा, एक न्यूयॉर्क CDL आवेदक को अपने सोशल सिक्योरिटी नंबर के संबंध में और क्या प्रदान करना होगा?","options":["कुछ नहीं; न्यूयॉर्क CDL के लिए सोशल सिक्योरिटी नंबर एकत्र नहीं करता","पिछले तीन वर्षों में से प्रत्येक का एक संघीय कर रिटर्न","एक सोशल सिक्योरिटी नंबर जो केवल CDL प्रदान किए जाने के बाद जारी किया गया हो","अपने सोशल सिक्योरिटी नंबर का प्रमाण, या यदि कभी जारी नहीं किया गया था तो एक हस्ताक्षरित शपथपत्र"],"explanation":"NY DMV को आपके सोशल सिक्योरिटी नंबर का प्रमाण आवश्यक है; यदि आपको कभी एक जारी नहीं किया गया था, तो आपको यह बताते हुए एक शपथपत्र पर हस्ताक्षर करने होंगे। स्रोत: NY DMV, Proof of Identity / How to Apply।"},"84":{"q":"एक न्यूयॉर्क आवेदक आमतौर पर किसी DMV कार्यालय में CDL प्रक्रिया कैसे शुरू करता है?","options":["किसी भी लिखित परीक्षा से पहले रोड टेस्ट निर्धारित करके और पास करके","कैरियर को एक Article 19-A शपथपत्र जमा करके","एक कमर्शियल लर्नर परमिट (CLP) के लिए आवेदन करके और आवश्यक लिखित ज्ञान परीक्षा(ओं) को पास करके","एक नवीनीकरण आवेदन डाक से भेजकर और एक नए लाइसेंस की प्रतीक्षा करके"],"explanation":"प्रक्रिया किसी DMV कार्यालय में शुरू होती है: आवेदक एक कमर्शियल लर्नर परमिट (CLP) के लिए आवेदन करता है और वांछित वर्ग और एंडोर्समेंट के लिए लिखित ज्ञान परीक्षा(एँ) पास करता है। स्रोत: NY DMV, Get a Commercial Driver License (CDL)।"},"85":{"q":"एक न्यूयॉर्क आवेदक Class A CLP प्राप्त करने के लिए आमतौर पर कौन सा लिखित ज्ञान परीक्षाओं का सेट देता है?","options":["केवल एक एकल संयुक्त वाणिज्यिक ड्राइविंग परीक्षा","केवल हैज़र्डस मटीरियल और पैसेंजर एंडोर्समेंट परीक्षाएँ","एक Article 19-A मौखिक परीक्षा और एक डिफ़ेंसिव ड्राइविंग परीक्षा","जनरल नॉलेज, एयर ब्रेक्स, और कॉम्बिनेशन व्हीकल्स"],"explanation":"Class A CLP के लिए, न्यूयॉर्क आवेदक आमतौर पर जनरल नॉलेज, एयर ब्रेक्स, और कॉम्बिनेशन व्हीकल्स ज्ञान परीक्षाएँ पास करते हैं। एंडोर्समेंट परीक्षाएँ (Hazmat, Passenger, School Bus, आदि) अलग से ली जाती हैं। स्रोत: NY DMV, CDL knowledge tests।"},"86":{"q":"न्यूयॉर्क द्वारा अपनी वैधता अवधि बढ़ाने के बाद एक न्यूयॉर्क कमर्शियल लर्नर परमिट (CLP) कितने समय के लिए वैध है?","options":["30 दिन","छह महीने","आठ वर्ष","एक वर्ष (365 दिन)"],"explanation":"न्यूयॉर्क ने CLP वैधता को छह महीने से बढ़ाकर एक वर्ष (365 दिन) कर दिया। ज्ञान परीक्षा स्कोर उसी अवधि के लिए वैध होते हैं। स्रोत: NY DMV, DMV Extends Validity of Commercial Learner Permit।"},"87":{"q":"CDL रोड (स्किल्स) टेस्ट देने से पहले एक न्यूयॉर्क आवेदक को CLP कम से कम कितने समय तक रखना आवश्यक है?","options":["कम से कम 90 दिन","कोई आवश्यक प्रतीक्षा अवधि नहीं है","कम से कम 14 दिन","कम से कम 6 महीने"],"explanation":"संघीय नियम का पालन करते हुए, आप अपने CLP जारी होने के 14 दिनों के भीतर की तारीख के लिए न्यूयॉर्क CDL रोड टेस्ट निर्धारित नहीं कर सकते। स्रोत: NY DMV, Get a Commercial Driver License (CDL) / FMCSA।"},"88":{"q":"पहले CDL के लिए (या किसी Hazmat, Passenger, या School Bus एंडोर्समेंट को जोड़ने के लिए) न्यूयॉर्क में CDL रोड टेस्ट देने से पहले, कौन सा प्रशिक्षण पहले पूरा किया जाना चाहिए?","options":["FMCSA Training Provider Registry पर सूचीबद्ध किसी प्रदाता से Entry-Level Driver Training (ELDT)","एक केवल-न्यूयॉर्क डिफ़ेंसिव ड्राइविंग अंक-कमी पाठ्यक्रम","एक Article 19-A द्विवार्षिक बिहाइंड-द-व्हील मूल्यांकन","एक 19A मोटर कैरियर शपथपत्र पाठ्यक्रम"],"explanation":"संघीय ELDT नियम (7 फ़रवरी, 2022 से प्रभावी) नए CDL आवेदकों और कुछ एंडोर्समेंट आवेदकों को स्किल्स टेस्ट से पहले FMCSA Training Provider Registry पर किसी प्रदाता से प्रशिक्षण पूरा करना आवश्यक करते हैं। स्रोत: NY DMV / FMCSA ELDT।"},"89":{"q":"न्यूयॉर्क में, पूर्ण किए गए ELDT को एक निर्धारित CDL रोड टेस्ट से कैसे संबंधित होने की आवश्यकता है?","options":["ELDT को रोड टेस्ट के दिन परीक्षण स्थल पर पूरा किया जा सकता है","आपका पूर्ण किया गया ELDT रोड टेस्ट से कम से कम 7 दिन पहले DMV के पास फ़ाइल में होना चाहिए, अन्यथा परीक्षा रद्द कर दी जाती है","ELDT को केवल रोड टेस्ट पास करने के 30 दिनों के भीतर फ़ाइल में होने की आवश्यकता है","न्यूयॉर्क DMV के पास ELDT का फ़ाइल में होना कभी आवश्यक नहीं है"],"explanation":"न्यूयॉर्क आपको ELDT समाप्त करने से पहले रोड टेस्ट निर्धारित करने देता है, लेकिन पूर्ण किया गया ELDT परीक्षा से कम से कम 7 दिन पहले DMV के पास फ़ाइल में होना चाहिए अन्यथा रोड टेस्ट रद्द कर दिया जाता है ($40 शुल्क खोता नहीं है; आप पुनर्निर्धारण करते हैं)। स्रोत: NY DMV, Get a CDL।"},"90":{"q":"न्यूयॉर्क में CDL रोड टेस्ट कैसे निर्धारित किया जाता है?","options":["बिना अपॉइंटमेंट के किसी भी DMV कार्यालय में जाकर और तुरंत परीक्षण देकर","NY DMV Road Test Scheduling System (ऑनलाइन पोर्टल/फ़ोन) के माध्यम से","केवल FMCSA को एक कागज़ी अनुरोध डाक से भेजकर","स्वचालित रूप से, ELDT प्रशिक्षण प्रदाता द्वारा आवेदक की ओर से"],"explanation":"न्यूयॉर्क CDL रोड टेस्ट DMV के Road Test Scheduling System (ऑनलाइन पोर्टल, फ़ोन द्वारा भी उपलब्ध) के माध्यम से निर्धारित किए जाते हैं। स्रोत: NY DMV, Schedule and Take a Road Test।"},"91":{"q":"न्यूयॉर्क CDL स्किल्स/रोड टेस्ट किन तीन घटकों से बना है?","options":["प्री-ट्रिप वाहन निरीक्षण, बेसिक कंट्रोल स्किल्स, और एक ऑन-रोड ड्राइविंग टेस्ट","एक लिखित परीक्षा, एक दृष्टि जाँच, और एक फ़िंगरप्रिंट जाँच","एक Hazmat टेस्ट, एक पैसेंजर टेस्ट, और एक स्कूल बस टेस्ट","एक Article 19-A मौखिक परीक्षा, एक मेडिकल परीक्षा, और एक डिफ़ेंसिव ड्राइविंग परीक्षा"],"explanation":"न्यूयॉर्क में CDL स्किल्स टेस्ट के तीन भाग होते हैं: एक प्री-ट्रिप वाहन निरीक्षण, एक बेसिक कंट्रोल स्किल्स टेस्ट, और एक ऑन-रोड ड्राइविंग टेस्ट। स्रोत: NY DMV / CDL Manual (CDL-10)।"},"92":{"q":"यदि आप न्यूयॉर्क CDL रोड टेस्ट एयर ब्रेक्स के बिना किसी वाहन में देते हैं, तो आपके CDL का क्या होता है?","options":["एक L प्रतिबंध जोड़ा जाता है, जो आपको एयर ब्रेक्स से सुसज्जित वाहनों का संचालन करने से रोकता है","आपका CDL स्वचालित रूप से सभी ब्रेक प्रकारों की अनुमति देने के लिए अपग्रेड हो जाता है","आपको डिफ़ॉल्ट रूप से एक Hazmat एंडोर्समेंट मिलता है","कुछ नहीं बदलता; ब्रेक उपकरण प्रतिबंधों को प्रभावित नहीं करता"],"explanation":"पूर्ण एयर ब्रेक्स के बिना किसी वाहन में परीक्षण देने पर एक 'L' प्रतिबंध (कोई एयर ब्रेक्स नहीं) लगता है। संबंधित प्रतिबंधों में 'E' (ऑटोमैटिक ट्रांसमिशन) और 'Z' (एयर-ओवर-हाइड्रॉलिक ब्रेक्स) शामिल हैं। स्रोत: NY DMV, Get a CDL / CDL Manual।"},"93":{"q":"न्यूयॉर्क CDL स्व-प्रमाणन (self-certification) के लिए एक ड्राइवर को कितनी संघीय ड्राइविंग श्रेणियाँ चुननी होती हैं?","options":["सभी चार संघीय ड्राइविंग श्रेणियाँ एक साथ","चार संघीय ड्राइविंग श्रेणियों में से एक","तीन संघीय ड्राइविंग श्रेणियों में से दो","कोई नहीं; न्यूयॉर्क में स्व-प्रमाणन वैकल्पिक है"],"explanation":"CDL धारकों को चार संघीय ड्राइविंग प्रकारों में से ठीक एक को चुनकर स्व-प्रमाणन करना होता है। स्रोत: NY DMV, Self-Certify Your Driving Type।"},"94":{"q":"वे चार संघीय स्व-प्रमाणन ड्राइविंग श्रेणियाँ कौन सी हैं जिनमें से एक न्यूयॉर्क CDL धारक चुनता है?","options":["लोकल, रीजनल, नेशनल, और इंटरनेशनल","Class A, Class B, Class C, और Class D","Interstate Non-Excepted, Intrastate Non-Excepted, Interstate Excepted, और Intrastate Excepted","Hazmat, Passenger, School Bus, और Tank"],"explanation":"चार स्व-प्रमाणन श्रेणियाँ हैं Interstate Non-Excepted (NI), Intrastate Non-Excepted (NA), Interstate Excepted (EI), और Intrastate Excepted (EA)। स्रोत: NY DMV, Self-Certify Your Driving Type।"},"95":{"q":"किन स्व-प्रमाणन श्रेणियों के लिए एक न्यूयॉर्क CDL धारक को एक वर्तमान यू.एस. DOT मेडिकल एग्ज़ामिनर्स सर्टिफ़िकेट फ़ाइल में रखना आवश्यक है?","options":["केवल Excepted श्रेणियाँ","Non-Excepted श्रेणियाँ (Interstate Non-Excepted और Intrastate Non-Excepted)","सभी चार श्रेणियाँ समान रूप से","किसी भी श्रेणी के लिए मेडिकल सर्टिफ़िकेट आवश्यक नहीं है"],"explanation":"जो ड्राइवर किसी Non-Excepted प्रकार (NI या NA) के लिए स्व-प्रमाणन करते हैं, उन्हें एक वर्तमान USDOT मेडिकल एग्ज़ामिनर्स सर्टिफ़िकेट फ़ाइल में रखना होगा; Excepted ड्राइवरों (EI/EA) को नहीं। स्रोत: NY DMV, CDL Medical Certification।"},"96":{"q":"वर्तमान संघीय और न्यूयॉर्क प्रक्रियाओं के तहत, एक CDL धारक का मेडिकल एग्ज़ामिनर्स सर्टिफ़िकेट आमतौर पर NY DMV को कैसे प्रेषित किया जाता है?","options":["प्रमाणित मेडिकल एग्ज़ामिनर इसे इलेक्ट्रॉनिक रूप से FMCSA National Registry को जमा करता है, जो परिणाम DMV को अग्रेषित करता है","ड्राइवर को हमेशा मूल कागज़ी सर्टिफ़िकेट किसी DMV कार्यालय में स्वयं पहुँचाना होगा","सर्टिफ़िकेट कभी DMV को रिपोर्ट नहीं किया जाता और केवल ड्राइवर द्वारा रखा जाता है","नियोक्ता प्रति वर्ष एक बार सर्टिफ़िकेट FMCSA को डाक से भेजता है"],"explanation":"संघीय नियमों के तहत, प्रमाणित मेडिकल एग्ज़ामिनर परीक्षा परिणाम FMCSA National Registry पर अपलोड करते हैं, जो फिर मेडिकल प्रमाणन स्थिति को इलेक्ट्रॉनिक रूप से NY DMV को प्रेषित करता है, न कि ड्राइवर द्वारा एक प्रति डाक से भेजना। स्रोत: NY DMV / FMCSA Medical Certification।"},"97":{"q":"एक न्यूयॉर्क CDL कितने समय के लिए वैध है, और इसे आमतौर पर कैसे नवीनीकृत किया जाता है?","options":["आठ वर्ष के लिए वैध; CDL आम तौर पर ऑनलाइन नवीनीकृत नहीं किए जा सकते और डाक से या व्यक्तिगत रूप से नवीनीकृत किए जाते हैं","एक वर्ष के लिए वैध; केवल ऑनलाइन नवीनीकृत","दो वर्ष के लिए वैध; बिना किसी कार्रवाई के स्वचालित रूप से नवीनीकृत","दस वर्ष के लिए वैध; केवल FMCSA में नवीनीकृत"],"explanation":"एक न्यूयॉर्क CDL आठ वर्ष के लिए वैध है। मानक लाइसेंसों के विपरीत, CDL आम तौर पर ऑनलाइन नवीनीकृत नहीं किए जा सकते और इन्हें डाक से या किसी DMV कार्यालय में नवीनीकृत किया जाना चाहिए। स्रोत: NY DMV, Renew a Commercial Driver License (CDL)।"},"98":{"q":"न्यूयॉर्क का Article 19-A किस ड्राइवर समूह के लिए विशेष आवश्यकताएँ निर्धारित करता है?","options":["न्यूयॉर्क सिटी में सभी यात्री-कार ड्राइवर","केवल खतरनाक सामग्री टैंक-ट्रक ड्राइवर","कवर किए गए मोटर कैरियरों के लिए संचालन करने वाले बस ड्राइवर (जैसे स्कूल बस और कुछ NYSDOT-अधिकृत कैरियर)","न्यूयॉर्क से गुज़रने वाले आउट-ऑफ़-स्टेट CDL धारक"],"explanation":"Article 19-A कवर किए गए मोटर कैरियरों के बस ड्राइवरों (जैसे, स्कूल बस कैरियर और कुछ NYSDOT-अधिकृत कैरियर) के लिए विशेष योग्यता आवश्यकताएँ स्थापित करता है, जिसमें द्विवार्षिक मेडिकल परीक्षाएँ, बिहाइंड-द-व्हील और लिखित/मौखिक परीक्षण शामिल हैं। स्रोत: NY DMV, Article 19-A Information।"}},"ar":{"0":{"q":"على الطرق السريعة في نيويورك، ما هو الحد الأقصى القانوني لارتفاع المركبة، بما في ذلك أي حمولة؟","options":["13 قدمًا و0 بوصة","13 قدمًا و6 بوصات","14 قدمًا و0 بوصة","12 قدمًا و6 بوصات"],"explanation":"يحدد قانون المركبات والمرور في نيويورك (VTL) القسم 385 ودليل CDL في نيويورك الحد الأقصى لارتفاع المركبة بـ 13 قدمًا و6 بوصات (13.5 قدمًا)، بما في ذلك الحمولة. وقد تكون الجسور والممرات العلوية المُعلَّمة أقل من ذلك."},"1":{"q":"ما هو الحد الأقصى للوزن الإجمالي المسموح به لمعظم المركبات على الطرق السريعة في نيويورك بدون تصريح خاص؟","options":["90,000 رطل","100,000 رطل","73,280 رطل","80,000 رطل"],"explanation":"بموجب VTL القسم 385 في نيويورك، لا يجوز عمومًا أن يتجاوز الوزن الإجمالي الكلي للمركبة أو التركيبة 80,000 رطل ما لم يُصدَر تصريح بالحجم الزائد/الوزن الزائد."},"2":{"q":"بموجب قانون المركبات والمرور في نيويورك، ما هو الحد الأقصى للوزن المسموح به على أي محور مفرد (بدون تصريح)؟","options":["18,000 رطل","24,000 رطل","20,000 رطل","22,400 رطل"],"explanation":"يحدد VTL القسم 385 في نيويورك الوزن على أي محور مفرد بـ 22,400 رطل. (على نظام الطرق السريعة بين الولايات Interstate، يُطبَّق الحد الفيدرالي الأدنى للمحور المفرد البالغ 20,000 رطل.)"},"3":{"q":"ما هو الحد الأقصى العام لعرض المركبة على الطرق السريعة في نيويورك، باستثناء الأماكن التي يُسمح فيها بعروض أوسع على الطرق السريعة المؤهلة؟","options":["102 بوصة (8 أقدام و6 بوصات)","120 بوصة (10 أقدام)","96 بوصة (8 أقدام)","90 بوصة (7 أقدام و6 بوصات)"],"explanation":"يحدد VTL القسم 385 في نيويورك الحد الأقصى العام للعرض بـ 96 بوصة (8 أقدام). وعلى نظام الطرق السريعة المؤهلة/بين الولايات Interstate وحارات المرور التي يبلغ عرضها 10 أقدام أو أكثر خارج NYC، يُسمح بما يصل إلى 102 بوصة."},"4":{"q":"على نظام الطرق السريعة المؤهلة (بين الولايات Interstate) في نيويورك، ما هو الحد الأقصى لعرض المركبة المسموح به؟","options":["108 بوصات (9 أقدام)","120 بوصة (10 أقدام)","96 بوصة (8 أقدام)","102 بوصة (8 أقدام و6 بوصات)"],"explanation":"على نظام الطرق السريعة المؤهلة/بين الولايات Interstate (والحارات التي يبلغ عرضها 10 أقدام على الأقل خارج NYC)، يسمح VTL القسم 385 في نيويورك بحد أقصى للعرض يبلغ 102 بوصة، باستثناء المرايا وبعض أجهزة السلامة."},"5":{"q":"في نيويورك، ما هو الحد الأقصى لطول الشاحنة المفردة (المستقيمة)، بما في ذلك الحمولة والمصدّات؟","options":["48 قدمًا","35 قدمًا","40 قدمًا","45 قدمًا"],"explanation":"يحدد VTL القسم 385 في نيويورك طول المركبة المفردة (باستثناء الحافلات المفصلية وأنصاف المقطورات) بـ 40 قدمًا، بما في ذلك الحمولة والمصدّات."},"6":{"q":"في نيويورك، ما هو الحد الأقصى للطول المسموح به لنصف مقطورة أو مقطورة تُشغَّل ضمن تركيبة؟","options":["53 قدمًا","40 قدمًا","45 قدمًا","48 قدمًا"],"explanation":"بموجب VTL القسم 385 في نيويورك، لا يجوز أن يتجاوز طول نصف المقطورة أو المقطورة 48 قدمًا، بما في ذلك الحمولة. ويتطلب تشغيل المقطورات بطول 53 قدمًا في نيويورك عمومًا تصاريح وصول خاصة."},"7":{"q":"على النظام الفيدرالي للطرق السريعة بين الولايات Interstate في نيويورك، ما هو الحد الأقصى للوزن المسموح به على مجموعة محاور مترادفة (tandem)؟","options":["40,000 رطل","22,400 رطل","36,000 رطل","34,000 رطل"],"explanation":"على نظام الطرق السريعة بين الولايات Interstate، يُطبَّق الحد الفيدرالي للمحور المترادف tandem البالغ 34,000 رطل في نيويورك، كما هو مشار إليه في 23 CFR 658.17 ودليل CDL في نيويورك."},"8":{"q":"على نظام الطرق السريعة بين الولايات Interstate في نيويورك، ما هو الحد الأقصى للوزن المسموح به على محور مفرد؟","options":["22,400 رطل","18,000 رطل","20,000 رطل","24,000 رطل"],"explanation":"يُطبَّق الحد الفيدرالي للمحور المفرد البالغ 20,000 رطل على نظام الطرق السريعة بين الولايات Interstate في نيويورك. أما الحد العام للمحور المفرد بموجب قانون الولاية في نيويورك (خارج Interstate) فهو أعلى ويبلغ 22,400 رطل."},"9":{"q":"في نيويورك، أي نوع من التصاريح يُستخدَم لنقل حمولة لا يمكن تقليصها إلى الحجم أو الوزن القانوني؟","options":["تصريح حمولة غير قابلة للتجزئة (نقل خاص)","شهادة تسجيل قياسية","تصريح وزن زائد لحمولة قابلة للتجزئة","تأييد المواد الخطرة (HazMat)"],"explanation":"تصدر NYSDOT تصاريح النقل الخاص (الحمولة غير القابلة للتجزئة) للحمولات التي لا يمكن تقسيمها إلى وحدات قانونية دون التأثير على السلامة المادية للحمولة، مثل آلة كبيرة واحدة."},"10":{"q":"أي جهة في نيويورك تُصدِر تصاريح النقل الخاص للحجم الزائد/الوزن الزائد للسفر على الطرق السريعة للولاية خارج مدينة نيويورك؟","options":["الإدارة الفيدرالية لسلامة ناقلات النقل بالمحركات (FMCSA)","إدارة النقل بولاية نيويورك (NYSDOT)","هيئة الطرق السريعة بولاية نيويورك (Thruway Authority)","NY DMV"],"explanation":"تصدر NYSDOT تصاريح الحجم الزائد/الوزن الزائد (النقل الخاص) للطرق السريعة للولاية. وداخل مدينة نيويورك، تصدر NYC DOT مثل هذه التصاريح، وتتحكم بعض هيئات الجسور/الأنفاق في معابرها الخاصة."},"11":{"q":"في نيويورك، يُعرَّف \"الحمولة القابلة للتجزئة\" بشكل أفضل بأنها حمولة:","options":["لا يمكن نقلها إلا ليلاً مع مرافقة","يمكن فصلها إلى وحدات قانونية دون التأثير على السلامة المادية للحمولة","يزيد وزنها على 80,000 رطل في قطعة واحدة","تتكون من آلة واحدة غير قابلة للتجزئة"],"explanation":"بموجب قواعد NYSDOT، الحمولة القابلة للتجزئة هي بضائع ذات أبعاد قانونية يمكن فصلها إلى وحدات ذات وزن قانوني دون التأثير على السلامة المادية للحمولة. وتصاريح الوزن الزائد للحمولات القابلة للتجزئة محدودة وغير صالحة على الطرق المحلية أو في NYC."},"12":{"q":"تصريح الوزن الزائد للحمولة القابلة للتجزئة في نيويورك يكون عمومًا غير صالح على أي مما يلي؟","options":["طرق وممرات المدن والقرى والمقاطعات المحلية والطرق داخل مدينة نيويورك","مسارات التجوال المخصصة من NYSDOT في شمال الولاية","الأجزاء التي تصونها الولاية من نظام الطرق السريعة المؤهلة","الطرق السريعة للولاية التي يغطيها نطاق التصريح"],"explanation":"تصاريح الوزن الزائد للحمولة القابلة للتجزئة من NYSDOT غير صالحة على طرق المدن أو القرى أو المقاطعات، ولا على الطرق الخاضعة لولاية هيئة MTA/الجسور أو الأنفاق، ولا داخل مدينة نيويورك. وتفرض تلك الجهات حدودها الخاصة."},"13":{"q":"صيغة الجسر الفيدرالية (Bridge Formula)، كما تُطبَّق في نيويورك، تحدد الوزن المسموح به على مجموعة من المحاور استنادًا بشكل أساسي إلى:","options":["عدد المحاور والمسافة (التباعد) بينها","نوع البضائع التي يجري نقلها","عمر وطراز الجرّار","حد السرعة المُعلَن على الطريق السريع"],"explanation":"تحدد صيغة الوزن الإجمالي للجسر الفيدرالية، المطبَّقة في نيويورك على نظام الطرق السريعة بين الولايات Interstate، الوزن على أي مجموعة من المحاور وفقًا لعدد المحاور والمسافة بين المحاور الخارجية، لحماية الجسور."},"14":{"q":"في نيويورك، ما هو الحد الأقصى للطول الإجمالي لتركيبة من المركبات (جرّار بالإضافة إلى مقطورة)، بما في ذلك الحمولة والمصدّات، على الطرق السريعة حيث لا تنطبق بدلات الطول الخاصة بالطرق السريعة المؤهلة؟","options":["60 قدمًا","65 قدمًا","75 قدمًا","53 قدمًا"],"explanation":"يحدد VTL القسم 385 في نيويورك تركيبة المركبات بـ 65 قدمًا إجمالاً، بما في ذلك الحمولة والمصدّات، باستثناء ما هو مسموح به خلافًا لذلك على نظام الطرق السريعة المؤهلة."},"15":{"q":"بموجب قانون نيويورك، ما هو الحد الأقصى للوزن المسموح به على أي عجلة واحدة من مركبة مزودة بإطارات هوائية؟","options":["10,000 رطل","8,000 رطل","11,200 رطل","12,500 رطل"],"explanation":"يحدد VTL القسم 385 في نيويورك الوزن على أي عجلة واحدة من مركبة بإطارات هوائية، عند التحميل، بـ 11,200 رطل (نصف حد المحور المفرد البالغ 22,400 رطل)."},"16":{"q":"بموجب VTL القسم 385 في نيويورك، يجوز أن يكون للمركبة التي تعمل أساسًا بمحرك يعمل بالغاز الطبيعي حد أقصى للوزن الإجمالي يصل إلى:","options":["80,000 رطل","82,000 رطل","88,000 رطل","85,000 رطل"],"explanation":"يسمح VTL القسم 385 في نيويورك بأن يكون للمركبة التي تعمل بمحرك يعمل أساسًا بالغاز الطبيعي حد أقصى للوزن الإجمالي يصل إلى 82,000 رطل، لمراعاة الوزن الإضافي لنظام الوقود."},"17":{"q":"في نيويورك، ما هو الحد الأقصى لطول حافلة تنقل أكثر من سبعة ركاب (باستثناء الحافلة المفصلية)؟","options":["45 قدمًا","40 قدمًا","62 قدمًا","55 قدمًا"],"explanation":"يحدد VTL القسم 385 في نيويورك طول الحافلة التي تنقل أكثر من سبعة ركاب بـ 45 قدمًا، في حين يجوز أن يصل طول الحافلة المفصلية إلى 62 قدمًا."},"18":{"q":"يريد ناقل في نيويورك نقل حمولة غير قابلة للتجزئة ذات حجم زائد/وزن زائد على الطرق السريعة للولاية. ما الذي يجب الحصول عليه قبل الرحلة؟","options":["تصريح نقل خاص من NYSDOT يُصدَر قبل النقل","رخصة CDL من الفئة A سارية فقط بدون تصريح","تصريح وزن زائد لحمولة قابلة للتجزئة","تأييد المواد الخطرة (HazMat)"],"explanation":"يتطلب نقل حمولة غير قابلة للتجزئة ذات حجم زائد أو وزن زائد على الطرق السريعة لولاية نيويورك الحصول مسبقًا على تصريح نقل خاص من NYSDOT؛ ويحدد التصريح المسار والأبعاد والوزن وأي شروط للمرافقة أو وقت السفر."},"19":{"q":"أي عبارة تصف بشكل أفضل كيف يمكن أن تختلف حدود الوزن بين الطرق السريعة للولاية في نيويورك والطرق المحلية أو الجسور؟","options":["حدود الجسور المُعلَنة لا تنطبق أبدًا على المركبات التجارية","الحدود المحلية متطابقة في جميع أنحاء الولاية بدون استثناءات مُعلَنة","قد يكون للطرق المحلية والجسور المُعلَنة حدود أقل يجب الالتزام بها حتى مع امتلاك تصريح من الولاية","تسمح الطرق المحلية دائمًا بحمولات أثقل من الطرق السريعة للولاية"],"explanation":"وفقًا لدليل CDL في نيويورك وNYSDOT، لا يلغي تصريح الحجم الزائد/الوزن الزائد من الولاية الحدود الأقل المُعلَنة على الطرق المحلية أو الجسور أو المرافق التي تديرها جهات أخرى؛ ويجب على السائقين الالتزام بالحد المُعلَن الأكثر تقييدًا."},"20":{"q":"بموجب تصنيف CDL في نيويورك، ما هي الفئة المطلوبة لتشغيل تركيبة جرّار-مقطورة؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"تُعرِّف NY DMV رخصة CDL من الفئة A بأنها \"جرّار-مقطورة\" (مركبة تركيبية). وتغطي الفئة B حافلة أو شاحنة بوحدة واحدة، وتغطي الفئة C شاحنة أو حافلة أو ليموزين ممدودة تتطلب تأييدًا. المصدر: NY DMV 'Get a Commercial Driver License (CDL)' / دليل السائق التجاري CDL-10."},"21":{"q":"وفقًا لـ NY DMV، تُشغَّل شاحنة بوحدة واحدة أو حافلة ليست مركبة تركيبية بموجب أي فئة من فئات CDL؟","options":["الفئة A","الفئة B","الفئة C","الفئة E"],"explanation":"تصف NY DMV الفئة B بأنها \"حافلة أو شاحنة بوحدة واحدة\". الفئة A هي تركيبة جرّار-مقطورة، والفئة C هي شاحنة أو حافلة أو ليموزين ممدودة تتطلب تأييدًا (مثل HazMat أو الركاب). المصدر: صفحات CDL في NY DMV / دليل CDL-10."},"22":{"q":"في نيويورك، أي فئة من فئات CDL تُوصَف بأنها تغطي شاحنة أو حافلة أو ليموزين ممدودة تتطلب تأييدًا محددًا؟","options":["الفئة A","الفئة B","الفئة C","الفئة M"],"explanation":"تُعرِّف NY DMV الفئة C بأنها \"شاحنة أو حافلة أو ليموزين ممدودة\" تتطلب تأييدًا، عادةً لأنها تنقل 16 راكبًا أو أكثر (بما في ذلك السائق) أو مواد خطرة. المصدر: NY DMV 'Get a Commercial Driver License (CDL)'."},"23":{"q":"ما هو الحد الأدنى للعمر للحصول على رخصة CDL في نيويورك صالحة للقيادة داخل الولاية فقط (داخل ولاية نيويورك)؟","options":["16 عامًا","18 عامًا","21 عامًا","25 عامًا"],"explanation":"يجب أن يكون عمر السائق 18 عامًا على الأقل للحصول على رخصة CDL في نيويورك للقيادة داخل الولاية (داخل نيويورك فقط). ويقتصر السائقون دون 21 عامًا على التشغيل داخل الولاية. المصدر: متطلبات السائق التجاري لدى NY DMV."},"24":{"q":"في نيويورك، ما هو الحد الأدنى للعمر المطلوب لقيادة مركبة تجارية في التجارة بين الولايات (عبر حدود الولايات)؟","options":["18 عامًا","19 عامًا","20 عامًا","21 عامًا"],"explanation":"يجب أن يكون عمرك 21 عامًا على الأقل لتشغيل مركبة تجارية في التجارة بين الولايات. ويقتصر السائقون الذين تتراوح أعمارهم بين 18 و20 عامًا والحاصلون على رخصة CDL في نيويورك على القيادة داخل الولاية (داخل نيويورك). المصدر: متطلبات CDL لدى NY DMV؛ FMCSA 49 CFR 391.11."},"25":{"q":"كم تبلغ مدة صلاحية تصريح المتعلم التجاري (CLP) في نيويورك بعد إصداره بموجب القواعد الحالية؟","options":["30 يومًا","ستة أشهر (180 يومًا)","سنة واحدة (365 يومًا)","خمس سنوات"],"explanation":"بالنسبة لتصاريح CLP الصادرة في أو بعد 27 ديسمبر 2022، مددت نيويورك صلاحية CLP إلى سنة واحدة (365 يومًا)، بعد أن كانت ستة أشهر سابقًا، لتبسيط العملية. المصدر: أخبار NY DMV، 'DMV Extends Validity of Commercial Learner Permit.'"},"26":{"q":"تتطلب القواعد الفيدرالية المطبَّقة في نيويورك من حامل CLP الانتظار مدة لا تقل عن كم بعد إصدار CLP قبل إجراء اختبار مهارات CDL (اختبار الطريق)؟","options":["لا توجد فترة انتظار دنيا","7 أيام","14 يومًا","30 يومًا"],"explanation":"بموجب القانون الفيدرالي (49 CFR 383.25)، المطبَّق في نيويورك، لا يكون حامل CLP مؤهلاً لإجراء اختبار مهارات CDL إلا بعد مرور 14 يومًا على الأقل من الإصدار الأولي لـ CLP. المصدر: 49 CFR 383.25؛ معايير CDL لدى FMCSA."},"27":{"q":"أي تأييد يحتاج إليه حامل رخصة CDL في نيويورك لنقل مواد خطرة تتطلب لافتات تحذيرية (placarding)؟","options":["H (المواد الخطرة)","N (مركبات الصهاريج)","T (المقطورات المزدوجة/الثلاثية)","S (الحافلة المدرسية)"],"explanation":"يُطلَب تأييد \"H\" (المواد الخطرة) لنقل كميات من المواد الخطرة تستلزم لافتات تحذيرية. وفي نيويورك يتطلب أن يكون عمرك 21 عامًا على الأقل، واجتياز اختبار كتابي، وإكمال ELDT للمواد الخطرة (للمتقدمين لأول مرة)، واجتياز فحص خلفية قائم على البصمات. المصدر: NY DMV 'CDL Endorsements.'"},"28":{"q":"للحصول على تأييد المواد الخطرة (H) في نيويورك، يجب على المتقدم إكمال أي خطوة متعلقة بالأمن؟","options":["فحص نظر لدى أخصائي بصريات خاص فقط","فحص خلفية قائم على البصمات (عبر IdentoGO)","مقابلة إقامة لمدة 10 سنوات مع الشرطة المحلية","اختبار كشف الكذب لدى DMV"],"explanation":"يجب على المتقدمين لتأييد المواد الخطرة (H) في نيويورك اجتياز فحص خلفية فيدرالي/خاص بالولاية قائم على البصمات، يُجرى عبر IdentoGO، بالإضافة إلى اجتياز الاختبار الكتابي وأن يكون عمرهم 21 عامًا على الأقل. المصدر: NY DMV 'CDL Endorsements'؛ برنامج تقييم تهديد المواد الخطرة لدى TSA."},"29":{"q":"أي تأييد CDL في نيويورك مطلوب لتشغيل مركبة مصممة لنقل السوائل أو الغازات بكميات كبيرة في صهريج مثبت بشكل دائم؟","options":["P (الركاب)","T (المقطورات المزدوجة/الثلاثية)","N (مركبات الصهاريج)","M (لفائف المعادن - Metal Coil)"],"explanation":"يُطلَب تأييد \"N\" (مركبات الصهاريج) لقيادة المركبات التي تنقل السوائل أو الغازات بكميات كبيرة في صهريج مثبت بشكل دائم يستوفي حدودًا معينة. المصدر: NY DMV 'CDL Endorsements'؛ دليل CDL-10 القسم 9 (مركبات الصهاريج)."},"30":{"q":"في نيويورك، أي تأييد مطلوب لسحب مقطورات مزدوجة أو ثلاثية؟","options":["T (المقطورات المزدوجة/الثلاثية)","N (مركبات الصهاريج)","H (المواد الخطرة)","P (الركاب)"],"explanation":"يُطلَب تأييد \"T\" (المقطورات المزدوجة/الثلاثية) لسحب أكثر من مقطورة واحدة. ويُحصَل عليه باجتياز اختبار معرفي؛ مع ملاحظة أن المقطورات الثلاثية ليست قانونية على جميع طرق نيويورك. المصدر: NY DMV 'CDL Endorsements'؛ دليل CDL-10 القسم 8 (المقطورات المزدوجة والثلاثية)."},"31":{"q":"أي تأييد يجب أن يحمله حامل رخصة CDL في نيويورك لقيادة حافلة أو فان تنقل 16 راكبًا أو أكثر (بما في ذلك السائق)؟","options":["S (الحافلة المدرسية)","P (الركاب)","N (مركبات الصهاريج)","T (المقطورات المزدوجة/الثلاثية)"],"explanation":"يُطلَب تأييد \"P\" (الركاب) لتشغيل المركبات المصممة لنقل 16 شخصًا أو أكثر بما في ذلك السائق. ويُبنى تأييد الحافلة المدرسية (S) فوق تأييد P. المصدر: NY DMV 'CDL Endorsements'؛ دليل CDL-10 القسم 4 (نقل الركاب)."},"32":{"q":"في نيويورك، ما هو الشرط المسبق للحصول على تأييد الحافلة المدرسية (S)؟","options":["حمل تأييد المواد الخطرة (H)","حمل تأييد الركاب (P) بالفعل، أو التقدم للحصول عليه في الوقت نفسه","حمل تأييد مركبات الصهاريج (N)","حمل تأييد المقطورات المزدوجة/الثلاثية (T)"],"explanation":"وفقًا لـ NY DMV، يجب أن يحمل السائق تأييد الركاب (P) بالفعل أو يتقدم للحصول على تأييدي P وS في الوقت نفسه للحصول على تأييد الحافلة المدرسية (S). المصدر: NY DMV 'CDL Endorsements.'"},"33":{"q":"أي عبارة حول اختبار المعرفة الخاص بتأييد الحافلة المدرسية (S) في نيويورك صحيحة؟","options":["يتكون من 20 سؤالاً متعدد الخيارات ويتطلب 16 إجابة صحيحة للنجاح","يتكون من 50 سؤالاً ويتطلب 45 إجابة صحيحة للنجاح","يتطلب اختبار طريق فقط دون اختبار كتابي","يُعفى منه أي شخص يحمل بالفعل رخصة CDL من الفئة A"],"explanation":"يستند الاختبار الكتابي لتأييد الحافلة المدرسية (S) في نيويورك إلى القسم 10 من دليل CDL ويتكون من 20 سؤالاً متعدد الخيارات؛ ويجب على السائق الإجابة بشكل صحيح عن 16 سؤالاً للنجاح. ولا يُطلَب اختبار طريق منفصل لتأييد S نفسه. المصدر: NY DMV 'CDL Endorsements.'"},"34":{"q":"تتطلب نيويورك تأييدًا خاصًا، غير موجود في كثير من الولايات الأخرى، للسائقين التجاريين الذين ينقلون أي بضائع يبلغ وزنها 5,000 رطل أو أكثر؟","options":["أسطوانات الغاز المضغوط","الحيوانات الحية","لفائف المعادن (Metal Coil)","النفايات الخطرة"],"explanation":"يتطلب قانون المركبات والمرور في نيويورك تأييد لفائف المعادن \"M\" (Metal Coil) للسائقين التجاريين الذين ينقلون لفائف معدنية يبلغ وزنها 5,000 رطل أو أكثر. وهو تأييد خاص بنيويورك يُحصَل عليه باجتياز اختبار كتابي مكون من 20 سؤالاً (16 إجابة صحيحة للنجاح). المصدر: NY DMV 'CDL Endorsements.'"},"35":{"q":"السائقون الذين يشغّلون حافلات لدى ناقل بالمحركات في نيويورك (مثل الناقلات المدرسية أو الخاضعة لتنظيم DOT) يخضعون لأي برنامج إضافي في الولاية؟","options":["Article 19-A (متطلبات خاصة لسائقي الحافلات)","Article 31 (برنامج القيادة تحت تأثير الكحول DWI)","قانون الرخصة المتدرجة (Graduated License Law)","قانون التحرك جانبًا (Move Over Law)"],"explanation":"تفرض Article 19-A من قانون المركبات والمرور في نيويورك متطلبات إضافية على سائقي الحافلات للناقلات بالمحركات المشمولة، بما في ذلك أن يكون عمرهم 21 عامًا على الأقل، وامتلاك رخصة سارية لعدة سنوات، واختبارات أداء بدني دورية، ومراجعة سنوية للقيادة الدفاعية/خلف المقود. المصدر: NY DMV Article 19-A Information؛ VTL Article 19-A."},"36":{"q":"بموجب قاعدة تدريب السائق المبتدئ الفيدرالية (ELDT) المطبَّقة في نيويورك، من الذي يجب أن يكمل التدريب قبل الاختبار؟","options":["السائقون الذين يسعون للحصول على تأييد المواد الخطرة فقط","المتقدمون لأول مرة للفئة A أو B، والترقيات من B إلى A، والمتقدمون لأول مرة لتأييد H أو P أو S","السائقون الذين تزيد أعمارهم على 65 عامًا فقط","كل حامل رخصة CDL عند كل تجديد للرخصة"],"explanation":"تنطبق ELDT على المتقدمين لأول مرة لرخصة CDL من الفئة A أو الفئة B، وحاملي الفئة B الذين يترقّون إلى الفئة A، والمتقدمين لأول مرة لتأييد المواد الخطرة (H) أو الركاب (P) أو الحافلة المدرسية (S)، لأي شخص حصل على CLP في أو بعد 7 فبراير 2022. المصدر: FMCSA Training Provider Registry؛ NY DMV."},"37":{"q":"أين يجب تسجيل تدريب السائق المبتدئ (ELDT) لمتقدم لرخصة CDL في نيويورك ليُحتسَب ضمن أهلية CDL؟","options":["على شهادة ورقية يحتفظ بها السائق فقط","في سجل مزودي التدريب لدى FMCSA (TPR)","في مكتب كاتب المقاطعة المحلي","فقط في ملف موظفي صاحب العمل الخاص بالسائق"],"explanation":"يجب إكمال ELDT لدى مزود مدرَج في سجل مزودي التدريب لدى FMCSA (TPR)، ويقدم المزود شهادة الإكمال إلكترونيًا إلى TPR قبل أن يتمكن المتقدم من إجراء اختبار CDL. المصدر: FMCSA Entry-Level Driver Training (ELDT) / Training Provider Registry."},"38":{"q":"عند التقدم للحصول على رخصة CDL في نيويورك، كيف تتحقق DMV من هوية المتقدم؟","options":["بطاقة هوية واحدة بصورة تكون كافية دائمًا","مستندات تبلغ مجموعها 6 نقاط على الأقل من إثبات الهوية، بالإضافة إلى رقم الضمان الاجتماعي","بيان شفهي بالهوية فقط","تقرير ائتماني وفاتورة خدمات"],"explanation":"تستخدم NY DMV نظامًا قائمًا على النقاط يتطلب مستندات تبلغ مجموعها 6 نقاط على الأقل من إثبات الهوية (مع أن يحمل أحدها على الأقل توقيعًا)، ويجب على المتقدمين تقديم رقم الضمان الاجتماعي الخاص بهم (أو توقيع إقرار إذا لم يُصدَر لهم رقم قط). المصدر: متطلبات إثبات الهوية لدى NY DMV (النموذج ID-44)."},"39":{"q":"كجزء من التصديق الذاتي الطبي، يجب على حامل رخصة CDL في نيويورك الذي يقود في التجارة بين الولايات وليس معفى من شرط البطاقة الطبية أن يحتفظ بماذا في الملف لدى DMV؟","options":["خطاب موثَّق من صاحب العمل","شهادة فاحص طبي حالية من USDOT (البطاقة الطبية)","نسخة من شهادة الثانوية العامة","تسجيل مركبة لكل شاحنة يقودها"],"explanation":"يجب على حاملي رخصة CDL التصديق الذاتي على فئة قيادتهم (مثل غير المعفى بين الولايات Non-Excepted Interstate)، وإذا كانوا غير معفيين، الاحتفاظ بشهادة فاحص طبي حالية من USDOT في الملف لدى NY DMV؛ وقد يؤدي عدم القيام بذلك إلى تخفيض درجة رخصة CDL. المصدر: NY DMV CDL Medical Certification ('Self-Certify Your Driving Type')."},"40":{"q":"ما هو الحد الأقصى لتركيز الكحول في الدم (BAC) الذي يجوز عنده قانونًا للشخص تشغيل مركبة تجارية بمحرك (CMV) في نيويورك؟","options":["0.02%","0.04%","0.08%","0.10%"],"explanation":"تتبع نيويورك القاعدة الفيدرالية: من غير القانوني تشغيل مركبة CMV بتركيز BAC يبلغ 0.04% أو أكثر. وهذا نصف حد الـ 0.08% للسائقين غير التجاريين. المصدر: NY CDL-10 Manual sec. 1.6.2؛ 49 CFR 383.51 Table 1."},"41":{"q":"بموجب قاعدة الموافقة الضمنية في نيويورك للسائقين التجاريين، فإن تشغيل مركبة CMV يعني أنك قد أعطيت موافقتك تلقائيًا على ماذا؟","options":["تفتيش حمولتك وسجل قيادتك","اختبار الكحول والمخدرات","إعادة فحص للنظر والفحص الطبي","تدقيق سجل قيادتك"],"explanation":"ينص دليل CDL في نيويورك على أنك إذا شغّلت مركبة CMV، فإنك تُعتبَر قد أعطيت موافقتك على اختبار الكحول. المصدر: NY CDL-10 Manual sec. 1.6.2؛ NY VTL 1194 (الموافقة الضمنية)."},"42":{"q":"إذا وُجِد لدى سائق مركبة CMV في نيويورك كمية قابلة للكشف من الكحول أقل من حد الـ 0.04%، فماذا يحدث؟","options":["لا شيء، لأن السائق دون الحد القانوني","يُوضَع السائق خارج الخدمة لمدة 24 ساعة","يُحرَم السائق من الأهلية لمدة 60 يومًا","يتلقى السائق إنذارًا كتابيًا فقط"],"explanation":"يُوضَع سائق مركبة CMV الذي لديه أي كمية قابلة للكشف من الكحول دون 0.04% خارج الخدمة لمدة 24 ساعة، رغم أنها دون الحد الموجب للحرمان. المصدر: NY CDL-10 Manual sec. 1.6.2."},"43":{"q":"بالنسبة لأول مخالفة كبرى (مثل قيادة مركبة CMV بتركيز BAC يبلغ 0.04% أو أعلى)، كم تبلغ مدة حرمان حامل رخصة CDL في نيويورك من الأهلية؟","options":["60 يومًا","120 يومًا","سنة واحدة على الأقل","ثلاث سنوات"],"explanation":"تؤدي أول مخالفة كبرى إلى حرمان من الأهلية لمدة سنة واحدة على الأقل. المصدر: NY CDL-10 Manual sec. 1.6.2؛ 49 CFR 383.51 Table 1."},"44":{"q":"يرتكب حامل رخصة CDL في نيويورك أول مخالفة كبرى أثناء تشغيل مركبة CMV تحمل لافتات تحذيرية للمواد الخطرة. كم تبلغ مدة الحرمان من الأهلية؟","options":["سنة واحدة","ثلاث سنوات","خمس سنوات","مدى الحياة"],"explanation":"تؤدي أول مخالفة كبرى تُرتكَب أثناء تشغيل مركبة CMV تحمل لافتات تحذيرية للمواد الخطرة إلى حرمان من الأهلية لمدة ثلاث سنوات، بدلاً من السنة الواحدة المعتادة. المصدر: NY CDL-10 Manual sec. 1.6.2؛ 49 CFR 383.51 Table 1."},"45":{"q":"ما هي مدة الحرمان من الأهلية لحامل رخصة CDL في نيويورك المُدان بمخالفة كبرى ثانية؟","options":["سنة واحدة","ثلاث سنوات","عشر سنوات","مدى الحياة"],"explanation":"تؤدي الإدانة الثانية بأي من المخالفات الكبرى المدرجة إلى حرمان مدى الحياة من CLP و/أو CDL. المصدر: NY CDL-10 Manual sec. 1.6.2؛ 49 CFR 383.51 Table 1."},"46":{"q":"في نيويورك، كيف يُعامَل رفض الخضوع لاختبار الكحول في الدم أثناء تشغيل مركبة CMV لأغراض الحرمان من أهلية CDL؟","options":["كمخالفة ورقية بسيطة دون حرمان من الأهلية","كمخالفة مرورية خطيرة فقط","كمخالفة كبرى، مثل الإدانة بالقيادة تحت تأثير الكحول (DUI) تمامًا","كمخالفة لأمر الإيقاف عن الخدمة"],"explanation":"رفض الخضوع لاختبار الكحول في الدم هو مخالفة كبرى ويحمل نفس الحد الأدنى للحرمان من الأهلية البالغ سنة واحدة لأول مخالفة، مثل الإدانة بالقيادة تحت تأثير الكحول (DUI). المصدر: NY CDL-10 Manual sec. 1.6.2؛ 49 CFR 383.51 Table 1."},"47":{"q":"أي مما يلي يُعد مخالفة كبرى يمكن أن تحرم حامل رخصة CDL في نيويورك من الأهلية، حتى لو ارتُكِبت في سيارة السائق الشخصية بدلاً من مركبة CMV؟","options":["اتباع مركبة أخرى من مسافة قريبة جدًا","القيادة تحت تأثير الكحول","إجراء تغيير غير سليم للحارة","تجاوز الحد بمقدار 15 ميلاً في الساعة"],"explanation":"القيادة تحت تأثير الكحول أو مادة خاضعة للرقابة في أي مركبة هي مخالفة كبرى تحرم حامل رخصة CDL من الأهلية؛ ولا يلزم أن تقع في مركبة CMV. أما الخيارات الأخرى فهي مخالفات مرورية خطيرة. المصدر: NY CDL-10 Manual sec. 1.6.2 و1.6.3."},"48":{"q":"يستخدم حامل رخصة CDL في نيويورك مركبة تجارية بمحرك لارتكاب جناية تتعلق بمواد خاضعة للرقابة. ما هي النتيجة؟","options":["حرمان من الأهلية لمدة 120 يومًا","حرمان من الأهلية لمدة ثلاث سنوات","حرمان مدى الحياة دون إعادة تأهيل بعد 10 سنوات","حرمان من الأهلية لمدة سنة واحدة"],"explanation":"يؤدي استخدام مركبة CMV لارتكاب جناية تتعلق بمواد خاضعة للرقابة إلى حرمان مدى الحياة من الأهلية، ولا يكون السائق مؤهلاً لإعادة التأهيل بعد 10 سنوات المتاحة لبعض حالات الحرمان مدى الحياة الأخرى. المصدر: NY CDL-10 Manual sec. 1.6.2؛ 49 CFR 383.51 Table 1."},"49":{"q":"أي مما يلي يُعد مخالفة كبرى تسبب الحرمان من أهلية CDL في نيويورك؟","options":["مغادرة مكان الحادث دون الإبلاغ عنه","القيادة بسرعة تتجاوز الحد بمقدار 12 ميلاً في الساعة","عدم استخدام إشارة الانعطاف","الوقوف في منطقة ممنوع الوقوف فيها"],"explanation":"مغادرة مكان الحادث دون الإبلاغ عنه هي مخالفة كبرى مدرجة تحمل حرمانًا من الأهلية لا يقل عن سنة واحدة لأول مخالفة. المصدر: NY CDL-10 Manual sec. 1.6.2؛ 49 CFR 383.51 Table 1."},"50":{"q":"أيٌّ مما يلي يُصنَّف على أنه مخالفة مرورية خطيرة (SERIOUS) بموجب قواعد CDL في نيويورك؟","options":["القيادة بنسبة كحول في الدم BAC تبلغ ‎.04%‎ أو أعلى","السرعة المفرطة بمقدار 15 ميلاً في الساعة أو أكثر فوق الحد المعلن","رفض إجراء اختبار كيميائي","مغادرة موقع الحادث"],"explanation":"السرعة المفرطة (15 ميلاً في الساعة أو أكثر فوق الحد المعلن) هي مخالفة مرورية خطيرة. أما الخيارات الأخرى فهي مخالفات كبرى (major offenses) تترتب عليها عقوبات أشد بكثير. المصدر: دليل NY CDL-10 القسم 1.6.3؛ 49 CFR 383.51 الجدول 2."},"51":{"q":"كم تبلغ مدة سحب الأهلية عن حامل CDL في نيويورك لارتكابه مخالفتين مروريتين خطيرتين في مركبة تجارية CMV خلال فترة ثلاث سنوات؟","options":["30 يومًا على الأقل","60 يومًا على الأقل","120 يومًا على الأقل","سنة واحدة على الأقل"],"explanation":"تؤدي مخالفتان مروريتان خطيرتان خلال فترة ثلاث سنوات (في مركبة تجارية CMV) إلى سحب الأهلية لمدة 60 يومًا على الأقل. المصدر: دليل NY CDL-10 القسم 1.6.3؛ 49 CFR 383.51 الجدول 2."},"52":{"q":"كم تبلغ مدة سحب الأهلية عن حامل CDL في نيويورك لارتكابه ثلاث مخالفات مرورية خطيرة في مركبة تجارية CMV خلال فترة ثلاث سنوات؟","options":["60 يومًا على الأقل","90 يومًا على الأقل","120 يومًا على الأقل","سنة واحدة على الأقل"],"explanation":"تؤدي ثلاث مخالفات مرورية خطيرة خلال فترة ثلاث سنوات (في مركبة تجارية CMV) إلى سحب الأهلية لمدة 120 يومًا على الأقل. المصدر: دليل NY CDL-10 القسم 1.6.3؛ 49 CFR 383.51 الجدول 2."},"53":{"q":"تشغيل مركبة تجارية CMV في نيويورك أثناء استخدام هاتف خلوي محمول باليد أو جهاز إرسال رسائل نصية يُصنَّف على أنه ماذا؟","options":["مخالفة كبرى","مخالفة مرورية خطيرة","انتهاك أمر إخراج من الخدمة (out-of-service)","مخالفة عند معبر السكة الحديدية"],"explanation":"يُدرَج استخدام هاتف خلوي محمول باليد و/أو جهاز إرسال رسائل نصية أثناء تشغيل مركبة تجارية CMV على أنه مخالفة مرورية خطيرة. كما تحظر نيويورك استخدام الأجهزة المحمولة باليد لجميع السائقين بموجب VTL 1225-c و1225-d. المصدر: دليل NY CDL-10 القسم 1.6.3."},"54":{"q":"أيٌّ مما يلي يُعدُّ مخالفة مرورية خطيرة وليس مخالفة كبرى لحامل CDL في نيويورك؟","options":["اتباع مركبة عن قرب أكثر من اللازم","قيادة مركبة تجارية CMV أثناء إلغاء CDL الخاص بك","استخدام مركبة تجارية CMV لارتكاب جناية","التسبب في وفاة من خلال تشغيل مركبة تجارية CMV بإهمال"],"explanation":"اتباع مركبة عن قرب أكثر من اللازم هو مخالفة مرورية خطيرة. أما الثلاثة الأخرى فهي مخالفات كبرى تترتب عليها مدة سحب أهلية لا تقل عن سنة واحدة (أو مدى الحياة). المصدر: دليل NY CDL-10 القسمان 1.6.2 و1.6.3؛ 49 CFR 383.51."},"55":{"q":"وفقًا لدليل CDL في نيويورك، كم تبلغ مدة سحب الأهلية عن حامل CDL عند أول إدانة بانتهاك أمر إخراج من الخدمة (out-of-service)؟","options":["90 يومًا على الأقل","30 يومًا على الأقل","سنة واحدة على الأقل","ثلاث سنوات على الأقل"],"explanation":"يُدرِج دليل NY CDL-10 مدة سحب أهلية لا تقل عن 90 يومًا لأول انتهاك لأمر إخراج من الخدمة. المصدر: دليل NY CDL-10 القسم 1.6.4. (ملاحظة: يحدد الجدول الفيدرالي في 49 CFR 383.51 حدًا أدنى قدره 180 يومًا للمخالفات الأولى غير المتعلقة بالمواد الخطرة HazMat.)"},"56":{"q":"بحسب دليل CDL في نيويورك، ما هي مدة سحب الأهلية لارتكاب انتهاكين لأمر إخراج من الخدمة (out-of-service) خلال فترة عشر سنوات؟","options":["60 يومًا على الأقل","120 يومًا على الأقل","سنة واحدة على الأقل","ثلاث سنوات على الأقل"],"explanation":"يؤدي انتهاكان لأمر إخراج من الخدمة خلال فترة عشر سنوات إلى سحب الأهلية لمدة سنة واحدة على الأقل. المصدر: دليل NY CDL-10 القسم 1.6.4."},"57":{"q":"بحسب دليل CDL في نيويورك، ما هي مدة سحب الأهلية لارتكاب ثلاثة انتهاكات أو أكثر لأمر إخراج من الخدمة (out-of-service) خلال فترة عشر سنوات؟","options":["سنة واحدة على الأقل","سنتان على الأقل","ثلاث سنوات على الأقل","خمس سنوات على الأقل"],"explanation":"تؤدي ثلاثة انتهاكات أو أكثر لأمر إخراج من الخدمة خلال فترة عشر سنوات إلى سحب الأهلية لمدة ثلاث سنوات على الأقل. المصدر: دليل NY CDL-10 القسم 1.6.4."},"58":{"q":"ما هي مدة سحب الأهلية عن حامل CDL في نيويورك عند أول مخالفة لمعبر السكة الحديدية مع الطريق السريع (railroad-highway grade crossing) تُرتكب أثناء تشغيل مركبة تجارية CMV؟","options":["30 يومًا على الأقل","60 يومًا على الأقل","120 يومًا على الأقل","سنة واحدة على الأقل"],"explanation":"تؤدي أول مخالفة لمعبر السكة الحديدية مع الطريق السريع إلى سحب الأهلية لمدة 60 يومًا على الأقل. المصدر: دليل NY CDL-10 القسم 1.6.5؛ 49 CFR 383.51 الجدول 3."},"59":{"q":"يرتكب حامل CDL في نيويورك ثالث مخالفة لمعبر السكة الحديدية مع الطريق السريع (railroad-highway grade crossing) خلال فترة ثلاث سنوات. ما هي مدة سحب الأهلية؟","options":["120 يومًا على الأقل","180 يومًا على الأقل","سنة واحدة على الأقل","ثلاث سنوات على الأقل"],"explanation":"تترتب على مخالفات معبر السكة الحديدية مع الطريق السريع مدة 60 يومًا على الأقل للمخالفة الأولى، و120 يومًا للثانية خلال ثلاث سنوات، وسنة واحدة على الأقل للثالثة خلال فترة ثلاث سنوات. المصدر: دليل NY CDL-10 القسم 1.6.5؛ 49 CFR 383.51 الجدول 3."},"60":{"q":"أنت تقود شاحنة جرّار-مقطورة في مدينة نيويورك وترى لافتة مكتوبًا عليها 'NO COMMERCIAL VEHICLES'. ماذا تشير هذه اللافتة بشأن الطريق الذي أمامك؟","options":["إنه طريق نزهة (parkway) تابع لولاية نيويورك مُصمَّم للسيارات فقط، حيث تُحظر المركبات التجارية","إنه مسار عبور مخصص للشاحنات (through truck route) ومفتوح ليلاً فقط","إنه مسار سريع معفى من الرسوم ومخصص للحافلات","إنه شارع توصيل محلي يجوز للشاحنات السير فيه أثناء التحميل فقط"],"explanation":"بُني نظام طرق النزهة (parkways) في نيويورك في أوائل القرن العشرين للسيارات فقط، ولا يُسمح بأي مركبات تجارية، بما في ذلك شاحنات الجرّار-المقطورة والحافلات، على طرق النزهة هذه. تشير لافتة 'NO COMMERCIAL VEHICLES' إلى طريق مخصص للسيارات فقط. المصدر: كتيّب طرق النزهة للشاحنات من NYSDOT؛ NY VTL."},"61":{"q":"يسأل سائق تجاري جديد عن سبب الخطورة الشديدة للجسور الحجرية المنخفضة فوق طرق النزهة (parkways) في جنوب ولاية نيويورك على الشاحنات. ما هي الإجابة الأفضل بناءً على قواعد نيويورك؟","options":["للجسور حدود وزن لكن لا توجد حدود ارتفاع معلنة","بعض الارتفاعات الرأسية المعلنة منخفضة إلى حد يصل إلى 6 أقدام و11 بوصة، وتصطدم الشاحنات المفرطة الارتفاع بها وتعلق تحتها","الجسور مخصصة حصريًا للحافلات أثناء ساعات الذروة","يُسمح للشاحنات لكن عليها إطلاق بوقها قبل كل جسر"],"explanation":"يحذّر NYSDOT من أن الجسور الحجرية المنخفضة على نظام طرق النزهة لها ارتفاعات رأسية معلنة منخفضة إلى حد يصل إلى 6 أقدام و11 بوصة. والمركبات التجارية، المحظورة من طرق النزهة، كثيرًا ما تصطدم بهذه الجسور المنخفضة وتعلق تحتها، مما يتسبب في حوادث خطيرة وتأخيرات طويلة. المصدر: كتيّب طرق النزهة للشاحنات من NYSDOT."},"62":{"q":"أيٌّ مما يلي طريق في جنوب ولاية نيويورك لا يُسمح فيه بأي مركبات تجارية، بما في ذلك شاحنات الجرّار-المقطورة؟","options":["طريق لونغ آيلاند السريع (I-495)","طريق نيويورك ستيت ثروواي (I-87)","طريق بروكلين-كوينز السريع (I-278)","طريق بِلت باركواي (Belt Parkway) في بروكلين وكوينز"],"explanation":"يُعدُّ بِلت باركواي (Belt Parkway) أحد طرق النزهة في جنوب الولاية (إلى جانب هنري هدسون، وكروس آيلاند، وهتشينسون ريفر، وغراند سنترال، ونورثرن ستيت وغيرها) حيث تُحظر المركبات التجارية. أما الطرق السريعة (Expressways) وطريق ثروواي (Thruway) فهي مسارات بين الولايات مفتوحة للشاحنات. المصدر: كتيّب طرق النزهة للشاحنات من NYSDOT؛ قيود طرق النزهة من NYC DOT."},"63":{"q":"يدخل سائق تجاري بصورة غير قانونية إلى طريق نزهة (parkway) في نيويورك فتعلق شاحنة جرّار-مقطورة تحت جسر منخفض. بالإضافة إلى الغرامات والنقاط، ما هي العاقبة الإضافية التي تحذّر منها نيويورك تحديدًا؟","options":["احتجاز إلزامي للمركبة لمدة 30 يومًا بغض النظر عن الضرر","فقدان CDL تلقائيًا لمدة سنة واحدة عند أول مخالفة","رسوم سحب قد تتجاوز 10,000 دولار لشاحنات الجرّار-المقطورة بالإضافة إلى تعويض الولاية عن إصلاح الجسر","حظر فيدرالي من العمل في جميع الولايات الخمسين"],"explanation":"يُدرِج NYSDOT عواقب قيادة مركبة تجارية على طريق نزهة: غرامات و/أو نقاط، واحتمال إصابة، وأضرار للمركبة وللجسر/الحاجز الواقي، ورسوم سحب تتجاوز 10,000 دولار لشاحنات الجرّار-المقطورة، وتعويض الولاية عن إصلاح الجسر. المصدر: كتيّب طرق النزهة للشاحنات من NYSDOT."},"64":{"q":"في مدينة نيويورك، تنقسم شبكة مسارات الشاحنات إلى فئتين. ما هما؟","options":["مسارات شاحنات نهارية ومسارات شاحنات ليلية","مسارات شاحنات محلية ومسارات شاحنات عابرة","مسارات شاحنات سريعة ومسارات شاحنات برسوم","مسارات شاحنات الأحياء ومسارات شاحنات الجسور"],"explanation":"تتكوّن شبكة مسارات الشاحنات في مدينة نيويورك (نحو 1,000 ميل، مُعرَّفة في القسم 4-13 من قواعد المرور بمدينة نيويورك) من مسارات الشاحنات المحلية (Local Truck Routes)، للشاحنات التي تقوم باستلام أو تسليم محلي داخل أحد الأحياء (borough)، ومسارات الشاحنات العابرة (Through Truck Routes)، للشاحنات التي تمرّ عبور دون أن يكون لها نقطة انطلاق أو وجهة في المنطقة. المصدر: توجيه مسارات الشاحنات من NYC DOT؛ قواعد المرور بمدينة نيويورك 4-13."},"65":{"q":"يجب على شاحنة أن تغادر مسار شاحنات مخصصًا في مدينة نيويورك للوصول إلى عنوان تسليم. بموجب قواعد مسارات الشاحنات في مدينة نيويورك، كيف يجب على السائق أن يتصرف؟","options":["استخدام أي شارع، في أي اتجاه، حتى اكتمال التسليم","مغادرة مسار الشاحنات عند التقاطع الأقرب إلى الوجهة، وسلوك أكثر الطرق مباشرةً، والعودة إلى أقرب مسار شاحنات بالطريقة نفسها","السير فقط في الشوارع السكنية لتجنّب ازدحام المرور","الحصول على تصريح خطّي منفصل للخروج عن المسار لكل عملية تسليم"],"explanation":"تسمح قواعد مدينة نيويورك للشاحنة بمغادرة المسار المخصص فقط للوصول إلى نقطة انطلاق أو وجهة. يجب على السائق المغادرة عند التقاطع الأقرب إلى الوجهة، والسير عبر أكثر الطرق مباشرةً، ثم العودة إلى أقرب مسار شاحنات مخصص عبر أكثر الطرق مباشرةً. المصدر: توجيه مسارات الشاحنات من NYC DOT؛ قواعد المرور بمدينة نيويورك 4-13."},"66":{"q":"أيُّ المركبات يُطلَب منها التوقف (STOP) عند كل معبر للسكة الحديدية مع الطريق السريع بموجب قواعد نيويورك والقواعد الفيدرالية التي اعتمدتها نيويورك؟","options":["جميع المركبات التجارية التي يزيد وزنها عن 26,000 رطل","المركبات التي تسحب مقطورات فقط","الحافلات التي تقلّ ركابًا والمركبات التي تنقل مواد خطرة تحمل لوحات تحذيرية (placards)","المركبات الصهريجية الفارغة فقط التي استُخدمت سابقًا للمواد القابلة للاشتعال"],"explanation":"في نيويورك، يجب على الحافلات التي تقلّ ركابًا والمركبات التجارية التي تعرض لوحات تحذيرية (placards) للمواد الخطرة أن تتوقف عند جميع معابر السكة الحديدية. تتوقف على بعد 50 قدمًا لكن ليس أقرب من 15 قدمًا، وتنظر وتستمع، ويجب ألا تبدّل التروس أثناء العبور. المصدر: دليل CDL في نيويورك CDL-10؛ 49 CFR 392.10."},"67":{"q":"يجب على سائق شاحنة مواد خطرة تحمل لوحات تحذيرية (placards) في نيويورك أن يتوقف عند معبر السكة الحديدية. ضمن أي مسافة من أقرب سكة يجب أن تتوقف المركبة؟","options":["على بعد 50 قدمًا لكن ليس أقرب من 15 قدمًا","على بعد 100 قدم لكن ليس أقرب من 25 قدمًا","على بعد 5 أقدام بالضبط من أقرب سكة","على بعد 30 قدمًا لكن ليس أقرب من 10 أقدام"],"explanation":"يجب على المركبات المطلوب منها التوقف عند معابر السكة الحديدية (شاحنات المواد الخطرة الحاملة للوحات التحذيرية placards والحافلات التي تقلّ ركابًا) أن تتوقف على بعد 50 قدمًا لكن ليس أقرب من 15 قدمًا من أقرب سكة، ثم تنظر وتستمع لقدوم القطارات قبل المتابعة دون تبديل التروس. المصدر: دليل CDL في نيويورك CDL-10؛ 49 CFR 392.10."},"68":{"q":"بموجب قانون \"أفسح الطريق\" (Move Over Law) في نيويورك (VTL 1144-a)، ماذا يجب على السائق التجاري أن يفعل عند الاقتراب من مركبة طوارئ أو مركبة خطر متوقفة على جانب الطريق مع أضوائها التحذيرية الوامضة؟","options":["التوقف تمامًا حتى تغادر مركبة الطوارئ","التباطؤ والانتقال، عند الإمكان، حارة كاملة بعيدًا عن المركبة المتوقفة","إطلاق البوق والحفاظ على السرعة المعلنة","الانتقال إلى الكتف والتجاوز من اليمين"],"explanation":"يتطلّب قانون \"أفسح الطريق\" (Move Over Law) في نيويورك من السائقين توخّي الحذر اللازم، والتباطؤ، والانتقال حارة كاملة بعيدًا عن مركبة طوارئ أو مركبة خطر متوقفة تعرض أضواءً وامضة عندما يكون من الآمن القيام بذلك. واعتبارًا من عام 2023 وُسِّع القانون ليشمل جميع المركبات المتوقفة. المصدر: NY VTL 1144-a؛ لجنة الحاكم للسلامة المرورية في نيويورك."},"69":{"q":"ينطبق قانون \"أفسح الطريق\" (Move Over Law) في نيويورك على مركبات الخطر كما ينطبق على مركبات الطوارئ. أيٌّ مما يلي يُعدُّ 'مركبة خطر' يشملها القانون؟","options":["سيارة ركاب متوقفة بصورة قانونية بجانب الرصيف","شاحنة سحب أو مركبة صيانة تعرض أضواءً كهرمانية وامضة","سيارة أجرة متوقفة لأخذ راكب","شاحنة توصيل مع تشغيل أضواء التحذير الرباعية في ممر سيارات"],"explanation":"يشمل قانون \"أفسح الطريق\" (Move Over Law) في نيويورك مركبات الخطر مثل شاحنات السحب، ومركبات الإنشاء والصيانة، ومركبات النظافة التي تعرض أضواءً كهرمانية وامضة، بالإضافة إلى مركبات الشرطة والإطفاء والإسعاف. المصدر: NY VTL 1144-a؛ مواد \"أفسح الطريق\" من نيويورك ستيت ثروواي."},"70":{"q":"بموجب قانون نيويورك، متى يجوز للسائق التجاري استخدام هاتف خلوي محمول باليد أو جهاز إرسال رسائل نصية أثناء تشغيل مركبة تجارية CMV؟","options":["فقط أثناء التوقف عند إشارة حمراء أو لافتة قف","فقط للمكالمات التي تقلّ عن 30 ثانية","فقط عند استخدام الجهاز للملاحة","أبدًا أثناء تشغيل المركبة التجارية CMV؛ فالاستخدام باليد وإرسال الرسائل النصية محظوران"],"explanation":"تحظر نيويورك على السائقين التجاريين استخدام هاتف محمول باليد أو جهاز إرسال رسائل نصية أثناء تشغيل مركبة تجارية CMV. وخلافًا لبعض الحالات غير التجارية، لا يجوز للسائق التجاري استخدام جهاز محمول باليد حتى عند التوقف عند إشارة. وتضيف الإدانة نقاطًا وتُعدُّ مخالفة CDL خطيرة. المصدر: NY VTL 1225-c و1225-d؛ دليل CDL في نيويورك CDL-10."},"71":{"q":"يُدان سائق تجاري في نيويورك للمرة الثانية خلال ثلاث سنوات بتشغيل مركبة تجارية CMV أثناء استخدام هاتف محمول باليد أو إرسال رسائل نصية. ما هي العاقبة الفيدرالية التي تُطبَّق فوق عقوبات نيويورك؟","options":["إلغاء CDL مدى الحياة بصورة دائمة","سحب أهلية CDL لمدة 60 يومًا عند الإدانة الثانية خلال ثلاث سنوات","مجرد تحذير خطّي من FMCSA","رسم إداري قدره 50 دولارًا دون سحب أهلية"],"explanation":"تسحب قواعد FMCSA الفيدرالية، المطبَّقة في نيويورك، أهلية حامل CDL لمدة 60 يومًا عند الإدانة الثانية باستخدام هاتف محمول باليد/إرسال رسائل نصية خلال ثلاث سنوات، ولمدة 120 يومًا عند الإدانة الثالثة أو ما بعدها خلال ثلاث سنوات، بالإضافة إلى غرامات الولاية والنقاط. المصدر: FMCSA 49 CFR 383.51؛ NY DMV."},"72":{"q":"بعد التوقف لحافلة مدرسية ذات أضواء حمراء وامضة في نيويورك، متى يجوز للسائق المتابعة؟","options":["فورًا بعد العد إلى خمسة","حالما لا يظهر أي أطفال، حتى لو ظلّت الأضواء تومض","عندما تستأنف الحافلة الحركة، أو يشير سائق الحافلة أو ضابط مرور إلى أنه من الآمن المتابعة","بعد أن تغلق الحافلة بابها، بغض النظر عن الأضواء"],"explanation":"في نيويورك، لا يجوز للسائق الذي توقف لحافلة مدرسية أن يتحرك مجددًا حتى تبدأ الحافلة بالتحرك، أو يشير سائق الحافلة أو ضابط شرطة/مرور إلى المتابعة. تتحكّم الأضواء الحمراء الوامضة في التوقف. المصدر: NY VTL 1174؛ دليل سائق NY DMV الفصل 6."},"73":{"q":"إذا تعيّن على مركبة تجارية التوقف على كتف طريق سريع باتجاه واحد أو مقسّم في نيويورك، فأين يجب وضع المثلثات التحذيرية الثلاثة (الأجهزة العاكسة)؟","options":["الثلاثة جميعها ضمن 10 أقدام خلف المركبة","عند نحو 10 أقدام و100 قدم و200 قدم باتجاه حركة المرور القادمة","واحد في الأمام واثنان مباشرة تحت المقطورة","عند 25 قدمًا و50 قدمًا و75 قدمًا على جانب السائق فقط"],"explanation":"على طريق سريع باتجاه واحد أو مقسّم، ضع الأجهزة التحذيرية على بعد نحو 10 أقدام و100 قدم و200 قدم من المركبة باتجاه حركة المرور القادمة، في منتصف الحارة أو الكتف الذي تشغله المركبة التجارية CMV. يجب وضع الأجهزة خلال 10 دقائق. المصدر: دليل CDL في نيويورك CDL-10؛ 49 CFR 392.22."},"74":{"q":"توقفت مركبة تجارية على طريق ذي حارتين باتجاهين في نيويورك. كيف يجب على السائق وضع المثلثات التحذيرية الطارئة الثلاثة؟","options":["واحد على بعد 10 أقدام إلى الجانب، وواحد على بعد 100 قدم خلف المركبة، وواحد على بعد 100 قدم أمامها","الثلاثة جميعها على بعد 200 قدم خلف المركبة","واحد على السقف واثنان على المصدّ الأمامي","واحد على بعد 10 أقدام خلفًا، وواحد على بعد 50 قدمًا خلفًا، وواحد على بعد 50 قدمًا أمامًا"],"explanation":"على طريق باتجاهين، ضع مثلثًا ضمن 10 أقدام من المؤخرة على جانب حركة المرور، وواحدًا على بعد نحو 100 قدم خلفًا، وواحدًا على بعد نحو 100 قدم أمام المركبة، بحيث تُحذَّر حركة المرور من كلا الاتجاهين. المصدر: دليل CDL في نيويورك CDL-10؛ 49 CFR 392.22."},"75":{"q":"في نيويورك، ما هو الحد الأقصى للارتفاع الذي يجوز أن تبلغه الشاحنة وحمولتها دون تصريح خاص للأحجام الزائدة (oversize)؟","options":["11 قدمًا","15 قدمًا","16 قدمًا و6 بوصات","13 قدمًا و6 بوصات"],"explanation":"بموجب القسم 385 من قانون المركبات والمرور في نيويورك (NY VTL)، يبلغ الحد الأقصى القانوني لارتفاع المركبة والحمولة 13 قدمًا و6 بوصات؛ والارتفاع البالغ 14 قدمًا أو أكثر يتطلّب تصريح أحجام زائدة (oversize). كما يجب على السائقين الالتزام بلافتات الارتفاع المعلنة، وهي شائعة على جسور نيويورك القديمة. المصدر: NY VTL 385؛ NY DMV."},"76":{"q":"يعرض جسر في نيويورك ارتفاعًا علويًّا معلنًا أقل من ارتفاع الشاحنة. ماذا يجب على السائق التجاري أن يفعل؟","options":["المتابعة ببطء وإطلاق البوق أثناء المرور تحته","تفريغ بعض الهواء من الإطارات لخفض المركبة والمتابعة","عدم المرور تحت الجسر والبحث بدلاً من ذلك عن طريق بديل قانوني","المتابعة إذا كانت الحمولة هي الجزء الوحيد الذي يتجاوز الارتفاع"],"explanation":"يحظر قانون نيويورك تحريك مركبة عبر أي جسر أو منشأة إذا تجاوز ارتفاع المركبة الارتفاع المعلن. يجب على السائق سلوك طريق بديل. وتُعدُّ اصطدامات المركبات المفرطة الارتفاع بالجسور المنخفضة وطرق النزهة مشكلة سلامة كبرى في نيويورك. المصدر: NY VTL 385؛ إرشادات NYSDOT بشأن اصطدامات الجسور."},"77":{"q":"كيف تُحصَّل الرسوم عادةً من مركبة تجارية على طريق نيويورك ستيت ثروواي الحديث؟","options":["يجب على السائقين التوقف ودفع نقدًا عند كل كشك تقاطع","من خلال التحصيل اللاحدودي للرسوم (cashless tolling) باستخدام بطاقات E-ZPass أو فواتير الرسوم بالبريد التي تقرأها بوابات علوية (gantries)","تُعفى الرسوم لجميع المركبات الحاملة لـ CDL","يدفع السائقون مسبقًا رسمًا سنويًا ثابتًا واحدًا في DMV"],"explanation":"يستخدم طريق نيويورك ستيت ثروواي التحصيل اللاحدودي للرسوم (cashless tolling): تقرأ البوابات العلوية (gantries) بطاقات E-ZPass أو تصوّر اللوحات لإصدار فاتورة رسوم بالبريد (Tolls by Mail)، بحيث لم تعد المركبات تتوقف عند الأكشاك. وتُحتسب الرسوم على المركبات التجارية حسب فئة المركبة، ويمكنها الحصول على خصومات مع NY E-ZPass. المصدر: هيئة نيويورك ستيت ثروواي - التحصيل اللاحدودي للرسوم."},"78":{"q":"ما هو أفضل ممارسة للسائق التجاري الذي يقود في نيويورك أثناء ظروف الشتاء مثل الثلوج والجليد؟","options":["الحفاظ على سرعة الطريق السريع ومسافة الاتباع المعتادتين لإبقاء حركة المرور سائرة","تقليل السرعة، وزيادة مسافة الاتباع، واستخدام سلاسل الإطارات حيثما تتطلّب الظروف أو المتطلبات المعلنة ذلك","الضغط على المكابح بقوة وتكرار لإبقائها دافئة","القيادة في الحارة اليسرى القصوى فقط وتعطيل جميع أنظمة الجر"],"explanation":"تجلب شتاءات نيويورك الثلوج والجليد، خاصة في مناطق شمال الولاية ومناطق التأثير البحيري (lake-effect). يوجّه دليل CDL في نيويورك السائقين إلى التباطؤ، وزيادة مسافة الاتباع، والكبح برفق، واستخدام سلاسل الإطارات عندما تتطلّب الظروف أو اللافتات المعلنة أجهزة جر. المصدر: دليل CDL في نيويورك CDL-10، القيادة في الظروف المعاكسة."},"79":{"q":"أيُّ جهة حكومية تُصدر رخص القيادة التجارية (CDLs) في ولاية نيويورك؟","options":["الإدارة الفيدرالية لسلامة الناقلات بالشاحنات (FMCSA)","إدارة المركبات الآلية في ولاية نيويورك (NY DMV)","إدارة النقل في ولاية نيويورك (NYSDOT)","إدارة المركبات الآلية الأمريكية"],"explanation":"في نيويورك، تتولى إدارة المركبات الآلية في ولاية نيويورك (NY DMV) إدارة وإصدار رخص CDL. وتحدد FMCSA المعايير الفيدرالية لـ CDL لكنها لا تُصدر الرخصة. المصدر: NY DMV، رخصة القيادة التجارية (CDL)."},"80":{"q":"قبل أن تتمكن من التقدم للحصول على CDL أو تصريح متعلّم تجاري (Commercial Learner Permit) في نيويورك، ما الذي يجب أن تكون حاملاً له بالفعل عمومًا؟","options":["رقم سلطة تشغيل فيدرالي بين الولايات","شهادة سائق حافلة مكتملة بموجب Article 19-A","شهادة فاحص طبي من U.S. DOT مؤرخة خلال 24 ساعة","رخصة قيادة سارية من ولاية نيويورك (الفئة D، أو الفئة E، أو الفئة C غير CDL) أو رخصة CDL سارية من ولاية أخرى"],"explanation":"تتطلّب NY DMV من المتقدم لأول مرة للحصول على CDL أن يكون حاملاً بالفعل لرخصة قيادة من نيويورك (الفئة D، أو E، أو C غير CDL) أو رخصة CDL سارية من خارج الولاية قبل التقدم. المصدر: NY DMV، احصل على رخصة قيادة تجارية (CDL)."},"81":{"q":"تتحقّق نيويورك من هوية المتقدم للحصول على CDL أو تصريح باستخدام أي نظام؟","options":["فحص خلفية فيدرالي يعتمد على بصمات الأصابع فقط","نظام تحقق من تاريخ الائتمان من 10 نقاط","إقرار موثّق بمستند واحد فقط","نظام إثبات الهوية المكوّن من 6 نقاط في NY DMV"],"explanation":"تستخدم نيويورك نظام إثبات هوية مكوّنًا من 6 نقاط: يجب على المتقدمين تقديم مستندات يبلغ مجموعها 6 نقاط على الأقل لإثبات هويتهم، بالإضافة إلى إثبات تاريخ الميلاد والإقامة. المصدر: NY DMV، إثبات الهوية (نظام 6 نقاط)."},"82":{"q":"بموجب نظام الهوية المكوّن من 6 نقاط في نيويورك، ما هي القاعدة بشأن المستندات التي تقدّمها؟","options":["تُقبل الصور المنسوخة فقط حتى تتمكن DMV من الاحتفاظ بها في الملف","يُقبل أي مستند طالما يُظهر صورتك","يجب أن تكون أصولاً أو نسخًا مصدّقة؛ ولا تُقبل الصور المنسوخة والمستندات المغلّفة بالبلاستيك","تُفضَّل المستندات المغلّفة بالبلاستيك لأنها تدوم لفترة أطول"],"explanation":"تتطلّب NY DMV أن تكون مستندات الـ 6 نقاط أصولاً أو نسخًا مصدّقة. ولن تقبل DMV الصور المنسوخة العادية أو المستندات المغلّفة بالبلاستيك. المصدر: NY DMV، إثبات الهوية."},"83":{"q":"بالإضافة إلى 6 نقاط من مستندات الهوية، ما الذي يجب أيضًا على المتقدم للحصول على CDL في نيويورك تقديمه بخصوص رقم الضمان الاجتماعي الخاص به؟","options":["لا شيء؛ فنيويورك لا تجمع أرقام الضمان الاجتماعي لرخص CDL","إقرار ضريبي فيدرالي عن كل من السنوات الثلاث الأخيرة","رقم ضمان اجتماعي يُصدَر فقط بعد منح CDL","إثبات رقم الضمان الاجتماعي الخاص به، أو إقرار موقّع إذا لم يُصدَر له واحد قط"],"explanation":"تتطلّب NY DMV إثبات رقم الضمان الاجتماعي الخاص بك؛ وإذا لم يُصدَر لك واحد قط، فيجب عليك توقيع إقرار يفيد بذلك. المصدر: NY DMV، إثبات الهوية / كيفية التقدم."},"84":{"q":"كيف يبدأ المتقدم في نيويورك عملية الحصول على CDL عادةً في مكتب DMV؟","options":["بجدولة اختبار القيادة على الطريق واجتيازه قبل أي اختبار خطّي","بتقديم إقرار Article 19-A إلى الناقل","بالتقدم للحصول على تصريح متعلّم تجاري (CLP) واجتياز اختبار (اختبارات) المعرفة الخطّي المطلوب","بإرسال طلب تجديد بالبريد وانتظار رخصة جديدة"],"explanation":"تبدأ العملية في مكتب DMV: يتقدم المتقدم للحصول على تصريح متعلّم تجاري (CLP) ويجتاز اختبار (اختبارات) المعرفة الخطّي للفئة والتظهيرات (endorsements) المطلوبة. المصدر: NY DMV، احصل على رخصة قيادة تجارية (CDL)."},"85":{"q":"أيُّ مجموعة من اختبارات المعرفة الخطّية يخضع لها المتقدم في نيويورك عادةً للحصول على CLP من الفئة A؟","options":["اختبار قيادة تجاري مجمّع واحد فقط","اختبارا تظهير المواد الخطرة والركاب فقط","اختبار شفهي بموجب Article 19-A واختبار قيادة دفاعية","المعرفة العامة، والمكابح الهوائية، والمركبات المركّبة"],"explanation":"للحصول على CLP من الفئة A، يجتاز المتقدمون في نيويورك عادةً اختبارات المعرفة العامة، والمكابح الهوائية، والمركبات المركّبة. وتُؤخذ اختبارات التظهير (المواد الخطرة HazMat، والركاب، والحافلة المدرسية، إلخ) بصورة منفصلة. المصدر: NY DMV، اختبارات معرفة CDL."},"86":{"q":"كم تبلغ مدة صلاحية تصريح المتعلّم التجاري (CLP) في نيويورك بعد أن مدّدت نيويورك فترة صلاحيته؟","options":["30 يومًا","ستة أشهر","ثماني سنوات","سنة واحدة (365 يومًا)"],"explanation":"مدّدت نيويورك صلاحية CLP من ستة أشهر إلى سنة واحدة (365 يومًا). وتسري درجات اختبار المعرفة للفترة نفسها. المصدر: NY DMV، DMV تمدّد صلاحية تصريح المتعلّم التجاري."},"87":{"q":"ما هو الحد الأدنى لمدة الزمن التي يجب على المتقدم في نيويورك أن يحتفظ خلالها بتصريح CLP قبل الخضوع لاختبار القيادة على الطريق (المهارات) لـ CDL؟","options":["90 يومًا على الأقل","لا توجد فترة انتظار مطلوبة","14 يومًا على الأقل","6 أشهر على الأقل"],"explanation":"اتباعًا للقاعدة الفيدرالية، لا يمكنك جدولة اختبار قيادة CDL على الطريق في نيويورك لتاريخ يقع ضمن 14 يومًا من تاريخ إصدار CLP الخاص بك. المصدر: NY DMV، احصل على رخصة قيادة تجارية (CDL) / FMCSA."},"88":{"q":"قبل الخضوع لاختبار قيادة CDL على الطريق في نيويورك لأول CDL (أو لإضافة تظهير المواد الخطرة HazMat، أو الركاب، أو الحافلة المدرسية)، ما هو التدريب الذي يجب إكماله أولاً؟","options":["تدريب السائق المبتدئ (ELDT) من مزوّد مُدرَج في سجل مزوّدي التدريب التابع لـ FMCSA","دورة نيويوركية فقط لخفض النقاط من خلال القيادة الدفاعية","تقييم نصف سنوي خلف عجلة القيادة بموجب Article 19-A","دورة إقرار ناقل بالشاحنات بموجب 19A"],"explanation":"تتطلّب قواعد ELDT الفيدرالية (السارية منذ 7 فبراير 2022) من المتقدمين الجدد لـ CDL ومن بعض المتقدمين للتظهيرات إكمال تدريب من مزوّد مُدرَج في سجل مزوّدي التدريب التابع لـ FMCSA قبل اختبار المهارات. المصدر: NY DMV / FMCSA ELDT."},"89":{"q":"في نيويورك، كيف يجب أن يرتبط تدريب ELDT المكتمل باختبار قيادة CDL المجدول على الطريق؟","options":["يمكن إكمال ELDT في موقع الاختبار يوم اختبار القيادة على الطريق","يجب أن يكون ELDT المكتمل الخاص بك مودَعًا لدى DMV قبل 7 أيام على الأقل من اختبار القيادة على الطريق، وإلا يُلغى الاختبار","يحتاج ELDT فقط إلى أن يكون مودَعًا خلال 30 يومًا بعد اجتياز اختبار القيادة على الطريق","لا يُطلَب أبدًا إيداع ELDT لدى NY DMV"],"explanation":"تتيح نيويورك لك جدولة اختبار القيادة على الطريق قبل إنهاء ELDT، لكن يجب أن يكون ELDT المكتمل مودَعًا لدى DMV قبل 7 أيام على الأقل من الاختبار وإلا يُلغى اختبار القيادة على الطريق (لا تُفقَد رسوم الـ 40 دولارًا؛ تُعيد الجدولة). المصدر: NY DMV، احصل على CDL."},"90":{"q":"كيف يُجدوَل اختبار قيادة CDL على الطريق في نيويورك؟","options":["بالدخول إلى أي مكتب DMV والاختبار فورًا دون موعد","من خلال نظام جدولة اختبارات القيادة على الطريق التابع لـ NY DMV (بوابة إلكترونية/هاتف)","فقط بإرسال طلب ورقي بالبريد إلى FMCSA","تلقائيًا، من قبل مزوّد تدريب ELDT نيابةً عن المتقدم"],"explanation":"تُجدوَل اختبارات قيادة CDL على الطريق في نيويورك من خلال نظام جدولة اختبارات القيادة على الطريق التابع لـ DMV (بوابة إلكترونية، متاحة أيضًا عبر الهاتف). المصدر: NY DMV، جدولة اختبار قيادة على الطريق وخوضه."},"91":{"q":"يتكوّن اختبار مهارات/قيادة CDL على الطريق في نيويورك من أي مكوّنات ثلاثة؟","options":["فحص المركبة قبل الرحلة، ومهارات التحكم الأساسية، واختبار القيادة على الطريق","اختبار خطّي، وفحص بصري، وفحص بصمات الأصابع","اختبار مواد خطرة، واختبار ركاب، واختبار حافلة مدرسية","اختبار شفهي بموجب Article 19-A، وفحص طبي، واختبار قيادة دفاعية"],"explanation":"يتكوّن اختبار مهارات CDL في نيويورك من ثلاثة أجزاء: فحص المركبة قبل الرحلة، واختبار مهارات التحكم الأساسية، واختبار القيادة على الطريق. المصدر: NY DMV / دليل CDL (CDL-10)."},"92":{"q":"إذا خضعت لاختبار قيادة CDL على الطريق في نيويورك بمركبة دون مكابح هوائية، فماذا يحدث لـ CDL الخاص بك؟","options":["يُضاف قيد L، يحظر عليك تشغيل المركبات المجهّزة بمكابح هوائية","تتم ترقية CDL الخاص بك للسماح بجميع أنواع المكابح تلقائيًا","تحصل على تظهير المواد الخطرة HazMat تلقائيًا","لا يتغيّر شيء؛ فمعدات المكابح لا تؤثر على القيود"],"explanation":"يؤدي الاختبار بمركبة دون مكابح هوائية كاملة إلى قيد 'L' (لا مكابح هوائية). وتشمل القيود ذات الصلة 'E' (ناقل حركة أوتوماتيكي) و'Z' (مكابح هوائية-هيدروليكية). المصدر: NY DMV، احصل على CDL / دليل CDL."},"93":{"q":"يتطلّب التصديق الذاتي لـ CDL في نيويورك من السائق أن يختار كم من فئات القيادة الفيدرالية؟","options":["جميع فئات القيادة الفيدرالية الأربع في آنٍ واحد","واحدة من أربع فئات قيادة فيدرالية","اثنتين من ثلاث فئات قيادة فيدرالية","لا شيء؛ فالتصديق الذاتي اختياري في نيويورك"],"explanation":"يجب على حاملي CDL إجراء تصديق ذاتي باختيار واحدة فقط من أربعة أنواع قيادة فيدرالية. المصدر: NY DMV، صدّق ذاتيًا على نوع قيادتك."},"94":{"q":"ما هي فئات القيادة الأربع للتصديق الذاتي الفيدرالي التي يختار منها حامل CDL في نيويورك؟","options":["محلية، وإقليمية، ووطنية، ودولية","الفئة A، والفئة B، والفئة C، والفئة D","بين الولايات غير معفاة، وداخل الولاية غير معفاة، وبين الولايات معفاة، وداخل الولاية معفاة","المواد الخطرة، والركاب، والحافلة المدرسية، والصهريج"],"explanation":"فئات التصديق الذاتي الأربع هي: بين الولايات غير معفاة (NI)، وداخل الولاية غير معفاة (NA)، وبين الولايات معفاة (EI)، وداخل الولاية معفاة (EA). المصدر: NY DMV، صدّق ذاتيًا على نوع قيادتك."},"95":{"q":"أيُّ فئات التصديق الذاتي تتطلّب من حامل CDL في نيويورك الاحتفاظ بشهادة فاحص طبي سارية من U.S. DOT في الملف؟","options":["الفئات المعفاة فقط","الفئتان غير المعفاتين (بين الولايات غير معفاة وداخل الولاية غير معفاة)","الفئات الأربع جميعها بالتساوي","لا تتطلّب أيٌّ من الفئات شهادة طبية"],"explanation":"يجب على السائقين الذين يصدّقون ذاتيًا على نوع غير معفى (NI أو NA) الاحتفاظ بشهادة فاحص طبي سارية من USDOT في الملف؛ أما السائقون المعفون (EI/EA) فلا يلزمهم ذلك. المصدر: NY DMV، التصديق الطبي لـ CDL."},"96":{"q":"بموجب الإجراءات الفيدرالية والنيويوركية الحالية، كيف تُرسَل شهادة الفاحص الطبي لحامل CDL إلى NY DMV عمومًا؟","options":["يقدّمها الفاحص الطبي المعتمد إلكترونيًا إلى السجل الوطني لـ FMCSA، الذي يحيل النتيجة إلى DMV","يجب على السائق دائمًا تسليم الشهادة الورقية الأصلية يدويًا إلى مكتب DMV","لا تُبلَّغ الشهادة أبدًا إلى DMV ويحتفظ بها السائق وحده","يرسل صاحب العمل الشهادة بالبريد إلى FMCSA مرة واحدة في السنة"],"explanation":"بموجب القواعد الفيدرالية، يرفع الفاحصون الطبيون المعتمدون نتائج الفحص إلى السجل الوطني لـ FMCSA، الذي يرسل بعد ذلك حالة التصديق الطبي إلى NY DMV إلكترونيًا، بدلاً من أن يرسل السائق نسخة بالبريد. المصدر: NY DMV / التصديق الطبي لـ FMCSA."},"97":{"q":"كم تبلغ مدة صلاحية CDL في نيويورك، وكيف يُجدَّد عادةً؟","options":["صالح لمدة ثماني سنوات؛ ولا يمكن تجديد رخص CDL عبر الإنترنت عمومًا وتُجدَّد بالبريد أو شخصيًا","صالح لمدة سنة واحدة؛ ويُجدَّد عبر الإنترنت فقط","صالح لمدة سنتين؛ ويُجدَّد تلقائيًا دون أي إجراء","صالح لمدة عشر سنوات؛ ويُجدَّد لدى FMCSA فقط"],"explanation":"تبلغ صلاحية CDL في نيويورك ثماني سنوات. وخلافًا للرخص العادية، لا يمكن تجديد رخص CDL عبر الإنترنت عمومًا ويجب تجديدها بالبريد أو في مكتب DMV. المصدر: NY DMV، جدّد رخصة قيادة تجارية (CDL)."},"98":{"q":"تضع Article 19-A في نيويورك متطلبات خاصة لأي مجموعة من السائقين؟","options":["جميع سائقي سيارات الركاب في مدينة نيويورك","سائقي شاحنات صهاريج المواد الخطرة فقط","سائقي الحافلات العاملين لدى ناقلات بالشاحنات مشمولة (مثل سائقي الحافلات المدرسية وبعض الناقلات المرخّصة من NYSDOT)","حاملي CDL من خارج الولاية الذين يمرّون عبر نيويورك"],"explanation":"تضع Article 19-A متطلبات تأهيل خاصة لسائقي حافلات الناقلات بالشاحنات المشمولة (مثل ناقلات الحافلات المدرسية وبعض الناقلات المرخّصة من NYSDOT)، بما في ذلك الفحوص الطبية نصف السنوية، والاختبار خلف عجلة القيادة والاختبار الخطّي/الشفهي. المصدر: NY DMV، معلومات Article 19-A."}}};
